            assign P5[i/2] = P4[i+1] & P4[i];
        end
    endgenerate

    assign G6 = G5[1] | (P5[1] & G5[0]);
    assign P6 = P5[1] & P5[0];

    assign C[1] = G1[0] | (P1[0] & carry_in);
    assign C[2] = G2[0] | (P2[0] & carry_in);
    assign C[4] = G3[0] | (P3[0] & carry_in);
    assign C[8] = G4[0] | (P4[0] & carry_in);
    assign C[16] = G5[0] | (P5[0] & carry_in);
