module pipelined_adder_32bit (
    input clk,       // Synchronous to posedge of clk 
    input reset,     // Synchronous active high reset
    input [31:0] A,  // 32 bit operand for addition  
    input [31:0] B,  // 32 bit operand for addition  
    input start,     // Active high signal to indicate when valid input data is provided
    output [31:0] S, // Final sum or result 
    output Co,       // Final carry out 
    output done      // Completion signal, active high when computation is complete    
);

    wire [7:0] A1, B1, A2, B2, A3, B3;
    wire carry1, carry2, carry3;
    wire [7:0] s13, s23, s12, A21, B21, A31, B31, A32, B32;
    wire [7:0] s1, s2, s3;
    wire control2, control1, control3, control4;

    dff #(1) FF00 (.clk(clk), .reset(reset), .D(1'b1), .Q(control1));

    dff #(8) FF11 (.clk(clk), .reset(reset), .D(A[15:8]), .Q(A1));
    dff #(8) FF12 (.clk(clk), .reset(reset), .D(B[15:8]), .Q(B1));
    dff #(8) FF13 (.clk(clk), .reset(reset), .D(A[23:16]), .Q(A2));
    dff #(8) FF14 (.clk(clk), .reset(reset), .D(B[23:16]), .Q(B2));
    dff #(8) FF15 (.clk(clk), .reset(reset), .D(A[31:24]), .Q(A3));
    dff #(8) FF16 (.clk(clk), .reset(reset), .D(B[31:24]), .Q(B3));

    carry_lookahead_adder #(8) ADD1 (.clk(clk), .reset(reset), .A(A[7:0]), .B(B[7:0]), .Cin(1'b0), .S(s1), .carry(carry1));

    dff #(1) FF01 (.clk(clk), .reset(reset), .D(control1), .Q(control2));

    dff #(8) FF21 (.clk(clk), .reset(reset), .D(s1), .Q(s12));
    dff #(8) FF23 (.clk(clk), .reset(reset), .D(A3), .Q(A21));
    dff #(8) FF24 (.clk(clk), .reset(reset), .D(B3), .Q(B21));
    dff #(8) FF25 (.clk(clk), .reset(reset), .D(A2), .Q(A31));
    dff #(8) FF26 (.clk(clk), .reset(reset), .D(B2), .Q(B31));

    carry_lookahead_adder #(8) ADD2 (.clk(clk), .reset(reset), .A(A1), .B(B1), .Cin(carry1), .S(s2), .carry(carry2));

    dff #(1) FF10 (.clk(clk), .reset(reset), .D(control2), .Q(control3));

    dff #(8) FF31 (.clk(clk), .reset(reset), .D(s2), .Q(s13));
    dff #(8) FF32 (.clk(clk), .reset(reset), .D(s12), .Q(s23));
    dff #(8) FF35 (.clk(clk), .reset(reset), .D(A31), .Q(A32));
    dff #(8) FF36 (.clk(clk), .reset(reset), .D(B31), .Q(B32));

    carry_lookahead_adder #(8) ADD3 (.clk(clk), .reset(reset), .A(A21), .B(B21), .Cin(carry2), .S(s3), .carry(carry3));

    dff #(1) FF111 (.clk(clk), .reset(reset), .D(control3), .Q(done));

    dff #(8) FF41 (.clk(clk), .reset(reset), .D(s13), .Q(S[7:0]));
    dff #(8) FF42 (.clk(clk), .reset(reset), .D(s23), .Q(S[15:8]));
    dff #(8) FF43 (.clk(clk), .reset(reset), .D(s3), .Q(S[23:16]));

    carry_lookahead_adder #(8) ADD4 (.clk(clk), .reset(reset), .A(A32), .B(B32), .Cin(carry3), .S(S[31:24]), .carry(Co));

endmodule

output.rtl/fir_filter.sv:
always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
         sample_delay1 <= 0;
         sample_delay2 <= 0;
         sample_delay3 <= 0;
         accumulator <= 0;
         // pipeline registers for output
         pipeline_reg0 <= 0;
         pipeline_reg1 <= 0;
         pipeline_reg2 <= 0;
         output_sample <= 0;
    end else begin
         // shift delays: sample_delay1 <= sample_delay2, sample_delay2 <= sample_delay3, sample_delay3 <= input_sample;
         // update accumulator: accumulator <= coeff0*input_sample + coeff1*sample_delay1 + coeff2*sample_delay2 + coeff3*sample_delay3;
         // pipeline registers: pipeline_reg0 <= accumulator; pipeline_reg1 <= pipeline_reg0; pipeline_reg2 <= pipeline_reg1; output_sample <= pipeline_reg2;
    end
end

module fir_filter (
    input wire clk,                  
    input wire reset,                
    input wire [15:0] data_in,       
    output reg [15:0] data_out,      
    input wire [1:0] window_type     
);

    // Coefficient registers for each tap
    reg [15:0] coeff0, coeff1, coeff2, coeff3, coeff4, coeff5, coeff6, coeff7;
    // Shift registers for data delay
    reg [15:0] shift_reg0, shift_reg1, shift_reg2, shift_reg3, shift_reg4, shift_reg5, shift_reg6, shift_reg7;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            // Comprehensive reset: clear all internal states and output
            data_out          <= 16'd0;
            shift_reg0        <= 16'd0;
            shift_reg1        <= 16'd0;
            shift_reg2        <= 16'd0;
            shift_reg3        <= 16'd0;
            shift_reg4        <= 16'd0;
            shift_reg5        <= 16'd0;
            shift_reg6        <= 16'd0;
            shift_reg7        <= 16'd0;
            coeff0            <= 16'd0;
            coeff1            <= 16'd0;
            coeff2            <= 16'd0;
            coeff3            <= 16'd0;
            coeff4            <= 16'd0;
            coeff5            <= 16'd0;
            coeff6            <= 16'd0;
            coeff7            <= 16'd0;
        end else begin
            // Dynamic coefficient selection based on window_type
            case (window_type)
                2'b00: begin  // Rectangular Window: coefficients 10 to 17
                    coeff0 = 16'd10;
                    coeff1 = 16'd11;
                    coeff2 = 16'd12;
                    coeff3 = 16'd13;
                    coeff4 = 16'd14;
                    coeff5 = 16'd15;
                    coeff6 = 16'd16;
                    coeff7 = 16'd17;
                end
                2'b01: begin  // Hanning Window: [2, 4, 8, 12, 12, 8, 4, 2]
                    coeff0 = 16'd2;
                    coeff1 = 16'd4;
                    coeff2 = 16'd8;
                    coeff3 = 16'd12;
                    coeff4 = 16'd12;
                    coeff5 = 16'd8;
                    coeff6 = 16'd4;
                    coeff7 = 16'd2;
                end
                2'b10: begin  // Hamming Window: [3, 6, 9, 11, 11, 9, 6, 3]
                    coeff0 = 16'd3;
                    coeff1 = 16'd6;
                    coeff2 = 16'd9;
                    coeff3 = 16'd11;
                    coeff4 = 16'd11;
                    coeff5 = 16'd9;
                    coeff6 = 16'd6;
                    coeff7 = 16'd3;
                end
                2'b11: begin  // Blackman Window: [1, 2, 5, 9, 9, 5, 2, 1]
                    coeff0 = 16'd1;
                    coeff1 = 16'd2;
                    coeff2 = 16'd5;
                    coeff3 = 16'd9;
                    coeff4 = 16'd9;
                    coeff5 = 16'd5;
                    coeff6 = 16'd2;
                    coeff7 = 16'd1;
                end
            endcase

            // FIR filter output calculation:
            // Multiply each delayed sample by its corresponding coefficient and sum the results.
            // A right shift by 4 bits is applied for normalization.
            reg [31:0] sum;
            sum = (shift_reg0 * coeff0) +
                  (shift_reg1 * coeff1) +
                  (shift_reg2 * coeff2) +
                  (shift_reg3 * coeff3) +
                  (shift_reg4 * coeff4) +
                  (shift_reg5 * coeff5) +
                  (shift_reg6 * coeff6) +
                  (shift_reg7 * coeff7);
            data_out <= sum >> 4;

            // Cascade data_in through the eight shift registers.
            // The oldest sample is shifted out and data_in enters at the beginning.
            shift_reg7 <= shift_reg6;
            shift_reg6 <= shift_reg5;
            shift_reg5 <= shift_reg4;
            shift_reg4 <= shift_reg3;
            shift_reg3 <= shift_reg2;
            shift_reg2 <= shift_reg1;
            shift_reg1 <= shift_reg0;
            shift_reg0 <= data_in;
        end
    end

endmodule

output.rtl/glitch_free_mux.sv:
module glitch_free_mux (
    input  wire         clk1,
    input  wire         clk2,
    input  wire         sel,
    input  wire         rst_n,
    output wire         clkout
);

  // Internal registers to control which clock is enabled.
  reg         clk1_en;
  reg         clk2_en;

  // Cross-domain coordination signals:
  // enable_clk2: asserted in the clk1 domain to request that clk2 be enabled.
  // clk2_disabled: asserted in the clk2 domain to signal that clk2 has been disabled,
  //               so that the clk1 domain can re-enable clk1.
  reg         enable_clk2;
  reg         clk2_disabled;

  // Registers to synchronize and detect transitions of the sel signal in each clock domain.
  // In the clk1 domain:
  reg         sel_sync1;
  reg         sel_prev1;
  // In the clk2 domain:
  reg         sel_sync2;
  reg         sel_prev2;

  // ------------------------------------------------------------------
  // clk1 domain: Manage clk1_en and coordinate switching.
  // When sel transitions from 0 to 1 (rising edge), disable clk1 and request
  // that clk2 be enabled. When clk2 is later disabled (via clk2_disabled),
  // re-enable clk1.
  // ------------------------------------------------------------------
  always @(posedge clk1 or negedge rst_n) begin
    if (!rst_n) begin
      clk1_en       <= 1'b0;
      sel_sync1     <= 1'b0;
      sel_prev1     <= 1'b0;
      clk2_disabled <= 1'b0;
    end else begin
      // Update registers for edge detection.
      sel_prev1 <= sel_sync1;
      sel_sync1 <= sel;

      // Detect rising edge of sel (0 -> 1): disable clk1 and request clk2 enable.
      if (sel_prev1 == 1'b0 && sel_sync1 == 1'b1) begin
        clk1_en       <= 1'b0;
        enable_clk2   <= 1'b1;
      end
      // If clk2 has been disabled (detected in the clk2 domain), then re-enable clk1.
      else if (clk2_disabled) begin
        clk1_en       <= 1'b1;
        clk2_disabled <= 1'b0;
      end
      // Default: when no transition is detected, set clk1_en based on sel.
      // When sel is 0, clk1 should be enabled; when sel is 1, clk1 remains disabled.
      else begin
        clk1_en <= (sel_sync1 == 1'b0) ? 1'b1 : 1'b0;
      end
    end
  end

  // ------------------------------------------------------------------
  // clk2 domain: Manage clk2_en and coordinate switching.
  // When a request from the clk1 domain (enable_clk2) is received, enable clk2.
  // When sel transitions from 1 to 0 (falling edge) in this domain, disable clk2
  // and assert clk2_disabled to signal the clk1 domain to re-enable clk1.
  // ------------------------------------------------------------------
  always @(posedge clk2 or negedge rst_n) begin
    if (!rst_n) begin
      clk2_en      <= 1'b0;
      sel_sync2    <= 1'b0;
      sel_prev2    <= 1'b0;
      // Note: enable_clk2 is driven by the clk1 domain.
    end else begin
      // Update registers for edge detection.
      sel_prev2 <= sel_sync2;
      sel_sync2 <= sel;

      // If a request to enable clk2 is received, then enable clk2.
      if (enable_clk2) begin
        clk2_en      <= 1'b1;
        enable_clk2  <= 1'b0;
      end
      // Detect falling edge of sel (1 -> 0): disable clk2 and signal clk1 domain.
      else if (sel_prev2 == 1'b1 && sel_sync2 == 1'b0) begin
        clk2_en      <= 1'b0;
        clk2_disabled<= 1'b1;
      end
      // Default: when no transition is detected, set clk2_en based on sel.
      // When sel is 1, clk2 should be enabled; when sel is 0, clk2 remains disabled.
      else begin
        clk2_en <= (sel_sync2 == 1'b1) ? 1'b1 : 1'b0;
      end
    end
  end

  // ------------------------------------------------------------------
  // Output clock generation:
  // The output clock (clkout) is generated by ORing the two input clocks,
  // each gated by its respective enable signal. This ensures that only one
  // clock is active at any time, providing glitch-free switching.
  // ------------------------------------------------------------------
  assign clkout = (clk1 & clk1_en) | (clk2 & clk2_en);

endmodule

input.rtl/glitch_free_mux.sv:
module glitch_free_mux
(
    input clk1,		//input clk1
    input clk2,		// input clk2
    input rst_n,	// async reset
    input sel,		// selection line
    output  clkout	// clock output
);

reg clkout_reg ;
reg clk1_enable, clk2_enable;
reg clk1_out, clk2_out ;


// CLK1 ENABLE LOGIC
always@(posedge clk1 or negedge rst_n  ) begin
        if (~rst_n) begin
            clk1_enable <= 0 ; 
        end else begin
            clk1_enable <= ~ clk2_enable & ~sel  ;
        end 
end

// CLK2 ENABLE LOGIC
always@(posedge clk2 or negedge rst_n  ) begin
       if (~rst_n) begin
           clk2_enable <= 0 ; 
       end else begin
           clk2_enable <= ~ clk1_enable & sel  ;
       end 
end

// OUTPUT LOGIC
assign clkout = (clk1 & clk1_enable) | (clk2 & clk2_enable) ;

endmodule

