module String_to_ASCII_Converter (
    input wire clk,                       // Clock signal
    input wire reset,                     // Reset signal
    input wire start,                     // Start conversion
    input wire [7:0] char_in [7:0],       // 8-character input string (7 bits per character: 0-95)
    output reg [7:0] ascii_out,           // Final latched ASCII output
    output reg valid,                     // Indicates valid output
    output reg ready                      // Indicates module ready to accept input
);
    // Parameters for character type identification
    localparam DIGIT   = 2'd0;
    localparam UPPER   = 2'd1;
    localparam LOWER   = 2'd2;
    localparam SPECIAL = 2'd3;
    // ASCII Offsets
    localparam DIGIT_OFFSET   = 8'd48;    // '0' = 48
    localparam UPPER_OFFSET   = 8'd65;    // 'A' = 65
    localparam LOWER_OFFSET   = 8'd97;    // 'a' = 97
    localparam SPECIAL_OFFSET = 8'd33;   // First special character '!' = 33
    // Registers
    reg [3:0] index;                      // Index for current character
    reg active;                           // Indicates active conversion
    reg [1:0] char_type;                  // Current character type
    reg [7:0] intermediate_ascii;         // Combinational ASCII value
    // Function to determine character type
    function [1:0] determine_char_type;
        input [7:0] char;
        begin
            if (char < 8'd10)
                determine_char_type = DIGIT;    // '0'-'9'
            else if (char < 8'd36)
                determine_char_type = UPPER;    // 'A'-'Z'
            else if (char < 8'd62)
                determine_char_type = LOWER;    // 'a'-'z'
            else
                determine_char_type = SPECIAL;  // Special characters
        end
    endfunction
    // Combinational logic for ASCII calculation
    always @(*) begin
        // Determine character type
        char_type = determine_char_type(char_in[index]);
        // Calculate ASCII based on character type
        case (char_type)
            DIGIT:   intermediate_ascii = char_in[index] + DIGIT_OFFSET;          // '0'-'9'
            UPPER:   intermediate_ascii = (char_in[index] - 8'd10) + UPPER_OFFSET; // 'A'-'Z'
            LOWER:   intermediate_ascii = (char_in[index] - 8'd36) + LOWER_OFFSET; // 'a'-'z'
            SPECIAL: intermediate_ascii = (char_in[index] - 8'd62) + SPECIAL_OFFSET; // Special characters
            default: intermediate_ascii = 8'd0;
        endcase
    end
    // Sequential logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            index       <= 4'd0;
            ascii_out   <= 8'd0;
            valid       <= 1'b0;
            ready       <= 1'b1;
            active      <= 1'b0;
        end else begin
            if (start && ready) begin
                // Start conversion
                ready <= 1'b0;
                active <= 1'b1;
                index <= 4'd0;
                valid <= 1'b0;
            end else if (active) begin
                // Process current character
                if (index < 8) begin
                    ascii_out <= intermediate_ascii; // Latch current ASCII value
                    valid <= 1'b1; // Indicate valid output
                    index <= index + 1;
                end else begin
                    // Finish conversion
                    active <= 1'b0;
                    ready <= 1'b1;
                    valid <= 1'b0;
                end
            end
        end
    end
endmodule

output.rtl/String_to_ASCII_Converter.sv:
module String_to_ASCII_Converter (
    input  wire         clk,
    input  wire         reset,
    input  wire         start,
    input  wire [7:0]   char_in [7:0],
    output reg  [7:0]   ascii_out [7:0],
    output reg          valid,
    output reg          ready
);

  //-------------------------------------------------------------------------
  // Combinational Conversion Logic:
  // For each input character (using the custom encoding):
  //   - Digits (0-9): value 0-9   -> ASCII = value + 48
  //   - Uppercase Letters (A-Z): value 10-35 -> ASCII = (value - 10) + 65
  //   - Lowercase Letters (a-z): value 36-61 -> ASCII = (value - 36) + 97
  //   - Special Characters: value 62-93 -> ASCII = (value - 62) + 33
  //     (Note: Although the specification mentioned 62-95, the expected output
  //      for "@" is 64, which requires that "@" be encoded as 93.)
  //-------------------------------------------------------------------------
  genvar j;
  generate
    for (j = 0; j < 8; j = j + 1) begin : conv_gen
      // Compute the ASCII conversion for each character concurrently.
      // This always_comb block ensures that all 8 outputs are computed in parallel.
      always @(*) begin
        if (char_in[j] < 10)
          // Digits: '0'-'9'
          ascii_out[j] = char_in[j] + 8'd48;
        else if (char_in[j] < 36)
          // Uppercase: 'A'-'Z'
          ascii_out[j] = (char_in[j] - 10) + 8'd65;
        else if (char_in[j] < 62)
          // Lowercase: 'a'-'z'
          ascii_out[j] = (char_in[j] - 36) + 8'd97;
        else if (char_in[j] < 94)
          // Special: '!' to '@' (with "@" expected as 64)
          ascii_out[j] = (char_in[j] - 62) + 8'd33;
        else
          ascii_out[j] = 8'd0;
      end
    end
  endgenerate

  //-------------------------------------------------------------------------
  // Control Logic:
  // When start is asserted and the module is ready, the conversion is performed
  // in one clock cycle. The valid signal is asserted immediately and ready is
  // deasserted during conversion. Once conversion completes (in the same cycle),
  // the outputs (all 8 ASCII values) are available and valid remains high.
  // On the next cycle (or when start is deasserted), valid is cleared and ready
  // is reasserted.
  //-------------------------------------------------------------------------
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      // Clear outputs and control signals on reset.
      integer k;
      for (k = 0; k < 8; k = k + 1)
        ascii_out[k] <= 8'd0;
      valid  <= 1'b0;
      ready  <= 1'b1;
    end else begin
      if (start && ready) begin
        // Start conversion: the combinational block computes all 8 outputs.
        // (They are available immediately and latched on this clock edge.)
        valid <= 1'b1;
        ready <= 1'b0;
      end else begin
        // No conversion in progress: clear outputs and assert ready.
        integer n;
        for (n = 0; n < 8; n = n + 1)
          ascii_out[n] <= 8'd0;
        valid <= 1'b0;
        ready <= 1'b1;
      end
    end
  end

endmodule

output.rtl/sync_muller_c_element.sv:
module sync_muller_c_element #(
  parameter NUM_INPUT  = 2,  // Number of input signals
  parameter PIPE_DEPTH = 1   // Number of pipeline stages (minimum 1)
) (
  input  logic                  clk,   // Clock signal
  input  logic                  srst,  // Synchronous reset (active-high)
  input  logic                  clr,   // Clear signal (clears pipeline and output)
  input  logic                  clk_en,// Clock enable signal
  input  logic [NUM_INPUT-1:0]  inp,   // Input signals (NUM_INPUT-width vector)
  output logic                  out    // Output signal
);

  // Pipeline to store intermediate states of inputs
  // The vector is partitioned into PIPE_DEPTH slices of NUM_INPUT bits each.
  logic [(PIPE_DEPTH*NUM_INPUT)-1:0] pipe;
  genvar i;

  // Generate block for pipeline implementation
  generate
    for (i = 0; i < PIPE_DEPTH; i = i + 1) begin : pipe_stage
      if (i == 0) begin : stage0
         always_ff @(posedge clk) begin
            if (srst || clr)
              pipe[0+:NUM_INPUT] <= '0;
            else if (clk_en)
              pipe[0+:NUM_INPUT] <= inp;
            // Else: retain current state when clk_en is low
         end
      end else begin : stage_other
         always_ff @(posedge clk) begin
            if (srst || clr)
              pipe[i*NUM_INPUT+:NUM_INPUT] <= '0;
            else if (clk_en)
              pipe[i*NUM_INPUT+:NUM_INPUT] <= pipe[(i-1)*NUM_INPUT+:NUM_INPUT];
            // Else: retain current state when clk_en is low
         end
      end
    end
  endgenerate

  // Output logic:
  // The output is updated based on the final pipeline stage.
  // It is set to 1 if all bits are high, 0 if all bits are low,
  // otherwise it retains its previous state.
  // Note: This creates an additional one-cycle delay, so the total latency is PIPE_DEPTH + 1 cycles.
  always_ff @(posedge clk) begin
    if (srst || clr)
      out <= 1'b0;
    else if (clk_en) begin
      logic [NUM_INPUT-1:0] final_stage;
      final_stage = pipe[(PIPE_DEPTH-1)*NUM_INPUT+:NUM_INPUT];
      if (final_stage == {NUM_INPUT{1'b1}})
        out <= 1'b1;
      else if (final_stage == {NUM_INPUT{1'b0}})
        out <= 1'b0;
      // Else: retain previous state of out
    end
    // Else: when clk_en is low, out remains unchanged
  end

endmodule

output.rtl/adc_data_rotate.sv:
module adc_data_rotate #(
    parameter DATA_WIDTH = 8  // Parameterized data width
)(
    // Inputs
    input  logic                     i_clk,             // Clock signal
    input  logic                     i_rst_n,           // Active-low reset
    input  logic [DATA_WIDTH-1:0]    i_adc_data_in,     // Input ADC data
    input  logic [3:0]               i_shift_count,     // Number of bits to shift (supports up to 15)
    input  logic                     i_shift_direction, // Shift direction (0: Left, 1: Right)

    // Outputs
    output logic [DATA_WIDTH-1:0]   o_processed_data,  // Rotated output data
    output logic                    o_operation_status // Operation status (0: Reset, 1: Active)
);

    // Internal signal for temporary storage during rotation
    logic [DATA_WIDTH-1:0] temp;
    // Loop index for bit-wise processing
    integer k;
    // Effective shift count computed as modulo DATA_WIDTH
    int shift_val;

    always_ff @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            o_processed_data <= '0;
            o_operation_status <= 0;
        end
        else begin
            o_operation_status <= 1;
            // Compute effective shift: i_shift_count modulo DATA_WIDTH
            shift_val = int'(i_shift_count) % DATA_WIDTH;

            // No rotation needed if shift_val is 0
            if (shift_val == 0)
                o_processed_data <= i_adc_data_in;
            // Left rotation: bits shifted out from the left re-enter on the right
            else if (i_shift_direction == 0) begin
                for (k = 0; k < DATA_WIDTH; k = k + 1) begin
                    temp[k] = i_adc_data_in[(k + shift_val) % DATA_WIDTH];
                end
                o_processed_data <= temp;
            end
            // Right rotation: bits shifted out from the right re-enter on the left
            else begin
                for (k = 0; k < DATA_WIDTH; k = k + 1) begin
                    temp[k] = i_adc_data_in[(k - shift_val + DATA_WIDTH) % DATA_WIDTH];
                end
                o_processed_data <= temp;
            end
        end
    end

endmodule

input.rtl/key_expansion_128aes.sv:
module key_expansion_128aes #(
    parameter NBW_KEY = 'd128,
    parameter NBW_OUT = 'd1408
) (
    input  logic               clk,
    input  logic               rst_async_n,
    input  logic               i_start,
    input  logic [NBW_KEY-1:0] i_key,
    output logic               o_done,
    output logic [NBW_OUT-1:0] o_expanded_key
);

localparam NBW_BYTE = 'd8;
localparam STEPS = 'd10;
localparam NBW_WORD = 'd32;

// Auxiliary wires
logic [NBW_BYTE-1:0] Rcon   [STEPS];
logic [NBW_KEY-1:0] valid_key;
logic [NBW_KEY-1:0] step_key[STEPS];
logic [NBW_OUT-1:0] expanded_key_nx;
logic [NBW_OUT-1:0] expanded_key_ff;

logic [STEPS:0] steps_ff;

logic [3:0] count_ff;
logic [3:0] count_nx;

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        expanded_key_ff <= {NBW_OUT{1'b0}};
        steps_ff <= 11'h400;
    end else begin
        expanded_key_ff <= expanded_key_nx;
        if(i_start || (|steps_ff[9:0])) begin
            steps_ff <= {steps_ff[STEPS-1:0], (i_start & o_done)};
        end
    end
end

assign o_done = steps_ff[STEPS];
assign o_expanded_key = expanded_key_ff;

assign Rcon[0] = 8'h01;
assign Rcon[1] = 8'h02;
assign Rcon[2] = 8'h04;
assign Rcon[3] = 8'h08;
assign Rcon[4] = 8'h10;
assign Rcon[5] = 8'h20;
assign Rcon[6] = 8'h40;
assign Rcon[7] = 8'h80;
assign Rcon[8] = 8'h1b;
assign Rcon[9] = 8'h36;

generate
    for(genvar i = 0; i < STEPS; i++) begin : steps
        logic [NBW_WORD-1:0] RotWord;
        logic [NBW_WORD-1:0] SubWord;
        logic [NBW_WORD-1:0] RconXor;

        sbox uu_sbox0 (
            .i_data(RotWord[31:24]),
            .o_data(SubWord[31:24])
        );

        sbox uu_sbox1 (
            .i_data(RotWord[23:16]),
            .o_data(SubWord[23:16])
        );

        sbox uu_sbox2 (
            .i_data(RotWord[15:8]),
            .o_data(SubWord[15:8])
        );

        sbox uu_sbox3 (
            .i_data(RotWord[7:0]),
            .o_data(SubWord[7:0])
        );

        always_comb begin
            RotWord = {expanded_key_ff[NBW_OUT-(i+1)*NBW_KEY+NBW_WORD-NBW_BYTE-1-:(NBW_WORD-NBW_BYTE)], expanded_key_ff[NBW_OUT-(i+1)*NBW_KEY+NBW_WORD-1-:NBW_BYTE]};
            RconXor = {SubWord[31:24]^Rcon[i], SubWord[23:0]};

            step_key[i][127:96] = expanded_key_ff[NBW_OUT-(4*i  )*NBW_WORD-1-:NBW_WORD] ^ RconXor;
            step_key[i][95 :64] = expanded_key_ff[NBW_OUT-(4*i+1)*NBW_WORD-1-:NBW_WORD] ^ step_key[i][127:96];
            step_key[i][63 :32] = expanded_key_ff[NBW_OUT-(4*i+2)*NBW_WORD-1-:NBW_WORD] ^ step_key[i][95 :64];
            step_key[i][31 :0 ] = expanded_key_ff[NBW_OUT-(4*i+3)*NBW_WORD-1-:NBW_WORD] ^ step_key[i][63 :32];
        end
    end
endgenerate

assign expanded_key_nx = {valid_key  , step_key[0], step_key[1], step_key[2],
                          step_key[3], step_key[4], step_key[5], step_key[6],
                          step_key[7], step_key[8], step_key[9]};

always_comb begin
    if (i_start & o_done) begin
        valid_key = i_key;
    end else begin
        valid_key = expanded_key_ff[NBW_OUT-1-:NBW_KEY];
    end
end

endmodule : key_expansion_128aes

