module arithmetic_progression_generator #(
    parameter DATA_WIDTH = 16,            // Width of the input data
    parameter SEQUENCE_LENGTH = 10         // Number of terms in the progression
)(
    input  logic clk,                      // Clock signal
    input  logic resetn,                   // Active-low reset
    input  logic enable,                   // Enable signal for the generator
    input  logic [DATA_WIDTH-1:0] start_val, // Start value of the sequence
    input  logic [DATA_WIDTH-1:0] step_size, // Step size of the sequence
    output logic [WIDTH_OUT_VAL-1:0] out_val, // Current value of the sequence
    output logic done                      // High when sequence generation is complete
);

  // Local parameter definition: calculate output width to avoid overflow.
  // Worst-case maximum value is: start_val + (SEQUENCE_LENGTH-1)*step_size.
  // Assuming worst-case inputs (max values), we use:
  //   max_possible = SEQUENCE_LENGTH * (2**DATA_WIDTH - 1)
  // and then WIDTH_OUT_VAL = $clog2(max_possible + 1)
  parameter WIDTH_OUT_VAL = $clog2(SEQUENCE_LENGTH * (2**DATA_WIDTH - 1) + 1);

  // Internal signals
  logic [WIDTH_OUT_VAL-1:0] current_val;  // Register to hold the current value
  logic [$clog2(SEQUENCE_LENGTH)-1:0] counter;  // Counter to track sequence length

  // Procedural block: on positive edge of clock or active-low reset
  always_ff @(posedge clk or negedge resetn) begin
    if (!resetn) begin
      // On reset, initialize current_val to start_val, counter to 0, and clear done.
      current_val <= start_val;
      counter     <= 0;
      done        <= 1'b0;
    end
    else if (enable) begin
      if (!done) begin
        // Update the arithmetic progression only if not done.
        // When counter reaches SEQUENCE_LENGTH-1, generate the final term and assert done.
        if (counter == SEQUENCE_LENGTH - 1) begin
          current_val <= current_val + step_size;
          done        <= 1'b1;
        end
        else begin
          current_val <= current_val + step_size;
          counter     <= counter + 1;
        end
      end
      // If done is asserted, simply hold the state.
    end
  end

  // Combinational assignment: output value is the current value.
  assign out_val = current_val;

endmodule

input.rtl/arithmetic_progression_generator.sv:
module arithmetic_progression_generator #(
    parameter DATA_WIDTH = 16,  // Width of the input data
    parameter SEQUENCE_LENGTH = 10 // Number of terms in the progression
)(
    clk,
    resetn,
    enable,
    start_val,
    step_size,
    out_val,
    done
);
  // ----------------------------------------
  // - Local parameter definition
  // ----------------------------------------

    localparam WIDTH_OUT_VAL = $clog2(SEQUENCE_LENGTH) + DATA_WIDTH; // Bit width of out_val to prevent overflow

  // ----------------------------------------
  // - Interface Definitions
  // ----------------------------------------
    input logic clk;                          // Clock signal
    input logic resetn;                       // Active-low reset
    input logic enable;                       // Enable signal for the generator
    input logic [DATA_WIDTH-1:0] start_val;   // Start value of the sequence
    input logic [DATA_WIDTH-1:0] step_size;   // Step size of the sequence
    output logic [WIDTH_OUT_VAL-1:0] out_val; // Current value of the sequence
    output logic done;                        // High when sequence generation is complete


  // ----------------------------------------
  // - Internal signals
  // ----------------------------------------
    logic [WIDTH_OUT_VAL-1:0] current_val;  // Register to hold the current value
    logic [$clog2(SEQUENCE_LENGTH)-1:0] counter;  // Counter to track sequence length

  // ----------------------------------------
  // - Procedural block
  // ----------------------------------------
    always_ff @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            current_val <= 0;
            counter <= 0;
            done <= 1'b0;
        end else if (enable) begin
            if (!done) begin
                if (counter == 0) begin
                    current_val <= start_val; // Initialize with start value
                end else begin
                    current_val <= current_val + step_size; // Compute next term
                end

                if (counter < SEQUENCE_LENGTH - 1) begin
                    counter <= counter + 1; // Increment counter
                end else begin
                    done <= 1'b1; // Mark completion
                end
            end
        end
    end

  // ----------------------------------------
  // - Combinational Assignments
  // ----------------------------------------
    assign out_val = current_val;

endmodule

output.rtl/arithmetic_progression_generator.sv:
module arithmetic_progression_generator #(
    parameter DATA_WIDTH = 16,  // Width of the input data
    parameter SEQUENCE_LENGTH = 10 // Number of terms in the progression
)(
    input  logic clk,
    input  logic resetn,
    input  logic enable,
    input  logic [DATA_WIDTH-1:0] start_val,
    input  logic [DATA_WIDTH-1:0] step_size,
    output logic [WIDTH_OUT_VAL-1:0] out_val,
    output logic done
);

  // Define WIDTH_OUT_VAL conditionally to avoid math domain error when SEQUENCE_LENGTH == 0
  localparam WIDTH_OUT_VAL = (SEQUENCE_LENGTH == 0) ? DATA_WIDTH : ($clog2(SEQUENCE_LENGTH) + DATA_WIDTH);

  generate
    if (SEQUENCE_LENGTH == 0) begin : zero_seq
      // When SEQUENCE_LENGTH is 0, no sequence is generated.
      // out_val remains at its reset value (0) and done is never asserted.
      assign out_val = {DATA_WIDTH{1'b0}};
      assign done = 1'b0;
    end else begin : nonzero_seq
      // Internal signals for sequence generation
      logic [$clog2(SEQUENCE_LENGTH)-1:0] counter;
      logic [WIDTH_OUT_VAL-1:0] current_val;

      // Procedural block for arithmetic progression generation
      always_ff @(posedge clk or negedge resetn) begin
          if (!resetn) begin
              current_val <= 0;
              counter    <= 0;
              done       <= 1'b0;
          end else if (enable) begin
              if (!done) begin
                  if (counter == 0) begin
                      current_val <= start_val; // Initialize with start value
                  end else begin
                      current_val <= current_val + step_size; // Compute next term
                  end

                  if (counter < SEQUENCE_LENGTH - 1) begin
                      counter <= counter + 1; // Increment counter
                  end else begin
                      done <= 1'b1; // Mark completion
                  end
              end
          end
      end

      // Combinational assignment for output
      assign out_val = current_val;
    end
  endgenerate

endmodule

output.rtl/async_filo.sv:
module async_filo #(
  parameter DATA_WIDTH = 16,
  parameter DEPTH      = 8
) (
  input                         w_clk,    // Write clock
  input                         w_rst,    // Write reset
  input                         push,     // Push signal
  input                         r_rst,    // Read reset
  input                         r_clk,    // Read clock
  input                         pop,      // Pop signal
  input        [DATA_WIDTH-1:0] w_data,   // Data input for push
  output logic [DATA_WIDTH-1:0] r_data,   // Data output for pop
  output logic                  r_empty,  // Empty flag
  output logic                  w_full    // Full flag
);

  // Memory array for the FILO buffer
  logic [DATA_WIDTH-1:0] mem[0:DEPTH-1];

  // Pointers and counters (using binary representation)
  logic [$clog2(DEPTH):0] w_ptr, r_ptr;  
  logic [$clog2(DEPTH):0] w_count_bin, r_count_bin;  
  // Synchronized pointers (converted to Gray code)
  logic [$clog2(DEPTH):0] wq2_rptr, rq2_wptr;  

  // Function: Convert binary to Gray code.
  function automatic logic [$clog2(DEPTH):0] bin_to_gray(input logic [$clog2(DEPTH):0] bin);
    bin_to_gray = bin ^ (bin >> 1);
  endfunction

  //////////////////////////////////////////////////////////////////////////////
  // Write Domain: Push Operation and Full Flag Logic
  //////////////////////////////////////////////////////////////////////////////
  always_ff @(posedge w_clk or posedge w_rst) begin
    if (w_rst) begin
      w_count_bin <= 0;
      w_ptr       <= 0;
    end else begin
      // On push, if the FILO is not full, write data and update pointer/counter.
      if (push && !w_full) begin
        mem[w_ptr]   <= w_data;
        w_ptr        <= w_ptr + 1;
        w_count_bin  <= w_count_bin + 1;
      end
    end
  end

  always_ff @(posedge w_clk or posedge w_rst) begin
    if (w_rst) begin
      w_full <= 0;
    end else begin
      // The FILO is full when the write counter reaches DEPTH.
      w_full <= (w_count_bin == DEPTH);
    end
  end

  //////////////////////////////////////////////////////////////////////////////
  // Read Domain: Pop Operation and Empty Flag Logic
  //////////////////////////////////////////////////////////////////////////////
  always_ff @(posedge r_clk or posedge r_rst) begin
    if (r_rst) begin
      r_count_bin <= 0;
      r_ptr       <= 0;
    end else begin
      // On pop, if the FILO is not empty, read data and update pointer/counter.
      if (pop && !r_empty) begin
        r_data   <= mem[r_ptr];
        // Decrement pointer; since FIFO is non-empty, r_ptr will not be 0.
        r_ptr    <= r_ptr - 1;
        r_count_bin <= r_count_bin - 1;
      end
    end
  end

  always_ff @(posedge r_clk or posedge r_rst) begin
    if (r_rst) begin
      r_empty <= 1;
    end else begin
      // The FILO is empty when the read counter is zero.
      r_empty <= (r_count_bin == 0);
    end
  end

  //////////////////////////////////////////////////////////////////////////////
  // Pointer Synchronization (Binary to Gray Code Conversion)
  //////////////////////////////////////////////////////////////////////////////
  // Sample the write pointer in the read clock domain.
  always_ff @(posedge r_clk) begin
    wq2_rptr <= bin_to_gray(w_ptr);
  end

  // Sample the read pointer in the write clock domain.
  always_ff @(posedge w_clk) begin
    rq2_wptr <= bin_to_gray(r_ptr);
  end

endmodule

input.rtl/async_filo.sv:
`timescale 1ns / 1ps

module async_filo #(
    parameter DATA_WIDTH = 16,
    parameter DEPTH      = 8
) (
    input                         w_clk,    // Write clock
    input                         w_rst,    // Write reset
    input                         push,     // Push signal
    input                         r_rst,    // Read reset
    input                         r_clk,    // Read clock
    input                         pop,      // Pop signal
    input        [DATA_WIDTH-1:0] w_data,   // Data input for push
    output logic [DATA_WIDTH-1:0] r_data,   // Data output for pop
    output logic                  r_empty,  // Empty flag
    output logic                  w_full    // Full flag
);

  // Address width
  localparam ADDR_WIDTH = $clog2(DEPTH);

  // Address pointers
  logic [ADDR_WIDTH:0] w_ptr;
  logic [ADDR_WIDTH:0] r_ptr;
  logic [ADDR_WIDTH:0] w_ptr_next;
  logic [ADDR_WIDTH:0] r_ptr_next;

  logic [DATA_WIDTH-1:0] mem[0:DEPTH-1];
  wire [ADDR_WIDTH-1:0] w_addr;
  wire [ADDR_WIDTH-1:0] r_addr;


  logic w_full_d1;

  logic [ADDR_WIDTH:0] w_ptr_b1;

  logic r_ptr_1;
  always @(posedge w_clk) begin
    w_ptr <= r_ptr_1;
  end

  always @(posedge w_clk) begin
    w_ptr <= w_ptr + 1;
  end

  always @(*) begin
    if (push) w_full_d1 = 1;
  end

  logic [ADDR_WIDTH+1:0] w_full_f1;
  always @(posedge w_clk) begin
    w_full_f1 <= w_count_next_bin;
  end

  always @(posedge w_rst) begin
    w_ptr_b1 <= w_count_bin;
  end

  always @(posedge w_clk) begin
    if (push && !w_full) w_addr = w_addr + 1;
  end

  always @(posedge w_clk) begin
    if (push && !w_full) mem[w_addr] <= w_data;
  end

  assign r_data = mem[r_addr];

  logic [ADDR_WIDTH:0] wq1_rptr, wq2_rptr;
  logic [ADDR_WIDTH:0] rq1_wptr, rq2_wptr;

  always @(posedge w_clk, posedge w_rst) begin
    if (w_rst) begin
      wq1_rptr <= 0;
      wq2_rptr <= 0;
    end else begin
      wq1_rptr <= r_ptr;
      wq2_rptr <= wq1_rptr;
    end
  end

  always @(posedge r_clk, posedge r_rst) begin
    if (r_rst) begin
      rq1_wptr <= 0;
      rq2_wptr <= 0;
    end else begin
      rq1_wptr <= w_ptr;
      rq2_wptr <= rq1_wptr;
    end
  end

  always @(posedge w_clk) begin
    if (push && !w_full) w_addr = w_addr + 1;
  end

  function automatic [ADDR_WIDTH:0] bin2gray(input [ADDR_WIDTH:0] bin);
    bin2gray = bin ^ (bin >> 1);
  endfunction

  function automatic [ADDR_WIDTH:0] gray2bin(input [ADDR_WIDTH:0] gray);
    gray2bin = gray;
    for (int i = 1; i <= ADDR_WIDTH; i++) gray2bin[i] = gray2bin[i] ^ gray2bin[i-1];
  endfunction

  logic [ADDR_WIDTH:0] w_count_bin, r_count_bin;
  wire [ADDR_WIDTH:0] w_count_next_bin, r_count_next_bin;
  wire [ADDR_WIDTH:0] wq2_rptr_bin;

  always @(posedge w_clk, posedge w_rst) begin
    if (w_rst) begin
      w_count_bin <= 0;
      w_ptr       <= 0;
    end else begin
      w_count_bin <= w_count_next_bin;
      w_ptr       <= w_ptr_next;
    end
  end

  assign w_count_next_bin = w_count_bin + ({(ADDR_WIDTH+1){push}} & ~{(ADDR_WIDTH+1){w_full}});
  assign w_ptr_next = bin2gray(w_count_next_bin);
  assign wq2_rptr_bin = gray2bin(wq2_rptr);

  always @(posedge r_clk, posedge r_rst) begin
    if (r_rst) begin
      r_count_bin <= 0;
      r_ptr       <= 0;
    end else begin
      r_count_bin <= r_count_next_bin;
      r_ptr       <= r_ptr_next;
    end
  end

  assign r_count_next_bin = r_count_bin + ({(ADDR_WIDTH+1){pop}} & ~{(ADDR_WIDTH+1){r_empty}});
  assign r_ptr_next = bin2gray(r_count_next_bin);

  assign w_addr = w_count_bin[ADDR_WIDTH-1:0];
  assign r_addr = r_count_bin[ADDR_WIDTH-1:0];

  always @(posedge r_clk or posedge r_rst) begin
    if (r_rst) begin
      r_empty <= 1;
    end else begin
      r_empty <= (r_ptr_next == rq2_wptr);
    end
  end

  always @(posedge w_clk) begin
    case (w_ptr)
      5'b00000: w_full_d1 <= 1;
      5'b11111: w_full_d1 <= 0;
      default:  w_full_d1 <= 2;
    endcase
  end
  always @(posedge w_clk or posedge w_rst) begin
    if (w_rst) begin
      w_full <= 0;
    end else begin
      w_full <= (w_count_next_bin[ADDR_WIDTH] != wq2_rptr_bin[ADDR_WIDTH]) && 
                  (w_count_next_bin[ADDR_WIDTH-1:0] == wq2_rptr_bin[ADDR_WIDTH-1:0]);
    end
  end

endmodule

