module pseudo_lru_nmru_policy #(
    parameter int NWAYS = 4,
    parameter int NINDEXES = 32
) (
    input         clock,
    input         reset,
    input  [$clog2(NINDEXES)-1:0] index,
    input  [$clog2(NWAYS)-1:0]  way_select,
    input         access,
    input         hit,
    output reg [$clog2(NWAYS)-1:0] way_replace
);

    // recency array: one per cache set (index), each with NWAYS bits.
    reg [NWAYS-1:0] recency [NINDEXES-1:0];

    integer i;
    integer reset_counter;

    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            // Initialize all recency bits to zero.
            for (reset_counter = 0; reset_counter < NINDEXES; reset_counter = reset_counter + 1) begin
                recency[reset_counter] <= {NWAYS{1'b0}};
            end
        end else begin
            // On a cache hit, mark the accessed way as recently used.
            if (hit) begin
                recency[index][way_select] <= 1'b1;
            end

            // Variables for candidate computation.
            integer zero_count;
            integer candidate;
            reg [NWAYS-1:0] zero_mask;
            zero_mask = {NWAYS{1'b1}};  // initialize mask to all ones

            // Build zero_mask: mark positions where recency bit is 0.
            for (i = 0; i < NWAYS; i = i + 1) begin
                if (recency[index][i] == 1'b0)
                    zero_mask[i] = 1'b1;
                else
                    zero_mask[i] = 1'b0;
            end

            // Count the number of zero bits.
            zero_count = 0;
            for (i = 0; i < NWAYS; i = i + 1) begin
                if (zero_mask[i] == 1'b1)
                    zero_count = zero_count + 1;
            end

            if (zero_count == 1) begin
                // LRU mode: exactly one way is not recently used.
                // Find that single zero bit.
                for (i = 0; i < NWAYS; i = i + 1) begin
                    if (zero_mask[i] == 1'b1) begin
                        candidate = i;
                        break;
                    end
                end
                // Update recency: mark the selected way as used and reset others.
                for (i = 0; i < NWAYS; i = i + 1) begin
                    if (i == candidate)
                        recency[index][i] <= 1'b1;
                    else
                        recency[index][i] <= 1'b0;
                end
            end else if (zero_count > 1) begin
                // NMRU mode: more than one way is not recently used.
                // Select the free slot with the smallest index.
                candidate = 0;
                for (i = 0; i < NWAYS; i = i + 1) begin
                    if (recency[index][i] == 1'b0) begin
                        candidate = i;
                        break;
                    end
                end
                // Do not update recency bits in NMRU mode.
            end else begin
                // Fallback: if no zero is found, choose way 0 and update recency.
                candidate = 0;
                for (i = 0; i < NWAYS; i = i + 1) begin
                    if (i == candidate)
                        recency[index][i] <= 1'b1;
                    else
                        recency[index][i] <= 1'b0;
                end
            end

            // Drive the replacement candidate output.
            way_replace <= candidate;
        end
    end

endmodule

output.rtl/lru_counter_policy.sv:
module lru_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input  clock,
    input  reset,
    input  [$clog2(NINDEXES)-1:0] index,
    input  [$clog2(NWAYS)-1:0] way_select,
    input  access,
    input  hit,
    output reg [$clog2(NWAYS)-1:0] way_replace
);

    // Each cache set (indexed by 'index') holds NWAYS counters.
    // Each counter is $clog2(NWAYS) bits wide.
    reg [(NWAYS * $clog2(NWAYS))-1:0] recency [NINDEXES-1:0];

    integer i, n, j;
    // Local variable for counter width.
    int cw = $clog2(NWAYS);

    // Sequential block: update recency array and determine replacement way.
    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            // Reset Behavior:
            // Initialize each counter in every cache set to a unique value (0 to NWAYS-1)
            // in ascending order.
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    recency[i][(n * cw) +: cw] <= $clog2(NWAYS)'(n);
                end
            end
        end else begin
            if (access) begin
                // Recency Update Logic:
                // Get the current recency vector for the selected cache set.
                logic [(NWAYS * cw)-1:0] old_val = recency[index];
                // Make a copy to build the updated value.
                logic [(NWAYS * cw)-1:0] new_val = old_val;
                logic [cw-1:0] prev;

                if (hit) begin
                    // Cache Hit:
                    // The accessed way (given by way_select) is updated.
                    int accessed_way = way_select;
                    // Capture the previous counter value for the accessed way.
                    prev = old_val[accessed_way * cw +: cw];
                    // Set the accessed way's counter to maximum (most recently used).
                    new_val[accessed_way * cw +: cw] = $clog2(NWAYS)'(NWAYS-1);
                    // Decrement all counters greater than the previous value.
                    for (j = 0; j < NWAYS; j = j + 1) begin
                        if (j != accessed_way) begin
                            if (old_val[j * cw +: cw] > prev)
                                new_val[j * cw +: cw] = old_val[j * cw +: cw] - 1;
                        end
                    end
                end else begin
                    // Cache Miss:
                    // Identify the least recently used (LRU) way (minimum counter value).
                    int replaced_way = 0;
                    prev = old_val[0 * cw +: cw];
                    for (j = 1; j < NWAYS; j = j + 1) begin
                        if (old_val[j * cw +: cw] < prev) begin
                            prev = old_val[j * cw +: cw];
                            replaced_way = j;
                        end
                    end
                    // Set the replaced way's counter to maximum.
                    new_val[replaced_way * cw +: cw] = $clog2(NWAYS)'(NWAYS-1);
                    // Decrement all counters greater than the previous value of the replaced way.
                    for (j = 0; j < NWAYS; j = j + 1) begin
                        if (j != replaced_way) begin
                            if (old_val[j * cw +: cw] > prev)
                                new_val[j * cw +: cw] = old_val[j * cw +: cw] - 1;
                        end
                    end
                end

                // Write back the updated recency vector for the selected cache set.
                recency[index] <= new_val;

                // Replacement Logic:
                // Determine the LRU way (the one with the minimum counter value) from the updated vector.
                int lru = 0;
                logic [cw-1:0] min_val = new_val[0 * cw +: cw];
                for (j = 1; j < NWAYS; j = j + 1) begin
                    if (new_val[j * cw +: cw] < min_val) begin
                        min_val = new_val[j * cw +: cw];
                        lru = j;
                    end
                end
                // Drive the replacement output.
                way_replace <= lru;
            end else begin
                // No access: no update; drive replacement output to a default value.
                way_replace <= 0;
            end
        end
    end

endmodule

output.rtl/mru_counter_policy.sv:
module mru_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input  clock,
    input  reset,
    input  [$clog2(NINDEXES)-1:0] index,
    input  [$clog2(NWAYS)-1:0] way_select,
    input  access,
    input  hit,
    output reg [$clog2(NWAYS)-1:0] way_replace
);

    // Define counter width based on number of ways.
    localparam CW = $clog2(NWAYS);

    // recency array: for each cache index, store a contiguous set of counters,
    // one per way. Each counter is CW bits wide.
    reg [(NWAYS * CW)-1:0] recency [NINDEXES-1:0];

    integer i, n;

    // Sequential block: all updates occur on the rising edge of clock or asynchronous reset.
    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            // Initialization: for each index and each way, initialize the counter
            // with a unique value from 0 to NWAYS-1 in ascending order.
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    recency[i][(n * CW) +: CW] <= n;
                end
            end
        end else begin
            if (access) begin
                if (hit) begin
                    // -----------------------------------------------------------
                    // Cache Hit: Update recency for the accessed way.
                    // -----------------------------------------------------------
                    // Save the old counter value for the accessed way.
                    reg [CW-1:0] old_val;
                    old_val = recency[index][(way_select * CW) +: CW];

                    // Set the accessed way's counter to maximum (MRU).
                    recency[index][(way_select * CW) +: CW] <= (NWAYS-1);

                    // Decrement all other counters that are greater than the old value.
                    for (n = 0; n < NWAYS; n = n + 1) begin
                        if (n != way_select) begin
                            if (recency[index][(n * CW) +: CW] > old_val)
                                recency[index][(n * CW) +: CW] <= recency[index][(n * CW) +: CW] - 1;
                        end
                    end

                    // For a hit, drive the replacement output to the accessed way.
                    way_replace <= way_select;
                end else begin
                    // -----------------------------------------------------------
                    // Cache Miss: Select the MRU way for replacement.
                    // -----------------------------------------------------------
                    // Find the way with the maximum counter value.
                    reg [CW-1:0] temp_mru;
                    integer j;
                    temp_mru = 0;
                    for (j = 0; j < NWAYS; j = j + 1) begin
                        if (recency[index][(j * CW) +: CW] > recency[index][(temp_mru * CW) +: CW])
                            temp_mru = j;
                    end

                    // Update the recency for the replaced way.
                    // (Since it is the MRU, its counter is already (NWAYS-1),
                    // but we perform the same update pattern as for a hit.)
                    reg [CW-1:0] replaced_val;
                    replaced_val = recency[index][(temp_mru * CW) +: CW];
                    recency[index][(temp_mru * CW) +: CW] <= (NWAYS-1);
                    for (n = 0; n < NWAYS; n = n + 1) begin
                        if (n != temp_mru) begin
                            if (recency[index][(n * CW) +: CW] > replaced_val)
                                recency[index][(n * CW) +: CW] <= recency[index][(n * CW) +: CW] - 1;
                        end
                    end

                    // Drive the replacement output to the selected MRU way.
                    way_replace <= temp_mru;
                end
            end else begin
                // No access: Optionally, you can leave way_replace unchanged or set a default.
                // Here, we simply retain the previous value.
            end
        end
    end

endmodule

output.rtl/lfu_counter_policy.sv:
module lfu_counter_policy #(
    parameter NWAYS    = 4,         // Number of cache ways (must be power of 2, at least 4)
    parameter NINDEXES = 32,        // Number of cache sets (must be power of 2)
    parameter COUNTERW = 2           // Width of frequency counters (at least 2)
)(
    input  logic clock,
    input  logic reset,
    input  logic [$clog2(NINDEXES)-1:0] index,
    input  logic [$clog2(NWAYS)-1:0] way_select,
    input  logic access,
    input  logic hit,
    output logic [$clog2(NWAYS)-1:0] way_replace
);

    // Maximum frequency value based on counter width
    localparam int unsigned MAX_FREQUENCY = (1 << COUNTERW) - 1;

    // Frequency array:
    // For each cache set (indexed by index), we maintain a vector of counters for each way.
    // Each counter is COUNTERW bits wide.
    reg [(NWAYS * COUNTERW)-1:0] frequency [NINDEXES-1:0];

    // Loop variables for initialization and updates
    integer i, n;

    // Sequential logic for reset and frequency updates.
    // All operations (hit/miss handling and replacement logic) complete in a single clock cycle.
    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            // Reset: Initialize all frequency counters to 0.
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    frequency[i][(n * COUNTERW) +: COUNTERW] <= {(COUNTERW){1'b0}};
                end
            end
        end else begin
            if (access) begin
                if (hit) begin
                    // ---------------------------------------------------------------
                    // HIT HANDLING:
                    // Increment the frequency counter for the accessed way if it hasn't reached MAX_FREQUENCY.
                    // If the counter is already at MAX_FREQUENCY, decrement the counters of the other ways
                    // that have a counter value higher than 2. This prevents stalling on the first way.
                    // ---------------------------------------------------------------
                    if (frequency[index][(way_select * COUNTERW) +: COUNTERW] < MAX_FREQUENCY) begin
                        frequency[index][(way_select * COUNTERW) +: COUNTERW] <= 
                            frequency[index][(way_select * COUNTERW) +: COUNTERW] + 1;
                    end else begin
                        // Accessed way is saturated; adjust other ways.
                        for (n = 0; n < NWAYS; n = n + 1) begin
                            if (n != way_select) begin
                                if (frequency[index][(n * COUNTERW) +: COUNTERW] > 2)
                                    frequency[index][(n * COUNTERW) +: COUNTERW] <= 
                                        frequency[index][(n * COUNTERW) +: COUNTERW] - 1;
                            end
                        end
                    end
                    // For hit cycles, no replacement is needed. Drive a default value.
                    way_replace = '0;
                end else begin
                    // ---------------------------------------------------------------
                    // MISS HANDLING:
                    // On a cache miss, determine the least frequently used way.
                    // In the event of a tie, select the way with the lower index.
                    // Then, set the counter of the selected replacement way to 1.
                    // ---------------------------------------------------------------
                    integer candidate;
                    logic [COUNTERW-1:0] min_val;
                    candidate = 0;
                    // Initialize min_val to the maximum possible counter value.
                    min_val = MAX_FREQUENCY;
                    // Iterate over all ways to find the one with the minimum frequency.
                    for (n = 0; n < NWAYS; n = n + 1) begin
                        if (frequency[index][(n * COUNTERW) +: COUNTERW] < min_val) begin
                            min_val = frequency[index][(n * COUNTERW) +: COUNTERW];
                            candidate = n;
                        end
                    end
                    // Update the counter of the replacement candidate to 1.
                    frequency[index][(candidate * COUNTERW) +: COUNTERW] <= 1;
                    // Drive the replacement output.
                    way_replace = candidate;
                end
            end else begin
                // No access: Drive default value for way_replace.
                way_replace = '0;
            end
        end
    end

endmodule

