      //     end
      // But then we need to compute computed_sum. We can do that in an always_comb block.
      // Let computed_sum be a combinational signal computed from r_data.
      // But then r_sum register is updated only when i_valid is high.
      // But what if i_valid is not high? Then r_sum remains unchanged.
      // That means the output will be valid from previous cycle. But specification says "o_valid is driven on the rising edge of the clk" and "when reset, o_valid is driven low."
      // I think it's acceptable to hold the previous sum if new data is not presented.
      // Alternatively, we can update r_sum every cycle, but then it would combine the previous r_data and new computed sum. But then it's not two-cycle pipeline.
      // So I'll do: update r_sum register only when i_valid is asserted.
      // But then what if i_valid is not asserted consecutively? Then o_valid remains high from previous cycle.
      // That might be acceptable.
      // Alternatively, we can update r_sum always, but then use a separate flag to indicate new data.
      // For simplicity, I'll update r_sum only when i_valid is high.
      // But then if i_valid is high continuously, then o_valid is high continuously. That is acceptable.
      // So I'll do that.
      // End always_ff block.
      // Then assign o_data = r_sum.
      // But then need to compute computed_sum from r_data.
      // I'll compute computed_sum in an always_comb block using a for loop.
      // But careful: if i_valid is not high, then r_data might be old. But that's fine.
      // I'll compute computed_sum as:
      // logic [OUT_WIDTH-1:0] computed_sum;
      // assign computed_sum = r_data[0+:IN_DATA_WIDTH];
      // for (int i=1; i<IN_DATA_NS; i++) computed_sum = computed_sum + r_data[i*IN_DATA_WIDTH +: IN_DATA_WIDTH];
      // But in SystemVerilog, for loops in combinational always_comb blocks are allowed.
      // So I'll do that.
      // So final code:
      // module cascaded_adder #(... parameters ...) (ports) begin
      //   logic [IN_DATA_WIDTH*IN_DATA_NS-1:0] r_data;
      //   logic [OUT_WIDTH-1:0] r_sum;
      //   always_ff @(posedge clk or negedge rst_n) begin
      //       if (!rst_n) begin
      //           r_data <= 0;
      //           r_sum <= 0;
      //           o_valid <= 0;
      //       end else begin
      //           if (i_valid) begin
      //               r_data <= i_data;
      //           end
      //           // computed_sum is computed from r_data
      //           // But we need to compute computed_sum in combinational logic block.
      //           // So I'll declare a reg computed_sum, but computed_sum is combinational so we can declare it as logic.
      //           // But then assign r_sum <= computed_sum if i_valid is high.
      //           if (i_valid) begin
      //               r_sum <= computed_sum; // computed_sum will be defined in always_comb block.
      //               o_valid <= 1'b1;
      //           end else begin
      //               r_sum <= r_sum; // hold previous sum
      //               o_valid <= o_valid; // hold valid flag
      //           end
      //       end
      //   end
      //   always_comb begin
      //       computed_sum = r_data[0+:IN_DATA_WIDTH];
      //       for (int i = 1; i < IN_DATA_NS; i++) begin
      //           computed_sum = computed_sum + r_data[i*IN_DATA_WIDTH +: IN_DATA_WIDTH];
      //       end
      //   end
      //   assign o_data = r_sum;
      // endmodule

module cascaded_adder #(
    parameter int IN_DATA_WIDTH = 16,                       // Width of each input data
    parameter int IN_DATA_NS = 4,                           // Number of input data elements
    parameter int NUM_STAGES = $clog2(IN_DATA_NS),          // Number of summation stages (calculated once)
    parameter logic [NUM_STAGES-1:0] REG = {NUM_STAGES{1'b1}}  // Control bits for register insertion
) (
   input  logic clk,
   input  logic rst_n,
   input  logic i_valid, 
   input  logic [IN_DATA_WIDTH*IN_DATA_NS-1:0] i_data,  // Flattened input data array
   output logic o_valid,
   output logic [(IN_DATA_WIDTH+$clog2(IN_DATA_NS))-1:0] o_data // Output data (sum)
);

   // Internal signals for the adder tree
   logic [IN_DATA_WIDTH*IN_DATA_NS-1:0] i_data_ff;                             // Flattened input data array register
   logic [IN_DATA_WIDTH-1:0] in_data_2d [IN_DATA_NS-1:0];                      // Intermediate 2D array
   logic [(IN_DATA_WIDTH+$clog2(IN_DATA_NS))-1:0] stage_output [NUM_STAGES-1:0][ (IN_DATA_NS>>1)-1:0];
   logic valid_ff;
   logic valid_pipeline [NUM_STAGES-1:0];  // Pipeline to handle the valid signal latencies based on REG

   // Register the input data on valid signal
   always_ff @(posedge clk or negedge rst_n) begin : reg_indata
      if(!rst_n)
         i_data_ff <= 0;
      else begin
         if(i_valid)
            i_data_ff <= i_data;
      end
   end

   // Convert flattened input to 2D array
   always_comb begin
       for (int i = 0; i < IN_DATA_NS; i++) begin : conv_1d_to_2d
           in_data_2d[i] = i_data_ff[(i+1)*IN_DATA_WIDTH-1 -: IN_DATA_WIDTH];
       end
   end

   // --------------------------------------------------------------------------
   // Adder Tree and Valid Signal Propagation using generate statements
   // --------------------------------------------------------------------------
   genvar stage;
   generate
      for (stage = 0; stage < NUM_STAGES; stage = stage + 1) begin : adder_tree_stage
         if (stage == 0) begin : stage0
             if (REG[0]) begin : registered_stage0
                // Registered version of stage 0: inputs come from in_data_2d
                always_ff @(posedge clk or negedge rst_n) begin
                   if (!rst_n) begin
                      for (int j = 0; j < (IN_DATA_NS>>1); j = j + 1)
                         stage_output[0][j] <= 0;
                      valid_pipeline[0] <= 1'b0;
                   end else if (valid_ff) begin
                      for (int j = 0; j < (IN_DATA_NS>>1); j = j + 1)
                         stage_output[0][j] <= in_data_2d[2*j] + in_data_2d[2*j+1];
                      valid_pipeline[0] <= 1'b1;
                   end
                end
             end else begin : combinational_stage0
                // Combinational version of stage 0: direct assignment
                for (genvar j = 0; j < (IN_DATA_NS>>1); j = j + 1) begin : stage0_comb
                   assign stage_output[0][j] = in_data_2d[2*j] + in_data_2d[2*j+1];
                end
                assign valid_pipeline[0] = valid_ff;
             end
         end else begin : stageN
             // For stage i (i > 0), inputs are taken from the previous stage's output
             if (REG[stage]) begin : registered_stageN
                always_ff @(posedge clk or negedge rst_n) begin
                   if (!rst_n) begin
                      for (int j = 0; j < (IN_DATA_NS >> (stage+1)); j = j + 1)
                         stage_output[stage][j] <= 0;
                      valid_pipeline[stage] <= 1'b0;
                   end else if (valid_pipeline[stage-1]) begin
                      for (int j = 0; j < (IN_DATA_NS >> (stage+1)); j = j + 1)
                         stage_output[stage][j] <= stage_output[stage-1][2*j] + stage_output[stage-1][2*j+1];
                      valid_pipeline[stage] <= 1'b1;
                   end
                end
             end else begin : combinational_stageN
                // Combinational version for stage i
                for (genvar j = 0; j < (IN_DATA_NS >> (stage+1)); j = j + 1) begin : stageN_comb
                   assign stage_output[stage][j] = stage_output[stage-1][2*j] + stage_output[stage-1][2*j+1];
                end
                assign valid_pipeline[stage] = valid_pipeline[stage-1];
             end
         end
      end
   endgenerate

   // --------------------------------------------------------------------------
   // Register valid signal from input
   // --------------------------------------------------------------------------
   always_ff @(posedge clk or negedge rst_n) begin
      if(!rst_n)
         valid_ff <= 1'b0;
      else 
         valid_ff <= i_valid;
   end

   // --------------------------------------------------------------------------
   // Final Output Data and Valid Signal Assignment
   // --------------------------------------------------------------------------
   always_ff @(posedge clk or negedge rst_n) begin
      if(!rst_n)
         o_valid <= 1'b0;
      else
         o_valid <= valid_pipeline[NUM_STAGES-1];
   end

   always_ff @(posedge clk or negedge rst_n) begin : reg_outdata
      if (!rst_n)
         o_data <= 0 ;
      else if (valid_pipeline[NUM_STAGES-1])
         o_data <= stage_output[NUM_STAGES-1][0];
   end

endmodule

