input.rtl/coffee_machine.sv:
module coffee_machine #(
    parameter NBW_DLY    = 'd5,
    parameter NBW_BEANS  = 'd2,
    parameter NS_BEANS   = 'd4,
    parameter NS_OP      = 'd3, // Fixed
    parameter NS_SENSOR  = 'd4  // Fixed
) (
    input  logic                 clk,
    input  logic                 rst_async_n,
    input  logic [NBW_DLY-1:0]   i_grind_delay,
    input  logic [NBW_DLY-1:0]   i_heat_delay,
    input  logic [NBW_DLY-1:0]   i_pour_delay,
    input  logic [NBW_BEANS-1:0] i_bean_sel,
    input  logic [NS_OP-1:0]     i_operation_sel,
    input  logic                 i_start,
    input  logic [NS_SENSOR-1:0] i_sensor,
    output logic [NS_BEANS-1:0]  o_bean_sel,
    output logic                 o_grind_beans,
    output logic                 o_use_powder,
    output logic                 o_heat_water,
    output logic                 o_pour_coffee,
    output logic                 o_error
);

// Fixed delays (bean selection and powder usage)
localparam SEL_CYCLES    = 'd3;
localparam POWDER_CYCLES = 'd2;

typedef enum logic [2:0] {
    IDLE     = 3'b000,
    BEAN_SEL = 3'b001,
    GRIND    = 3'b011,
    POWDER   = 3'b111,
    HEAT     = 3'b110,
    POUR     = 3'b100
} state_t;

// ----------------------------------------
// - Wires/Registers creation
// ----------------------------------------
state_t state_ff, state_nx;
logic [NBW_DLY:0]     counter_ff, counter_nx;
logic [NBW_DLY-1:0]   grind_delay_ff, heat_delay_ff, pour_delay_ff;
logic [NS_OP-1:0]     operation_sel_ff;
logic [NBW_BEANS-1:0] bean_sel_in_ff;
logic                 start_ff;

// Output assignment (error conditions)
always_comb begin : error_logic
    if(state_ff == IDLE) begin
        o_error = (i_sensor[0] | i_sensor[3]) | (&i_operation_sel[2:1]) | (i_operation_sel[1] & i_sensor[1]) | ((i_operation_sel[2] || i_operation_sel[0]) & i_sensor[2]);
    end else begin
        o_error = i_sensor[3];
    end
end

// ----------------------------------------
// - Registers
// ----------------------------------------
always_ff @(posedge clk) begin : data_regs
    start_ff <= i_start & ~(i_sensor[0] | i_sensor[3]) & (|i_operation_sel[2:1]) & ~(i_operation_sel[1] & i_sensor[1]) & ~((i_operation_sel == 3'b100 || i_operation_sel == 3'b001) & i_sensor[2]);

    if(i_start && state_ff == IDLE) begin
        operation_sel_ff <= i_operation_sel;
        grind_delay_ff   <= i_grind_delay;
        heat_delay_ff    <= i_heat_delay;
        pour_delay_ff    <= i_pour_delay;
        bean_sel_in_ff   <= i_bean_sel;
    end

    counter_ff      <= counter_nx;
end

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        state_ff <= IDLE;
    end else begin
        state_ff <= state_nx;
    end
end

// ----------------------------------------
// - FSM update
// ----------------------------------------
always_comb begin
    case(state_ff)
        IDLE: begin
            counter_nx = 0;

            if(start_ff) begin
                if(~(|i_operation_sel[2:1])) begin
                    state_nx = HEAT;
                end else if(i_operation_sel[1]) begin
                    state_nx = BEAN_SEL;
                end else if(i_operation_sel[0]) begin
                    state_nx = POUR;
                end else begin
                    state_nx = POWDER;
                end
            end else begin
                state_nx = IDLE;
            end
        end
        BEAN_SEL: begin
            if(counter_ff >= SEL_CYCLES) begin
                counter_nx = 0;
                state_nx   = GRIND;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = BEAN_SEL;
            end
        end
        GRIND: begin
            if(counter_ff >= grind_delay_ff) begin
                counter_nx = 0;
                if(operation_sel_ff[0]) begin
                    state_nx = POWDER;
                end else begin
                    state_nx = HEAT;
                end
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = GRIND;
            end
        end
        POWDER: begin
            if(counter_ff >= POWDER_CYCLES) begin
                counter_nx = 0;
                state_nx   = POUR;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = POUR;
            end
        end
        HEAT: begin
            if(counter_ff >= heat_delay_ff) begin
                counter_nx = 0;
                if(|operation_sel_ff[1:0]) begin
                    state_nx = POWDER;
                end else begin
                    state_nx = POUR;
                end
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = HEAT;
            end
        end
        POUR: begin
            if(counter_ff >= pour_delay_ff) begin
                counter_nx = 0;
                state_nx   = IDLE;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = POUR;
            end
        end
        default: begin
            counter_nx = 0;
            state_nx   = IDLE;
        end
    endcase
end

// ----------------------------------------
// - Controller outputs
// ----------------------------------------
always_comb begin
    case(state_ff)
        IDLE: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_use_powder    = 1'b0;
            o_grind_beans   = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        BEAN_SEL: begin
            o_bean_sel                      = 1'b0; // Set all bits to 0
            o_bean_sel[bean_sel_in_ff]      = 1'b1; // Only the position of bean_sel_ff should be 1
            o_grind_beans                   = 1'b0;
            o_use_powder                    = 1'b0;
            o_heat_water                    = 1'b0;
            o_pour_coffee                   = 1'b0;
        end
        GRIND: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b1;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        POWDER: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b1;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        HEAT: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b1;
            o_pour_coffee   = 1'b0;
        end
        POUR: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b1;
        end
        default: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
    endcase
end

endmodule : coffee_machine

output.rtl/signed_comparator.sv:
module signed_unsigned_comparator #(parameter WIDTH = 5)(
    input  logic [WIDTH-1:0] i_A,
    input  logic [WIDTH-1:0] i_B,
    input  logic             i_enable,
    input  logic             i_mode,    // High = signed mode, Low = magnitude mode
    output logic             o_greater,
    output logic             o_less,
    output logic             o_equal
);

    // Intermediate signals for magnitude mode (absolute value computation)
    logic [WIDTH-1:0] abs_A;
    logic [WIDTH-1:0] abs_B;

    always_comb begin
        // Default: all outputs low
        o_greater = 1'b0;
        o_less    = 1'b0;
        o_equal   = 1'b0;

        if (!i_enable) begin
            // When disabled, all outputs remain inactive.
        end else begin
            if (i_mode) begin
                // Signed Mode: Compare as signed integers.
                if (i_A > i_B)
                    o_greater = 1'b1;
                else if (i_A < i_B)
                    o_less    = 1'b1;
                else
                    o_equal   = 1'b1;
            end else begin
                // Magnitude Mode: Compute the absolute values of i_A and i_B.
                // For a negative number, absolute value = ~number + 1.
                abs_A = (i_A[WIDTH-1]) ? (~i_A + 1) : i_A;
                abs_B = (i_B[WIDTH-1]) ? (~i_B + 1) : i_B;

                if (abs_A > abs_B)
                    o_greater = 1'b1;
                else if (abs_A < abs_B)
                    o_less    = 1'b1;
                else
                    o_equal   = 1'b1;
            end
        end
    end

endmodule

output.rtl/complex_multiplier.sv:
module complex_multiplier (
    input  logic         clk,
    input  logic         arst_n,
    input  logic [15:0]  a_real,
    input  logic [15:0]  a_imag,
    input  logic [15:0]  b_real,
    input  logic [15:0]  b_imag,
    output logic [31:0]  result_real,
    output logic [31:0]  result_imag
);

    // Complex multiplication:
    // (a_real + j*a_imag) * (b_real + j*b_imag) =
    //   (a_real*b_real - a_imag*b_imag) + j*(a_real*b_imag + a_imag*b_real)
    always_ff @(posedge clk or negedge arst_n) begin
        if (!arst_n) begin
            result_real <= 32'b0;
            result_imag <= 32'b0;
        end else begin
            result_real <= (a_real * b_real) - (a_imag * b_imag);
            result_imag <= (a_real * b_imag) + (a_imag * b_real);
        end
    end

endmodule

output.rtl/enhanced_fsm_signal_processor.v:
module enhanced_fsm_signal_processor(
    input         i_clk,
    input         i_rst_n,
    input         i_enable,
    input         i_clear,
    input         i_ack,
    input         i_fault,
    input  [4:0]  i_vector_1,
    input  [4:0]  i_vector_2,
    input  [4:0]  i_vector_3,
    input  [4:0]  i_vector_4,
    input  [4:0]  i_vector_5,
    input  [4:0]  i_vector_6,
    output reg    o_ready,
    output reg    o_error,
    output reg [1:0] o_fsm_status,
    output reg [7:0] o_vector_1,
    output reg [7:0] o_vector_2,
    output reg [7:0] o_vector_3,
    output reg [7:0] o_vector_4
);

  // State encoding: IDLE = 00, PROCESS = 01, READY = 10, FAULT = 11
  localparam IDLE   = 2'b00;
  localparam PROCESS= 2'b01;
  localparam READY  = 2'b10;
  localparam FAULT  = 2'b11;

  // Combinational bus: Concatenate six 5-bit vectors into a 30-bit bus,
  // then append two '1' bits at the LSB to form a 32-bit bus.
  // Mapping: o_vector_1 = bus[31:24], o_vector_2 = bus[23:16],
  //          o_vector_3 = bus[15:8],  o_vector_4 = bus[7:0]
  wire [31:0] bus;
  assign bus = { i_vector_1, i_vector_2, i_vector_3, i_vector_4, i_vector_5, i_vector_6, 2'b11 };

  reg [1:0] state;

  // Synchronous state and output update
  always @(posedge i_clk or negedge i_rst_n) begin
    if (!i_rst_n) begin
      state             <= IDLE;
      o_ready           <= 1'b0;
      o_error           <= 1'b0;
      o_vector_1        <= 8'b0;
      o_vector_2        <= 8'b0;
      o_vector_3        <= 8'b0;
      o_vector_4        <= 8'b0;
    end
    else begin
      // Fault precedence: if i_fault is asserted, force state to FAULT
      if (i_fault) begin
        state <= FAULT;
      end
      else begin
        case (state)
          IDLE: begin
            if (i_enable)
              state <= PROCESS;
            else
              state <= IDLE;
          end
          PROCESS: begin
            state <= READY;
          end
          READY: begin
            if (i_ack)
              state <= IDLE;
            else
              state <= READY;
          end
          FAULT: begin
            // In FAULT, transition to IDLE only when i_clear is asserted
            if (i_clear)
              state <= IDLE;
            else
              state <= FAULT;
          end
          default: state <= IDLE;
        endcase
      end

      // Update outputs based on current state
      case (state)
        IDLE: begin
          o_ready           <= 1'b0;
          o_error           <= 1'b0;
          o_vector_1        <= 8'b0;
          o_vector_2        <= 8'b0;
          o_vector_3        <= 8'b0;
          o_vector_4        <= 8'b0;
        end
        PROCESS: begin
          o_ready           <= 1'b0;
          o_error           <= 1'b0;
          o_vector_1        <= bus[31:24];
          o_vector_2        <= bus[23:16];
          o_vector_3        <= bus[15:8];
          o_vector_4        <= bus[7:0];
        end
        READY: begin
          o_ready           <= 1'b1;
          o_error           <= 1'b0;
          o_vector_1        <= 8'b0;
          o_vector_2        <= 8'b0;
          o_vector_3        <= 8'b0;
          o_vector_4        <= 8'b0;
        end
        FAULT: begin
          o_ready           <= 1'b0;
          o_error           <= 1'b1;
          o_vector_1        <= 8'b0;
          o_vector_2        <= 8'b0;
          o_vector_3        <= 8'b0;
          o_vector_4        <= 8'b0;
        end
        default: begin
          o_ready           <= 1'b0;
          o_error           <= 1'b0;
          o_vector_1        <= 8'b0;
          o_vector_2        <= 8'b0;
          o_vector_3        <= 8'b0;
          o_vector_4        <= 8'b0;
        end
      endcase
    end
  end

  // Update FSM status output (synchronous to clock)
  always @(posedge i_clk or negedge i_rst_n) begin
    if (!i_rst_n)
      o_fsm_status <= IDLE;
    else
      o_fsm_status <= state;
  end

endmodule

output.rtl/low_pass_filter.sv:
module low_pass_filter #(
  parameter DATA_WIDTH = 16,
  parameter COEFF_WIDTH = 16,
  parameter NUM_TAPS   = 8
) (
  input  logic                         clk,
  input  logic                         reset,
  input  logic [DATA_WIDTH*NUM_TAPS-1:0] data_in,
  input  logic                         valid_in,
  input  logic [COEFF_WIDTH*NUM_TAPS-1:0] coeffs,
  output logic [NBW_MULT+$clog2(NUM_TAPS)-1:0] data_out,
  output logic                         valid_out
);

  // Define intermediate and output widths
  localparam integer NBW_MULT = DATA_WIDTH + COEFF_WIDTH;
  localparam integer OUT_WIDTH = NBW_MULT + $clog2(NUM_TAPS);

  // Internal registers to store the registered input data and coefficients.
  // These registers hold NUM_TAPS samples each.
  logic signed [DATA_WIDTH-1:0] data_reg [0:NUM_TAPS-1];
  logic signed [COEFF_WIDTH-1:0] coeff_reg [0:NUM_TAPS-1];

  // Register to hold the valid signal (one-cycle delay).
  logic valid_reg;

  // Register to hold the computed convolution result.
  logic signed [OUT_WIDTH-1:0] result_reg;

  // Intermediate combinational result of the convolution.
  logic signed [OUT_WIDTH-1:0] result_comb;

  // Combinational Logic:
  // Convert the registered 1D streams into an effective 2D array and perform
  // element-wise multiplication with reversed coefficient order, then sum the products.
  always_comb begin
    result_comb = '0;
    for (int i = 0; i < NUM_TAPS; i++) begin
      // Multiply the i-th data tap by the corresponding coefficient from the reversed order.
      logic signed [NBW_MULT-1:0] product;
      product = data_reg[i] * coeff_reg[NUM_TAPS-1 - i];
      // Extend the product to the output width before accumulation.
      result_comb = result_comb + {{(OUT_WIDTH - NBW_MULT){1'b0}}, product};
    end
  end

  // Sequential Logic:
  // On each clock cycle, update the registered data and coefficients if valid_in is high.
  // Compute the convolution result from the stored values and register the output.
  always_ff @(posedge clk) begin
    if (reset) begin
      // Clear all internal registers on reset.
      for (int i = 0; i < NUM_TAPS; i++) begin
        data_reg[i] <= '0;
        coeff_reg[i] <= '0;
      end
      valid_reg   <= 1'b0;
      result_reg  <= '0;
    end
    else begin
      if (valid_in) begin
        // Unpack the packed input data and coefficients into the internal arrays.
        for (int i = 0; i < NUM_TAPS; i++) begin
          data_reg[i] <= data_in[i*DATA_WIDTH +: DATA_WIDTH];
          coeff_reg[i] <= coeffs[i*COEFF_WIDTH +: COEFF_WIDTH];
        end
        valid_reg <= valid_in;
      end
      // Always update the result register with the computed convolution.
      result_reg <= result_comb;
    end
  end

  // Output assignments:
  // data_out is the registered convolution result.
  // valid_out is the one-cycle registered valid signal.
  assign data_out = result_reg;
  assign valid_out = valid_reg;

endmodule

output.rtl/decimator_and_peak_detector.sv:
module advanced_decimator_with_adaptive_peak_detection #
  (
   parameter N              = 8,          // Total number of input samples
   parameter DATA_WIDTH     = 16,         // Bit-width of each sample
   parameter DEC_FACTOR     = 4           // Decimation factor (must divide N)
   )
  (
   input  logic                      clk,
   input  logic                      reset,
   input  logic                      valid_in,
   // Packed input: N samples of signed DATA_WIDTH bits (sample0 is the leftmost)
   input  signed [DATA_WIDTH*N-1:0]  data_in,
   output logic                      valid_out,
   // Packed output: (N/DEC_FACTOR) decimated samples
   output signed [DATA_WIDTH*(N/DEC_FACTOR)-1:0] data_out,
   // Peak value among the decimated samples
   output signed [DATA_WIDTH-1:0]   peak_value
   );

  //-------------------------------------------------------------------------
  // Internal registers and wires
  //-------------------------------------------------------------------------
  // Register to hold the input data (one pipeline stage)
  reg [DATA_WIDTH*N-1:0] data_reg;
  reg                     valid_data;  // Registered copy of valid_in

  // Intermediate combinational results: decimated output and peak value
  wire [DATA_WIDTH*(N/DEC_FACTOR)-1:0] decimated_out;
  wire signed [DATA_WIDTH-1:0]         peak_value_comb;

  // Registered outputs: decimated data and peak value
  reg [DATA_WIDTH*(N/DEC_FACTOR)-1:0] decimated_reg;
  reg signed [DATA_WIDTH-1:0]         peak_reg;

  //-------------------------------------------------------------------------
  // 1. Input Data Registering
  //-------------------------------------------------------------------------
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      data_reg      <= '0;
      valid_data    <= 1'b0;
    end else begin
      if (valid_in) begin
        data_reg      <= data_in;
        valid_data    <= 1'b1;
      end else begin
        valid_data    <= 1'b0;
      end
    end
  end

  //-------------------------------------------------------------------------
  // 2. Decimation and Peak Detection (Combinational Logic)
  //-------------------------------------------------------------------------
  // This block unpacks the registered input data, selects one sample per DEC_FACTOR,
  // and computes the peak value among the decimated samples.
  always_comb begin
    int i;
    // Temporary array to hold decimated samples
    logic signed [DATA_WIDTH-1:0] decimated [0:(N/DEC_FACTOR)-1];

    // Decimation: for each index, select sample at position i*DEC_FACTOR.
    // Note: data_reg is packed as {sample0, sample1, ..., sample[N-1]}.
    for (i = 0; i < N/DEC_FACTOR; i++) begin
      // Extract sample: sample index = i*DEC_FACTOR.
      // Slicing: the leftmost DATA_WIDTH bits correspond to sample0.
      decimated[i] = data_reg [ ((i+1)*DEC_FACTOR*DATA_WIDTH)-1 -: DATA_WIDTH ];
    end

    // Peak Detection: find the maximum value among decimated samples.
    logic signed [DATA_WIDTH-1:0] peak;
    peak = decimated[0];
    for (i = 1; i < N/DEC_FACTOR; i++) begin
      if (decimated[i] > peak)
        peak = decimated[i];
    end

    // Pack the decimated samples into a temporary vector.
    // The samples are packed in order: decimated[0] becomes the most significant.
    logic signed [DATA_WIDTH*(N/DEC_FACTOR)-1:0] temp_decimated;
    for (i = 0; i < N/DEC_FACTOR; i++) begin
      temp_decimated [ ((N/DEC_FACTOR)-1-i)*DATA_WIDTH +: DATA_WIDTH ] = decimated[i];
    end

    decimated_out    = temp_decimated;
    peak_value_comb  = peak;
  end

  //-------------------------------------------------------------------------
  // 3. Output Registering (Pipeline Stage)
  //-------------------------------------------------------------------------
  // Register the combinational results to achieve a 1-cycle pipeline latency.
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      decimated_reg <= '0;
      peak_reg      <= '0;
      valid_out     <= 1'b0;
    end else if (valid_data) begin
      decimated_reg <= decimated_out;
      peak_reg      <= peak_value_comb;
      valid_out     <= 1'b1;
    end else begin
      valid_out     <= 1'b0;
    end
  end

  //-------------------------------------------------------------------------
  // 4. Output Assignment
  //-------------------------------------------------------------------------
  assign data_out   = decimated_reg;
  assign peak_value = peak_reg;

endmodule

