module cont_adder #(
  parameter DATA_WIDTH     = 32,
  parameter signed THRESHOLD_VALUE_1 = 50,
  parameter signed THRESHOLD_VALUE_2 = 100,
  parameter signed THRESHOLD_VALUE_3 = 150,
  parameter ACCUM_MODE     = 0,
  parameter WEIGHT         = 1,
  parameter signed SAT_MAX = (2**(DATA_WIDTH-1))-1,
  parameter signed SAT_MIN = -(2**(DATA_WIDTH-1))
) (
  input  logic                         clk,
  input  logic                         reset,
  input  logic                         accum_clear,
  input  logic                         enable,
  input  logic signed [DATA_WIDTH-1:0] data_in,
  input  logic                         data_valid,
  input  logic [15:0]                  window_size,
  output logic signed [DATA_WIDTH-1:0] sum_out,
  output logic signed [DATA_WIDTH-1:0] avg_out,
  output logic                         threshold_1,
  output logic                         threshold_2,
  output logic                         threshold_3,
  output logic                         sum_ready,
  output logic                         busy
);

  // Internal state declaration
  typedef enum logic [1:0] {IDLE, ACCUM, DONE} state_t;
  state_t state;
  logic signed [DATA_WIDTH-1:0] sum_accum;
  logic [15:0] sample_count;
  logic signed [DATA_WIDTH-1:0] weighted_in_reg;
  logic signed [DATA_WIDTH-1:0] new_sum;
  logic signed [DATA_WIDTH-1:0] sat_sum;

  // Combined sequential block for weighted input, new sum and saturation logic
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      weighted_in_reg <= 0;
      new_sum         <= 0;
      sat_sum         <= 0;
    end
    else if (enable && data_valid) begin
      weighted_in_reg <= (WEIGHT == 1) ? data_in : data_in * WEIGHT;
      new_sum         <= sum_accum + weighted_in_reg;
      if (new_sum > SAT_MAX)
        sat_sum <= SAT_MAX;
      else if (new_sum < SAT_MIN)
        sat_sum <= SAT_MIN;
      else
        sat_sum <= new_sum;
    end
    // No update: registers hold previous value
  end

  // Combined sequential block for state machine and output generation
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      state         <= IDLE;
      sum_accum     <= 0;
      sample_count  <= 0;
      sum_out       <= 0;
      avg_out       <= 0;
      sum_ready     <= 0;
      threshold_1   <= 0;
      threshold_2   <= 0;
      threshold_3   <= 0;
      busy          <= 0;
    end
    else if (accum_clear) begin
      state         <= IDLE;
      sum_accum     <= 0;
      sample_count  <= 0;
      sum_out       <= 0;
      avg_out       <= 0;
      sum_ready     <= 0;
      threshold_1   <= 0;
      threshold_2   <= 0;
      threshold_3   <= 0;
      busy          <= 0;
    end
    else if (enable && data_valid) begin
      // State machine update with compacted assignments
      case (state)
        IDLE: begin
          state         <= ACCUM;
          sum_accum     <= sat_sum;
          sample_count  <= 1;
        end
        ACCUM: begin
          sum_accum     <= sat_sum;
          sample_count  <= sample_count + 1;
          if (ACCUM_MODE == 1)
            state <= ((sample_count + 1) >= window_size) ? DONE : ACCUM;
          else
            state <= ((((sat_sum >= THRESHOLD_VALUE_1) || (sat_sum <= -THRESHOLD_VALUE_1)) ||
                       ((sat_sum >= THRESHOLD_VALUE_2) || (sat_sum <= -THRESHOLD_VALUE_2)) ||
                       ((sat_sum >= THRESHOLD_VALUE_3) || (sat_sum <= -THRESHOLD_VALUE_3))) ? DONE : ACCUM);
        end
        DONE: begin
          state         <= IDLE;
          sum_accum     <= 0;
          sample_count  <= 0;
        end
        default: state <= IDLE;
      endcase

      // Generate outputs based on state
      busy <= (state == ACCUM);
      if (state == DONE) begin
        sum_out       <= sum_accum;
        avg_out       <= (ACCUM_MODE == 1) ? (sum_accum / sample_count) : 0;
        sum_ready     <= 1;
        threshold_1   <= ((sum_accum >= THRESHOLD_VALUE_1) || (sum_accum <= -THRESHOLD_VALUE_1)) ? 1 : 0;
        threshold_2   <= ((sum_accum >= THRESHOLD_VALUE_2) || (sum_accum <= -THRESHOLD_VALUE_2)) ? 1 : 0;
        threshold_3   <= ((sum_accum >= THRESHOLD_VALUE_3) || (sum_accum <= -THRESHOLD_VALUE_3)) ? 1 : 0;
      end
      else begin
        sum_out       <= 0;
        avg_out       <= 0;
        sum_ready     <= 0;
        threshold_1   <= 0;
        threshold_2   <= 0;
        threshold_3   <= 0;
      end
    end
  end

endmodule

output.rtl/convolutional_encoder.sv:
module convolutional_encoder (
    input  logic         clk,
    input  logic         rst,
    input  logic         data_in,
    output logic         encoded_bit1,
    output logic         encoded_bit2
);

  // 2-bit shift register to hold the previous two bits.
  // Convention: shift_reg[1] is the oldest bit, shift_reg[0] is the next bit.
  logic [1:0] shift_reg;

  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      shift_reg      <= 2'b00;
      encoded_bit1   <= 1'b0;
      encoded_bit2   <= 1'b0;
    end else begin
      // Update the shift register:
      // New data_in is shifted into the LSB while the previous LSB becomes the MSB.
      shift_reg <= { shift_reg[0], data_in };

      // The encoding window is: [oldest = shift_reg[1], middle = shift_reg[0], current = data_in]

      // Generator polynomial g1 = "111" (x^2 + x + 1):
      // encoded_bit1 = (oldest XOR middle XOR current)
      encoded_bit1 <= shift_reg[1] ^ shift_reg[0] ^ data_in;

      // Generator polynomial g2 = "101" (x^2 + 1):
      // encoded_bit2 = (oldest XOR current)
      encoded_bit2 <= shift_reg[1] ^ data_in;
    end
  end

endmodule

module convolutional_encoder (
    input  wire clk,
    input  wire rst,
    input  wire data_in,
    output reg encoded_bit1,
    output reg encoded_bit2
);
    // Shift register for constraint length K=3 (2 bits of memory)
    reg [1:0] shift_reg;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            shift_reg    <= 2'b00;
            encoded_bit1 <= 1'b0;
            encoded_bit2 <= 1'b0;
        end else begin
            // Shift the register: new data_in enters at LSB, MSB becomes oldest bit
            shift_reg <= {shift_reg[0], data_in};

            // Convolutional encoding using generator polynomials:
            // g1(x) = x^2 + x + 1  -> coefficients: [1, 1, 1]
            // g2(x) = x^2 + 1      -> coefficients: [1, 0, 1]
            //
            // With shift_reg[1] as the oldest, shift_reg[0] as the next, and data_in as current,
            // encoded_bit1 = shift_reg[1] XOR shift_reg[0] XOR data_in
            // encoded_bit2 = shift_reg[1] XOR data_in
            encoded_bit1 <= shift_reg[1] ^ shift_reg[0] ^ data_in;
            encoded_bit2 <= shift_reg[1] ^ data_in;
        end
    end
endmodule

output.rtl/crossbar_switch.sv:
module crossbar_switch #(
    parameter DATA_WIDTH = 8,  // Parameterized data width
    localparam NUM_PORTS = 4,
    localparam DATA_WIDTH_IN = (DATA_WIDTH + $clog2(NUM_PORTS))
)(
    input  logic                        clk,        // Clock signal
    input  logic                        reset,      // Reset signal
    // Input data and destination IDs
    input  logic [DATA_WIDTH_IN-1 :0]  in0, in1, in2, in3,  // Input data
    input  logic                       valid_in0, valid_in1, valid_in2, valid_in3,  // Input data valid
    // Output data
    output logic  [DATA_WIDTH-1:0]      out0, out1, out2, out3,  // Output data
    output logic                        valid_out0, valid_out1, valid_out2, valid_out3  // Output data valid
);

    // Internal Signals
    logic [$clog2(NUM_PORTS)-1 : 0] dest0, dest1, dest2, dest3;  // Destination ID for each input

    // ----------------------------------------
    // - Procedural blocks
    // ----------------------------------------
    always @(posedge clk or negedge reset) begin
        if (!reset) begin
            out0      <= 0;
            out1      <= 0;
            out2      <= 0;
            out3      <= 0;
            valid_out0<= 1'b0;
            valid_out1<= 1'b0;
            valid_out2<= 1'b0;
            valid_out3<= 1'b0;
        end else begin
            // Default assignments: clear outputs
            out0      <= 0;
            out1      <= 0;
            out2      <= 0;
            out3      <= 0;
            valid_out0<= 1'b0;
            valid_out1<= 1'b0;
            valid_out2<= 1'b0;
            valid_out3<= 1'b0;

            if (valid_in0) begin
                // Routing for Input 0
                case(dest0)
                    2'd0: begin 
                        out0      <= in0[DATA_WIDTH-1:0];
                        valid_out0<= 1'b1;
                    end
                    2'd1: begin 
                        out1      <= in0[DATA_WIDTH-1:0];
                        valid_out1<= 1'b1;
                    end
                    2'd2: begin 
                        out2      <= in0[DATA_WIDTH-1:0];
                        valid_out2<= 1'b1;
                    end
                    2'd3: begin 
                        out3      <= in0[DATA_WIDTH-1:0];
                        valid_out3<= 1'b1;
                    end
                    default: ;
                endcase
            end else if (valid_in1) begin
                // Routing for Input 1
                case(dest1)
                    2'd0: begin 
                        out0      <= in1[DATA_WIDTH-1:0];
                        valid_out0<= 1'b1;
                    end
                    2'd1: begin 
                        out1      <= in1[DATA_WIDTH-1:0];
                        valid_out1<= 1'b1;
                    end
                    2'd2: begin 
                        out2      <= in1[DATA_WIDTH-1:0];
                        valid_out2<= 1'b1;
                    end
                    2'd3: begin 
                        out3      <= in1[DATA_WIDTH-1:0];
                        valid_out3<= 1'b1;
                    end
                    default: ;
                endcase
            end else if (valid_in2) begin
                // Routing for Input 2
                case(dest2)
                    2'd0: begin 
                        out0      <= in2[DATA_WIDTH-1:0];
                        valid_out0<= 1'b1;
                    end
                    2'd1: begin 
                        out1      <= in2[DATA_WIDTH-1:0];
                        valid_out1<= 1'b1;
                    end
                    2'd2: begin 
                        out2      <= in2[DATA_WIDTH-1:0];
                        valid_out2<= 1'b1;
                    end
                    2'd3: begin 
                        out3      <= in2[DATA_WIDTH-1:0];
                        valid_out3<= 1'b1;
                    end
                    default: ;
                endcase
            end else if (valid_in3) begin
                // Routing for Input 3
                case(dest3)
                    2'd0: begin 
                        out0      <= in3[DATA_WIDTH-1:0];
                        valid_out0<= 1'b1;
                    end
                    2'd1: begin 
                        out1      <= in3[DATA_WIDTH-1:0];
                        valid_out1<= 1'b1;
                    end
                    2'd2: begin 
                        out2      <= in3[DATA_WIDTH-1:0];
                        valid_out2<= 1'b1;
                    end
                    2'd3: begin 
                        out3      <= in3[DATA_WIDTH-1:0];
                        valid_out3<= 1'b1;
                    end
                    default: ;
                endcase
            end else begin
                // No valid input: all outputs remain 0
                out0      <= 0;
                out1      <= 0;
                out2      <= 0;
                out3      <= 0;
            end
        end
    end

    // ----------------------------------------
    // - Combinational Assignments
    // ----------------------------------------
    assign dest0 = in0 [DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2] ; // Destination port ID for in0 data
    assign dest1 = in1 [DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2] ; // Destination port ID for in1 data
    assign dest2 = in2 [DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2] ; // Destination port ID for in2 data
    assign dest3 = in3 [DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2] ; // Destination port ID for in3 data

endmodule

output.rtl/data_bus_controller.sv:
module data_bus_controller #(
  parameter AFINITY = 0
)(
  input         clk,
  input         rst_n,

  output        m0_read,
  input         m0_valid,
  input  [31:0] m0_data,

  output        m1_read,
  input         m1_valid,
  input  [31:0] m1_data,

  input         s_read,
  output        s_valid,
  output [31:0] s_data
);

  // Internal registers to implement one-cycle latency.
  // valid_reg indicates that a transaction is registered.
  // data_reg holds the transaction data.
  // clear_next is used to delay clearing the registered transaction until the next cycle.
  reg valid_reg;
  reg [31:0] data_reg;
  reg clear_next;

  // The handshake always registers a transaction from the masters (if any)
  // and then outputs it one cycle later.
  // If both masters drive a transaction in the same cycle, AFINITY selects which one.
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      valid_reg   <= 1'b0;
      data_reg    <= 32'd0;
      clear_next  <= 1'b0;
    end else begin
      // If the previous cycle had a registered transaction and the slave was ready,
      // schedule clearing the register in this cycle.
      if (clear_next) begin
        valid_reg   <= 1'b0;
        data_reg    <= 32'd0;
        clear_next  <= 1'b0;
      end
      // If there is no registered transaction, sample the masters.
      else if (!valid_reg) begin
        if (m0_valid || m1_valid) begin
          // If both masters are valid simultaneously, use AFINITY to choose.
          if (m0_valid && m1_valid) begin
            if (AFINITY == 0)
              data_reg <= m0_data;
            else
              data_reg <= m1_data;
          end
          else if (m0_valid)
            data_reg <= m0_data;
          else if (m1_valid)
            data_reg <= m1_data;
          valid_reg <= 1'b1;
        end
      end
      // Set the flag to clear the registered transaction in the next cycle
      // if the slave is ready.
      clear_next <= (s_read && valid_reg);
    end
  end

  // Drive the slave interface outputs.
  // s_valid and s_data present the registered transaction.
  assign s_valid = valid_reg;
  assign s_data  = data_reg;

  // The master ready signals are simply driven by the slave's ready.
  assign m0_read = s_read;
  assign m1_read = s_read;

endmodule

input.rtl/data_serializer.sv:
module data_serializer #(
  parameter DATA_W   = 8,
  parameter BIT_ORDER= 0,
  parameter PARITY   = 0
)(
  input                  clk,
  input                  reset,
  // Parallel data interface
  input                  p_valid_i,
  input  [DATA_W-1:0]    p_data_i,
  output                 p_ready_o,
  // Serial data interface
  output                 s_valid_o,
  output                 s_data_o,
  input                  s_ready_i,
  // Transmission enable
  input                  tx_en_i
);

  // Local constants
  localparam ST_RX = 1'b0;
  localparam ST_TX = 1'b1;

  // If PARITY != 0 => We use 1 extra bit for parity
  localparam EXTRA_BIT = (PARITY == 0) ? 0 : 1;
  localparam SHIFT_W   = DATA_W + EXTRA_BIT;

  // Internal regs
  reg                    state_q, state_d;
  reg  [SHIFT_W-1:0]     shift_reg_q, shift_reg_d;
  reg  [$clog2(SHIFT_W)-1:0] count_q, count_d;

  // Parity calculation
  wire parity_bit_even = ^p_data_i;   // XOR => "even"
  wire parity_bit_odd  = ~^p_data_i;  // invert XOR => "odd"

  wire parity_bit = (PARITY == 1) ? parity_bit_even :
                    (PARITY == 2) ? parity_bit_odd  :
                                    1'b0; // NONE

  // Sequential state & register updates
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      state_q     <= ST_RX;
      shift_reg_q <= {SHIFT_W{1'b0}};
      count_q     <= 0;
    end else begin
      state_q     <= state_d;
      shift_reg_q <= shift_reg_d;
      count_q     <= count_d;
    end
  end

  // Next-state logic
  always @* begin
    // Default assignments
    state_d     = state_q;
    shift_reg_d = shift_reg_q;
    count_d     = count_q;

    case (state_q)

      // ST_RX: Load parallel data + parity
      ST_RX: begin
        if (p_valid_i) begin
          if (BIT_ORDER == 0) begin
            // LSB-first => store LSB in shift_reg_d[0]
            if (EXTRA_BIT == 1)
              shift_reg_d = {parity_bit, p_data_i};  // 9 bits if PARITY!=0
            else
              shift_reg_d = p_data_i;                // 8 bits if PARITY=0
          end
          else begin
            // MSB-first => store MSB in shift_reg_d[SHIFT_W-1]
            // If parity is used, it goes in the LSB or SHIFT_W-1?
            // We'll put it in the LSB if EXTRA_BIT=1
            if (EXTRA_BIT == 1) begin
              shift_reg_d[8:4] = {p_data_i[4:0],parity_bit};
              shift_reg_d[3:0] = p_data_i[8:5];
            end else
              shift_reg_d = p_data_i;
          end

          count_d = 0;
          state_d = ST_TX;
        end
      end

      // ST_TX: Shift bits out until SHIFT_W done
      ST_TX: begin
        // Only shift if s_ready_i & tx_en_i
        if (s_ready_i && tx_en_i) begin
          if (count_q == (SHIFT_W - 1)) begin
            // Done sending SHIFT_W bits
            state_d   = ST_RX;
            count_d   = 0;
          end
          else begin
            if (BIT_ORDER == 1) begin
              if (EXTRA_BIT == 1) begin
                // SHIFT left by 2 bits
                shift_reg_d[SHIFT_W-1:2] = shift_reg_q[SHIFT_W-3:0];
                shift_reg_d[1:0]         = 2'b00;
                count_d                  = count_q + 2;
              end
              else begin
                // Normal MSB-first => shift left by 1
                shift_reg_d = {shift_reg_q[SHIFT_W-2:0], 1'b0};
                count_d     = count_q + 1;
              end
            end
            else begin
              // LSB-first => shift right by 1 (no bug)
              shift_reg_d = {1'b0, shift_reg_q[SHIFT_W-1:1]};
              count_d     = count_q + 1;
            end
          end
        end
      end

      default: begin
        state_d = ST_RX; // safe fallback
      end
    endcase
  end

  // Outputs
  assign s_valid_o = (state_q == ST_TX);

  // LSB-first => s_data_o = shift_reg_q[0]
  // MSB-first => s_data_o = shift_reg_q[SHIFT_W-1]
  assign s_data_o  = (BIT_ORDER == 0) ? shift_reg_q[0] : shift_reg_q[SHIFT_W-1];

  assign p_ready_o = (state_q == ST_RX);

endmodule

