output.rtl/data_width_converter.sv:
module data_width_converter (
    input  logic         clk,
    input  logic         reset,
    input  logic [31:0]  data_in,
    input  logic         data_valid,
    output logic [127:0] o_data_out,
    output logic         o_data_out_valid
);

    // Parameter for number of samples needed.
    parameter NUM_SAMPLES = 4;

    // 2-bit counter to count valid inputs (range 0 to 3)
    logic [1:0] count;

    // Buffer to store the four 32-bit samples.
    // We store samples in reverse order so that the first received sample becomes the MSB.
    logic [31:0] buffer [0:3];

    // Synchronous process triggered by clock and asynchronous reset.
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            // Reset internal counter and clear buffer.
            count              <= 2'd0;
            o_data_out_valid   <= 1'b0;
            buffer[0]          <= 32'd0;
            buffer[1]          <= 32'd0;
            buffer[2]          <= 32'd0;
            buffer[3]          <= 32'd0;
        end
        else begin
            if (data_valid) begin
                // Store the incoming data into the buffer at the position determined by count.
                if (count == 2'd0)
                    buffer[3] <= data_in;
                else if (count == 2'd1)
                    buffer[2] <= data_in;
                else if (count == 2'd2)
                    buffer[1] <= data_in;
                else if (count == 2'd3)
                    buffer[0] <= data_in;

                // Increment the counter.
                count <= count + 1;

                // When four valid inputs have been received, output the concatenated data.
                if (count == NUM_SAMPLES - 1) begin
                    // Concatenate the samples in order: first sample (MSB) to fourth sample (LSB).
                    o_data_out    <= { buffer[3], buffer[2], buffer[1], buffer[0] };
                    o_data_out_valid <= 1'b1;
                    // Reset counter for the next group of four inputs.
                    count         <= 2'd0;
                end
                else begin
                    o_data_out_valid <= 1'b0;
                end
            end
            // If data_valid is not asserted, hold the state.
        end
    end

endmodule

output.rtl/dbi_enc.sv:
module dbi_enc (
    input  logic [39:0] data_in,
    input  logic        clk,
    input  logic        rst_n,
    output logic [39:0] data_out,
    output logic [1:0]  dbi_cntrl
);

  // Internal register to store previous data for comparison
  logic [39:0] prev_data;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      prev_data <= 40'b0;
      data_out  <= 40'b0;
      dbi_cntrl <= 2'b00;
    end else begin
      // Split data_in into two 20-bit groups:
      // Group-1: MSBs (bits [39:20])
      // Group-0: LSBs (bits [19:0])
      logic [19:0] group1, group0;
      group1 = data_in[39:20];
      group0 = data_in[19:0];

      // Count bit differences between current groups and previous data.
      // For each bit position, compare group1 with prev_data[39:20] and group0 with prev_data[19:0].
      integer i;
      logic [20:0] diff1, diff0;
      diff1 = 0;
      diff0 = 0;
      for (i = 0; i < 20; i = i + 1) begin
        diff1 += group1[i] ^ prev_data[20+i];
        diff0 += group0[i] ^ prev_data[i];
      end

      // Generate control signals:
      // If more than 10 bits differ, set the corresponding control bit to 1.
      logic control1, control0;
      control1 = (diff1 > 10);
      control0 = (diff0 > 10);

      // Generate new data_out based on control signals:
      // For Group-1 (MSBs): if control1 is high, invert the bits; otherwise, pass through unchanged.
      // For Group-0 (LSBs): if control0 is high, invert the bits; otherwise, pass through unchanged.
      logic [39:0] new_data;
      if (control1)
        new_data[39:20] = ~group1;
      else
        new_data[39:20] = group1;
      if (control0)
        new_data[19:0] = ~group0;
      else
        new_data[19:0] = group0;

      // Update outputs and previous data register:
      // The new data_out becomes the "previous data" for the next operation.
      data_out  <= new_data;
      prev_data <= new_data;
      dbi_cntrl <= {control1, control0};
    end
  end

endmodule

output.rtl/dbi_dec.sv:
module dbi_dec (
   // Inputs
   input  wire        rst_n,     // Asynchronous reset
   input  wire        clk,       // Clock
   input  wire [39:0] data_in,   // Data input before DBI decoder logic
   input  wire [1:0]  dbi_cntrl, // Indicate data inversion enabled for each group 
   // Outputs
   output reg  [39:0] data_out   // Output data after DBI logic
   );

   // DBI Decoder: decode each 20-bit group based on the control signals.
   // Group-1: bits [39:20], Group-0: bits [19:0]
   // LSB of dbi_cntrl corresponds to Group-0, MSB corresponds to Group-1.
   always @(posedge clk or negedge rst_n) begin
       if (!rst_n) begin
           data_out <= 40'h0000_0000;
       end else begin
           data_out[39:20] <= (dbi_cntrl[1] ? ~data_in[39:20] : data_in[39:20]);
           data_out[19:0]  <= (dbi_cntrl[0] ? ~data_in[19:0]  : data_in[19:0]);
       end
   end

endmodule

output.rtl/cvdp_copilot_decode_firstbit.sv:
module cvdp_copilot_decode_firstbit #(
  parameter int InWidth_g = 32,
  parameter int InReg_g   = 1,
  parameter int OutReg_g  = 1,
  parameter int PlRegs_g  = 1  // Number of pipeline registers for first-bit decoding logic
) (
  input  logic Clk,
  input  logic Rst,
  input  logic [InWidth_g-1:0] In_Data,
  input  logic In_Valid,
  output logic [($clog2(InWidth_g))-1:0] Out_FirstBit,
  output logic Out_Found,
  output logic Out_Valid
);

  //-------------------------------------------------------------------------
  // Local parameters
  //-------------------------------------------------------------------------
  // Number of bits required to encode the index of the first set bit
  localparam int BinBits_c = $clog2(InWidth_g);
  // Compute padded width: if InWidth_g is not a power-of-two, pad to the next power-of-two.
  localparam int Pow2Width = (InWidth_g == (1 << BinBits_c)) ? InWidth_g : (1 << (BinBits_c + 1));

  //-------------------------------------------------------------------------
  // Input Register (if enabled)
  //-------------------------------------------------------------------------
  logic [InWidth_g-1:0] in_reg_data;
  logic in_reg_valid;

  if (InReg_g) begin : reg_input
    always_ff @(posedge Clk or posedge Rst) begin
      if (Rst) begin
        in_reg_data  <= '0;
        in_reg_valid <= 1'b0;
      end else begin
        in_reg_data  <= In_Data;
        in_reg_valid <= In_Valid;
      end
    end
  end

  //-------------------------------------------------------------------------
  // Combinational First-Bit Decoder Logic
  //-------------------------------------------------------------------------
  // This block searches for the lowest set bit in the input vector.
  // If In_Valid is asserted, it iterates from bit 0 to InWidth_g-1.
  // If no set bit is found, Out_Found is de-asserted and Out_FirstBit is zero.
  //
  // Note: The input vector is assumed to be already the correct width.
  // If InWidth_g is not a power-of-two, the design internally considers
  // only the lower InWidth_g bits (i.e. no extra bits are processed).
  //
  // The combinational result is later pipelined through PlRegs_g stages.
  //-------------------------------------------------------------------------
  logic [BinBits_c-1:0] comb_first;
  logic comb_found;
  logic comb_valid;

  always_comb begin
    // Use registered input if enabled; otherwise, use the direct input.
    comb_valid = (InReg_g) ? in_reg_valid : In_Valid;
    if (comb_valid) begin
      comb_found = 1'b0;
      comb_first = '0;
      integer i;
      for (i = 0; i < InWidth_g; i = i + 1) begin
        if ((InReg_g ? in_reg_data[i] : In_Data[i])) begin
          comb_found = 1'b1;
          comb_first = i;
          // Exit the loop once the first set bit is found.
          break;
        end
      end
    end else begin
      comb_found = 1'b0;
      comb_first = '0;
    end
  end

  //-------------------------------------------------------------------------
  // Pipeline Registers for First-Bit Decoder Logic
  //-------------------------------------------------------------------------
  // The combinational result (comb_first, comb_found, comb_valid) is
  // registered through PlRegs_g pipeline stages. When PlRegs_g = 0, the
  // detection occurs in one cycle; for PlRegs_g > 0, the result is
  // registered across multiple stages.
  //
  // We create an array of pipeline registers where index 0 holds the
  // combinational result and indices 1 to PlRegs_g hold the pipelined data.
  //-------------------------------------------------------------------------
  logic [BinBits_c-1:0] pipe_first [0:PlRegs_g];
  logic pipe_found [0:PlRegs_g];
  logic pipe_valid [0:PlRegs_g];

  // Stage 0: Direct combinational result
  assign pipe_first[0] = comb_first;
  assign pipe_found[0] = comb_found;
  assign pipe_valid[0] = comb_valid;

  // Pipeline register stages: Each stage registers the output of the previous stage.
  generate
    genvar i;
    for (i = 1; i <= PlRegs_g; i++) begin : pipeline_stages
      always_ff @(posedge Clk or posedge Rst) begin
        if (Rst) begin
          pipe_valid[i]   <= 1'b0;
          pipe_first[i]   <= '0;
          pipe_found[i]   <= 1'b0;
        end else begin
          pipe_valid[i]   <= pipe_valid[i-1];
          pipe_first[i]   <= pipe_first[i-1];
          pipe_found[i]   <= pipe_found[i-1];
        end
      end
    end
  endgenerate

  // Final pipelined result: use the output of the last pipeline stage if any.
  logic final_valid;
  logic final_found;
  logic [BinBits_c-1:0] final_first;

  assign final_valid = (PlRegs_g > 0) ? pipe_valid[PlRegs_g] : comb_valid;
  assign final_first = (PlRegs_g > 0) ? pipe_first[PlRegs_g] : comb_first;
  assign final_found = (PlRegs_g > 0) ? pipe_found[PlRegs_g] : comb_found;

  //-------------------------------------------------------------------------
  // Output Register (if enabled)
  //-------------------------------------------------------------------------
  // If OutReg_g is enabled, the final pipelined result is registered before
  // being sent out. Otherwise, the result is directly assigned.
  //-------------------------------------------------------------------------
  if (OutReg_g) begin : reg_output
    always_ff @(posedge Clk or posedge Rst) begin
      if (Rst) begin
        Out_Valid     <= 1'b0;
        Out_FirstBit  <= '0;
        Out_Found     <= 1'b0;
      end else begin
        Out_Valid     <= final_valid;
        Out_FirstBit  <= final_first;
        Out_Found     <= final_found;
      end
    end
  end else begin : no_reg_output
    assign Out_Valid     = final_valid;
    assign Out_FirstBit  = final_first;
    assign Out_Found     = final_found;
  end

endmodule

