module digital_dice_roller (
    input  logic         clk,
    input  logic         reset_n,
    input  logic         button,
    output logic [2:0]   dice_value
);

    // Define the two FSM states: IDLE and ROLLING.
    typedef enum logic {IDLE, ROLLING} state_t;
    state_t state, next_state;
    logic [2:0] counter;
    logic [2:0] next_counter;

    // Sequential logic: update state, counter, and output on clock edge or asynchronous reset.
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            state      <= IDLE;
            counter    <= 3'b000; // Not a valid dice value but per spec on reset.
            dice_value <= 3'b000;
        end else begin
            state      <= next_state;
            counter    <= next_counter;
            // In ROLLING state, update dice_value with the current counter value.
            // In IDLE state, hold the last dice_value.
            dice_value <= (state == ROLLING) ? counter : dice_value;
        end
    end

    // Combinational logic: determine next state and counter value.
    always_comb begin
        next_state    = state;
        next_counter  = counter;
        case (state)
            IDLE: begin
                // Transition to ROLLING when button is HIGH.
                if (button) begin
                    next_state    = ROLLING;
                    next_counter  = 3'b001; // Start counting at 1.
                end
            end
            ROLLING: begin
                // If button becomes LOW, return to IDLE.
                if (!button) begin
                    next_state = IDLE;
                end else begin
                    // When button is HIGH, increment the counter on every clock edge.
                    // Ensure the counter cycles between 1 and 6.
                    if (counter == 3'b110) begin
                        next_counter = 3'b001;
                    end else begin
                        next_counter = counter + 1;
                    end
                end
            end
            default: begin
                next_state    = IDLE;
                next_counter  = counter;
            end
        endcase
    end

endmodule

input.rtl/digital_dice_roller.sv:
module digital_dice_roller #(
    parameter int DICE_MAX  = 6,                    // Maximum dice value
    parameter int BIT_WIDTH = $clog2(DICE_MAX) + 1  // Bit width to represent dice value
) (
    input wire clk,
    input wire reset,  // Asynchronous reset signal
    input wire button,
    output reg [BIT_WIDTH-1:0] dice_value
);

  // State encoding
  typedef enum logic [1:0] {
    IDLE    = 2'b00,
    ROLLING = 2'b01
  } state_t;

  state_t current_state, next_state;
  reg [BIT_WIDTH-1:0] counter;  // Counter to represent dice values

  // State transition and asynchronous reset logic (sequential)
  always_ff @(posedge clk or negedge reset) begin
    if (!reset) begin
      // Reset to initial values when async_reset is asserted
      current_state <= IDLE;
      counter <= 1;
      dice_value <= 1;
    end else begin
      current_state <= next_state;
    end
  end

  // Next state logic and counter increment (combinational)
  always_comb begin
    next_state = current_state;

    case (current_state)
      IDLE: begin
        if (button) next_state = ROLLING;
      end

      ROLLING: begin
        if (!button) next_state = IDLE;
      end
    endcase
  end

  // Counter logic to simulate rolling dice values from 1 to DICE_MAX
  always_ff @(posedge clk or negedge reset) begin
    if (!reset) begin
      // Reset counter and dice value when async_reset is asserted
      counter <= 1;
      dice_value <= 1;
    end else if (current_state == ROLLING) begin
      if (counter == DICE_MAX) counter <= 1;  // Reset to 1 after reaching DICE_MAX
      else counter <= counter + 1;
    end else if (current_state == IDLE) begin
      dice_value <= counter;  // Latch the final value
    end
  end
endmodule

output.rtl/digital_dice_roller.sv:
module digital_dice_roller #(
    parameter int DICE_MAX  = 6,                    // Maximum dice value per dice
    parameter int NUM_DICE  = 2,                    // Number of dice to roll simultaneously
    parameter int BIT_WIDTH = $clog2(DICE_MAX) + 1  // Bit width to represent dice values [1, DICE_MAX]
) (
    input  wire                   clk,
    input  wire                   reset,  // Active LOW asynchronous reset
    input  wire                   button,
    output reg  [(NUM_DICE*BIT_WIDTH)-1:0] dice_values
);

  // State encoding
  typedef enum logic [1:0] {
    IDLE    = 2'b00,
    ROLLING = 2'b01
  } state_t;

  state_t current_state, next_state;

  // Arrays for each dice: counter and 16-bit LFSR random seed
  logic [BIT_WIDTH-1:0] counter [0:NUM_DICE-1];
  logic [15:0]          random_seed [0:NUM_DICE-1];

  // Next state combinational logic
  always_comb begin
    next_state = current_state;
    case (current_state)
      IDLE:    if (button)
                 next_state = ROLLING;
      ROLLING: if (!button)
                 next_state = IDLE;
      default: next_state = current_state;
    endcase
  end

  // FSM, LFSR update, and counter update on positive clock edge or asynchronous reset
  always_ff @(posedge clk or negedge reset) begin
    if (!reset) begin
      // Reset: set FSM to IDLE, initialize each dice counter to 1,
      // assign unique 16-bit seeds (e.g., dice1=1, dice2=2, etc.)
      current_state <= IDLE;
      for (int i = 0; i < NUM_DICE; i++) begin
         random_seed[i] <= i + 1;
         counter[i]     <= 1;
      end
      dice_values <= { {(NUM_DICE*BIT_WIDTH){1'b0}} };
    end else begin
      current_state <= next_state;
      if (current_state == ROLLING) begin
         // For each dice, update the 16-bit LFSR using polynomial: x^16 + x^5 + x^4 + x^3 + 1
         // Feedback bit is computed as: feedback = bit15 ^ bit4 ^ bit3 ^ bit2
         for (int i = 0; i < NUM_DICE; i++) begin
            bit feedback;
            feedback = random_seed[i][15] ^ random_seed[i][4] ^ random_seed[i][3] ^ random_seed[i][2];
            random_seed[i] <= { random_seed[i][14:0], feedback };
         end
         // Update each dice counter based on the random seed.
         // The dice value is computed as: (random_seed % DICE_MAX) + 1
         for (int i = 0; i < NUM_DICE; i++) begin
            counter[i] <= (random_seed[i] % DICE_MAX) + 1;
         end
      end else if (current_state == IDLE) begin
         // When transitioning to IDLE, latch the current counter values into the flattened output.
         // Each dice's value is stored in a BIT_WIDTH segment.
         for (int i = 0; i < NUM_DICE; i++) begin
            dice_values[(i+1)*BIT_WIDTH-1 -: BIT_WIDTH] = counter[i];
         end
      end
    end
  end

endmodule

output.rtl/dig_stopwatch.sv:
module dig_stopwatch (
  input  logic         clk,
  input  logic         reset,
  input  logic         start_stop,
  output logic [5:0]   seconds,
  output logic [5:0]   minutes,
  output logic         hour
);

  // Parameter: input clock frequency in Hz (default 50,000,000 Hz)
  parameter integer CLK_FREQ = 50_000_000;

  // Internal clock divider to generate a one-second pulse.
  // The divider counts from 0 to CLK_FREQ-1. When it reaches CLK_FREQ-1,
  // a single pulse (one_sec_pulse) is generated for one clock cycle.
  reg [31:0] clk_divider;
  reg        one_sec_pulse;

  // Clock divider and one-second pulse generation.
  // Asynchronous reset: when reset is high, all registers are cleared.
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      clk_divider   <= 32'd0;
      one_sec_pulse <= 1'b0;
    end else begin
      clk_divider   <= clk_divider + 1;
      if (clk_divider == (CLK_FREQ - 1))
        one_sec_pulse <= 1'b1;
      else
        one_sec_pulse <= 1'b0;
    end
  end

  // Counters for seconds, minutes, and hour.
  // The counters update on the rising edge of one_sec_pulse.
  // - Seconds (6-bit): 0-59. When 59, resets to 0 and minutes increment.
  // - Minutes (6-bit): 0-59. When 59, resets to 0 and hour is set to 1.
  // - Hour (1-bit): Set to 1 after one hour is reached; then holds.
  // The stopwatch only updates when start_stop is high.
  always @(posedge one_sec_pulse or posedge reset) begin
    if (reset) begin
      seconds <= 6'd0;
      minutes <= 6'd0;
      hour    <= 1'b0;
    end else if (start_stop && (hour != 1'b1)) begin
      if (seconds == 6'd59) begin
        seconds <= 6'd0;
        if (minutes == 6'd59) begin
          minutes <= 6'd0;
          hour    <= 1'b1; // Stopwatch holds at 1 hour, 0 minutes, 0 seconds.
        end else begin
          minutes <= minutes + 1;
        end
      end else begin
        seconds <= seconds + 1;
      end
    end
  end

endmodule

input.rtl/dig_stopwatch.sv:
module dig_stopwatch #(
    parameter CLK_FREQ = 50000000  // Default clock frequency is 50 MHz
)(
    input wire clk,                // Input clock (parameterized frequency)
    input wire reset,              // Reset signal
    input wire start_stop,         // Start/Stop control
    output reg [5:0] seconds,      // Seconds counter (0-59)
    output reg [5:0] minutes,      // Minutes counter (0-59)
    output reg hour                // Hour counter 
);

    localparam COUNTER_MAX = CLK_FREQ - 1;  // Calculate max counter value
    reg [$clog2(COUNTER_MAX):0] counter;    // Clock divider counter width based on CLK_FREQ
    reg one_sec_pulse;                      // One second pulse signal

    // Clock divider to create a 1 Hz clock pulse from parameterized frequency
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            counter <= 0;
            one_sec_pulse <= 0;
        end else begin
            if (start_stop) begin
                if (counter == COUNTER_MAX) begin
                    counter <= 0;
                    one_sec_pulse <= 1'b1;        // Generate a pulse every second
                end else begin
                    counter <= counter + 1;
                    one_sec_pulse <= 1'b0;
                end
            end else begin
                one_sec_pulse <= 1'b0;           // Ensure one_sec_pulse is cleared if paused
            end
        end
    end

    // Stopwatch logic
    always @(posedge one_sec_pulse or posedge reset) begin
        if (reset) begin
            seconds <= 6'b0;
            minutes <= 6'b0;
            hour <= 1'b0;
        end else if (start_stop == 1 && hour == 0) begin
            if (seconds < 59) begin
                seconds <= seconds + 1'b1;
            end else begin
                seconds <= 6'b0;
                if (minutes < 59) begin
                    minutes <= minutes + 1'b1;
                end else begin
                    minutes <= 6'b0;
                    hour <= 1'b1;
                end
            end
        end
    end

endmodule

