        IDLE:begin
            if(overload_detected) begin
                next_state = OVERLOAD_HALT;
            end else if(emergency_stop) begin
                next_state = EMERGENCY_HALT;
            end else if(call_requests_internal != 0)begin
                if(max_request > current_floor_reg)begin
                    next_state = MOVING_UP;
                end else if(min_request < current_floor_reg) begin
                    next_state = MOVING_DOWN;
                end
            end
        end

        MOVING_UP: begin
            if(emergency_stop)begin
                next_state = EMERGENCY_HALT;
            end else if(call_requests_internal[current_floor_reg+1]) begin
                current_floor_next = current_floor_reg + 1;
                next_state = DOOR_OPEN;
            end else if(current_floor_reg >= max_request) begin
                // If we reach the highest request, go idle
                next_state = IDLE;
            end else begin
                current_floor_next = current_floor_reg + 1;
                next_state = MOVING_UP;
            end
        end

        MOVING_DOWN: begin
            if(emergency_stop)begin
                next_state = EMERGENCY_HALT;
            end else if(call_requests_internal[current_floor_reg-1]) begin
                current_floor_next = current_floor_reg - 1;
                next_state = DOOR_OPEN;
            end else if(current_floor_reg <= min_request) begin
                // If we reach the lowest request, go idle
                next_state = IDLE;
            end else begin
                current_floor_next = current_floor_reg - 1;
                next_state = MOVING_DOWN;
            end
        end

        EMERGENCY_HALT: begin
            if (!emergency_stop) begin
                next_state = IDLE;
                current_floor_next = 0; // Optionally reset to ground floor
            end
        end

        DOOR_OPEN: begin
            if(overload_detected) begin
                next_state = OVERLOAD_HALT;
            end else if (door_open_counter == 0) begin
                next_state = IDLE;
            end else begin
                next_state = DOOR_OPEN;
            end
        end

        OVERLOAD_HALT: begin
            if(!overload_detected) begin
                if(door_open) begin
                    next_state = DOOR_OPEN;
                end else begin
                    next_state = IDLE;
                end
            end
        end
    endcase
end


// Door open control logic
always @(posedge clk or posedge reset) begin
    if (reset) begin
        door_open <= 0;
    end else begin
        if (present_state == OVERLOAD_HALT) begin
            door_open <= 1;
        end else if (present_state == DOOR_OPEN) begin
            if (door_open_counter > 0) begin
                door_open <= 1;
            end else begin
                door_open <= 0;
            end
        end else begin
            door_open <= 0;
        end
    end
end


always@(*) begin
    if(present_state == OVERLOAD_HALT) begin
        door_open <= 1;
    end else if(present_state == DOOR_OPEN) begin
        door_open <= 1;
    end else begin
        door_open <= 0;
    end
end


always @(posedge clk or posedge reset) begin
    if(reset) begin
        door_open_counter <= DOOR_OPEN_CYCLES;
    end else if( present_state == DOOR_OPEN) begin
        if(door_open_counter > 0 ) begin
            door_open_counter = door_open_counter - 1;
        end else begin
            door_open_counter <= DOOR_OPEN_CYCLES;
        end
    end else begin
        door_open_counter <= DOOR_OPEN_CYCLES;
    end

end


// Call request management
always@(*)begin
    if(reset) begin
        call_requests_internal = 0;
    end else begin
        if(call_requests_internal[current_floor_reg])begin
            call_requests_internal[current_floor_reg] = 0;      // Clear served request
        end
        call_requests_internal = call_requests_internal | call_requests;    // Update requests
    end
end

// Direction control logic
always@(*)begin
    if(reset) begin
        direction = 1;
    end else begin
        if(present_state == MOVING_UP)begin
            direction = 1;
        end else if (present_state == MOVING_DOWN) begin
            direction = 0;
        end else begin
            direction = 1;
        end
    end
end


// Seven-segment display converter instantiation
floor_to_seven_segment floor_display_converter (
    .clk(clk),
    .floor_display({{8-($clog2(N)){1'b0}},current_floor_reg}),
    .seven_seg_out(seven_seg_out),
    .seven_seg_out_anode(seven_seg_out_anode),
    .thousand(thousand), .hundred(hundred),.ten(ten),.one(one)
);

endmodule

output.rtl/elevator_control_system.sv:
module elevator_control_system #(
    parameter N = 8, // Number of floors
    parameter DOOR_OPEN_TIME_MS = 500 // Door open time in milliseconds
) (
    input wire clk,                   // 100MHz clock input
    input wire reset,                 // Active-high reset signal
    input wire [N-1:0] call_requests, // External Floor call requests
    input wire emergency_stop,        // Emergency stop signal
    input wire overload_detected,
    output wire [$clog2(N)-1:0] current_floor, // Current floor of the elevator
    output reg direction,             // Elevator direction: 1 = up, 0 = down
    output reg door_open,             // Door open signal
    output reg [2:0] system_status,    // Elevator system state indicator
    output overload_warning,          // Overload warning signal
    output [3:0] thousand,
    output [3:0] hundred,
    output [3:0] ten,
    output [3:0] one,
    output wire [6:0] seven_seg_out,    // Seven-segment display output for current floor visualization
    output wire [3:0] seven_seg_out_anode // Signal for switching between ones, tens, hundred, thousand place on seven segment
);

// State Encoding
localparam IDLE           = 3'b000;          // Elevator is idle
localparam MOVING_UP      = 3'b001;         // Elevator moving up
localparam MOVING_DOWN    = 3'b010;         // Elevator moving down
localparam EMERGENCY_HALT = 3'b011;         // Emergency halt state
localparam DOOR_OPEN      = 3'b100;         // Door open state
localparam OVERLOAD_HALT  = 3'b101;         // New state for overload condition

// Internal registers
reg [N-1:0] call_requests_internal;   // Internal copy of call requests
reg [2:0] present_state, next_state;  // FSM current and next states
reg [$clog2(N)-1:0] max_request;       // Highest requested floor
reg [$clog2(N)-1:0] min_request;        // Lowest requested floor

// Door open time configuration
`ifdef SIMULATION
    localparam CLK_FREQ_MHZ         = 100;  // Clock frequency in MHz
    localparam SIM_DOOR_OPEN_TIME_MS = 0.05; // Shorter door open time for simulation
    localparam DOOR_OPEN_CYCLES     = (SIM_DOOR_OPEN_TIME_MS * CLK_FREQ_MHZ * 1000); // Door open cycles for simulation   
`else
    // Calculating door open cycles based on time and clock frequency
    localparam CLK_FREQ_MHZ         = 100;  // Clock frequency in MHz
    localparam DOOR_OPEN_CYCLES     = (DOOR_OPEN_TIME_MS * CLK_FREQ_MHZ * 1000);   // Door open cycles for real implementation
`endif

reg [$clog2(DOOR_OPEN_CYCLES)-1:0] door_open_counter;   // Counter for door open duration

reg [$clog2(N)-1:0] current_floor_reg, current_floor_next = 0;

assign current_floor = current_floor_reg;

// Update overload warning signal
assign overload_warning = (overload_detected == 1 && present_state == OVERLOAD_HALT);

// FSM state transition (sequential)
always @(posedge clk or posedge reset) begin
    if (reset) begin
        present_state   <= IDLE;
        system_status   <= IDLE;
        current_floor_reg <= 0;        
    end else begin
        present_state   <= next_state;
        system_status   <= next_state;
        current_floor_reg <= current_floor_next;
    end
end

// Calculate max_request and min_request based on active requests
always @(*) begin
    if (reset) begin
        max_request = 0;
        min_request = {$clog2(N){1'b1}};
    end else begin        
        max_request = 0;
        min_request = {$clog2(N){1'b1}};
        for (integer i = 0; i < N; i = i + 1) begin
            if (call_requests_internal[i]) begin
                if (i > max_request)
                    max_request = i[$clog2(N)-1:0]; 
                if (i < min_request)  
                    min_request = i[$clog2(N)-1:0]; 
            end
        end
    end
end

// FSM next state and current floor update logic (combinational)
always @(*) begin
    // Default assignments to ensure full coverage
    next_state      = present_state;
    current_floor_next = current_floor_reg;

    case (present_state)
        IDLE: begin
            if (overload_detected)
                next_state = OVERLOAD_HALT;
            else if (emergency_stop)
                next_state = EMERGENCY_HALT;
            else if (call_requests_internal != 0) begin
                if (max_request > current_floor_reg)
                    next_state = MOVING_UP;
                else if (min_request < current_floor_reg)
                    next_state = MOVING_DOWN;
            end
        end

        MOVING_UP: begin
            if (emergency_stop)
                next_state = EMERGENCY_HALT;
            else if (call_requests_internal[current_floor_reg + 1]) begin
                current_floor_next = current_floor_reg + 1;
                next_state = DOOR_OPEN;
            end else if (current_floor_reg >= max_request) begin
                next_state = IDLE;
            end else begin
                current_floor_next = current_floor_reg + 1;
                next_state = MOVING_UP;
            end
        end

        MOVING_DOWN: begin
            if (emergency_stop)
                next_state = EMERGENCY_HALT;
            else if (call_requests_internal[current_floor_reg - 1]) begin
                current_floor_next = current_floor_reg - 1;
                next_state = DOOR_OPEN;
            end else if (current_floor_reg <= min_request) begin
                next_state = IDLE;
            end else begin
                current_floor_next = current_floor_reg - 1;
                next_state = MOVING_DOWN;
            end
        end

        EMERGENCY_HALT: begin
            if (!emergency_stop) begin
                next_state = IDLE;
                current_floor_next = 0;
            end
        end

        DOOR_OPEN: begin
            if (overload_detected)
                next_state = OVERLOAD_HALT;
            else if (door_open_counter == 0)
                next_state = IDLE;
            else
                next_state = DOOR_OPEN;
        end

        OVERLOAD_HALT: begin
            if (!overload_detected)
                next_state = (door_open) ? DOOR_OPEN : IDLE;
        end

        default: begin
            next_state = present_state;
            current_floor_next = current_floor_reg;
        end
    endcase
end

// Door open control logic (sequential)
always @(posedge clk or posedge reset) begin
    if (reset)
        door_open <= 0;
    else begin
        if (present_state == OVERLOAD_HALT)
            door_open <= 1;
        else if (present_state == DOOR_OPEN) begin
            if (door_open_counter > 0)
                door_open <= 1;
            else
                door_open <= 0;
        end else
            door_open <= 0;
    end
end

// Door open counter update (sequential non-blocking)
always @(posedge clk or posedge reset) begin
    if (reset)
        door_open_counter <= DOOR_OPEN_CYCLES;
    else if (present_state == DOOR_OPEN) begin
        if (door_open_counter > 0)
            door_open_counter <= door_open_counter - 1;
        else
            door_open_counter <= DOOR_OPEN_CYCLES;
    end else
        door_open_counter <= DOOR_OPEN_CYCLES;
end

// Call request management (sequential non-blocking)
always @(posedge clk or posedge reset) begin
    if (reset)
        call_requests_internal <= 0;
    else begin
        if (call_requests_internal[current_floor_reg])
            call_requests_internal[current_floor_reg] <= 0; // Clear served request
        call_requests_internal <= call_requests_internal | call_requests; // Update requests
    end
end

// Direction control logic (combinational)
always @(*) begin
    if (reset)
        direction = 1;
    else begin
        if (present_state == MOVING_UP)
            direction = 1;
        else if (present_state == MOVING_DOWN)
            direction = 0;
        else
            direction = 1;
    end
end

// Seven-segment display converter instantiation
floor_to_seven_segment floor_display_converter (
    .clk(clk),
    .floor_display({{8-($clog2(N)){1'b0}}, current_floor_reg}),
    .seven_seg_out(seven_seg_out),
    .seven_seg_out_anode(seven_seg_out_anode),
    .thousand(thousand),
    .hundred(hundred),
    .ten(ten),
    .one(one)
);

endmodule

output.rtl/ethernet_parser.v:
module ethernet_parser (
    input         clk,
    input         rst,
    input         vld,
    input         sof,
    input  [31:0] data,
    input         eof,
    output reg    ack,
    output reg [15:0] field,
    output reg    field_vld
);

    // State encoding
    localparam IDLE        = 2'b00,
               EXTRACTING  = 2'b01,
               DONE        = 2'b10,
               FAIL_FINAL  = 2'b11;

    reg [1:0] state;
    reg [3:0] beat_cnt;
    reg [15:0] temp_extracted_field;

    // ack is fixed as high
    always @(*) begin
        ack = 1'b1;
    end

    // State machine and register updates
    always @(posedge clk) begin
        if (rst) begin
            state            <= IDLE;
            beat_cnt         <= 4'd0;
            field            <= 16'd0;
            field_vld        <= 1'b0;
            temp_extracted_field <= 16'd0;
        end else begin
            case (state)
                IDLE: begin
                    if (sof && vld) begin
                        state            <= EXTRACTING;
                        beat_cnt         <= 4'd0;
                        field_vld        <= 1'b0;
                        temp_extracted_field <= 16'd0;
                    end else begin
                        state <= IDLE;
                    end
                end

                EXTRACTING: begin
                    if (vld) begin
                        if (beat_cnt == 4'd1) begin
                            // Capture the 2 most significant bytes (data[31:16])
                            temp_extracted_field <= data[31:16];
                            state <= DONE;
                        end else begin
                            beat_cnt <= beat_cnt + 1;
                            state <= EXTRACTING;
                        end
                    end else begin
                        state <= EXTRACTING;
                    end
                end

                DONE: begin
                    field <= temp_extracted_field;
                    field_vld <= 1'b1;
                    if (eof) begin
                        state <= FAIL_FINAL;
                    end else begin
                        state <= DONE;
                    end
                end

                FAIL_FINAL: begin
                    field_vld <= 1'b0;
                    state <= IDLE;
                end

                default: state <= IDLE;
            endcase
        end
    end

endmodule

output.rtl/apb_controller.sv:
module apb_controller (
  input  logic         clk,
  input  logic         reset_n,
  input  logic         select_a_i,
  input  logic         select_b_i,
  input  logic         select_c_i,
  input  logic [31:0]  addr_a_i,
  input  logic [31:0]  data_a_i,
  input  logic [31:0]  addr_b_i,
  input  logic [31:0]  data_b_i,
  input  logic [31:0]  addr_c_i,
  input  logic [31:0]  data_c_i,
  input  logic         apb_pready_i,
  output logic         apb_psel_o,
  output logic         apb_penable_o,
  output logic         apb_pwrite_o,
  output logic [31:0]  apb_paddr_o,
  output logic [31:0]  apb_pwdata_o
);

  // State encoding: IDLE, SETUP, ACCESS
  localparam logic [1:0] IDLE   = 2'b00;
  localparam logic [1:0] SETUP  = 2'b01;
  localparam logic [1:0] ACCESS = 2'b10;

  // Internal registers to capture the selected event's address and data.
  reg  [31:0] addr_reg;
  reg  [31:0] data_reg;
  // 4-bit timeout counter (counts clock cycles in ACCESS phase)
  reg  [3:0]  timeout_counter;
  // State register
  reg  [1:0]  state;

  // Synchronous state machine with outputs driven in one always_ff block.
  always_ff @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
      state            <= IDLE;
      timeout_counter  <= 4'd0;
      addr_reg         <= 32'd0;
      data_reg         <= 32'd0;
      apb_psel_o       <= 1'b0;
      apb_penable_o    <= 1'b0;
      apb_pwrite_o     <= 1'b0;
      apb_paddr_o      <= 32'd0;
      apb_pwdata_o     <= 32'd0;
    end
    else begin
      case (state)
        // IDLE State: Capture transaction info if an event is triggered.
        IDLE: begin
          // Priority: select_a_i > select_b_i > select_c_i.
          if (select_a_i) begin
            addr_reg <= addr_a_i;
            data_reg <= data_a_i;
            state    <= SETUP;
          end
          else if (select_b_i) begin
            addr_reg <= addr_b_i;
            data_reg <= data_b_i;
            state    <= SETUP;
          end
          else if (select_c_i) begin
            addr_reg <= addr_c_i;
            data_reg <= data_c_i;
            state    <= SETUP;
          end
          else begin
            state <= IDLE;
          end

          // Ensure outputs are deasserted in IDLE.
          apb_psel_o   <= 1'b0;
          apb_penable_o<= 1'b0;
          apb_pwrite_o <= 1'b0;
          apb_paddr_o  <= 32'd0;
          apb_pwdata_o <= 32'd0;
          timeout_counter <= 4'd0;
        end

        // SETUP Phase: Assert APB control signals and load address/data.
        SETUP: begin
          apb_psel_o   <= 1'b1;
          apb_pwrite_o <= 1'b1;
          apb_paddr_o  <= addr_reg;
          apb_pwdata_o <= data_reg;
          // penable remains low.
          apb_penable_o<= 1'b0;
          state        <= ACCESS;
        end

        // ACCESS Phase: Maintain signals and wait for peripheral ready.
        ACCESS: begin
          apb_psel_o   <= 1'b1;
          apb_pwrite_o <= 1'b1;
          apb_paddr_o  <= addr_reg;
          apb_pwdata_o <= data_reg;
          apb_penable_o<= 1'b1;
          // If peripheral asserts ready, complete transaction.
          if (apb_pready_i) begin
            state        <= IDLE;
            // Deassert control signals immediately upon completion.
            apb_psel_o   <= 1'b0;
            apb_penable_o<= 1'b0;
          end
          // Timeout mechanism: if ready is not asserted within 15 cycles, abort.
          else if (timeout_counter == 4'd15) begin
            state        <= IDLE;
            apb_psel_o   <= 1'b0;
            apb_penable_o<= 1'b0;
          end
          else begin
            state        <= ACCESS;
            timeout_counter <= timeout_counter + 1;
          end
        end

        default: begin
          state <= IDLE;
          apb_psel_o   <= 1'b0;
          apb_penable_o<= 1'b0;
          apb_pwrite_o <= 1'b0;
          apb_paddr_o  <= 32'd0;
          apb_pwdata_o <= 32'd0;
        end
      endcase
    end
  end

endmodule

output.rtl/factorial.sv:
module factorial (
  input  logic         clk,
  input  logic         arst_n,
  input  logic [4:0]   num_in,
  input  logic         start,
  output logic         busy,
  output logic [63:0]  fact,
  output logic         done
);

  // Define FSM states
  typedef enum logic [1:0] {
    IDLE = 2'b00,
    BUSY = 2'b01,
    DONE = 2'b10
  } state_t;

  state_t state, next_state;

  // Internal registers
  logic [4:0] counter;       // holds the current multiplier value
  logic [63:0] fact_reg;     // holds the computed factorial

  // Next state logic (combinational)
  always_comb begin
    next_state = state;
    case (state)
      IDLE: begin
        if (start)
          next_state = BUSY;
      end
      BUSY: begin
        if (counter == 5'd0)
          next_state = DONE;
        else
          next_state = BUSY;
      end
      DONE: begin
        next_state = IDLE;
      end
      default: next_state = IDLE;
    endcase
  end

  // Sequential logic: state update, register updates, and output driving
  always_ff @(posedge clk or negedge arst_n) begin
    if (!arst_n) begin
      state         <= IDLE;
      counter       <= 5'd0;
      fact_reg      <= 64'd1;
      busy          <= 1'b0;
      done          <= 1'b0;
    end
    else begin
      state <= next_state;
      case (state)
        IDLE: begin
          // Capture input and initialize computation
          if (start) begin
            counter <= num_in;
            fact_reg <= 64'd1;
          end
          busy <= 1'b0;
          done <= 1'b0;
        end
        BUSY: begin
          if (counter != 5'd0) begin
            // Multiply fact_reg by the current counter value
            fact_reg <= fact_reg * counter;
            counter <= counter - 5'd1;
          end
          busy <= 1'b1;
          done <= 1'b0;
        end
        DONE: begin
          // Hold the result for one cycle
          busy <= 1'b0;
          done <= 1'b1;
        end
        default: begin
          busy <= 1'b0;
          done <= 1'b0;
        end
      endcase
    end
  end

  // Drive the output
  assign fact = fact_reg;

endmodule

output.rtl/fan_controller.sv:
module fan_controller (
    input  wire         clk,                 // System clock
    input  wire         reset,               // Asynchronous active high reset
    output reg          fan_pwm_out,         // PWM output for fan control

    // APB signals
    input  wire         psel,                // Slave select
    input  wire         penable,             // Enable signal (start of access phase)
    input  wire         pwrite,              // Write control (1 = write, 0 = read)
    input  wire [7:0]   paddr,               // Address bus
    input  wire [7:0]   pwdata,              // Write data bus
    output reg  [7:0]   prdata,              // Read data bus
    output reg          pready,              // Ready signal
    output reg          pslverr              // Slave error signal
);

  // Internal registers for temperature thresholds and sensor data
  reg [7:0] TEMP_LOW;      // Register at address 0x0a
  reg [7:0] TEMP_MED;      // Register at address 0x0b
  reg [7:0] TEMP_HIGH;     // Register at address 0x0c
  reg [7:0] temp_adc_in;   // Register at address 0x0f (simulated sensor data)

  // PWM generation registers
  reg [7:0] pwm_counter;   // Internal counter for PWM period
  reg [7:0] pwm_duty;      // Duty cycle threshold (determines PWM high time)

  // Optional state register for APB protocol (0: idle, 1: setup, 2: access)
  reg [1:0] apb_state;

  //--------------------------------------------------------------------------
  // APB Interface State Machine and Register Access
  //--------------------------------------------------------------------------
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      apb_state      <= 2'd0;
      pready         <= 1'b0;
      pslverr        <= 1'b0;
      // Initialize registers to default values.
      TEMP_LOW       <= 8'd0;
      TEMP_MED       <= 8'd0;
      TEMP_HIGH      <= 8'd0;
      temp_adc_in    <= 8'd0;
    end
    else begin
      // When not selected, clear status signals and return to idle.
      if (!psel) begin
        pready      <= 1'b0;
        pslverr     <= 1'b0;
        apb_state   <= 2'd0;
      end
      else begin
        if (penable) begin
          // Access phase: perform read or write based on paddr and pwrite.
          pready <= 1'b1;
          case (paddr)
            8'h0a: begin
              if (pwrite)
                TEMP_LOW <= pwdata;
              else
                prdata  <= TEMP_LOW;
            end
            8'h0b: begin
              if (pwrite)
                TEMP_MED <= pwdata;
              else
                prdata  <= TEMP_MED;
            end
            8'h0c: begin
              if (pwrite)
                TEMP_HIGH <= pwdata;
              else
                prdata  <= TEMP_HIGH;
            end
            8'h0f: begin
              if (pwrite)
                temp_adc_in <= pwdata;
              else
                prdata  <= temp_adc_in;
            end
            default: begin
              // Invalid address: assert slave error.
              pslverr <= 1'b1;
            end
          endcase
          apb_state <= 2'd2; // Mark access phase
        end
        else begin
          // Setup phase: psel asserted but penable not yet asserted.
          pready  <= 1'b0;
          pslverr <= 1'b0;
          apb_state <= 2'd1;
        end
      end
    end
  end

  //--------------------------------------------------------------------------
  // PWM Duty Cycle Determination Based on Temperature Thresholds
  //--------------------------------------------------------------------------
  // The PWM duty cycle is selected based on the sensor reading (temp_adc_in)
  // and the three threshold registers. The following duty cycles are used:
  //   • Below TEMP_LOW: 25% duty cycle  (counter threshold = 64)
  //   • Between TEMP_LOW and TEMP_MED: 50% duty cycle (threshold = 128)
  //   • Between TEMP_MED and TEMP_HIGH: 75% duty cycle (threshold = 192)
  //   • Above TEMP_HIGH: 100% duty cycle (threshold = 255)
  //
  // On reset, all registers are 0. To ensure the fan is disabled on reset,
  // we force pwm_duty to 0 when all registers are in their default state.
  //--------------------------------------------------------------------------
  always @(*) begin
    if ( (TEMP_LOW   == 8'd0) && (TEMP_MED   == 8'd0) &&
         (TEMP_HIGH  == 8'd0) && (temp_adc_in == 8'd0) )
      pwm_duty = 8'd0;
    else if (temp_adc_in < TEMP_LOW)
      pwm_duty = 8'd64;    // 25% duty cycle: high for 64 cycles out of 256
    else if (temp_adc_in < TEMP_MED)
      pwm_duty = 8'd128;   // 50% duty cycle: high for 128 cycles out of 256
    else if (temp_adc_in < TEMP_HIGH)
      pwm_duty = 8'd192;   // 75% duty cycle: high for 192 cycles out of 256
    else
      pwm_duty = 8'd255;   // 100% duty cycle: high for 255 cycles out of 256
  end

  //--------------------------------------------------------------------------
  // PWM Signal Generation
  //--------------------------------------------------------------------------
  // A 256-cycle period is used. The pwm_counter increments each clock cycle.
  // When pwm_counter reaches pwm_duty, it resets to 0. The PWM output is high
  // when pwm_counter is less than pwm_duty, and low otherwise.
  //--------------------------------------------------------------------------
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      pwm_counter   <= 8'd0;
      fan_pwm_out   <= 1'b0;
    end
    else begin
      if (pwm_counter == pwm_duty)
        pwm_counter <= 8'd0;
      else
        pwm_counter <= pwm_counter + 1;
      fan_pwm_out <= (pwm_counter < pwm_duty) ? 1'b1 : 1'b0;
    end
  end

endmodule

