module fibonacci_series(
    input  logic         clk,
    input  logic         rst,
    output logic [31:0]  fib_out,
    output logic         overflow_flag
);

  // Internal registers for Fibonacci numbers
  logic [31:0] RegA, RegB;
  // Flag to indicate that an overflow was detected in the previous cycle.
  logic overflow_pending;

  // Synchronous process for Fibonacci sequence generation and overflow handling
  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      // Reset: Initialize to F(0) = 0, F(1) = 1, output F(0) and clear flags
      RegA          <= 32'd0;
      RegB          <= 32'd1;
      fib_out       <= 32'd0;
      overflow_flag <= 1'b0;
      overflow_pending <= 1'b0;
    end
    // If an overflow was detected in the previous cycle, reset the sequence and assert overflow_flag.
    else if (overflow_pending) begin
      RegA          <= 32'd0;
      RegB          <= 32'd1;
      fib_out       <= 32'd0;
      overflow_flag <= 1'b1;
      overflow_pending <= 1'b0;
    end
    else begin
      // Calculate next Fibonacci number using 33-bit addition to detect overflow.
      logic [32:0] next_fib;
      next_fib = {1'b0, RegA} + {1'b0, RegB};

      if (next_fib[32]) begin
        // Overflow detected: Propagate the last valid Fibonacci number (RegB)
        fib_out       <= RegB;
        overflow_pending <= 1'b1;
        // Do not update registers in this cycle.
      end
      else begin
        // Normal update: shift registers and update output.
        RegA          <= RegB;
        RegB          <= next_fib[31:0];
        fib_out       <= RegB;
        overflow_flag <= 1'b0;
        overflow_pending <= 1'b0;
      end
    end
  end

endmodule

output.rtl/fifo_async.sv:
fifo_async.sv
//------------------------------------------------------------------------------
// Asynchronous FIFO with Configurable Depth and Data Width
// Supports asynchronous writes (w_clk) and reads (r_clk) with cross‐domain
// synchronization using Gray-coded pointers.
//
// Parameters:
//   DATA_WIDTH - width of the data bus
//   DEPTH      - number of data elements that can be stored
//
// Interface:
//   Write domain:
//     w_clk   - write clock
//     w_rst   - asynchronous write reset
//     w_inc   - write enable
//     w_data  - data to be stored
//     w_full  - indicates FIFO is full
//
//   Read domain:
//     r_clk   - read clock
//     r_rst   - asynchronous read reset
//     r_inc   - read enable
//     r_data  - data output
//     r_empty - indicates FIFO is empty
//
// Behavior:
//   - Write and read pointers are maintained as binary counters with an extra
//     bit for overflow. The binary pointer is converted to Gray code for safe
//     cross-domain comparison.
//   - The FIFO is empty when the write and read pointers are exactly equal.
//   - The FIFO is full when, aside from the overflow (MSB) bit, the pointers
//     are equal but the MSB differs.
//   - Two-stage synchronizers pass the Gray-coded pointers across clock domains.
//------------------------------------------------------------------------------

module fifo_async #(
  parameter DATA_WIDTH = 8,
  parameter DEPTH      = 16
)(
  input  logic         w_clk,
  input  logic         w_rst,
  input  logic         w_inc,
  input  logic [DATA_WIDTH-1:0] w_data,
  input  logic         r_clk,
  input  logic         r_rst,
  input  logic         r_inc,
  output logic         w_full,
  output logic         r_empty,
  output logic [DATA_WIDTH-1:0] r_data
);

  //-------------------------------------------------------------------------
  // Local Parameters
  //-------------------------------------------------------------------------
  // Pointer width: log2(DEPTH) + 1 (extra bit for overflow)
  localparam PTR_WIDTH = $clog2(DEPTH) + 1;

  //-------------------------------------------------------------------------
  // Write Domain: Pointer and Gray Code Conversion
  //-------------------------------------------------------------------------
  // Binary write pointer (including overflow bit)
  reg [PTR_WIDTH-1:0] w_ptr_bin;
  // Lower bits used as memory index
  wire [PTR_WIDTH-2:0] w_ptr_index = w_ptr_bin[PTR_WIDTH-2:0];

  // Convert binary pointer to Gray code.
  // g[PTR_WIDTH-1] = b[PTR_WIDTH-1]
  // For i = PTR_WIDTH-2 downto 0: g[i] = b[i+1] XOR b[i]
  wire [PTR_WIDTH-1:0] w_ptr_gray;
  genvar i;
  generate
    for (i = 0; i < PTR_WIDTH; i = i + 1) begin : w_gray_conv
      if (i == PTR_WIDTH-1)
        assign w_ptr_gray[i] = w_ptr_bin[PTR_WIDTH-1];
      else
        assign w_ptr_gray[i] = w_ptr_bin[i+1] ^ w_ptr_bin[i];
    end
  endgenerate

  //-------------------------------------------------------------------------
