logic [NBW_WORD-1:0] data_out_nx     [LINES][COLUMNS];
logic [NBW_WORD-1:0] data_xtimes2_ff [LINES][COLUMNS];
logic [NBW_WORD-1:0] data_xtimes3_ff [LINES][COLUMNS];
logic [NBW_WORD-1:0] data_xtimes9_ff [LINES][COLUMNS];
logic [NBW_WORD-1:0] data_xtimesB_ff [LINES][COLUMNS];
logic [NBW_WORD-1:0] data_xtimesD_ff [LINES][COLUMNS];
logic [NBW_WORD-1:0] data_xtimesE_ff [LINES][COLUMNS];
logic [NBW_WORD-1:0] data_out_ff     [LINES][COLUMNS];

logic [NBW_WORD-1:0] data_xtimes2 [LINES][COLUMNS];
logic [NBW_WORD-1:0] data_xtimes4 [LINES][COLUMNS];
logic [NBW_WORD-1:0] data_xtimes8 [LINES][COLUMNS];

// ----------------------------------------
// - Control registers
// ----------------------------------------
always_ff @(posedge clk or negedge rst_async_n) begin : ctrl_regs
    if (!rst_async_n) begin
        valid_ff <= 0;
        key_ff   <= 0;
    end else begin
        valid_ff[0]         <= i_valid;
        valid_ff[LATENCY:1] <= valid_ff[LATENCY-1:0];
        if(i_update_key) begin
            key_ff <= i_key;
        end
    end
end

// ----------------------------------------
// - Data registers
// ----------------------------------------
always_ff @(posedge clk) begin : data_regs
    for (int line = 0; line < LINES; line++) begin
        for (int column = 0; column < COLUMNS; column++) begin
            if(i_valid) begin
                if(i_encrypt) begin
                    data_in_ff[line][column] <= i_data[NBW_DATA-1-(column*NBW_WORD + line*NBW_WORD*COLUMNS)-:NBW_WORD];
                end else begin
                    data_in_ff[line][column] <= i_data[NBW_DATA-1-(column*NBW_WORD + line*NBW_WORD*COLUMNS)-:NBW_WORD] ^ key_ff[NBW_KEY-line*NBW_WORD-1-:NBW_WORD];            
                end
            end

            data_xtimes2_ff[line][column] <= data_xtimes2_nx[line][column];
            data_xtimes3_ff[line][column] <= data_xtimes3_nx[line][column];
            data_xtimes9_ff[line][column] <= data_xtimes9_nx[line][column];
            data_xtimesB_ff[line][column] <= data_xtimesB_nx[line][column];
            data_xtimesD_ff[line][column] <= data_xtimesD_nx[line][column];
            data_xtimesE_ff[line][column] <= data_xtimesE_nx[line][column];

            if(valid_ff[2]) begin
                data_out_ff[line][column] <= data_out_nx[line][column];
            end
        end
    end
end

// ----------------------------------------
// - Intermediary steps
// ----------------------------------------

// Calculate GF(2^8) multiplication by 2, 4 and 8
always_comb begin : multiply_gf2_4_8
    for (int line = 0; line < LINES; line++) begin
        for (int column = 0; column < COLUMNS; column++) begin
            data_xtimes2[line][column] = data_in_ff[line][column] << 1 ^ MOD_POLY;
            data_xtimes4[line][column] = data_in_ff[line][column] << 2 ^ MOD_POLY;
            data_xtimes8[line][column] = data_in_ff[line][column] << 4 ^ MOD_POLY;
        end
    end
end

// Calculate GF(2^8) multiplications by the values in the polynomial
always_comb begin : multiply_gf
    for (int line = 0; line < LINES; line++) begin
        for (int column = 0; column < COLUMNS; column++) begin
            data_xtimes2_nx[line][column] = data_xtimes2[line][column];
            if(i_encrypt) begin
                data_xtimes3_nx[line][column] = data_xtimes2[line][column] ^ data_in_ff[line][column];
                data_xtimes9_nx[line][column] = data_xtimes9_ff[line][column];
                data_xtimesB_nx[line][column] = data_xtimesB_ff[line][column];
                data_xtimesD_nx[line][column] = data_xtimesD_ff[line][column];
                data_xtimesE_nx[line][column] = data_xtimesE_ff[line][column];
            end else begin
                data_xtimes3_nx[line][column] = data_xtimes3_ff[line][column];
                data_xtimes9_nx[line][column] = data_xtimes8[line][column] ^ data_in_ff[line][column];
                data_xtimesB_nx[line][column] = data_xtimes8[line][column] ^ data_xtimes2[line][column] ^ data_in_ff  [line][column];
                data_xtimesD_nx[line][column] = data_xtimes8[line][column] ^ data_xtimes4[line][column] ^ data_in_ff  [line][column];
                data_xtimesE_nx[line][column] = data_xtimes8[line][column] ^ data_xtimes4[line][column] ^ data_xtimes2[line][column] ^ data_in_ff[line][column];
            end
        end
    end
end

// Calculate output matrix
always_comb begin : out_matrix
    if(i_encrypt) begin
        for (int column = 0; column < COLUMNS; column++) begin
            data_out_nx[0][column] = data_xtimes2_ff[0][column] ^ data_xtimes3_ff[1][column] ^ data_in_ff[2][column] ^ data_in_ff[3][column];
            data_out_nx[1][column] = data_xtimes2_ff[1][column] ^ data_xtimes3_ff[2][column] ^ data_in_ff[3][column] ^ data_in_ff[0][column];
            data_out_nx[2][column] = data_xtimes2_ff[2][column] ^ data_xtimes3_ff[3][column] ^ data_in_ff[0][column] ^ data_in_ff[1][column];
            data_out_nx[3][column] = data_xtimes2_ff[3][column] ^ data_xtimes3_ff[0][column] ^ data_in_ff[1][column] ^ data_in_ff[2][column];
        end
    end else begin
        for (int column = 0; column < COLUMNS; column++) begin
            data_out_nx[0][column] = data_xtimesE_ff[0][column] ^ data_xtimesB_ff[1][column] ^ data_xtimesD_ff[2][column] ^ data_xtimes9_ff[3][column];
            data_out_nx[1][column] = data_xtimesE_ff[1][column] ^ data_xtimesB_ff[2][column] ^ data_xtimesD_ff[3][column] ^ data_xtimes9_ff[0][column];
            data_out_nx[2][column] = data_xtimesE_ff[2][column] ^ data_xtimesB_ff[3][column] ^ data_xtimesD_ff[0][column] ^ data_xtimes9_ff[1][column];
            data_out_nx[3][column] = data_xtimesE_ff[3][column] ^ data_xtimesB_ff[0][column] ^ data_xtimesD_ff[1][column] ^ data_xtimes9_ff[2][column];
        end
    end
end

// ----------------------------------------
// - Assign outputs
// ----------------------------------------

// Map output values from lines x columns to a single dimension
always_comb begin : out_mapping
    if(valid_ff[LATENCY]) begin
        for (int line = 0; line < LINES; line++) begin
            for (int column = 0; column < COLUMNS; column++) begin
                if(i_encrypt) begin
                    o_data[NBW_DATA-(column*NBW_WORD + line*NBW_WORD*COLUMNS)-1-:NBW_WORD] = data_out_ff[line][column] ^ key_ff[NBW_KEY-line*NBW_WORD-1-:NBW_WORD];
                end else begin
                    o_data[NBW_DATA-(column*NBW_WORD + line*NBW_WORD*COLUMNS)-1-:NBW_WORD] = data_out_ff[line][column];
                end
            end
        end
    end else begin
        o_data = 0;
    end
end

assign o_valid = valid_ff[LATENCY];

endmodule : galois_encryption

output.rtl/divider.sv:
module divider #
(
    parameter WIDTH = 32
)
(
    input  wire                  clk,
    input  wire                  rst_n,      
    input  wire                  start,      
    input  wire [WIDTH-1 : 0]    dividend,   
    input  wire [WIDTH-1 : 0]    divisor,    
    output wire [WIDTH-1 : 0]    quotient,   
    output wire [WIDTH-1 : 0]    remainder,  
    output wire                  valid       
);

    localparam AW = WIDTH + 1;
    // FSM states
    localparam IDLE = 2'b00;
    localparam BUSY = 2'b01;
    localparam DONE = 2'b10;

    reg [1:0] state_reg, state_next;

    // AQ register: A (upper AW bits) and Q (lower WIDTH bits)
    reg [AW+WIDTH-1 : 0] aq_reg, aq_next;

    // Divisor register
    reg [AW-1 : 0] m_reg, m_next;

    // Iteration counter (number of bits processed)
    reg [$clog2(WIDTH)-1:0] n_reg, n_next;

    // Final outputs registers
    reg [WIDTH-1:0] quotient_reg, quotient_next;
    reg [WIDTH-1:0] remainder_reg, remainder_next;
    reg valid_reg, valid_next;

    // Output assignments
    assign quotient  = quotient_reg;
    assign remainder = remainder_reg;
    assign valid     = valid_reg;

    // Next state logic and output logic
    always @(*) begin
        // Default assignments
        state_next = state_reg;
        aq_next = aq_reg;
        m_next = m_reg;
        n_next = n_reg;
        quotient_next = quotient_reg;
        remainder_reg = remainder_reg; // no update by default
        valid_next = valid_reg;

        case (state_reg)
            IDLE: begin
                if (start) begin
                    state_next = BUSY;
                    // Load registers: A = 0, Q = dividend, m = divisor, n = WIDTH
                    aq_next = { {AW{1'b0}}, dividend }; // top AW bits = 0, lower = dividend
                    m_next = divisor;
                    n_next = WIDTH;
                    quotient_next = {WIDTH{1'b0}};
                    remainder_reg = {WIDTH{1'b0}};
                    valid_next = 1'b0;
                end
            end

            BUSY: begin
                // Decision bit from previous A (MSB of A)
                // A is in aq_reg[AW+WIDTH-1 : WIDTH]
                // MSB of A is aq_reg[AW+WIDTH-1]
                bit decision;
                decision = aq_reg[AW+WIDTH-1];

                // Shift left AQ by 1: new AQ = { aq_reg[AW+WIDTH-1:1], 1'b0 }
                // But we need to compute new A and new Q separately.
                // New A = (aq_reg[AW+WIDTH-1:WIDTH] << 1) + (decision ? m_reg : -m_reg)
                // new Q = (aq_reg[WIDTH-1:0] << 1) | (~newA[AW-1])
                // Let's compute newA first.
                // We need to extend m_reg to AW bits: {1'b0, m_reg}
                wire [AW-1:0] m_ext = {1'b0, m_reg};
                wire [AW-1:0] sub_m = ~m_ext + 1; // two's complement of m_ext

                wire [AW-1:0] shifted_A = aq_reg[AW+WIDTH-1:WIDTH] << 1;
                wire [AW-1:0] newA;
                if (decision)
                    newA = shifted_A + m_ext;
                else
                    newA = shifted_A + sub_m; // addition of two's complement gives subtraction

                // The quotient bit is the inverse of the MSB of newA (i.e., ~newA[AW-1])
                bit q_bit;
                q_bit = ~newA[AW-1];

                // New Q = (aq_reg[WIDTH-1:0] << 1) OR q_bit
                wire [WIDTH-1:0] shifted_Q = aq_reg[WIDTH-1:0] << 1;
                wire [WIDTH-1:0] newQ = shifted_Q | q_bit;

                // Combine new A and new Q into aq_next
                aq_next = { newA, newQ };

                // Decrement iteration counter
                n_next = n_reg - 1;

                // Stay in BUSY if more iterations remain, else transition to DONE
                if (n_reg != 0)
                    state_next = BUSY;
                else
                    state_next = DONE;

                // In BUSY, outputs are not valid yet.
                valid_next = 1'b0;
            end

            DONE: begin
                // Final adjustment: if sign bit of A is 1, then A = A + m_reg
                // A is in aq_reg[AW+WIDTH-1: WIDTH]
                // Check MSB of A: aq_reg[AW+WIDTH-1]
                if (aq_reg[AW+WIDTH-1])
                    remainder_reg = (aq_reg[AW+WIDTH-1:WIDTH] + {1'b0, m_reg})[WIDTH-1:0];
                else
                    remainder_reg = aq_reg[AW+WIDTH-1:WIDTH][WIDTH-1:0];

                // Quotient is the Q part of aq_reg
                quotient_next = aq_reg[WIDTH-1:0];

                // Remain valid until start is de-asserted
                valid_next = 1'b1;

                // Transition back to IDLE when start is low.
                if (!start)
                    state_next = IDLE;
                else
                    state_next = DONE;
            end

            default: state_next = IDLE;
        endcase
    end

    // Sequential block
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state_reg <= IDLE;
            aq_reg   <= { (AW+WIDTH){1'b0} };
            m_reg    <= {AW{1'b0}};
            n_reg    <= { $clog2(WIDTH){1'b0} };
            quotient_reg <= {WIDTH{1'b0}};
            remainder_reg <= {WIDTH{1'b0}};
            valid_reg <= 1'b0;
        end else begin
            state_reg <= state_next;
            aq_reg   <= aq_next;
            m_reg    <= m_next;
            n_reg    <= n_next;
            quotient_reg <= quotient_next;
            remainder_reg <= remainder_reg; // updated in combinational always block for DONE state, but we need to update in sequential block as well.
            valid_reg <= valid_next;
        end
    end

endmodule

input.rtl/divider.sv:
//////////////////////////////////////////////
// Top-Level Gold-Schmidt Division Module
//////////////////////////////////////////////
module divider (
    input  logic         clk,
    input  logic         rst_n,
    input  logic         start,
    input  logic [17:0]  dividend,  // unsigned
    input  logic [17:0]  divisor,   // unsigned
    output logic [17:0]  dv_out,
    output logic         valid
);

    //////////////////////////////////////////////
    // Local parameters
    //////////////////////////////////////////////
    localparam logic [17:0] TWO  = 18'b000000010_000000000;  // "2.0" in Q9.9
    localparam logic [17:0] ZERO = 18'b000000000_000000000;  // "0.0" in Q9.9

    //////////////////////////////////////////////
    // Internal signals
    //////////////////////////////////////////////
    logic [17:0] D_0, N_0;
    logic [17:0] D, D2, D4, D6, D8, D10, D12, D14, D16, D18, D20;
    logic [17:0] N, N2, N4, N6, N8, N10, N12, N14, N16, N18, N20, N21;
    logic [17:0] F, F1, F2, F3, F4, F5, F6, F7, F8, F9;
    logic [47:0] D1, N1, D3, N3, D5, N5, D7, N7, D9, N9, D11, N11, D13, N13, D15, N15, D17, N17, D19, N19;

    // Pipeline stage flags
    logic st1, st2, st3, st4, st5, st6, st7, st8, st9, st10, st11, st12;

    //////////////////////////////////////////////
    // Pre-registers for dividend/divisor
    //////////////////////////////////////////////
    reg18 reg_dividend_pre(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(dividend),
        .data_out(N_0)
    );

    reg18 reg_divisor_pre(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(divisor),
        .data_out(D_0)
    );

    // Pipeline control for "start"
    dff1 ff0(
        .clk   (clk),
        .reset (~rst_n),
        .d     (start),
        .q     (st1)
    );

    //////////////////////////////////////////////
    // Prescaling: only for magnitude < 1
    //////////////////////////////////////////////
    logic [17:0] prescaled_divisor, prescaled_dividend;
    pre_scaler prescaler_inst(
        .a(D_0),
        .c(N_0),
        .b(prescaled_divisor),
        .d(prescaled_dividend)
    );

    //////////////////////////////////////////////
    // Register the prescaled divisor & dividend
    //////////////////////////////////////////////
    reg18 reg_divisor_stage1(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(prescaled_divisor),
        .data_out(D)
    );

    reg18 reg_dividend_stage1(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(prescaled_dividend),
        .data_out(N)
    );

    dff1 ff1(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st1),
        .q     (st2)
    );

    //////////////////////////////////////////////
    // Stage 1: Compute F = (2 - D), multiply, register
    //////////////////////////////////////////////
    always_comb begin
        // Because we're unsigned and D < 1.0, we do F = 2 - D
        F = TWO - D;
    end

    assign D1 = F * D;
    assign N1 = F * N;

    reg18 reg_divisor_stage2(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D1[26:9]),     // Keep 18 bits
        .data_out(D2)
    );

    reg18 reg_dividend_stage2(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N1[26:9]),
        .data_out(N2)
    );

    dff1 ff2(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st2),
        .q     (st3)
    );

    //////////////////////////////////////////////
    // Stage 2: F1 = 2 - D2, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F1 = TWO - D2;
    end

    assign D3 = F1 * D2;
    assign N3 = F1 * N2;

    reg18 reg_divisor_stage3(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D3[26:9]),
        .data_out(D4)
    );

    reg18 reg_dividend_stage3(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N3[26:9]),
        .data_out(N4)
    );

    dff1 ff3(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st3),
        .q     (st4)
    );

    //////////////////////////////////////////////
    // Stage 3: F2 = 2 - D4, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F2 = TWO - D4;
    end

    assign D5 = F2 * D4;
    assign N5 = F2 * N4;

    reg18 reg_divisor_stage4(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D5[26:9]),
        .data_out(D6)
    );

    reg18 reg_dividend_stage4(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N5[26:9]),
        .data_out(N6)
    );

    dff1 ff4(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st4),
        .q     (st5)
    );

    //////////////////////////////////////////////
    // Stage 4: F3 = 2 - D6, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F3 = TWO - D6;
    end

    assign D7 = F3 * D6;
    assign N7 = F3 * N6;

    reg18 reg_divisor_stage5(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D7[26:9]),
        .data_out(D8)
    );

    reg18 reg_dividend_stage5(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N7[26:9]),
        .data_out(N8)
    );

    dff1 ff6(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st5),
        .q     (st6)
    );

    //////////////////////////////////////////////
    // Stage 5: F4 = 2 - D8, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F4 = TWO - D8;
    end

    assign D9 = F4 * D8;
    assign N9 = F4 * N8;

    reg18 reg_divisor_stage6(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D9[26:9]),
        .data_out(D10)
    );
    reg18 reg_dividend_stage6(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N9[26:9]),
        .data_out(N10)
    );

    dff1 ff8(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st6),
        .q     (st7)
    );

    //////////////////////////////////////////////
    // Stage 6: F5 = 2 - D10, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F5 = TWO - D10;
    end

    assign D11 = F5 * D10;
    assign N11 = F5 * N10;

    reg18 reg_divisor_stage7(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D11[26:9]),
        .data_out(D12)
    );
    reg18 reg_dividend_stage7(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N11[26:9]),
        .data_out(N12)
    );

    dff1 ff9(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st7),
        .q     (st8)
    );


    //////////////////////////////////////////////
    // Stage 7: F6 = 2 - D12, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F6 = TWO - D12;
    end

    assign D13 = F6 * D12;
    assign N13 = F6 * N12;

    reg18 reg_divisor_stage8(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D13[26:9]),
        .data_out(D14)
    );
    reg18 reg_dividend_stage8(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N13[26:9]),
        .data_out(N14)
    );

    dff1 ff10(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st8),
        .q     (st9)
    );


    //////////////////////////////////////////////
    // Stage 8: F7 = 2 - D14, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F7 = TWO - D14;
    end

    assign D15 = F7 * D14;
    assign N15 = F7 * N14;

    reg18 reg_divisor_stage9(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D15[26:9]),
        .data_out(D16)
    );
    reg18 reg_dividend_stage9(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N15[26:9]),
        .data_out(N16)
    );

    dff1 ff11(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st9),
        .q     (st10)
    );

    //////////////////////////////////////////////
    // Stage 9: F8 = 2 - D16, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F8 = TWO - D16;
    end

    assign D17 = F8 * D16;
    assign N17 = F8 * N16;

    reg18 reg_divisor_stage10(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D17[26:9]),
        .data_out(D18)
    );
    reg18 reg_dividend_stage10(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N17[26:9]),
        .data_out(N18)
    );

    dff1 ff12(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st10),
        .q     (st11)
    );

    //////////////////////////////////////////////
    // Stage 10: F9 = 2 - D18, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F9 = TWO - D18;
    end

    assign D19 = F9 * D18;
    assign N19 = F9 * N18;

    reg18 reg_divisor_stage11(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D19[26:9]),
        .data_out(D20)
    );
    reg18 reg_dividend_stage11(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N19[26:9]),
        .data_out(N20)
    );

    dff1 ff13(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st11),
        .q     (st12)
    );

    always_comb begin
        N21 = N20;
    end

    // Final output register
    reg18 reg_quotient_out(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N21),
        .data_out(dv_out)
    );

    // Final pipeline control
    dff1 ff14(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st12),
        .q     (valid)
    );

endmodule

////////////////////////////////////////////////
// Pre-scaling (Prescaling) Module
////////////////////////////////////////////////
module pre_scaler (
    input  logic [17:0] a,  // unsigned divisor
    input  logic [17:0] c,  // unsigned dividend
    output logic [17:0] b,  // prescaled divisor
    output logic [17:0] d   // prescaled dividend
);
    // For simplicity, if 'a' is large, we shift until it is < 1.0 in Q9.9 format
    // That means the integer bits of 'a' must be 0. We find how many leading bits
    // we need to shift out.

    always_comb begin : SHIFT_LOGIC
        // 'a' has 18 bits in total, where the top 9 bits are integer, bottom 9 bits are fractional.
        // We want the integer part of 'a' to be 0 => 'a[17:9]' should be zero after shifting.

        if (a[17]) begin
            b = a >> 8;
            d = c >> 8;
        end
        else if (a[16]) begin
            b = a >> 7;
            d = c >> 7;
        end
        else if (a[15]) begin
            b = a >> 6;
            d = c >> 6;
        end
        else if (a[14]) begin
            b = a >> 5;
            d = c >> 5;
        end
        else if (a[13]) begin
            b = a >> 4;
            d = c >> 4;
        end
        else if (a[12]) begin
            b = a >> 3;
            d = c >> 3;
        end
        else if (a[11]) begin
            b = a >> 2;
            d = c >> 2;
        end
        else if (a[10]) begin
            b = a >> 1;
            d = c >> 1;
        end
        else begin
            b = a;
            d = c;
        end
    end
endmodule

////////////////////////////////////////////////
// Single-bit DFF
////////////////////////////////////////////////
module dff1 (
    input  logic clk,
    input  logic reset,
    input  logic d,
    output logic q
);
    always_ff @(posedge clk) begin
        if (reset) 
            q <= 1'b0;
        else
            q <= d;
    end
endmodule


////////////////////////////////////////////////
// 18-bit register (parallel load)
////////////////////////////////////////////////
module reg18 (
    input  logic        clk,
    input  logic        reset,
    input  logic [17:0] data_in,
    output logic [17:0] data_out
);
    always_ff @(posedge clk) begin
        if (reset) 
            data_out <= 18'd0;
        else
            data_out <= data_in;
    end
endmodule

