// New top-level module for 3-input GCD calculation using existing gcd_top instances.
module gcd_3_ip #(
   parameter WIDTH = 4
)(
   input                     clk,             // Clock signal
   input                     rst,             // Active High Synchronous reset
   input  [WIDTH-1:0]        A,               // First input operand
   input  [WIDTH-1:0]        B,               // Second input operand
   input  [WIDTH-1:0]        C,               // Third input operand
   input                     go,              // Start signal to begin 3-input GCD computation
   output logic [WIDTH-1:0]  OUT,             // Output for the final GCD result
   output logic              done             // Signal to indicate completion of 3-input GCD computation
);

   // Intermediate signals for the two 2-input GCD computations.
   logic [WIDTH-1:0] gcd_ab;
   logic [WIDTH-1:0] gcd_bc;
   logic done_ab;
   logic done_bc;

   // Instantiate gcd_top for computing GCD of A and B.
   gcd_top #(.WIDTH(WIDTH)) gcd_top_inst_AB (
      .clk   (clk),
      .rst   (rst),
      .A     (A),
      .B     (B),
      .go    (go),
      .OUT   (gcd_ab),
      .done  (done_ab)
   );

   // Instantiate gcd_top for computing GCD of B and C.
   gcd_top #(.WIDTH(WIDTH)) gcd_top_inst_BC (
      .clk   (clk),
      .rst   (rst),
      .A     (B),
      .B     (C),
      .go    (go),
      .OUT   (gcd_bc),
      .done  (done_bc)
   );

   // Final 2-input GCD computation using the results of the intermediate computations.
   // Latch the control signal to ensure final computation starts only when both intermediate computations are ready.
   logic final_go;
   logic final_done;
   logic [WIDTH-1:0] final_gcd;

   // Latch final_go: assert when both intermediate computations are done.
   always_ff @(posedge clk or posedge rst) begin
      if (rst)
         final_go <= 1'b0;
      else if (done_ab && done_bc && !final_go)
         final_go <= 1'b1;
      else if (final_go && final_done)
         final_go <= 1'b0;
   end

   // Instantiate gcd_top for final GCD computation.
   gcd_top #(.WIDTH(WIDTH)) gcd_top_inst_FINAL (
      .clk   (clk),
      .rst   (rst),
      .A     (gcd_ab),
      .B     (gcd_bc),
      .go    (final_go),
      .OUT   (final_gcd),
      .done  (final_done)
   );

   // Drive top-level outputs.
   assign OUT = final_gcd;
   assign done = final_done;

endmodule

