    logic [N-1:0] count_gray;
    logic [N-1:0] count_ring;

    // BINARY_UP count logic
    always_ff @(posedge clk_in) begin
        if (rst_in)
            count_bin_up <= {N{1'b0}};
        else if (enable_in)
            count_bin_up <= count_bin_up + 1;
        else
            count_bin_up <= count_bin_up;
    end

    // BINARY_DOWN count logic
    always_ff @(posedge clk_in) begin
        if (rst_in)
            count_bin_down <= {N{1'b0}};
        else if (enable_in)
            count_bin_down <= count_bin_down - 1;
        else
            count_bin_down <= count_bin_down;
    end

    // MODULO_N count logic
    always_ff @(posedge clk_in) begin
        if (rst_in)
            count_modulo <= {N{1'b0}};
        else if (enable_in) begin
            if (count_modulo == ref_modulo)
                count_modulo <= {N{1'b0}};
            else
                count_modulo <= count_modulo + 1;
        end else
            count_modulo <= count_modulo;
    end

    // JOHNSON count logic
    always_ff @(posedge clk_in) begin
        if (rst_in)
            count_johnson <= {N{1'b0}};
        else if (enable_in)
            count_johnson <= {~count_johnson[0], count_johnson[N-1:1]};
        else
            count_johnson <= count_johnson;
    end

    // GRAY count logic (internal count)
    always_ff @(posedge clk_in) begin
        if (rst_in)
            count_gray <= {N{1'b0}};
        else if (enable_in)
            count_gray <= count_gray + 1;
        else
            count_gray <= count_gray;
    end

    // RING count logic
    always_ff @(posedge clk_in) begin
        if (rst_in)
            count_ring <= {N{1'b0}};
        else if (enable_in) begin
            if (count_ring == {N{1'b0}})
                count_ring <= {{(N-1){1'b0}}, 1'b1};
            else
                count_ring <= {count_ring[N-2:0], count_ring[N-1]};
        end else
            count_ring <= count_ring;
    end

    // Multiplexer to select the count based on mode_in
    always_comb begin
        case (mode_in)
            BINARY_UP:   count_mux = count_bin_up;
            BINARY_DOWN: count_mux = count_bin_down;
            MODULO_N:    count_mux = count_modulo;
            JOHNSON:     count_mux = count_johnson;
            GRAY:        count_mux = count_gray;
            RING:        count_mux = count_ring;
            default:     count_mux = {N{1'b0}};
        endcase
    end

    assign o_count = (mode_in == GRAY) ? (count_mux ^ (count_mux >> 1)) : count_mux;

endmodule

output.rtl/generic_counter.sv:
module generic_counter #(parameter N = 8) (
    input  logic         clk_in,          
    input  logic         rst_in,          
    input  logic [2:0]   mode_in,         
    input  logic         enable_in,       
    input  logic [N-1:0] ref_modulo,      
    output logic [N-1:0] o_count          
);

  // Mode definitions
  parameter BINARY_UP   = 3'b000;
  parameter BINARY_DOWN = 3'b001;
  parameter MODULO_N    = 3'b010;
  parameter JOHNSON     = 3'b011;
  parameter GRAY        = 3'b100;
  parameter RING        = 3'b101;

  // Counters for each mode
  logic [N-1:0] count_bin_up;
  logic [N-1:0] count_bin_down;
  logic [N-1:0] count_modulo;
  logic [N-1:0] count_johnson;
  logic [N-1:0] count_gray;
  logic [N-1:0] count_ring;

  // ---------------------------------------------------------------------
  // Combined always_ff block to update all counters concurrently.
  // This reduces the overhead of multiple clocked blocks while keeping
  // the one-cycle latency and functional equivalence.
  // ---------------------------------------------------------------------
  always_ff @(posedge clk_in) begin
    if (rst_in) begin
      count_bin_up     <= {N{1'b0}};
      count_bin_down   <= {N{1'b0}};
      count_modulo     <= {N{1'b0}};
      count_johnson    <= {N{1'b0}};
      count_gray       <= {N{1'b0}};
      count_ring       <= {N{1'b0}};
    end
    else begin
      // BINARY_UP: Increment on enable
      if (enable_in)
        count_bin_up <= count_bin_up + 1;

      // BINARY_DOWN: Decrement on enable
      if (enable_in)
        count_bin_down <= count_bin_down - 1;

      // MODULO_N: Increment and wrap-around on reaching ref_modulo
      if (enable_in)
        count_modulo <= (count_modulo == ref_modulo) ? {N{1'b0}} : count_modulo + 1;

      // JOHNSON: Rotate with bit inversion at bit0
      if (enable_in)
        count_johnson <= {~count_johnson[0], count_johnson[N-1:1]};

      // GRAY: Simple binary counter (internal count)
      if (enable_in)
        count_gray <= count_gray + 1;

      // RING: Rotate right (circular bit shift)
      if (enable_in)
        count_ring <= (count_ring == {N{1'b0}}) 
                      ? {{(N-1){1'b0}}, 1'b1} 
                      : {count_ring[N-2:0], count_ring[N-1]};
    end
  end

  // ---------------------------------------------------------------------
  // Function-based multiplexer to select the output counter.
  // Using a function helps synthesis tools optimize the combinational
  // logic, reducing both cell and wire overhead.
  // ---------------------------------------------------------------------
  function automatic logic [N-1:0] mux_sel(input logic [2:0] mode);
    case (mode)
      BINARY_UP:   mux_sel = count_bin_up;
      BINARY_DOWN: mux_sel = count_bin_down;
      MODULO_N:    mux_sel = count_modulo;
      JOHNSON:     mux_sel = count_johnson;
      GRAY:        mux_sel = count_gray ^ (count_gray >> 1);
      RING:        mux_sel = count_ring;
      default:     mux_sel = {N{1'b0}};
    endcase
  endfunction

  // Output assignment with one-cycle latency
  assign o_count = mux_sel(mode_in);

endmodule

output.rtl/gf_multiplier.sv:
module gf_multiplier (
  input  logic [3:0] A,  // Multiplicand (4-bit)
  input  logic [3:0] B,  // Multiplier (4-bit)
  output logic [3:0] result  // Product (4-bit)
);

  // In this implementation, we use a 5-bit register for the multiplicand
  // during shifting so that we can check for overflow (MSB) and perform
  // polynomial reduction with the irreducible polynomial x^4 + x + 1 (5'b10011).
  // The final multiplicand is maintained as a 4-bit value.

  always_comb begin
    logic [3:0] res;       // Intermediate result (4-bit)
    logic [4:0] mult;      // Multiplicand as a 5-bit value
    integer i;

    res = 4'b0;
    // Initialize multiplicand with an extra leading zero to form a 5-bit value.
    mult = {1'b0, A};

    // Process each bit of multiplier B (LSB to MSB)
    for (i = 0; i < 4; i = i + 1) begin
      // If the current bit of B is 1, XOR the lower 4 bits of the multiplicand with result.
      if (B[i])
        res = res ^ mult[3:0];

      // Shift multiplicand left by 1 bit (5-bit shift to capture potential overflow)
      mult = mult << 1;

      // If overflow occurs (MSB is 1), perform polynomial reduction.
      if (mult[4])
        mult = mult ^ 5'b10011;

      // Retain only the lower 4 bits for the next iteration.
      mult = mult[3:0];
    end

    result = res;
  end

endmodule

output.rtl/gf_mac.sv:
module gf_mac #(parameter WIDTH = 8) (
    input  [WIDTH-1:0] a,
    input  [WIDTH-1:0] b,
    output [7:0] result
);

    // Calculate number of 8-bit segments (WIDTH must be a multiple of 8)
    localparam NUM_SEGMENTS = WIDTH / 8;

    // Array to hold the result of each 8-bit GF multiplication
    wire [7:0] mult_results [0:NUM_SEGMENTS-1];

    // Instantiate a gf_multiplier for each 8-bit segment
    genvar i;
    generate
        for (i = 0; i < NUM_SEGMENTS; i = i + 1) begin : mac_instances
            // Extract the i-th 8-bit segment from a and b (LSB first)
            gf_multiplier u_gf_multiplier (
                .A(a[8*i + 7:8*i]),
                .B(b[8*i + 7:8*i]),
                .result(mult_results[i])
            );
        end
    endgenerate

    // Cumulative XOR of all segment multiplication results
    reg [7:0] temp_result;
    always_comb begin
        temp_result = 8'b0;
        integer j;
        for (j = 0; j < NUM_SEGMENTS; j = j + 1) begin
            temp_result = temp_result ^ mult_results[j];
        end
    end

    assign result = temp_result;

endmodule

