module gf_mac #(
    parameter WIDTH = 32  // Input width, should be a multiple of 8
)(
    input [WIDTH-1:0] a,  // Multiplicand
    input [WIDTH-1:0] b,  // Multiplier
    output reg [7:0] result // 8-bit XORed result of all GF multiplications
);

    integer i;
    reg [7:0] temp_result;
    wire [7:0] partial_results [(WIDTH/8)-1:0];

    // Generate GF multipliers for each 8-bit segment
    genvar j;
    generate
        for (j = 0; j < WIDTH/8; j = j + 1) begin : segment_mult
            gf_multiplier segment_mult (
                .A(a[(j+1)*8-1:j*8]),
                .B(b[(j+1)*8-1:j*8]),
                .result(partial_results[j])
            );
        end
    endgenerate

    // XOR all segment results
    always @(*) begin
        temp_result = 8'b0;
        for (i = 0; i < WIDTH/8; i = i + 1) begin
            temp_result = temp_result ^ partial_results[i];
        end
        result = temp_result;
    end
endmodule

module gf_multiplier (
    input [7:0] A,
    input [7:0] B,
    output reg [7:0] result
);
    reg [7:0] temp_result;
    reg [8:0] multiplicand;
    reg [8:0] irreducible_poly = 9'b100011011; // x^8 + x^4 + x^3 + x + 1

    integer i;

    always @(*) begin
        temp_result = 8'b00000000;
        multiplicand = {1'b0, A};
        for (i = 0; i < 8; i = i + 1) begin
            if (B[i]) begin
                temp_result = temp_result ^ multiplicand[7:0];
            end
            multiplicand = multiplicand << 1;
            if (multiplicand[8]) begin
                multiplicand = multiplicand ^ irreducible_poly;
            end
        end
        result = temp_result;
    end
endmodule

output.rtl/gf_mac.sv:
module gf_mac #(
    parameter WIDTH = 32  // Input width, should be a multiple of 8
)(
    input [WIDTH-1:0] a,  // Multiplicand
    input [WIDTH-1:0] b,  // Multiplier
    output reg [7:0] result, // 8-bit XORed result of all GF multiplications
    output reg error_flag,   // 1 if error (WIDTH not multiple of 8), 0 otherwise
    output reg valid_result  // 1 if computation is valid, 0 otherwise
);

    // Use generate-if to handle valid vs invalid WIDTH cases
    generate
        if (WIDTH % 8 != 0) begin : invalid_width
            // Invalid Width: Do not perform any computation.
            always @(*) begin
                result    = 8'b0;
                valid_result = 1'b0;
                error_flag = 1'b1;
            end
        end
        else begin : valid_width
            // Valid Width: Perform GF multiplication and accumulation.
            integer i;
            reg [7:0] temp_result;
            wire [7:0] partial_results [(WIDTH/8)-1:0];

            // Generate GF multipliers for each 8-bit segment.
            genvar j;
            generate
                for (j = 0; j < WIDTH/8; j = j + 1) begin : segment_mult
                    gf_multiplier segment_mult (
                        .A(a[(j+1)*8-1:j*8]),
                        .B(b[(j+1)*8-1:j*8]),
                        .result(partial_results[j])
                    );
                end
            endgenerate

            // XOR all segment results and drive the outputs.
            always @(*) begin
                temp_result = 8'b0;
                for (i = 0; i < WIDTH/8; i = i + 1) begin
                    temp_result = temp_result ^ partial_results[i];
                end
                result     = temp_result;
                valid_result = 1'b1;
                error_flag = 1'b0;
            end
        end
    endgenerate

endmodule

module gf_multiplier (
    input [7:0] A,
    input [7:0] B,
    output reg [7:0] result
);
    reg [7:0] temp_result;
    reg [8:0] multiplicand;
    reg [8:0] irreducible_poly = 9'b100011011; // x^8 + x^4 + x^3 + x + 1

    integer i;

    always @(*) begin
        temp_result = 8'b00000000;
        multiplicand = {1'b0, A};
        for (i = 0; i < 8; i = i + 1) begin
            if (B[i]) begin
                temp_result = temp_result ^ multiplicand[7:0];
            end
            multiplicand = multiplicand << 1;
            if (multiplicand[8]) begin
                multiplicand = multiplicand ^ irreducible_poly;
            end
        end
        result = temp_result;
    end
endmodule

output.rtl/gmii_rx_to_axi_stream.sv:
module gmii_rx_to_axi_stream (
    // GMII Input Signals:
    input  wire        gmii_rx_clk,
    input  wire [7:0]  gmii_rxd,
    input  wire        gmii_rx_dv,

    // AXI-Stream Output Signals:
    output wire [7:0]  m_axis_tdata,
    output wire        m_axis_tvalid,
    input  wire        m_axis_tready,
    output wire        m_axis_tlast
);

    // State definitions
    localparam IDLE     = 2'b00,
               RECEIVING = 2'b01,
               FINISHED  = 2'b10;

    // Parameter to define frame length (number of bytes per frame)
    parameter FRAME_LENGTH = 8;

    // Registers for state machine and byte counting
    reg [1:0] state;
    reg [3:0] byte_count;  // 4-bit counter (sufficient for FRAME_LENGTH=8)

    // Registers to hold data and control signals
    reg [7:0] data_reg;
    reg       tvalid_reg;
    reg       tlast_reg;

    // Output assignments
    assign m_axis_tdata  = data_reg;
    assign m_axis_tvalid = tvalid_reg;
    assign m_axis_tlast  = tlast_reg;

    // Main state machine: driven by gmii_rx_clk
    always @(posedge gmii_rx_clk) begin
        case (state)
            IDLE: begin
                // Wait for the start of frame indicated by gmii_rx_dv
                if (gmii_rx_dv) begin
                    state         <= RECEIVING;
                    byte_count    <= 0;
                    data_reg      <= gmii_rxd; // capture first byte
                    tvalid_reg    <= 1'b1;
                    tlast_reg     <= 1'b0;
                end else begin
                    tvalid_reg    <= 1'b0;
                    tlast_reg     <= 1'b0;
                end
            end

            RECEIVING: begin
                if (gmii_rx_dv) begin
                    // When gmii_rx_dv is valid, check if downstream is ready
                    if (m_axis_tready) begin
                        // Transfer the current byte and prepare for the next
                        data_reg      <= gmii_rxd; // load next byte
                        byte_count    <= byte_count + 1;
                        // Assert tlast when the final byte is reached
                        if (byte_count == FRAME_LENGTH - 1) begin
                            tlast_reg   <= 1'b1;
                            state       <= FINISHED;
                        end else begin
                            tlast_reg   <= 1'b0;
                        end
                    end else begin
                        // If downstream not ready, de-assert tvalid as specified
                        tvalid_reg   <= 1'b0;
                    end
                end else begin
                    // gmii_rx_dv deasserted: end-of-frame detected
                    state         <= FINISHED;
                    tlast_reg     <= 1'b1;
                end
            end

            FINISHED: begin
                // Wait for downstream to be ready to flush the final tlast signal
                if (m_axis_tready) begin
                    state         <= IDLE;
                    tvalid_reg    <= 1'b0;
                    tlast_reg     <= 1'b0;
                end
            end

            default: state <= IDLE;
        endcase
    end

endmodule

output.rtl/gray_to_binary.sv:
module gray_to_binary #(
    parameter WIDTH      = 4,  // Specify the width of the Gray code input
    parameter DEBUG_MODE = 0   // Debug mode: 0 = Disabled, 1 = Enabled
) (
    input  logic [WIDTH-1:0] gray_in,     
    output logic [WIDTH-1:0] binary_out, 
    output logic [WIDTH-1:0] debug_mask,  
    output logic             parity,   
    output logic             valid      
);

  // Internal signals for processing stages
  logic [WIDTH-1:0] intermediate_stage_1;
  logic [WIDTH-1:0] final_binary;
  logic             valid_stage_1;
  logic             valid_stage_2;

  always @* begin

    // Stage 1: Intermediate Binary Computation
    intermediate_stage_1[WIDTH-1] = gray_in[WIDTH-1];
    for (int i = WIDTH - 2; i >= 0; i--) begin
      intermediate_stage_1[i] = intermediate_stage_1[i+1] ^ gray_in[i];
    end
    valid_stage_1 = 1'b1;  

    // Stage 2: Debugging and Masking
    final_binary = intermediate_stage_1;
    if (DEBUG_MODE) begin
      debug_mask = ~final_binary; // Invert final_binary for diagnostic purposes
    end else begin
      debug_mask = {WIDTH{1'b0}}; // No debug mask when debugging is disabled
    end
    valid_stage_2 = 1'b1;

    // Stage 3: Final Outputs
    binary_out = final_binary;
    parity = ^final_binary;  // Reduction XOR to compute parity (0 = even, 1 = odd)
    valid = 1'b1;            // Computation complete and valid

  end

endmodule

