module hill_cipher (
    input logic clk,
    input logic reset,
    input logic start,
    input logic [14:0] plaintext,   // 3 letters, 5 bits each
    input logic [44:0] key,         // 9 elements, 5 bits each
    output logic [14:0] ciphertext, // 3 letters, 5 bits each 
    output logic done
);

    logic [4:0] P0, P1, P2;
    logic [4:0] K00, K01, K02;
    logic [4:0] K10, K11, K12;
    logic [4:0] K20, K21, K22;

    logic [5:0] temp0, temp1, temp2;
    logic [4:0] C0_reg, C1_reg, C2_reg;

    typedef enum logic [1:0] {
        IDLE        = 2'b00,
        COMPUTE     = 2'b01,
        COMPUTE_MOD = 2'b10,
        DONE        = 2'b11
    } state_t;

    state_t current_state, next_state;

    assign P0 = plaintext[14:10];
    assign P1 = plaintext[9:5];
    assign P2 = plaintext[4:0];

    assign K00 = key[44:40];
    assign K01 = key[39:35];
    assign K02 = key[34:30];
    assign K10 = key[29:25];
    assign K11 = key[24:20];
    assign K12 = key[19:15];
    assign K20 = key[14:10];
    assign K21 = key[9:5];
    assign K22 = key[4:0];

    always_ff @(posedge clk or posedge reset) begin
        if (reset)
            current_state <= IDLE;
        else
            current_state <= next_state;
    end

    always_comb begin
        next_state = current_state;
        done = 1'b0;

        case (current_state)
            IDLE: begin
                if (start)
                    next_state = COMPUTE;
            end
            COMPUTE: begin
                next_state = COMPUTE_MOD;
            end
            COMPUTE_MOD: begin
                next_state = DONE;
            end
            DONE: begin
                done = 1'b1;
                next_state = IDLE;
            end
            default: next_state = IDLE;
        endcase
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            temp0 <= 12'b0;
            temp1 <= 12'b0;
            temp2 <= 12'b0;
            C0_reg <= 5'b0;
            C1_reg <= 5'b0;
            C2_reg <= 5'b0;
        end
        else begin
            case (current_state)
                COMPUTE: begin
                    temp0 <= (K00 * P0)%26 + (K01 * P1)%26 + (K02 * P2)%26;
                    temp1 <= (K10 * P0)%26 + (K11 * P1)%26 + (K12 * P2)%26;
                    temp2 <= (K20 * P0)%26 + (K21 * P1)%26 + (K22 * P2)%26;
                end
                COMPUTE_MOD: begin
                    C0_reg <= temp0%26;
                    C1_reg <= temp1%26;
                    C2_reg <= temp2%26;
                end
                default: begin
                    temp0 <= 12'b0;
                    temp1 <= 12'b0;
                    temp2 <= 12'b0;
                    C0_reg <= 5'b0;
                    C1_reg <= 5'b0;
                    C2_reg <= 5'b0;
                end
            endcase
        end
    end

    assign ciphertext = {C0_reg, C1_reg, C2_reg};

endmodule

output.rtl/hill_cipher.sv:
module hill_cipher (
    input  logic         clk,
    input  logic         reset,
    input  logic         start,
    input  logic [14:0]  plaintext,   // 3 letters, 5 bits each
    input  logic [44:0]  key,         // 9 elements, 5 bits each
    output logic [14:0]  ciphertext,  // 3 letters, 5 bits each 
    output logic         done
);

    // Split plaintext into individual 5-bit letters
    logic [4:0] P0, P1, P2;
    // Extract key matrix elements
    logic [4:0] K00, K01, K02;
    logic [4:0] K10, K11, K12;
    logic [4:0] K20, K21, K22;

    // Intermediate computation registers.
    // Each term (Kxx * Py) % MOD yields a value in [0,25]. Their sum is at most 75,
    // so 7 bits are sufficient to hold the sum without truncation warnings.
    logic [6:0] temp0, temp1, temp2;
    // Final ciphertext registers (each 5 bits)
    logic [4:0] C0_reg, C1_reg, C2_reg;

    // Define modulus constant with an explicit width to match the intermediate results.
    parameter logic [9:0] MOD = 10'd26;

    // Finite state machine states
    typedef enum logic [1:0] {
        IDLE        = 2'b00,
        COMPUTE     = 2'b01,
        COMPUTE_MOD = 2'b10,
        DONE        = 2'b11
    } state_t;

    state_t current_state, next_state;

    // Assign individual plaintext segments
    assign P0 = plaintext[14:10];
    assign P1 = plaintext[9:5];
    assign P2 = plaintext[4:0];

    // Assign key matrix elements from the 45-bit key vector
    assign K00 = key[44:40];
    assign K01 = key[39:35];
    assign K02 = key[34:30];
    assign K10 = key[29:25];
    assign K11 = key[24:20];
    assign K12 = key[19:15];
    assign K20 = key[14:10];
    assign K21 = key[9:5];
    assign K22 = key[4:0];

    // Synchronous state register update
    always_ff @(posedge clk or posedge reset) begin
        if (reset)
            current_state <= IDLE;
        else
            current_state <= next_state;
    end

    // Combinational next-state logic and done signal generation
    always_comb begin
        next_state = current_state;
        done       = 1'b0;

        case (current_state)
            IDLE: begin
                if (start)
                    next_state = COMPUTE;
            end
            COMPUTE: begin
                next_state = COMPUTE_MOD;
            end
            COMPUTE_MOD: begin
                next_state = DONE;
            end
            DONE: begin
                done       = 1'b1;
                next_state = IDLE;
            end
            default: next_state = IDLE;
        endcase
    end

    // Computation and register update logic
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            temp0  <= 7'b0;
            temp1  <= 7'b0;
            temp2  <= 7'b0;
            C0_reg <= 5'b0;
            C1_reg <= 5'b0;
            C2_reg <= 5'b0;
        end
        else begin
            case (current_state)
                COMPUTE: begin
                    // Each multiplication yields a 10-bit result; applying % MOD (10'd26)
                    // gives a value in [0,25]. We then add three such terms.
                    // Slicing the sum to 7 bits avoids any truncation warnings.
                    temp0 <= ((((K00 * P0) % MOD) + ((K01 * P1) % MOD) + ((K02 * P2) % MOD)))[6:0];
                    temp1 <= ((((K10 * P0) % MOD) + ((K11 * P1) % MOD) + ((K12 * P2) % MOD)))[6:0];
                    temp2 <= ((((K20 * P0) % MOD) + ((K21 * P1) % MOD) + ((K22 * P2) % MOD)))[6:0];
                end
                COMPUTE_MOD: begin
                    // Extend the 7-bit intermediate result to 9 bits to safely perform modulo.
                    // The final result (in the range 0-25) is then sliced to 5 bits.
                    C0_reg <= ( {2{1'b0}, temp0} % MOD )[4:0];
                    C1_reg <= ( {2{1'b0}, temp1} % MOD )[4:0];
                    C2_reg <= ( {2{1'b0}, temp2} % MOD )[4:0];
                end
                default: begin
                    temp0  <= 7'b0;
                    temp1  <= 7'b0;
                    temp2  <= 7'b0;
                    C0_reg <= 5'b0;
                    C1_reg <= 5'b0;
                    C2_reg <= 5'b0;
                end
            endcase
        end
    end

    // Combine the three 5-bit ciphertext registers into a 15-bit output.
    assign ciphertext = {C0_reg, C1_reg, C2_reg};

endmodule

output.rtl/hmac_reg_interface.sv:
module hmac_reg_interface #(
    parameter DATA_WIDTH = 8,
    parameter ADDR_WIDTH = 8  
) (
    input  logic                  clk,       
    input  logic                  rst_n,     
    input  logic                  write_en,  
    input  logic                  read_en,   
    input  logic [ADDR_WIDTH-1:0] addr,      
    input  logic [DATA_WIDTH-1:0] wdata,     
    input  logic                  i_wait_en,
    output logic [DATA_WIDTH-1:0] rdata,     
    output logic                  hmac_valid,
    output logic                  hmac_key_error
);

    // Number of registers
    localparam NUM_REGS = 1 << ADDR_WIDTH;
    // Constant for XOR operation: for every 2 bits, XOR with 2'b01.
    localparam [DATA_WIDTH-1:0] XOR = {(DATA_WIDTH/2){2'b01}};

    // FSM States
    typedef enum logic [2:0] {
        IDLE     = 3'b000,
        ANALYZE  = 3'b001,
        XOR_DATA = 3'b010,
        WRITE    = 3'b011,
        LOST     = 3'b100,
        CHECK_KEY= 3'b101,
        TRIG_WAIT= 3'b110
    } state_t;

    state_t current_state, next_state;

    // Registers array
    logic [DATA_WIDTH-1:0] registers [NUM_REGS-1:0];

    // Special HMAC registers
    logic [DATA_WIDTH-1:0] hmac_key;
    logic [DATA_WIDTH-1:0] hmac_data;

    // Intermediate data register to capture and process wdata
    logic [DATA_WIDTH-1:0] data_reg;

    //-------------------------------------------------------------------------
    // Sequential logic: state register update and register operations.
    //-------------------------------------------------------------------------
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            current_state <= IDLE;
            data_reg      <= '0;
            hmac_valid    <= 1'b0;
            hmac_key      <= '0;
            hmac_data     <= '0;
            // Clear all registers
            for (int i = 0; i < NUM_REGS; i++)
                registers[i] <= '0;
        end
        else begin
            // Capture current state value before updating.
            logic old_state;
            old_state = current_state;
            current_state <= next_state;
            case (old_state)
                IDLE: begin
                    // Capture input data when write_en is asserted.
                    if (write_en)
                        data_reg <= wdata;
                end
                ANALYZE: begin
                    // No action needed.
                end
                XOR_DATA: begin
                    // Perform XOR transformation on wdata.
                    data_reg <= wdata ^ XOR;
                end
                WRITE: begin
                    // Write the processed data to registers.
                    // Special handling for HMAC key (addr==0) and data (addr==1).
                    if (addr == 0)
                        hmac_key <= data_reg;
                    else if (addr == 1)
                        hmac_data <= data_reg;
                    else
                        registers[addr] <= data_reg;
                    // Assert hmac_valid during write.
                    hmac_valid <= 1'b1;
                end
                LOST,
                CHECK_KEY,
                TRIG_WAIT: begin
                    // No write operations in these states.
                end
                default: begin
                    // No operation.
                end
            endcase
        end
    end

    //-------------------------------------------------------------------------
    // Combinational logic: Next state determination.
    //-------------------------------------------------------------------------
    always_comb begin
        case (current_state)
            IDLE: begin
                // Transition to ANALYZE if write_en is asserted.
                next_state = (write_en) ? ANALYZE : IDLE;
            end
            ANALYZE: begin
                // If MSB of wdata is 1, go to XOR_DATA; otherwise, go to WRITE.
                next_state = (wdata[DATA_WIDTH-1] == 1) ? XOR_DATA : WRITE;
            end
            XOR_DATA: begin
                next_state = WRITE;
            end
            WRITE: begin
                // If write_en is asserted again, restart (IDLE); else go to LOST.
                next_state = (write_en) ? IDLE : LOST;
            end
            LOST: begin
                // If read_en is asserted, move to CHECK_KEY; otherwise, remain in LOST.
                next_state = (read_en) ? CHECK_KEY : LOST;
            end
            CHECK_KEY: begin
                // Check HMAC key validity: top 2 bits and bottom 2 bits must be 0.
                if ((hmac_key[DATA_WIDTH-1:DATA_WIDTH-2] == 2'b00) &&
                    (hmac_key[1:0] == 2'b00))
                    next_state = TRIG_WAIT;
                else
                    next_state = WRITE;
            end
            TRIG_WAIT: begin
                // Wait for i_wait_en to de-assert.
                if (!i_wait_en) begin
                    // If both hmac_key and hmac_data are non-zero, return to IDLE.
                    if ((hmac_data != 0) && (hmac_key != 0))
                        next_state = IDLE;
                    else
                        next_state = WRITE;
                end
                else
                    next_state = TRIG_WAIT;
            end
            default: begin
                next_state = IDLE;
            end
        endcase
    end

    //-------------------------------------------------------------------------
    // Combinational logic: Read operation.
    //-------------------------------------------------------------------------
    always_comb begin
        // Read is performed only when read_en is asserted and FSM is not in WRITE state.
        if (read_en && (current_state != WRITE)) begin
            if (addr == 0)
                rdata = hmac_key;
            else if (addr == 1)
                rdata = hmac_data;
            else
                rdata = registers[addr];
        end
        else begin
            rdata = '0;
        end
    end

    //-------------------------------------------------------------------------
    // Combinational logic: HMAC Key Error Flag.
    //-------------------------------------------------------------------------
    always_comb begin
        // If the key's top 2 bits and bottom 2 bits are 0, the key is valid.
        if ((hmac_key[DATA_WIDTH-1:DATA_WIDTH-2] == 2'b00) &&
            (hmac_key[1:0] == 2'b00))
            hmac_key_error = 1'b0;
        else
            hmac_key_error = 1'b1;
    end

endmodule

output.rtl/huffman_encoder.sv:
module huffman_encoder(
    input  wire        clk,
    input  wire        reset,
    input  wire        data_valid,
    input  wire [3:0]  data_in,
    input  wire [1:0]  data_priority,
    input  wire        update_enable,
    input  wire [3:0]  config_symbol,
    input  wire [6:0]  config_code,
    input  wire [2:0]  config_length,
    output reg [6:0]   huffman_code_out,
    output reg         code_valid,
    output reg         error_flag
);

// Internal signals for Huffman table and code length
wire [6:0] huffman_code;
wire [2:0] code_length;

// Queue outputs from priority queues
wire [3:0] high_queue_out, medium_queue_out, low_queue_out;

// FSM state declaration
localparam [2:0] IDLE       = 3'd0,
                  PREPARE    = 3'd1,
                  CHECK_UPDATE = 3'd2,
                  ENCODE     = 3'd3,
                  OUTPUT     = 3'd4,
                  UPDATE_TABLE = 3'd5,
                  HANDLE_ERROR = 3'd6;

reg [2:0] state;
reg [2:0] next_state;

// Queue pointer and count registers (each queue assumed to have 16 entries)
reg [3:0] high_ptr, medium_ptr, low_ptr;
reg [3:0] high_count, medium_count, low_count;

// Register to hold the current symbol read from the highest priority queue
reg [3:0] current_symbol;

// Register for Huffman table update address
reg [3:0] table_addr;

// Write enable signals for queue RAMs
wire high_we;
wire medium_we;
wire low_we;
assign high_we   = (state == PREPARE) && data_valid && (data_priority == 2'b10);
assign medium_we = (state == PREPARE) && data_valid && (data_priority == 2'b01);
assign low_we    = (state == PREPARE) && data_valid && (data_priority == 2'b00);

// Write enable signals for Huffman table RAMs during update
wire table_we, length_we;
assign table_we  = (state == UPDATE_TABLE);
assign length_we = (state == UPDATE_TABLE);

// Combinational signals to detect non-empty queues
wire read_from_high;
wire read_from_medium;
wire read_from_low;
assign read_from_high   = (state == OUTPUT) && (high_count > 0);
assign read_from_medium = (state == OUTPUT) && (high_count == 0) && (medium_count > 0);
assign read_from_low    = (state == OUTPUT) && (high_count == 0) && (medium_count == 0) && (low_count > 0);

// FSM state register update and output logic
always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
        state           <= IDLE;
        high_ptr        <= 4'd0;
        medium_ptr      <= 4'd0;
        low_ptr         <= 4'd0;
        high_count      <= 4'd0;
        medium_count    <= 4'd0;
        low_count       <= 4'd0;
        current_symbol  <= 4'd0;
        table_addr      <= 4'd0;
        huffman_code_out<= 7'd0;
        code_valid      <= 1'b0;
        error_flag      <= 1'b0;
    end else begin
        // Update pointers and counts on read events
        if (read_from_high) begin
            high_ptr   <= high_ptr + 1;
            high_count <= high_count - 1;
        end else if (read_from_medium) begin
            medium_ptr <= medium_ptr + 1;
            medium_count <= medium_count - 1;
        end else if (read_from_low) begin
            low_ptr    <= low_ptr + 1;
            low_count  <= low_count - 1;
        end

        // Capture current symbol from the appropriate queue
        if (state == OUTPUT) begin
            if (read_from_high)
                current_symbol <= high_queue_out;
            else if (read_from_medium)
                current_symbol <= medium_queue_out;
            else if (read_from_low)
                current_symbol <= low_queue_out;
        end

        // FSM state transitions
        case (state)
            IDLE: begin
                if (update_enable)
                    state <= CHECK_UPDATE;
                else if (data_valid)
                    state <= PREPARE;
                else
                    state <= IDLE;
            end
            PREPARE: begin
                // Data enqueued into the appropriate queue via RAM write
                state <= OUTPUT;
            end
            OUTPUT: begin
                if (read_from_high || read_from_medium || read_from_low)
                    state <= ENCODE;
                else
                    state <= IDLE;
            end
            ENCODE: begin
                // In ENCODE, use current_symbol to read from Huffman table RAMs
                // The outputs are driven in the next clock cycle
                state <= IDLE;
            end
            CHECK_UPDATE: begin
                // Validate update parameters (assumed valid in this example)
                state <= UPDATE_TABLE;
            end
            UPDATE_TABLE: begin
                // Set update address and write new Huffman code and length
                table_addr <= config_symbol;
                state <= IDLE;
            end
            HANDLE_ERROR: begin
                error_flag <= 1'b1;
                // Remain in error state until reset
            end
            default: state <= IDLE;
        endcase
    end
end

// Instantiate priority queue RAMs for High, Medium, and Low priority
single_port_ram #(
    .DATA_WIDTH(4),
    .ADDR_WIDTH(4)
) high_queue_ram (
    .clk   (clk),
    .we    (high_we),
    .addr  (high_ptr),
    .din   (data_in),
    .dout  (high_queue_out)
);

single_port_ram #(
    .DATA_WIDTH(4),
    .ADDR_WIDTH(4)
) medium_queue_ram (
    .clk   (clk),
    .we    (medium_we),
    .addr  (medium_ptr),
    .din   (data_in),
    .dout  (medium_queue_out)
);

single_port_ram #(
    .DATA_WIDTH(4),
    .ADDR_WIDTH(4)
) low_queue_ram (
    .clk   (clk),
    .we    (low_we),
    .addr  (low_ptr),
    .din   (data_in),
    .dout  (low_queue_out)
);

// Instantiate Huffman Table RAM for storing Huffman codes
single_port_ram #(
    .DATA_WIDTH(7),
    .ADDR_WIDTH(4)
) huffman_table_inst (
    .clk   (clk),
    .we    (table_we),
    .addr  (table_addr),
    .din   (config_code),
    .dout  (huffman_code)
);

// Instantiate RAM for storing Huffman code lengths
single_port_ram #(
    .DATA_WIDTH(3),
    .ADDR_WIDTH(4)
) code_length_inst (
    .clk   (clk),
    .we    (length_we),
    .addr  (table_addr),
    .din   (config_length),
    .dout  (code_length)
);

endmodule

output.rtl/single_port_ram.sv:
module single_port_ram #(
    parameter DATA_WIDTH = 8,
    parameter ADDR_WIDTH = 4
)(
    input  wire clk,
    input  wire we,
    input  wire [ADDR_WIDTH-1:0] addr,
    input  wire [DATA_WIDTH-1:0] din,
    output reg  [DATA_WIDTH-1:0] dout
);

    // Simple memory array implementation for a single-port RAM
    reg [DATA_WIDTH-1:0] mem [0:(1<<ADDR_WIDTH)-1];

    always_ff @(posedge clk) begin
        if (we)
            mem[addr] <= din;
        dout <= mem[addr];
    end

endmodule

