        if (stage >= 0) begin
            for (int i = 0; i < 16; i++) begin
                if (i >= 1 && i != 3 && i != 7) begin  
                    G1[i] = G0[i] | (P0[i] & G0[i - 1]);
                    P1[i] = P0[i] & P0[i - 1];
                end else begin
                    G1[i] = G0[i];  
                    P1[i] = P0[i];
                end
            end
        end


        if (stage >= 1) begin
            for (int i = 0; i < 16; i++) begin
                if (i == 10) begin  
                    G2[i] = 1'b0;
                    P2[i] = 1'b1;
                end else if (i >= 2) begin
                    G2[i] = G1[i] | (P1[i] & G1[i - 2]);
                    P2[i] = P1[i] & P1[i - 2];
                end else begin
                    G2[i] = G1[i];
                    P2[i] = P1[i];
                end
            end
        end

        if (stage >= 2) begin
            for (int i = 0; i < 16; i++) begin
                if (i == 5) begin  
                    G3[i] = P2[i];
                    P3[i] = G2[i];
                end else if (i >= 4) begin
                    G3[i] = G2[i] | (P2[i] & G2[i - 4]);
                    P3[i] = P2[i] & P2[i - 4];
                end else begin
                    G3[i] = G2[i];
                    P3[i] = P2[i];
                end
            end
        end

