              mult_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= matrix_a[((gv1*COL_A)+gv3)*INPUT_DATA_WIDTH+:INPUT_DATA_WIDTH] * matrix_b[((gv3*COL_B)+gv2)*INPUT_DATA_WIDTH+:INPUT_DATA_WIDTH]; 


          always_ff @(posedge clk)
            if (srst)
              add_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= '0; 
            else if (gv3 == 0)
              add_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= mult_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH];
            else
              add_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= mult_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] + add_stage[((((gv1*COL_B)+gv2)*COL_A)+(gv3-1))*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH];
        end


        always_ff @(posedge clk)
          if (srst)
            matrix_c[((gv1*COL_B)+gv2)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= '0; // Reset output matrix element
          else if (valid_out_reg[COL_A])
            matrix_c[((gv1*COL_B)+gv2)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= add_stage[((((gv1*COL_B)+gv2)*COL_A)+(COL_A-1))*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH]; // Set output to the accumulated result
      end
    end

  endgenerate

endmodule

output.rtl/cvdp_copilot_mem_allocator.sv:
module cvdp_copilot_mem_allocator #(
    parameter SIZE  = 4,
    parameter ADDRW = $clog2(SIZE)
) (
    input  wire             clk,
    input  wire             reset,

    input  wire             acquire_en,    
    output wire [ADDRW-1:0] acquire_addr,      

    input  wire             release_en,
    input  wire [ADDRW-1:0] release_addr,    

    output wire             empty,
    output wire             full    
);
    // Register to hold current free slot bitmap
    reg [SIZE-1:0] free_slots, free_slots_n;
    // Registered output for next available address
    reg [ADDRW-1:0] acquire_addr_r;
    // Registered empty and full flags
    reg empty_r, full_r;    

    // Wire from leading zero counter: computes the index of the first free slot
    wire [ADDRW-1:0] free_index;
    // The leading zero counter also provides an "all zeros" flag (not used further)
    wire full_d;

    // Instantiate the leading zero counter.
    // DATA_WIDTH is set to SIZE so that it operates on the free_slots_n bitmap.
    cvdp_leading_zero_cnt #(
        .DATA_WIDTH(SIZE),
        .REVERSE(0)
    ) free_slots_sel (
        .data       (free_slots_n),
        .leading_zeros(free_index),
        .all_zeros  (full_d)
    ); 

    // Sequential process: update free_slots, acquire_addr, empty and full signals
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            // On reset: mark all slots as free, set acquire_addr to 0,
            // and indicate that the pool is empty and not full.
            free_slots     <= {SIZE{1}};
            acquire_addr_r <= 0;
            empty_r        <= 1;
            full_r         <= 0;
        end else begin
            // Default: carry forward the current free_slots
            free_slots_n = free_slots;

            // If an allocation request is asserted, clear the free slot indicated
            // by the current acquire_addr (which reflects the previous cycle's free_index).
            if (acquire_en) begin
                free_slots_n = free_slots_n & ~(1 << acquire_addr_r);
            end

            // If a release request is asserted, mark the corresponding slot as free.
            if (release_en) begin
                free_slots_n = free_slots_n | (1 << release_addr);
            end

            // Register the updated free_slots for the next cycle.
            free_slots <= free_slots_n;

            // Update the acquire_addr output register with the new first available slot.
            // The leading zero counter computes free_index combinationally from free_slots_n.
            acquire_addr_r <= free_index;

            // Update the empty and full flags based on the registered free_slots.
            // The allocator is empty when all bits are 1, and full when no bits are 1.
            empty_r <= (free_slots == {SIZE{1}});
            full_r  <= (free_slots == 0);
        end
    end

    // Drive the output signals.
    assign acquire_addr = acquire_addr_r;
    assign empty        = empty_r;
    assign full         = full_r;

endmodule

input.rtl/signed_sequential_booth_multiplier.s:
module signed_sequential_booth_multiplier #(parameter WIDTH = 8) (
    input  wire signed [WIDTH-1:0] A,
    input  wire signed [WIDTH-1:0] B,
    input  wire clk,
    input  wire rst,
    input  wire start,
    output reg  signed [2*WIDTH-1:0] result,
    output reg done
);

    // FSM states
    typedef enum logic [2:0] {
        IDLE     = 3'b000,
        ENCODE   = 3'b001, 
        PARTIAL  = 3'b010, 
        ADDITION = 3'b011, 
        DONE     = 3'b100
    } state_t;

    state_t state, next_state;

    // Registers for control and data signals
    reg signed [2*WIDTH-1:0] partial_products [0:WIDTH/2-1];
    reg signed [2*WIDTH-1:0] multiplicand;
    reg signed [WIDTH:0] booth_bits; 
    reg signed [2*WIDTH-1:0] accumulator;  
    reg [2:0] encoding_bits [0:WIDTH/2-1];
    reg [$clog2(WIDTH/2):0] addition_counter; // Counter for addition cycles
    integer i;

    // State machine: Sequential process for state transitions
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    // State machine: Combinational process for next-state logic
    always @(*) begin
        case (state)
            IDLE: begin
                if (start) begin
                    next_state = ENCODE;
                end else begin
                    next_state = IDLE;
                end
            end

            ENCODE: begin
                next_state = PARTIAL;
            end

            PARTIAL: begin
                next_state = ADDITION;
            end

            ADDITION: begin
                next_state = DONE;
            end

            DONE: begin
                if (!start) begin
                    next_state = IDLE;
                end else begin
                    next_state = DONE;
                end
            end

            default: begin
                next_state = IDLE;
            end
        endcase
    end

    // Signal assignments: Perform operations based on current state
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            done <= 0;
            result <= 0;
            accumulator <= 0;
            addition_counter <= 0;
            multiplicand <= 0;
            booth_bits <= 0;
            for (i = 0; i < WIDTH/2; i = i + 1) begin
                encoding_bits[i] <= 0;
                partial_products[i] <= 0;
            end
        end else begin
            case (state)
                IDLE: begin
                    // Prepare for new computation
                    done <= 0;
                    result <= 0;
                    if (start) begin
                        multiplicand <= {{(WIDTH){A[WIDTH-1]}}, A}; // Sign-extend A
                        booth_bits <= {B, 1'b0};
                        accumulator <= 0;
                        for (i = 0; i < WIDTH/2; i = i + 1) begin
                            partial_products[i] <= 0;
                        end
                    end
                end

                ENCODE: begin
                    // Extract 3-bit Booth segments
                    for (i = 0; i < WIDTH/2; i = i + 1) begin
                        encoding_bits[i] <= booth_bits[2*i +: 3];
                    end
                end

                PARTIAL: begin
                    // Generate partial products based on Booth encoding
                    for (i = 0; i < WIDTH/2; i = i + 1) begin
                        case (encoding_bits[i])
                            3'b001, 3'b010: partial_products[i] <= (multiplicand << (2 * i));
                            3'b011:         partial_products[i] <= ((multiplicand << 1) << (2 * i));
                            3'b100:         partial_products[i] <= -((multiplicand << 1) << (2 * i));
                            3'b101, 3'b110: partial_products[i] <= -(multiplicand << (2 * i));
                            default:        partial_products[i] <= 0;
                        endcase
                    end
                end

                ADDITION: begin
                    accumulator <= 0;
                    for (i = 0; i < WIDTH/2; i = i + 1) begin
                      accumulator <= accumulator + partial_products[i];  
                    end
                end

                DONE: begin
                    // Output the result
                    result <= accumulator;
                    done <= 1;
                end
            endcase
        end
    end
endmodule

