module mux_synch (
    input  [7:0] data_in,    // asynchronous data input
    input        req,        // indicates that data is available at data_in
    input        dst_clk,    // destination clock (synchronization occurs on this clock)
    input        src_clk,    // source clock (associated with data_in)
    input        nrst,       // asynchronous active-low reset
    output reg [7:0] data_out // synchronized version of data_in in the destination clock domain
);

    // Synchronize the req signal using a two-flop synchronizer (nff)
    wire req_sync;
    nff req_sync_inst (
        .d_in  (req),
        .dst_clk(dst_clk),
        .rst   (nrst),
        .syncd (req_sync)
    );

    // Pipeline registers for data synchronization (3 stages)
    reg [7:0] data_sync0, data_sync1, data_sync2;

    always @(posedge dst_clk or negedge nrst) begin
        if (!nrst) begin
            data_sync0 <= 8'b0;
            data_sync1 <= 8'b0;
            data_sync2 <= 8'b0;
            data_out   <= 8'b0;
        end else begin
            if (req_sync) begin
                // Capture the asynchronous data_in into the pipeline
                data_sync0 <= data_in;
                data_sync1 <= data_sync0;
                data_sync2 <= data_sync1;
            end
            // Otherwise, hold the previously synchronized value
            data_out <= data_sync2;
        end
    end

endmodule

module nff  (
    input  d_in,    // input data that needs to be synchronized to the dst_clk domain
    input  dst_clk, // destination domain clock
    input  rst,     // asynchronous active-low reset
    output reg syncd // synchronized output (2-clock-cycle delayed version of d_in)
);

    reg sync_reg0, sync_reg1;

    always @(posedge dst_clk or negedge rst) begin
        if (!rst) begin
            sync_reg0 <= 1'b0;
            sync_reg1 <= 1'b0;
            syncd     <= 1'b0;
        end else begin
            sync_reg0 <= d_in;
            sync_reg1 <= sync_reg0;
            syncd     <= sync_reg1;
        end
    end

endmodule

module mux_synch (

    input [7:0] data_in,   			//asynchronous data input
    input req,                  		//indicating that data is available at the data_in input
    input dst_clk,                 		//destination clock
    input src_clk,                 		//source clock
    input nrst,                    		//asynchronous reset 
    output reg [7:0] data_out,              //synchronized version of data_in to the destination clock domain
    output ack_out 
);

    wire syncd_req, anded_req, syncd_ack;
    reg syncd_req_1, ack;

    // 2-flop synchronizer for the request signal
    nff req_synch_0 (.d_in(req), .dst_clk(dst_clk), .rst(nrst), .syncd(syncd_req));

    // One clock cycle delay to detect a positive edge
    always_ff @(posedge dst_clk)
    begin
        syncd_req_1 <= syncd_req;
    end

    // Edge detector: high when syncd_req transitions from 0 to 1
    assign anded_req = (!syncd_req_1 && syncd_req);

    // Data capture: latch data_in into data_out when a valid request is detected
    always_ff @(posedge dst_clk or negedge nrst)
    begin
        if (!nrst)
            data_out <= 1'b0;                // force output to zero on reset
        else if (anded_req == 1'b1)
            data_out <= data_in;             // latch data_in to data_out
        else
            data_out <= data_out;            // hold the data until next request
    end

    // Acknowledgment signal generation with pulse stretching in the destination domain.
    // This ensures that the ack pulse is held for two clock cycles so that it is more likely
    // to be captured by the two-flop synchronizer when crossing to the source clock domain.
    always_ff @(posedge dst_clk or negedge nrst)
    begin
        if (!nrst)
            ack <= 1'b0;
        else if (anded_req)
            ack <= 1'b1;
        else if (ack)  // Stretch the ack pulse for an extra clock cycle
            ack <= 1'b1;
        else
            ack <= 1'b0;
    end

    // Synchronize the ack signal back to the source clock domain using a two-flop synchronizer.
    nff enable_synch_1 (.d_in(ack), .dst_clk(src_clk), .rst(nrst), .syncd(syncd_ack));

    // Output the synchronized acknowledgment signal.
    assign ack_out = syncd_ack;

endmodule

// Two-flop synchronizer module
module nff (
    input d_in,   									// input data to be synchronized
    input dst_clk,     								// destination clock
    input rst,         								// asynchronous active-low reset
    output reg syncd 								// synchronized output (2-clock-cycle delayed version of d_in)
);

    reg dmeta;             								// intermediate register

    always @(posedge dst_clk or negedge rst)
    begin
        if (!rst)              								// active-low asynchronous reset
        begin
            syncd <= 1'b0;
            dmeta <= 1'b0;
        end
        else
        begin
            dmeta <= d_in;      								// pass input to intermediate register
            syncd <= dmeta;     								// pass intermediate value to output register
        end
    end

endmodule

output.rtl/nbit_swizzling.sv:
module nbit_swizzling #(
  parameter DATA_WIDTH = 64
)(
  input  logic [DATA_WIDTH-1:0] data_in,
  input  logic [1:0]            sel,
  output logic [DATA_WIDTH-1:0] data_out
);

  always_comb begin
    case (sel)
      2'b00: begin
        // Reverse the entire input.
        for (int i = 0; i < DATA_WIDTH; i++) begin
          data_out[i] = data_in[DATA_WIDTH-1-i];
        end
      end
      2'b01: begin
        // Divide into two equal halves and reverse each half.
        int half = DATA_WIDTH / 2;
        for (int j = 0; j < 2; j++) begin
          // For the first half, the MSB of that segment is at DATA_WIDTH-1.
          // For the second half, the MSB is at half-1.
          for (int i = 0; i < half; i++) begin
            data_out[j*half + i] = data_in[(j==0 ? DATA_WIDTH-1 : half-1) - i];
          end
        end
      end
      2'b10: begin
        // Divide into four equal quarters and reverse each quarter.
        int quarter = DATA_WIDTH / 4;
        for (int j = 0; j < 4; j++) begin
          for (int i = 0; i < quarter; i++) begin
            data_out[j*quarter + i] = data_in[DATA_WIDTH - 1 - j*quarter - i];
          end
        end
      end
      2'b11: begin
        // Divide into eight equal eighths and reverse each eighth.
        int eighth = DATA_WIDTH / 8;
        for (int j = 0; j < 8; j++) begin
          for (int i = 0; i < eighth; i++) begin
            data_out[j*eighth + i] = data_in[DATA_WIDTH - 1 - j*eighth - i];
          end
        end
      end
      default: begin
        // In the default case, pass the input directly.
        data_out = data_in;
      end
    endcase
  end

endmodule

input.rtl/nbit_swizzling.sv:
module nbit_swizzling #(parameter DATA_WIDTH = 64)(
    input [DATA_WIDTH-1:0] data_in,                                         // Input data of size DATA_WIDTH 
    input [1:0] sel,                	                                    //  2-bit selection signal 
    output reg [DATA_WIDTH-1:0] data_out                                    // Output data of size DATA_WIDTH 
);

integer i; 

always @(*) begin
    case(sel)
        2'b00: begin
            for (i = 0; i < DATA_WIDTH; i = i + 1) begin
                data_out[i] = data_in[DATA_WIDTH-1-i];                      
            end
        end

        2'b01: begin
            for (i = 0; i < DATA_WIDTH/2; i = i + 1) begin
