module gate_target(
   input  logic        [1:0] gate_select,
   output logic signed [3:0] o_1,
   output logic signed [3:0] o_2,
   output logic signed [3:0] o_3,
   output logic signed [3:0] o_4
);
   always_comb begin
     case(gate_select)
          2'b00 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
          2'b01 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b10 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b11 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
        default : begin
                    o_1 =  0; 
                    o_2 =  0; 
                    o_3 =  0; 
                    o_4 =  0; 
                  end
        endcase
   end
endmodule

