output.rtl/pipeline_mac.sv:
module pipeline_mac #(
    parameter DWIDTH = 16,  // Bit width for multiplicand and multiplier
    parameter N      = 4    // Number of data points to accumulate over
) (
    clk,
    rstn,
    multiplicand,
    multiplier,
    valid_i,
    result,
    valid_out
);

  // ----------------------------------------
  // - Local parameter definition
  // ----------------------------------------
  // Calculate accumulator width to safely hold the sum of N products.
  // Each multiplication produces a 2*DWIDTH result.
  // Accumulating N such products requires an extra log2(N) bits.
  localparam DWIDTH_ACCUMULATOR = 2*DWIDTH + $clog2(N);

  // ----------------------------------------
  // - Interface Definitions
  // ----------------------------------------
  input  logic                        clk;                                // Clock signal
  input  logic                        rstn;                               // Active low reset signal
  input  logic [DWIDTH-1:0]           multiplicand;                       // Input multiplicand
  input  logic [DWIDTH-1:0]           multiplier;                         // Input multiplier
  input  logic                        valid_i;                            // Input valid signal
  output logic [DWIDTH_ACCUMULATOR-1:0] result;                             // Accumulated result output
  output logic                        valid_out;                          // Output valid signal

  // ----------------------------------------
  // - Internal signals
  // ----------------------------------------
  logic [DWIDTH_ACCUMULATOR-1:0] mult_result_reg;    // Register to store intermediate multiplication result
  logic [DWIDTH_ACCUMULATOR-1:0] accumulation_reg;   // Register to store accumulated result
  logic [$clog2(N):0]          counter;               // Combinational counter (derived from counter_reg)
  logic [$clog2(N):0]          counter_reg;           // Register to hold the counter value
  logic                       count_rst, accumulator_rst;  // Reset signals for counter and accumulator
  logic                       valid_out_s0, valid_out_s1, valid_out_s2; // Intermediate valid output signals

  // ----------------------------------------
  // - Combinational Assignments
  // ----------------------------------------
  // The counter is updated only on valid input, except when a reset (count_rst) is asserted.
  assign counter = count_rst ? 'b1 : (valid_i & rstn ? (counter_reg + 'd1) : counter_reg);
  assign valid_out_s0 = (counter_reg == N-1);    // Assert when N valid inputs have been processed
  assign count_rst    = valid_out_s1;              // Reset counter after output is generated
  assign accumulator_rst = valid_out_s1;            // Reset accumulator after output is generated
  assign result       = accumulation_reg;          // Drive the final accumulated result
  assign valid_out    = valid_out_s1 & ~valid_out_s2; // Pulse valid_out on the rising edge of valid_out_s1

  // ----------------------------------------
  // - Procedural Blocks
  // ----------------------------------------

  // Stage 1 of the pipeline: Perform multiplication
  always @(posedge clk or negedge rstn) begin
     if (!rstn) begin
        mult_result_reg <= '0;
     end
     else if (valid_i) begin
        mult_result_reg <= multiplicand * multiplier;
     end
     else begin
        // Hold the previous multiplication result if valid_i is low
        mult_result_reg <= mult_result_reg;
     end
  end

  // Stage 2 of the pipeline: Accumulation logic
  always @(posedge clk or negedge rstn) begin
     if (!rstn) begin
        accumulation_reg <= '0;
     end
     else if (accumulator_rst) begin
        // Clear the accumulator after output is generated
        accumulation_reg <= '0;
     end
     else if (valid_i) begin
        accumulation_reg <= accumulation_reg + mult_result_reg;
     end
     else begin
        // Hold the current accumulated value if valid_i is low
        accumulation_reg <= accumulation_reg;
     end
  end

  // N-bit counter to track the number of accumulations
  always @(posedge clk or negedge rstn) begin
     if (!rstn) begin
        counter_reg <= '0;
     end
     else if (count_rst) begin
        counter_reg <= '0;
     end
     else if (valid_i) begin
        counter_reg <= counter_reg + 1;
     end
     else begin
        counter_reg <= counter_reg;
     end
  end

  // Register valid output for 2-stage pipeline
  always @(posedge clk or negedge rstn) begin
     if (!rstn) begin
        valid_out_s1 <= 0;
        valid_out_s2 <= 0;
     end
     else begin
        // Delay valid_out_s1 by one cycle to detect its rising edge
        valid_out_s2 <= valid_out_s1;
        if (valid_out_s0)
            valid_out_s1 <= 1;
        else
            valid_out_s1 <= 0;
     end
  end

endmodule

output.rtl/piso_8bit.sv:
Module: piso_8bit
// Description: This module generates 8-bit data continuously in an incremental manner 
// through a Parallel In Serial Out (PISO) shift register. The data is shifted out in 
// MSB-to-LSB order so that, for example, when the internal register holds 8'b0000_0001, 
// the first clock cycle outputs 0 (MSB) and the eighth outputs 1 (LSB). After every 8 
// clock cycles, the internal 8-bit register (data_reg) is incremented by 1 (wrapping 
// from 1111_1111 to 0000_0000). The shifting process is controlled by a clock and an 
// asynchronous active LOW reset. During reset, the serial_out is forced to logic LOW.

module piso_8bit (
  input  logic clk,       // Clock signal (50:50 duty cycle)
  input  logic rst,       // Asynchronous active LOW reset
  output logic serial_out // Serial output data
);

  // Internal registers
  reg [7:0] data_reg;   // Holds the current 8-bit value to be shifted out
  reg [7:0] shift_reg;  // Shift register for serial output
  reg [2:0] bit_count;  // Counter to track the number of bits shifted out

  always_ff @(posedge clk or negedge rst) begin
    if (!rst) begin
      // Asynchronous reset: initialize registers and force serial_out low
      data_reg   <= 8'b0000_0001;
      shift_reg  <= 8'b0000_0000;
      bit_count  <= 3'b000;
      serial_out <= 1'b0;
    end else begin
      if (bit_count == 3'b000) begin
        // Start of a new 8-bit period: load the shift register with the current value
        shift_reg <= data_reg;
        // Increment data_reg for the next cycle (wraps from 1111_1111 to 0000_0000)
        data_reg  <= data_reg + 1;
      end

      // Shift out the MSB of shift_reg on each clock cycle
      serial_out <= shift_reg[7];
      shift_reg  <= shift_reg >> 1;
      bit_count  <= bit_count + 1;
    end
  end

endmodule

output.rtl/pkt_detector.sv:
module pkt_detector #(
    parameter PKT_CNT_WIDTH = 4
) (
    input  logic                       reset,
    input  logic                       clk,
    input  logic [7:0]                 data_in,
    input  logic                       data_k_flag,
    output logic [PKT_CNT_WIDTH - 1:0] pkt_count,
    output logic [159:0]               pkt_data,
    output logic                       mem_read_detected,
    output logic                       mem_write_detected,
    output logic                       io_read_detected,
    output logic                       io_write_detected,
    output logic                       cfg_read0_detected,
    output logic                       cfg_write0_detected,
    output logic                       cfg_read1_detected,
    output logic                       cfg_write1_detected,
    output logic                       completion_detected,
    output logic                       completion_data_detected,
    output logic                       error_detected
);

    // Define control symbols and packet size
    localparam [7:0] START_SYMBOL = 8'hFB;
    localparam [7:0] END_SYMBOL   = 8'hFD;
    localparam       PKT_BYTES    = 20;

    // State machine states
    typedef enum logic [1:0] {
        S_IDLE     = 2'b00,
        S_ACTIVE   = 2'b01,
        S_WAIT_END = 2'b10,
        S_ERROR    = 2'b11
    } state_t;

    state_t curr_state, nxt_state;

    // Internal registers
    logic [7:0]    byte_cnt;
    logic [159:0]  pkt_reg;

    // --------------------------------------------------------------------
    // State Register: synchronous update with asynchronous reset
    // --------------------------------------------------------------------
    always_ff @(posedge clk or negedge reset) begin
        if (!reset)
            curr_state <= S_IDLE;
        else
            curr_state <= nxt_state;
    end

    // --------------------------------------------------------------------
    // Next State Logic: Determines next state based on current state and
    // input conditions.
    // --------------------------------------------------------------------
    always_comb begin
        case (curr_state)
            S_IDLE: 
                if ((data_in == START_SYMBOL) && (data_k_flag == 1'b1))
                    nxt_state = S_ACTIVE;
                else
                    nxt_state = S_IDLE;

            S_ACTIVE: 
                if (byte_cnt == PKT_BYTES)
                    nxt_state = S_WAIT_END;
                else
                    nxt_state = S_ACTIVE;

            S_WAIT_END: 
                if (pkt_reg[159:152] == END_SYMBOL)
                    nxt_state = S_IDLE;
                else
                    nxt_state = S_ERROR;

            S_ERROR: 
                if ((data_in == START_SYMBOL) && (data_k_flag == 1'b1))
                    nxt_state = S_ACTIVE;
                else
                    nxt_state = S_ERROR;

            default: nxt_state = S_IDLE;
        endcase
    end

    // --------------------------------------------------------------------
    // Sequential Logic: Update internal registers, accumulate packet data,
    // validate the packet, update outputs, and handle error conditions.
    // --------------------------------------------------------------------
    always_ff @(posedge clk or negedge reset) begin
        if (!reset) begin
            byte_cnt           <= 8'd0;
            pkt_reg            <= 160'd0;
            pkt_count          <= {PKT_CNT_WIDTH{1'b0}};
            pkt_data           <= 160'd0;
            mem_read_detected  <= 1'b0;
            mem_write_detected <= 1'b0;
            io_read_detected   <= 1'b0;
            io_write_detected  <= 1'b0;
            cfg_read0_detected <= 1'b0;
            cfg_write0_detected<= 1'b0;
            cfg_read1_detected <= 1'b0;
            cfg_write1_detected<= 1'b0;
            completion_detected<= 1'b0;
            completion_data_detected<= 1'b0;
            error_detected     <= 1'b0;
        end
        else begin
            case (curr_state)
                S_IDLE: begin
                    // On detecting a valid start symbol, clear error flag and
                    // initialize the packet registers.
                    if ((data_in == START_SYMBOL) && (data_k_flag == 1'b1)) begin
                        byte_cnt           <= 8'd0;
                        pkt_reg            <= 160'd0;
                        error_detected     <= 1'b0;
                    end
                end

                S_ACTIVE: begin
                    // Accumulate packet data into the shift register.
                    // The first byte accumulated is treated as the packet header.
                    if (byte_cnt < PKT_BYTES) begin
                        pkt_reg <= {pkt_reg[151:0], data_in};
                        byte_cnt <= byte_cnt + 1;
                    end
                end

                S_WAIT_END: begin
                    // Validate the packet by checking the END_SYMBOL in the last byte.
                    if (pkt_reg[159:152] == END_SYMBOL) begin
                        // Valid packet: update packet counter and data output.
                        pkt_count  <= pkt_count + 1;
                        pkt_data   <= pkt_reg;
                        // Decode the header (first byte of the packet) to set detection flags.
                        case (pkt_reg[31:24])
                            8'h01: mem_read_detected   <= 1'b1;
                            8'h02: mem_write_detected  <= 1'b1;
                            8'h03: io_read_detected    <= 1'b1;
                            8'h04: io_write_detected   <= 1'b1;
                            8'h05: cfg_read0_detected  <= 1'b1;
                            8'h06: cfg_write0_detected <= 1'b1;
                            8'h07: cfg_read1_detected  <= 1'b1;
                            8'h08: cfg_write1_detected <= 1'b1;
                            8'h09: completion_detected <= 1'b1;
                            8'h0A: completion_data_detected <= 1'b1;
                            default: ; // No flag set for other header values.
                        endcase
                    end
                    else begin
                        // Invalid packet: assert error flag.
                        error_detected <= 1'b1;
                    end
                end

                S_ERROR: begin
                    // In error state, keep the error flag asserted and clear the
                    // packet registers to allow recovery.
                    error_detected     <= 1'b1;
                    byte_cnt           <= 8'd0;
                    pkt_reg            <= 160'd0;
                    // Clear detection flags.
                    mem_read_detected   <= 1'b0;
                    mem_write_detected  <= 1'b0;
                    io_read_detected    <= 1'b0;
                    io_write_detected   <= 1'b0;
                    cfg_read0_detected  <= 1'b0;
                    cfg_write0_detected <= 1'b0;
                    cfg_read1_detected  <= 1'b0;
                    cfg_write1_detected <= 1'b0;
                    completion_detected <= 1'b0;
                    completion_data_detected <= 1'b0;
                end

                default: begin
                    // No operation for undefined states.
                end
            endcase
        end
    end

endmodule

output.rtl/cvdp_prbs_gen.sv:
module cvdp_prbs_gen #(
    parameter int CHECK_MODE   = 0,  // 0 = Generator Mode, 1 = Checker Mode
    parameter int POLY_LENGTH  = 31, // Length of the LFSR (number of stages)
    parameter int POLY_TAP     = 3,  // Tap position (1-indexed; must be <= POLY_LENGTH)
    parameter int WIDTH        = 16  // Data bus width
)(
    input  logic         clk,
    input  logic         rst,           // Active high synchronous reset
    input  logic [WIDTH-1:0] data_in,    // In generator mode, expected to be all zeros
    output logic [WIDTH-1:0] data_out    // In generator mode: PRBS pattern; in checker mode: error flags
);

    // Internal LFSR register (width = POLY_LENGTH)
    logic [POLY_LENGTH-1:0] prbs_reg;

    // Synchronous process: LFSR update and output generation
    always_ff @(posedge clk or posedge rst) begin
        if (rst) begin
            // On reset: initialize PRBS register to all ones and set data_out to all ones
            prbs_reg <= {POLY_LENGTH{1'b1}};
            data_out <= {WIDTH{1'b1}};
        end else begin
            // Compute feedback bit:
            // Note: Using 1-indexed positions: bit at POLY_TAP is prbs_reg[POLY_TAP-1]
            // and the MSB is prbs_reg[POLY_LENGTH-1].
            logic fb;
            fb = prbs_reg[POLY_TAP-1] ^ prbs_reg[POLY_LENGTH-1];

            // Update LFSR: shift right and insert feedback bit at MSB
            prbs_reg <= {fb, prbs_reg[POLY_LENGTH-1:1]};

            // Mode-dependent output assignment
            if (CHECK_MODE == 0) begin
                // Generator Mode: Output the generated PRBS pattern (lower WIDTH bits of LFSR)
                data_out <= prbs_reg[WIDTH-1:0];
            end else begin
                // Checker Mode: Compare input data with the generated PRBS pattern.
                // The XOR result will be non-zero if there is any bit mismatch.
                data_out <= data_in ^ prbs_reg[WIDTH-1:0];
            end
        end
    end

endmodule

