module prim_max_find #(
  parameter int NumSrc = 8,
  parameter int Width = 8,
  // Derived parameters
  localparam int SrcWidth = $clog2(NumSrc),
  localparam int NumLevels = $clog2(NumSrc) - 1,
  localparam int NumNodes = 2**(NumLevels+1)
) (
  input                         clk_i,
  input                         rst_ni,
  input [Width*NumSrc-1:0]      values_i,    // Flattened Input values
  input [NumSrc-1:0]            valid_i,     // Input valid bits
  output wire [Width-1:0]       max_value_o, // Maximum value
  output wire [SrcWidth-1:0]    max_idx_o,   // Index of the maximum value
  output wire                   max_valid_o  // Whether any of the inputs is valid
);

  reg [NumNodes-1:0]                vld_tree [0:NumLevels];
  reg [SrcWidth-1:0]                 idx_tree [0:NumLevels][NumNodes-1:0];
  reg [Width-1:0]                    max_tree [0:NumLevels][NumNodes-1:0];

  generate
    for (genvar level = 0; level <= NumLevels; level++) begin : gen_tree
      localparam int Base0 = (2**level);
      localparam int Base1 = (2**(level+1));

      for (genvar offset = 0; offset < 2**level; offset++) begin : gen_level
        localparam int Pa = Base0 + offset;
        localparam int C0 = Base1 + 2*offset;
        localparam int C1 = Base1 + 2*offset + 1;

        if (level == NumLevels) begin : gen_leafs
          if (offset < NumSrc) begin : gen_assign
            always @(posedge clk_i or negedge rst_ni) begin
              if (!rst_ni) begin
                vld_tree[level][Pa] <= 1'b0;
                idx_tree[level][Pa] <= '0;
                max_tree[level][Pa] <= '0;
              end else begin
                vld_tree[level][Pa] <= valid_i[offset];
                idx_tree[level][Pa] <= offset;
                max_tree[level][Pa] <= values_i[(offset+1)*Width : offset*Width];
              end
            end
          end else begin : gen_tie_off
            always @(posedge clk_i or negedge rst_ni) begin
              if (!rst_ni) begin
                vld_tree[level][Pa] <= 1'b0;
                idx_tree[level][Pa] <= '0;
                max_tree[level][Pa] <= '0;
              end
            end
          end
        end

        else begin : gen_nodes
          reg sel; 
          always @(posedge clk_i or negedge rst_ni) begin
            if (!rst_ni) begin
              vld_tree[level][Pa] <= 1'b0;
              idx_tree[level][Pa] <= '0;
              max_tree[level][Pa] <= '0;
            end else begin
              sel = (~vld_tree[level+1][C0] & vld_tree[level+1][C1]) |
                    (vld_tree[level+1][C0] & vld_tree[level+1][C1] & (max_tree[level+1][C1] > max_tree[level+1][C0]));

              vld_tree[level][Pa] <= (sel) ? vld_tree[level+1][C1] : vld_tree[level+1][C0];
              idx_tree[level][Pa] <= (sel) ? idx_tree[level+1][C1] : idx_tree[level+1][C0];
              max_tree[level][Pa] <= (sel) ? max_tree[level+1][C1] : max_tree[level+1][C0];
            end
          end
        end
      end : gen_level
    end : gen_tree
  endgenerate

  assign max_valid_o = vld_tree[0][0];
  assign max_idx_o   = idx_tree[0][0];
  assign max_value_o = max_tree[0][0];

endmodule

output.rtl/prim_max_find.sv:
module prim_max_find #(
  parameter int NumSrc = 8,
  parameter int Width = 8,
  // Derived parameters: use "Levels" to denote the total number of levels (0 = root, Levels-1 = leaves)
  localparam int SrcWidth = $clog2(NumSrc),
  localparam int Levels   = $clog2(NumSrc),
  // Total nodes in a complete binary tree with "Levels" levels is 2**Levels - 1
  localparam int NumNodes = 2**Levels - 1
) (
  input                         clk_i,
  input                         rst_ni,
  input [Width*NumSrc-1:0]      values_i,    // Flattened input values: each source occupies [offset*Width +: Width]
  input [NumSrc-1:0]            valid_i,     // Validity bits for each source
  output wire [Width-1:0]       max_value_o, // Maximum value among valid inputs
  output wire [SrcWidth-1:0]    max_idx_o,   // Index of the maximum value
  output wire                   max_valid_o  // Indicates if any input is valid
);

  // Tree arrays: each level is indexed from 0 to (2**level - 1)
  reg [NumNodes-1:0]                vld_tree [0:Levels];
  reg [SrcWidth-1:0]                 idx_tree [0:Levels][NumNodes-1:0];
  reg [Width-1:0]                    max_tree [0:Levels][NumNodes-1:0];

  generate
    // Loop over levels: level 0 is the root; level Levels-1 are the leaves.
    for (genvar level = 0; level < Levels; level++) begin : gen_tree
      // Correct the base addresses for a binary heap-style indexing:
      // For level L, valid indices run from (2**L - 1) to (2**(L+1) - 2)
      localparam int Base0 = (2**level - 1);
      localparam int Base1 = (2**(level+1) - 1);

      // For each node at this level, there are 2**level nodes.
      for (genvar offset = 0; offset < 2**level; offset++) begin : gen_level
        localparam int Pa = Base0 + offset;
        // Children of node Pa are located at indices:
        localparam int C0 = Base1 + 2*offset;
        localparam int C1 = Base1 + 2*offset + 1;

        if (level == Levels - 1) begin : gen_leafs
          if (offset < NumSrc) begin : gen_assign
            always @(posedge clk_i or negedge rst_ni) begin
              if (!rst_ni) begin
                vld_tree[level][Pa] <= 1'b0;
                idx_tree[level][Pa] <= '0;
                max_tree[level][Pa] <= '0;
              end else begin
                // Extract the correct slice for the i-th source.
                vld_tree[level][Pa] <= valid_i[offset];
                idx_tree[level][Pa] <= offset;
                max_tree[level][Pa] <= values_i[offset*Width +: Width];
              end
            end
          end else begin : gen_tie_off
            always @(posedge clk_i or negedge rst_ni) begin
              if (!rst_ni) begin
                vld_tree[level][Pa] <= 1'b0;
                idx_tree[level][Pa] <= '0;
                max_tree[level][Pa] <= '0;
              end
            end
          end
        end else begin : gen_nodes
          reg sel;
          always @(posedge clk_i or negedge rst_ni) begin
            if (!rst_ni) begin
              vld_tree[level][Pa] <= 1'b0;
              idx_tree[level][Pa] <= '0;
              max_tree[level][Pa] <= '0;
            end else begin
              // Select the child with the valid (and, if both valid, the greater) value.
              sel = (~vld_tree[level+1][C0] & vld_tree[level+1][C1]) |
                    (vld_tree[level+1][C0] & vld_tree[level+1][C1] & (max_tree[level+1][C1] > max_tree[level+1][C0]));

              vld_tree[level][Pa] <= (sel) ? vld_tree[level+1][C1] : vld_tree[level+1][C0];
              idx_tree[level][Pa] <= (sel) ? idx_tree[level+1][C1] : idx_tree[level+1][C0];
              max_tree[level][Pa] <= (sel) ? max_tree[level+1][C1] : max_tree[level+1][C0];
            end
          end
        end
      end : gen_level
    end : gen_tree
  endgenerate

  // The final maximum is obtained from the root (level 0, index 0)
  assign max_valid_o = vld_tree[0][0];
  assign max_idx_o   = idx_tree[0][0];
  assign max_value_o = max_tree[0][0];

endmodule

input.rtl/radix2_div.sv:
module radix2_div(
    input            clk,
    input            rst_n,
    input            start,
    input      [7:0] dividend,
    input      [7:0] divisor,
    output reg [7:0] quotient,
    output reg [7:0] remainder,
    output reg       done
);

    reg [7:0] rem;
    reg [3:0] bit_counter;
    reg [7:0] divisor_reg;
    reg       busy;

    // Normal, correct shift and compare logic
    wire [8:0] shifted_rem = {rem, dividend[bit_counter]};
    wire       bit_set     = shifted_rem >= {1'b0, divisor_reg};
    wire [8:0] next_rem    = bit_set ? (shifted_rem - {1'b0, divisor_reg}) : shifted_rem;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            quotient <= 8'd0;
        else if (start && !busy) begin
            if (divisor == 8'd0)
                quotient <= 8'hFF;
            else
                quotient <= 8'd0;
        end
        else if (busy) begin
            quotient[bit_counter] <= bit_set;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            rem <= 8'd0;
        else if (start && !busy)
            rem <= 8'd0;
        else if (busy)
            rem <= next_rem[7:0];
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            remainder <= 8'd0;
        else if (start && !busy && divisor == 8'd0)
            remainder <= 8'hFF;
        else if (busy && bit_counter == 4'd0) begin
            if (next_rem[7:0] != 8'd0)
                remainder <= next_rem[7:0] + 1'b1;
            else
                remainder <= next_rem[7:0];
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            bit_counter <= 4'd0;
        else if (start && !busy) begin
            if (divisor != 8'd0)
                bit_counter <= 4'd7;  // Start from MSB
        end
        else if (busy && bit_counter != 4'd0) begin
            bit_counter <= bit_counter - 4'd1; // Normal decrement
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            divisor_reg <= 8'd0;
        else if (start && !busy && divisor != 8'd0)
            divisor_reg <= divisor;
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            done <= 1'b0;
        else if (start && !busy) begin
            if (divisor == 8'd0)
                done <= 1'b1;
            else
                done <= 1'b0;
        end
        else if (busy && bit_counter == 4'd0)
            done <= 1'b1;
        else
            done <= 1'b0;
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            busy <= 1'b0;
        else if (start && !busy) begin
            if (divisor != 8'd0)
                busy <= 1'b1;
            else
                busy <= 1'b0;
        end
        else if (busy && bit_counter == 4'd0)
            busy <= 1'b0;
    end

endmodule

