module inter_block #(
    parameter ROW_COL_WIDTH = 16,
    parameter SUB_BLOCKS    = 4,
    parameter DATA_WIDTH    = ROW_COL_WIDTH*ROW_COL_WIDTH
)(
    input  logic clk,
    input  logic rst_n,
    input  logic i_valid,
    input  logic [DATA_WIDTH-1:0] in_data, // Input: 256 bits
    output logic [DATA_WIDTH-1:0] out_data // Output: 256 bits rearranged
);

    // Removed unused counter_output and its related parameter NBW_COUNTER_OUTPUT

    localparam CHUNK = 8;
    localparam NBW_COUNTER = $clog2(SUB_BLOCKS) + 1;
    localparam NBW_COUNTER_SUB_OUT = 2;
    localparam OUT_CYCLES = 32;

    logic [NBW_COUNTER-1:0] counter_sub_blocks;
    logic [NBW_COUNTER_SUB_OUT-1:0] counter_sub_out;

    logic [DATA_WIDTH-1:0] in_data_reg [SUB_BLOCKS-1:0];
    logic [DATA_WIDTH-1:0] out_data_intra_block [SUB_BLOCKS-1:0];
    logic [DATA_WIDTH-1:0] out_data_intra_block_reg [SUB_BLOCKS-1:0];
    logic [DATA_WIDTH-1:0] out_data_aux [SUB_BLOCKS-1:0];
    logic start_intra;

    // Latch input data and manage sub-block counter
    always_ff @(posedge clk or negedge rst_n) begin
       if (!rst_n) begin
          counter_sub_blocks <= {NBW_COUNTER{1'b0}};
          start_intra        <= 0;
          for (int i = 0; i < SUB_BLOCKS; i++) begin
             in_data_reg[i] <= {DATA_WIDTH{1'b0}};
          end
       end
       else begin
          if (i_valid) begin
             in_data_reg[counter_sub_blocks] <= in_data;

             if (counter_sub_blocks == SUB_BLOCKS) begin
                counter_sub_blocks <= {NBW_COUNTER{1'b0}};
             end
             else begin
                start_intra <= 0;
                counter_sub_blocks <= counter_sub_blocks + 1;
             end
          end
          else if (counter_sub_blocks == SUB_BLOCKS) begin
             start_intra        <= 1;
             counter_sub_blocks <= {NBW_COUNTER{1'b0}};
          end
       end
    end

    // Instantiate intra_block modules (excluded from review)
    genvar k;
    generate 
       for (k = 0; k < SUB_BLOCKS; k++) begin
          intra_block uu_intra_block (
             .in_data(in_data_reg[k]),
             .out_data(out_data_intra_block[k])
          );
       end
    endgenerate

    // Capture intra_block outputs
    always_ff @(posedge clk or negedge rst_n) begin
       if (!rst_n) begin
          for (int i = 0; i < SUB_BLOCKS; i++) begin
             out_data_intra_block_reg[i] <= {DATA_WIDTH{1'b0}};
          end
       end
       else begin
          if (start_intra) begin
             for (int i = 0; i < SUB_BLOCKS; i++) begin
                out_data_intra_block_reg[i] <= out_data_intra_block[i];
             end
          end
       end
    end

    // Rearrange data and output; note the change from blocking (=) to non-blocking (<=) assignments
    always_ff @(posedge clk or negedge rst_n) begin
       if (!rst_n) begin
          counter_sub_out <= {NBW_COUNTER_SUB_OUT{1'b1}};
          out_data        <= {DATA_WIDTH{1'b0}};
          for (int i = 0; i < SUB_BLOCKS; i++) begin
             out_data_aux[i] <= {DATA_WIDTH{1'b0}};
          end      
       end
       else begin
          if (start_intra) begin
             for (int i = 0; i < 32; i++) begin
                out_data_aux[0][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][((i+1)*CHUNK)-1-:CHUNK];
                out_data_aux[1][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][(((i+1)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
                out_data_aux[2][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][(((i+2)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
                out_data_aux[3][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][(((i+3)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
             end
             counter_sub_out <= counter_sub_out + 1;
             out_data        <= out_data_aux[counter_sub_out];
          end
       end
    end

endmodule

input.rtl/intra_block.sv:
module intra_block #(
    parameter ROW_COL_WIDTH = 16,
    parameter DATA_WIDTH = ROW_COL_WIDTH*ROW_COL_WIDTH
)(
    input logic [DATA_WIDTH-1:0] in_data,  // Input: 256 bits
    output logic [DATA_WIDTH-1:0] out_data // Output: 256 bits rearranged
);

    // Temporary storage for intermediate calculations
    logic [3:0] r_prime [0:255]; // Row index for each bit
    logic [3:0] c_prime [0:255]; // Column index for each bit

    logic [ROW_COL_WIDTH-1:0] prev_out_data [ROW_COL_WIDTH-1:0];

    always_comb begin
       for(int i = 0; i < 256; i++) begin
         if (i < 128) begin
            r_prime[i] = (i - 2 * (i / 16)) % 16;
            c_prime[i] = (i -     (i / 16)) % 16;
         end
         else begin
            r_prime[i] = (i - 2 * (i / 16) - 1) % 16;
            c_prime[i] = (i - (i / 16) - 1) % 16;
         end
       end
    end
    int j, k;
    logic [7:0] output_index[256];
    always_comb begin
      for (j = 0; j < 256; j++) begin
           output_index[j] = r_prime[j] * 16 + c_prime[j];
           out_data[j]     = in_data[output_index[j]];
        end
    end
endmodule

output.rtl/intra_block.sv:
module intra_block #(
    parameter ROW_COL_WIDTH = 16,
    parameter DATA_WIDTH = ROW_COL_WIDTH*ROW_COL_WIDTH
)(
    input  logic [DATA_WIDTH-1:0] in_data,  // Input: 256 bits
    output logic [DATA_WIDTH-1:0] out_data // Output: 256 bits rearranged
);

  // Optimized combinational logic: compute output indices on the fly,
  // eliminating intermediate arrays and reducing wiring significantly.
  always_comb begin
    for (int j = 0; j < 256; j++) begin
      if (j < 128) begin
         // For j in [0,127]:
         //   Let q = j/16 and r = j % 16.
         //   r_prime = (r - 2*q) mod 16, c_prime = (r - q) mod 16.
         int q = j / 16;
         int r = j % 16;
         int row = (r + 16 - (2 * q)) % 16;  // Ensures non-negative result
         int col = (r + 16 - q) % 16;
         out_data[j] = in_data[(row * 16) + col];
      end else begin
         // For j in [128,255]:
         //   Let q = j/16 and r = j % 16.
         //   r_prime = (r - 1 - 2*q) mod 16, c_prime = (r - 1 - q) mod 16.
         int q = j / 16;
         int r = j % 16;
         int row = (r + 16 - 1 - (2 * q)) % 16;
         int col = (r + 16 - 1 - q) % 16;
         out_data[j] = in_data[(row * 16) + col];
      end
    end
  end

endmodule

output.rtl/sdram_controller.sv:
module sdram_controller (
    input  logic         clk,
    input  logic         reset,
    input  logic [23:0]  addr,
    input  logic [15:0]  data_in,
    output logic [15:0]  data_out,
    input  logic         read,
    input  logic         write,
    output logic         sdram_clk,
    output logic         sdram_cke,
    output logic         sdram_cs,
    output logic         sdram_ras,
    output logic         sdram_cas,
    output logic         sdram_we,
    output logic [23:0]  sdram_addr,
    output logic [1:0]   sdram_ba,
    input  logic [15:0]  sdram_dq,
    output logic [15:0]  dq_out
);

   // State encoding
   typedef enum logic [2:0] {
       INIT     = 3'd0,
       IDLE     = 3'd1,
       ACTIVATE = 3'd2,
       READ     = 3'd3,
       WRITE    = 3'd4,
       REFRESH  = 3'd5
   } state_t;

   state_t state, next_state;

   // Counters
   logic [9:0]  init_counter;  // 10-cycle initialization sequence
   logic [10:0] idle_counter;  // 1024-cycle idle timeout for auto-refresh

   // Data output register for READ state
   logic [15:0] data_out_reg;

   // FSM state register and counter updates
   always_ff @(posedge clk or posedge reset) begin
       if (reset) begin
           state         <= INIT;
           init_counter  <= 10'd0;
           idle_counter  <= 11'd0;
           data_out_reg  <= 16'd0;
       end else begin
           state <= next_state;
           if (state == INIT) begin
               init_counter <= init_counter + 1;
           end else if (state == IDLE) begin
               if (read || write)
                   idle_counter <= 11'd0;
               else if (idle_counter == 11'd1023)
                   idle_counter <= 11'd0;  // trigger auto-refresh
               else
                   idle_counter <= idle_counter + 1;
           end
       end
   end

   // Next state logic
   always_comb begin
       unique case (state)
           INIT: begin
               if (init_counter == 10'd9)
                   next_state = IDLE;
               else
                   next_state = INIT;
           end
           IDLE: begin
               if (read || write)
                   next_state = ACTIVATE;
               else if (idle_counter == 11'd1023)
                   next_state = REFRESH;
               else
                   next_state = IDLE;
           end
           ACTIVATE: begin
               if (read)
                   next_state = READ;
               else if (write)
                   next_state = WRITE;
               else
                   next_state = ACTIVATE;
           end
           READ:    next_state = IDLE;
           WRITE:   next_state = IDLE;
           REFRESH: next_state = IDLE;
           default: next_state = IDLE;
       endcase
   end

   // Capture data on READ state
   always_ff @(posedge clk or posedge reset) begin
       if (reset)
           data_out_reg <= 16'd0;
       else if (state == READ)
           data_out_reg <= sdram_dq;
   end

   // Output logic for SDRAM control signals and data bus
   always_comb begin
       // Default assignments common to most states
       sdram_clk = clk;
       sdram_cke = 1'b1;
       sdram_cs  = 1'b1;

       case (state)
           INIT: begin
               sdram_ras = 1'b1;
               sdram_cas = 1'b1;
               sdram_we  = 1'b0;
               sdram_addr = 24'd0;
               sdram_ba  = 2'd0;
               dq_out    = 16'd0;
           end
           IDLE: begin
               sdram_ras = 1'b1;
               sdram_cas = 1'b1;
               sdram_we  = 1'b0;
               sdram_addr = addr[21:0];
               sdram_ba  = addr[23:22];
               dq_out    = 16'bz;  // High impedance during idle
           end
           ACTIVATE: begin
               sdram_ras = 1'b1;
               sdram_cas = 1'b1;
               sdram_we  = 1'b0;
               sdram_addr = addr[21:0];
               sdram_ba  = addr[23:22];
               dq_out    = 16'd0;
           end
           READ: begin
               sdram_ras = 1'b0;    // Row not active for read
               sdram_cas = 1'b1;
               sdram_we  = 1'b0;
               sdram_addr = addr[21:0];
               sdram_ba  = addr[23:22];
               dq_out    = 16'bz;  // High impedance to read data
           end
           WRITE: begin
               sdram_ras = 1'b0;
               sdram_cas = 1'b1;
               sdram_we  = 1'b1;
               sdram_addr = addr[21:0];
               sdram_ba  = addr[23:22];
               dq_out    = data_in;
           end
           REFRESH: begin
               sdram_ras = 1'b1;
               sdram_cas = 1'b1;
               sdram_we  = 1'b0;
               sdram_addr = 24'd0;
               sdram_ba  = 2'd0;
               dq_out    = 16'd0;
           end
           default: begin
               sdram_ras = 1'b1;
               sdram_cas = 1'b1;
               sdram_we  = 1'b0;
               sdram_addr = addr[21:0];
               sdram_ba  = addr[23:22];
               dq_out    = 16'bz;
           end
       endcase
   end

   // Drive data_out based on current state
   always_comb begin
       if (state == READ)
           data_out = data_out_reg;
       else
           data_out = 16'd0;
   end

endmodule

output.rtl/secure_read_write_bus_interface.v:
module secure_read_write_bus_interface #
(
  parameter p_configurable_key = 8'hAA,
  parameter p_data_width       = 8,
  parameter p_addr_width       = 8
)
(
  input  wire [p_addr_width-1:0]  i_addr,
  input  wire [p_data_width-1:0]  i_data_in,
  input  wire [7:0]               i_key_in,
  input  wire                     i_read_write_enable, // 1 = read, 0 = write
  input  wire                     i_capture_pulse,
  input  wire                     i_reset_bar,         // asynchronous active-low reset
  output reg  [p_data_width-1:0]  o_data_out,
  output reg                     o_error
);

  // Internal memory: depth = 2^p_addr_width, width = p_data_width.
  reg [p_data_width-1:0] mem [(1<<p_addr_width)-1:0];

  integer i;

  // Operations are gated by the rising edge of i_capture_pulse.
  // Asynchronous reset is active when i_reset_bar is low.
  always @(posedge i_capture_pulse or negedge i_reset_bar) begin
    if (!i_reset_bar) begin
      // Asynchronous reset: clear outputs and memory.
      o_error         <= 1'b0;
      o_data_out      <= {p_data_width{1'b0}};
      for (i = 0; i < (1<<p_addr_width); i = i + 1) begin
        mem[i] <= {p_data_width{1'b0}};
      end
    end
    else begin
      if (i_key_in == p_configurable_key) begin
        // Authorized access.
        o_error <= 1'b0;
        if (!i_read_write_enable) begin
          // Write operation: store i_data_in into memory at address i_addr.
          mem[i_addr] <= i_data_in;
          // For write operations, o_data_out remains 0.
          o_data_out <= {p_data_width{1'b0}};
        end
        else begin
          // Read operation: output data from memory at address i_addr.
          o_data_out <= mem[i_addr];
        end
      end
      else begin
        // Unauthorized access: flag error and set outputs to default (0).
        o_error    <= 1'b1;
        o_data_out <= {p_data_width{1'b0}};
      end
    end
  end

endmodule

output.rtl/secure_read_write_register_bank.v:
module secure_read_write_register_bank #(
  parameter p_address_width = 8,
  parameter p_data_width    = 8,
  parameter p_unlock_code_0 = 8'hAB,
  parameter p_unlock_code_1 = 8'hCD
)(
  input  wire [p_address_width-1:0] i_addr,
  input  wire [p_data_width-1:0]    i_data_in,
  input  wire                       i_read_write_enable, // 0 = write, 1 = read
  input  wire                       i_capture_pulse,
  input  wire                       i_rst_n,
  output reg  [p_data_width-1:0]    o_data_out
);

  //-------------------------------------------------------------------------
  // Register bank: an array of 2^(p_address_width) registers, each p_data_width bits.
  //-------------------------------------------------------------------------
  reg [p_data_width-1:0] reg_bank [0:((1<<p_address_width)-1)];

  //-------------------------------------------------------------------------
  // Unlock state machine signals
  //-------------------------------------------------------------------------
  // locked: 1 means the register bank is locked (unlock sequence not complete)
  //          0 means unlocked.
  reg locked;
  // first_unlock: set when a correct unlock code is written to address 0.
  reg first_unlock;

  //-------------------------------------------------------------------------
  // Synchronous process: Triggered on the rising edge of i_capture_pulse
  // or on asynchronous active-low reset (i_rst_n).
  //-------------------------------------------------------------------------
  always @(posedge i_capture_pulse or negedge i_rst_n) begin
    if (!i_rst_n) begin
      locked      <= 1'b1;
      first_unlock<= 1'b0;
      // Optionally, one could clear the register bank here.
      // integer j;
      // for (j = 0; j < (1<<p_address_width); j = j + 1)
      //   reg_bank[j] <= {p_data_width{1'b0}};
    end
    else begin
      // Determine operation type:
      // i_read_write_enable = 0 --> Write operation
      // i_read_write_enable = 1 --> Read operation
      if (!i_read_write_enable) begin  // Write operation
        if (locked) begin
          // When locked, only addresses 0 and 1 are allowed.
          if (i_addr == p_address_width'd0) begin
            // If not already waiting for the second unlock code...
            if (first_unlock == 1'b0) begin
              if (i_data_in == p_unlock_code_0) begin
                first_unlock <= 1'b1;  // Record that unlock code 0 has been written.
                reg_bank[0]  <= i_data_in;
              end
              else begin
                // Incorrect code; remain locked.
                first_unlock <= 1'b0;
              end
            end
            else begin
              // Already waiting for the second code: ignore any additional write to address 0.
              first_unlock <= 1'b0;
            end
          end
          else if (i_addr == p_address_width'd1) begin
            if (first_unlock == 1'b1) begin
              if (i_data_in == p_unlock_code_1) begin
                // Correct second unlock code received; complete the unlock sequence.
                locked      <= 1'b0;
                first_unlock<= 1'b0;
                reg_bank[1] <= i_data_in;
              end
              else begin
                // Incorrect code; remain locked.
                first_unlock <= 1'b0;
              end
            end
            else begin
              // Not in the proper state for unlocking; ignore write.
              first_unlock <= 1'b0;
            end
          end
          else begin
            // Attempt to write to any address other than 0 or 1 while locked is not allowed.
            // Do nothing.
          end
        end
        else begin
          // Unlocked: allow write to any address.
          reg_bank[i_addr] <= i_data_in;
        end
        // For write operations, output 0 on the data bus.
        o_data_out <= {p_data_width{1'b0}};
      end
      else begin  // Read operation
        if (locked) begin
          // While locked, always output 0.
          o_data_out <= {p_data_width{1'b0}};
        end
        else begin
          // In unlocked state, only addresses 0 and 1 are write-only.
          if ((i_addr == p_address_width'd0) || (i_addr == p_address_width'd1))
            o_data_out <= {p_data_width{1'b0}};
          else
            o_data_out <= reg_bank[i_addr];
        end
      end
    end
  end

endmodule

output.rtl/secure_variable_timer.v:
module secure_variable_timer (
    input wire i_clk,           // Clock signal (rising-edge triggered)
    input wire i_rst_n,         // Active-low synchronous reset signal
    input wire i_data_in,       // Serial data input
    output reg [3:0] o_time_left, // 4-bit output showing remaining time during counting phase
    output reg o_processing,    // Asserted high when the timer is actively counting
    output reg o_completed,     // Asserted high when the timer completes its delay
    input wire i_ack            // Acknowledgment signal to reset after completion
);

    //-------------------------------------------------------------------------
    // State Encoding
    //-------------------------------------------------------------------------
    localparam IDLE      = 2'b00;
    localparam CONFIG    = 2'b01;
    localparam COUNT     = 2'b10;
    localparam WAIT_ACK  = 2'b11;

    //-------------------------------------------------------------------------
    // Internal Registers
    //-------------------------------------------------------------------------
    reg [1:0] state;
    reg [3:0] pattern_shift; // Shift register for detecting the 1101 start pattern
    reg [3:0] config_reg;    // Shift register for reading the 4-bit delay value
    reg [1:0] config_count;  // Counts the number of bits received in CONFIG state
    reg [3:0] delay;         // Delay value configured from serial input
    reg [9:0] cycle_counter; // 10-bit counter for cycles within a 1000-cycle interval
    reg [3:0] interval;      // 4-bit counter for completed 1000-cycle intervals

    //-------------------------------------------------------------------------
    // Main FSM Process
    //-------------------------------------------------------------------------
    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            // Synchronous reset: return to idle state and clear registers
            state            <= IDLE;
            pattern_shift    <= 4'b0;
            config_reg       <= 4'b0;
            config_count     <= 2'b0;
            delay            <= 4'b0;
            cycle_counter    <= 10'b0;
            interval         <= 4'b0;
            o_time_left      <= 4'b0;
            o_processing     <= 1'b0;
            o_completed      <= 1'b0;
        end else begin
            case (state)
                //----------------------------------------------------------------
                // IDLE State: Search for the 1101 start pattern
                //----------------------------------------------------------------
                IDLE: begin
                    // Shift in the serial bit; most significant bit comes in first.
                    pattern_shift <= {pattern_shift[2:0], i_data_in};
                    // When the pattern 1101 is detected, move to CONFIG state.
                    if (pattern_shift == 4'b1101)
                        state <= CONFIG;
                    else
                        state <= IDLE;

                    // In idle, outputs are not valid.
                    o_processing <= 1'b0;
                    o_completed  <= 1'b0;
                    o_time_left  <= 4'b0; // Don't care (set to 0)
                end

                //----------------------------------------------------------------
                // CONFIG State: Read the next 4 bits to configure the delay.
                //----------------------------------------------------------------
                CONFIG: begin
                    // Shift in the next 4 bits (MSB first) to form the delay value.
                    config_reg <= {config_reg[2:0], i_data_in};
                    config_count <= config_count + 1;
                    // Once 4 bits have been received...
                    if (config_count == 2'b11) begin
                        delay            <= config_reg;
                        state            <= COUNT;
                        config_count     <= 2'b0;     // Reset configuration counter
                        interval         <= 4'b0;     // Initialize interval counter
                        cycle_counter    <= 10'b0;    // Initialize cycle counter
                        o_time_left      <= delay;    // Start with full delay value
                    end
                    o_processing <= 1'b0;
                    o_completed  <= 1'b0;
                    o_time_left  <= 4'b0; // Not valid in CONFIG phase
                end

                //----------------------------------------------------------------
                // COUNT State: Count for ((delay + 1) * 1000) clock cycles.
                // The counting is divided into intervals of 1000 cycles.
                //----------------------------------------------------------------
                COUNT: begin
                    o_processing <= 1'b1; // Timer is actively counting
                    cycle_counter <= cycle_counter + 1;

                    // When one 1000-cycle interval is complete...
                    if (cycle_counter == 10'd999) begin
                        // Calculate total intervals = delay + 1.
                        // We count intervals from 0 to (delay+1)-1.
                        if (interval == (delay + 1) - 1) begin
                            // Final interval reached; complete counting.
                            state <= WAIT_ACK;
                        end else begin
                            // Increment interval and update remaining time.
                            interval <= interval + 1;
                            o_time_left <= delay - interval;
                        end
                    end
                    o_completed <= 1'b0;
                end

                //----------------------------------------------------------------
                // WAIT_ACK State: Wait for the acknowledgment signal to reset.
                //----------------------------------------------------------------
                WAIT_ACK: begin
                    o_completed <= 1'b1; // Notify that counting is complete
                    // Wait until the acknowledgment (i_ack) is asserted.
                    if (i_ack)
                        state <= IDLE;
                    o_processing <= 1'b0;
                    o_time_left  <= 4'b0;
                end

                default: state <= IDLE;
            endcase
        end
    end

endmodule

output.rtl/binary_to_one_hot_decoder_sequential:
module binary_to_one_hot_decoder_sequencial #(
    parameter BINARY_WIDTH = 5,
    parameter OUTPUT_WIDTH = 32
)(
    input  wire         i_clk,
    input  wire         i_rstb,
    input  wire [BINARY_WIDTH-1:0] i_binary_in,
    output reg  [OUTPUT_WIDTH-1:0] o_one_hot_out
);

  // Parameter constraint: OUTPUT_WIDTH must be at least 2^BINARY_WIDTH.
  // This check is for simulation and will generate an error if the constraint is violated.
  initial begin
      if (OUTPUT_WIDTH < (1 << BINARY_WIDTH)) begin
          $error("Parameter error: OUTPUT_WIDTH (%0d) must be at least %0d (2^BINARY_WIDTH)", OUTPUT_WIDTH, (1 << BINARY_WIDTH));
      end
  end

  always @(posedge i_clk or negedge i_rstb) begin
      if (!i_rstb) begin
          o_one_hot_out <= {OUTPUT_WIDTH{1'b0}};
      end else begin
          // Reset the output to all zeros.
          o_one_hot_out <= {OUTPUT_WIDTH{1'b0}};
          // Set only the bit corresponding to i_binary_in, if within range.
          if (i_binary_in < OUTPUT_WIDTH)
              o_one_hot_out[i_binary_in] <= 1'b1;
      end
  end

endmodule

output.rtl/serial_in_parallel_out_8bit.sv:
module serial_in_parallel_out_8bit(
    input  logic clock,
    input  logic serial_in,
    output logic [7:0] parallel_out
);

    // Initialize the register to an unknown state (all x).
    // In simulation this helps to illustrate that no data has been shifted in yet.
    initial begin
        parallel_out = 8'bx;
    end

    // On every rising edge of the clock, shift the register left by one bit.
    // The serial input is inserted into the LSB.
    always_ff @(posedge clock) begin
        parallel_out <= {parallel_out[6:0], serial_in};
    end

endmodule

input.rtl/serial_in_parallel_out_8bit.sv:
module serial_in_parallel_out_8bit (input clock,serial_in,output reg [7:0] parallel_out);

always @(posedge clock)  
  begin
    parallel_out[7:1] <=parallel_out[6:0];     
    parallel_out[0] <= serial_in;  
  end  

endmodule

output.rtl/serial_in_parallel_out_8bit.sv:
module sipo_top which instantiates
// the serial_in_parallel_out_8bit and onebit_ecc modules.

module sipo_top #(
    parameter DATA_WIDTH = 16,
    parameter SHIFT_DIRECTION = 1,
    parameter CODE_WIDTH = DATA_WIDTH + $clog2(DATA_WIDTH+1)
)
(
    input clk,
    input rst,
    input serial_in,
    input shift_en,
    input [CODE_WIDTH-1:0] received,
    output done,
    output [DATA_WIDTH-1:0] data_out,
    output [CODE_WIDTH-1:0] encoded,
    output error_detected,
    output error_corrected
);

   // Wires to connect the SIPO module to the ECC block
   wire [DATA_WIDTH-1:0] sipo_parallel_out;
   wire sipo_done;

   // Instantiate the Serial in Parallel Out module
   serial_in_parallel_out_8bit #(
      .WIDTH(64),                // Number of shifts to complete (default 64)
      .SHIFT_DIRECTION(SHIFT_DIRECTION),
      .DATA_WIDTH(DATA_WIDTH)     // Overriding default DATA_WIDTH for output width
   ) sipo_inst (
      .clk(clk),
      .rst(rst),
      .sin(serial_in),
      .shift_en(shift_en),
      .done(sipo_done),
      .parallel_out(sipo_parallel_out)
   );

   // Instantiate the One Bit ECC module
   onebit_ecc #(
      .DATA_WIDTH(DATA_WIDTH),
      .CODE_WIDTH(CODE_WIDTH)
   ) ecc_inst (
      .data_in(sipo_parallel_out),
      .received(received),
      .data_out(data_out),
      .encoded(encoded),
      .error_detected(error_detected),
      .error_corrected(error_corrected)
   );

   // Drive the top-level done signal from the SIPO module's done output
   assign done = sipo_done;

endmodule

module sipo_top #(
    parameter DATA_WIDTH = 16,                                   // Width of the shift register
    parameter SHIFT_DIRECTION = 1,                               // Determines Left or right shift
    parameter CODE_WIDTH = DATA_WIDTH + $clog2(DATA_WIDTH + 1),   // Encoded width
    parameter CRC_WIDTH = DATA_WIDTH / 2,                        // Width for CRC generation
    parameter POLY = 8'b10101010                                 // Default polynomial for CRC
)(
    input clk,                                   // Clock input
    input reset_n,                               // Reset input
    input serial_in,                             // Serial input to SIPO
    input shift_en,                              // Shift enable                     
    input [CODE_WIDTH-1:0] received,             // Received encoded data 
    input [CRC_WIDTH-1:0] received_crc,          // Received CRC value
    output done,                                 // Done signal indicating completion of shift
    output [DATA_WIDTH-1:0] data_out,            // Corrected output of ECC block
    output [CODE_WIDTH-1:0] encoded,             // Encoded output
    output error_detected,                       // Error detected flag
    output error_corrected,                      // Error corrected flag
    output [CRC_WIDTH-1:0] crc_out,              // CRC output from CRC generator
    output crc_error                             // CRC error flag (asserted if crc_out != received_crc)
);

    wire [DATA_WIDTH-1:0] parallel_out;
    // (sipo_out_ecc_in is not used in this design)

    // Instantiate the SIPO block
    serial_in_parallel_out_8bit #(
        .WIDTH(DATA_WIDTH),
        .SHIFT_DIRECTION(SHIFT_DIRECTION)
    ) uut_sipo (
        .clk(clk),               // Clock input
        .reset_n(reset_n),       // Reset input
        .sin(serial_in),         // Serial input to SIPO
        .shift_en(shift_en),     // Shift enable for SIPO
        .done(done),             // Done signal from SIPO
        .parallel_out(parallel_out)  // Parallel output from SIPO
    );

    // Instantiate the one-bit ECC block
    onebit_ecc #(
        .DATA_WIDTH(DATA_WIDTH),
        .CODE_WIDTH(CODE_WIDTH)
    ) uut_onebit_ecc1 (
        .data_in(parallel_out),
        .encoded(encoded),
        .received(received),
        .data_out(data_out),
        .error_detected(error_detected),
        .error_corrected(error_corrected)
    );

    // Instantiate the CRC generator block
    crc_generator #(
        .DATA_WIDTH(DATA_WIDTH),
        .CRC_WIDTH(CRC_WIDTH),
        .POLY(POLY)
    ) uut_crc (
        .clk(clk),
        .reset_n(reset_n),
        .data_in(parallel_out),   // Data input for CRC calculation
        .crc_out(crc_out)
    );

    // Compare generated CRC with received CRC to generate error flag
    assign crc_error = (crc_out !== received_crc);

endmodule

// Serial in Parallel out module
module serial_in_parallel_out_8bit  #(
    parameter WIDTH = 64,               // Width of the shift register
    parameter SHIFT_DIRECTION = 1       // Determines if shifting left (1) or right (0)
)(
    input clk,                          // Clock signal
    input reset_n,                      // Active low reset
    input sin,                          // Serial input
    input shift_en,                     // Shift enable signal
    output reg done,                    // Done signal indicating completion of shift
    output reg [WIDTH-1:0] parallel_out // Parallel output
);

    localparam COUNT_WIDTH = $clog2(WIDTH); // Calculate width for shift_count

    reg [COUNT_WIDTH:0] shift_count;        // Counter to track number of shifts

    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin                                   
            parallel_out     <= {WIDTH{1'b0}};                
            done             <= 1'b0;                         
            shift_count      <= {COUNT_WIDTH{1'b0}};          
        end else begin
            if (shift_en) begin
                if (SHIFT_DIRECTION) begin
                    parallel_out    <= {parallel_out[WIDTH-2:0], sin}; 
                end else begin
                    parallel_out    <= {sin, parallel_out[WIDTH-1:1]}; 
                end
                shift_count   <= shift_count + 1;                      
            end

            if (shift_count == (WIDTH - 1)) begin
                done         <= 1'b1;                                 
                shift_count  <= {COUNT_WIDTH{1'b0}};                  
            end else begin
                done         <= 1'b0;                                  
            end
        end
    end 
endmodule


// One-bit ECC module
module onebit_ecc #(
    parameter DATA_WIDTH = 4,                                  // Width of the data input
    parameter CODE_WIDTH = DATA_WIDTH + $clog2(DATA_WIDTH + 1) // Encoded width
)(
    input [DATA_WIDTH-1:0] data_in,                     // Input data
    output reg [CODE_WIDTH-1:0] encoded,                // Encoded output
    input [CODE_WIDTH-1:0] received,                    // Received encoded data
    output reg [DATA_WIDTH-1:0] data_out,               // Corrected output
    output reg error_detected,                          // Error detected flag
    output reg error_corrected                          // Error corrected flag
);

    localparam PARITY_BITS = CODE_WIDTH - DATA_WIDTH;   // Number of parity bits

    reg [PARITY_BITS-1:0] syndrome;                     // Syndrome for error detection
    reg [CODE_WIDTH-1:0] corrected_data;                // Corrected received data

    integer idx_i, idx_j, idx_k;
    integer idx_m, idx_n;
    integer idx_p, idx_q;

    always @(*) begin
        encoded = 0;
        idx_k = 0;
        for (idx_i = 0; idx_i < CODE_WIDTH; idx_i = idx_i + 1) begin
            if ((idx_i + 1) & (idx_i)) begin
                encoded[idx_i] = data_in[idx_k];
                idx_k = idx_k + 1;
            end
        end
        for (idx_i = 0; idx_i < PARITY_BITS; idx_i = idx_i + 1) begin
            encoded[(1 << idx_i) - 1] = 0; 
            for (idx_j = 0; idx_j < CODE_WIDTH; idx_j = idx_j + 1) begin
                if (((idx_j + 1) & (1 << idx_i)) && ((idx_j + 1) != (1 << idx_i))) begin
                    encoded[(1 << idx_i) - 1] = encoded[(1 << idx_i) - 1] ^ encoded[idx_j];
                end
            end
        end
    end

    always @(*) begin
        syndrome = 0; 
        for (idx_m = 0; idx_m < PARITY_BITS; idx_m = idx_m + 1) begin
            for (idx_n = 0; idx_n < CODE_WIDTH; idx_n = idx_n + 1) begin
                if ((idx_n + 1) & (1 << idx_m)) begin
                    syndrome[idx_m] = syndrome[idx_m] ^ received[idx_n];
                end
            end
        end
    end

    always @(*) begin
        error_detected = |syndrome; 
    end

    always @(*) begin
        corrected_data = received;
        if (error_detected) begin
            corrected_data[syndrome - 1] = ~corrected_data[syndrome - 1]; 
        end
    end

    always @(*) begin
        idx_q = 0;
        for (idx_p = 0; idx_p < CODE_WIDTH; idx_p = idx_p + 1) begin
            if ((idx_p + 1) & (idx_p)) begin
                data_out[idx_q] = corrected_data[idx_p];
                idx_q = idx_q + 1;
            end
        end
    end

    always @(*) begin
        error_corrected = error_detected; 
    end

endmodule

// CRC Generator module
module crc_generator #(
    parameter DATA_WIDTH = 16,      // Width of the input data
    parameter CRC_WIDTH = DATA_WIDTH / 2, // Width of the CRC output
    parameter POLY = 8'b10101010     // CRC polynomial
)(
    input clk,                       // Clock signal
    input reset_n,                   // Active low reset
    input [DATA_WIDTH-1:0] data_in,  // Input data for CRC calculation
    output reg [CRC_WIDTH-1:0] crc_out // CRC output
);

    reg [CRC_WIDTH-1:0] crc_reg;
    integer count;

    // Sequential CRC calculation: process one bit per clock cycle
    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            crc_reg <= 0;
            count <= 0;
        end else begin
            if (count < DATA_WIDTH) begin
                // If MSB of crc_reg XOR current data bit is 1, XOR with POLY
                if (crc_reg[CRC_WIDTH-1] ^ data_in[count])
                    crc_reg <= (crc_reg << 1) ^ POLY;
                else
                    crc_reg <= crc_reg << 1;
                count <= count + 1;
            end
            // Once all bits are processed, hold crc_reg
        end
    end

    // Latch the final crc_reg value to crc_out when processing is complete
    always @(posedge clk) begin
        if (count >= DATA_WIDTH)
            crc_out <= crc_reg;
    end

endmodule

