  end
end
assign load_data_int_out = load_data_int[DATA_WIDTH+INPUT_DATA-1:INPUT_DATA];
assign read_data_int_out = read_data_int[DATA_WIDTH+INPUT_DATA-1:INPUT_DATA];

wire [DATA_WIDTH+2-1:0] load_data_gain, read_data_gain;
assign load_data_gain = {load_data_int_out[DATA_WIDTH-1], load_data_int_out, 1'b0} + {{(2){load_data_int_out[DATA_WIDTH-1]}}, load_data_int_out};
assign read_data_gain = {read_data_int_out[DATA_WIDTH-1], read_data_int_out, 1'b0} + {{(2){read_data_int_out[DATA_WIDTH-1]}}, read_data_int_out};

assign l_aca1 = {{(A1_WIDTH){load_data_gain[DATA_WIDTH+2-1]}}, load_data_gain} - {{(A1_WIDTH){l_er0[DATA_WIDTH+2-1]}}, l_er0} + l_ac1;
assign r_aca1 = {{(A1_WIDTH){read_data_gain[DATA_WIDTH+2-1]}}, read_data_gain} - {{(A1_WIDTH){r_er0[DATA_WIDTH+2-1]}}, r_er0} + r_ac1;
assign l_aca2 = {{(A2_WIDTH-A1_WIDTH){l_aca1[DATA_WIDTH+A1_WIDTH+2-1]}}, l_aca1} - {{(A2_WIDTH){l_er0[DATA_WIDTH+2-1]}}, l_er0} - {{(A2_WIDTH+1){l_er0_prev[DATA_WIDTH+2-1]}}, l_er0_prev[DATA_WIDTH+2-1:1]} + l_ac2;
assign r_aca2 = {{(A2_WIDTH-A1_WIDTH){r_aca1[DATA_WIDTH+A1_WIDTH+2-1]}}, r_aca1} - {{(A2_WIDTH){r_er0[DATA_WIDTH+2-1]}}, r_er0} - {{(A2_WIDTH+1){r_er0_prev[DATA_WIDTH+2-1]}}, r_er0_prev[DATA_WIDTH+2-1:1]} + r_ac2;

always @ (posedge clk_sig) begin
  if (clk_en_sig) begin
    l_ac1 <= #1 l_aca1;
    r_ac1 <= #1 r_aca1;
    l_ac2 <= #1 l_aca2;
    r_ac2 <= #1 r_aca2;
  end
end

assign l_quant = {l_ac2[DATA_WIDTH+A2_WIDTH+2-1], l_ac2} + {{(DATA_WIDTH+A2_WIDTH+3-READ_WIDTH){s_out[READ_WIDTH-1]}}, s_out[READ_WIDTH-1:0]};
assign r_quant = {r_ac2[DATA_WIDTH+A2_WIDTH+2-1], r_ac2} + {{(DATA_WIDTH+A2_WIDTH+3-READ_WIDTH){s_out[READ_WIDTH-1]}}, s_out[READ_WIDTH-1:0]};

assign l_er0 = l_quant[DATA_WIDTH+A2_WIDTH+3-1] ? {1'b1, {(DATA_WIDTH+2-1){1'b0}}} : {1'b0, {(DATA_WIDTH+2-1){1'b1}}};
assign r_er0 = r_quant[DATA_WIDTH+A2_WIDTH+3-1] ? {1'b1, {(DATA_WIDTH+2-1){1'b0}}} : {1'b0, {(DATA_WIDTH+2-1){1'b1}}};

always @ (posedge clk_sig)
begin
  if (clk_en_sig)
  begin
    if (~|load_data_gain)
    begin
      left_sig <= #1 ~left_sig;
    end
    else
    begin
      left_sig <= #1 ~l_er0[DATA_WIDTH+2-1];
    end

    if (~|read_data_gain)
    begin
      right_sig <= #1 ~right_sig;
    end
    else
    begin
      right_sig <= #1 ~r_er0[DATA_WIDTH+2-1];
    end
  end
end
endmodule

input.rtl/signal_correlator.sv:
module signal_correlator(
    input clk,
    input reset,
    input [7:0] input_signal,
    input [7:0] reference_signal,
    output reg [3:0] correlation_output // 4-bit output
);

integer i;
reg [3:0] sum;  

always @(posedge clk or posedge reset) begin
    if (reset) begin
        correlation_output <= 0;
        sum = 0;  
    end else begin
        sum = 0;  
        for (i = 0; i < 8; i = i + 1) begin
            sum = sum + (input_signal[i] & reference_signal[i]); 
        end
    end
end

endmodule

output.rtl/signal_correlator.sv:
module signal_correlator(
    input clk,
    input reset,
    input [7:0] input_signal,
    input [7:0] reference_signal,
    output reg [3:0] correlation_output
);

    integer i;
    reg [3:0] sum;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            correlation_output <= 0;
            sum <= 0;
        end else begin
            sum <= 0;
            // Compute weighted sum: each matching bit adds +2
            for (i = 0; i < 8; i = i + 1) begin
                sum <= sum + 2 * (input_signal[i] & reference_signal[i]);
            end
            // Clamp the output to 15 if sum exceeds 15
            if (sum > 15)
                correlation_output <= 15;
            else
                correlation_output <= sum;
        end
    end

endmodule

output.rtl/signedadder.v:
module signedadder #(parameter DATA_WIDTH = 8)(
    input i_clk,
    input i_rst_n,
    input i_start,
    input i_enable,
    input i_mode,
    input i_clear,
    input [DATA_WIDTH-1:0] i_operand_a,
    input [DATA_WIDTH-1:0] i_operand_b,
    output reg [DATA_WIDTH-1:0] o_resultant_sum,
    output reg o_overflow,
    output reg o_ready,
    output reg [1:0] o_status
);

    // State encoding
    localparam IDLE   = 2'b00;
    localparam LOAD   = 2'b01;
    localparam COMPUTE= 2'b10;
    localparam OUTPUT = 2'b11;

    // Internal registers to hold operands and computation results
    reg [DATA_WIDTH-1:0] operand_a_reg;
    reg [DATA_WIDTH-1:0] operand_b_reg;
    reg [DATA_WIDTH-1:0] sum_reg;
    reg overflow_reg;
    reg [1:0] state;

    // Internal combinational wires for computation
    // Compute two's complement of operand_b when needed (for subtraction)
    wire [DATA_WIDTH-1:0] b_neg;
    assign b_neg = ~operand_b_reg + 1;

    // Compute the sum based on operation mode.
    // For addition: sum = operand_a_reg + operand_b_reg.
    // For subtraction: sum = operand_a_reg + b_neg.
    wire [DATA_WIDTH-1:0] sum_wire;
    assign sum_wire = operand_a_reg + (i_mode ? b_neg : operand_b_reg);

    // Overflow detection logic.
    // For addition:
    //   overflow occurs if (a and b are positive and result is negative) or
    //   (a and b are negative and result is positive).
    // For subtraction:
    //   overflow occurs if (signs of a and -b differ and sign of result differs from a).
    wire overflow_wire;
    assign overflow_wire = (i_mode ?
         // Subtraction overflow: (a[MSB] XOR (-b)[MSB]) AND (result[MSB] XOR a[MSB])
         ((operand_a_reg[DATA_WIDTH-1] ^ b_neg[DATA_WIDTH-1]) & (sum_wire[DATA_WIDTH-1] ^ operand_a_reg[DATA_WIDTH-1]))
       :
         // Addition overflow:
         ((operand_a_reg[DATA_WIDTH-1] & operand_b_reg[DATA_WIDTH-1] & ~sum_wire[DATA_WIDTH-1]) |
          (~operand_a_reg[DATA_WIDTH-1] & ~operand_b_reg[DATA_WIDTH-1] & sum_wire[DATA_WIDTH-1]))
    );

    // Synchronous state machine with asynchronous reset and clear.
    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            state           <= IDLE;
            operand_a_reg   <= {DATA_WIDTH{1'b0}};
            operand_b_reg   <= {DATA_WIDTH{1'b0}};
            sum_reg         <= {DATA_WIDTH{1'b0}};
            overflow_reg    <= 1'b0;
            o_resultant_sum <= {DATA_WIDTH{1'b0}};
            o_overflow      <= 1'b0;
            o_ready         <= 1'b0;
            o_status        <= IDLE;
        end
        else if (i_clear) begin
            state           <= IDLE;
            operand_a_reg   <= {DATA_WIDTH{1'b0}};
            operand_b_reg   <= {DATA_WIDTH{1'b0}};
            sum_reg         <= {DATA_WIDTH{1'b0}};
            overflow_reg    <= 1'b0;
            o_resultant_sum <= {DATA_WIDTH{1'b0}};
            o_overflow      <= 1'b0;
            o_ready         <= 1'b0;
            o_status        <= IDLE;
        end
        else begin
            case (state)
                IDLE: begin
                    o_ready  <= 1'b0;
                    o_status <= IDLE;
                    // Wait for start signal while enable is high.
                    if (i_start && i_enable) begin
                        state <= LOAD;
                    end
                end
                LOAD: begin
                    o_status <= LOAD;
                    // Capture input operands.
                    operand_a_reg <= i_operand_a;
                    operand_b_reg <= i_operand_b;
                    state <= COMPUTE;
                end
                COMPUTE: begin
                    o_status <= COMPUTE;
                    // Perform the arithmetic operation.
                    sum_reg     <= sum_wire;
                    overflow_reg<= overflow_wire;
                    state <= OUTPUT;
                end
                OUTPUT: begin
                    o_status <= OUTPUT;
                    // Drive outputs with computed results.
                    o_resultant_sum <= sum_reg;
                    o_overflow      <= overflow_reg;
                    o_ready          <= 1'b1;
                    // Return to IDLE for the next operation.
                    state <= IDLE;
                end
                default: state <= IDLE;
            endcase
        end
    end

endmodule

output.rtl/spi_fsm.v:
module spi_fsm (
    input  wire         i_clk,       // System clock
    input  wire         i_rst_b,     // Active-low async reset
    input  wire [15:0]  i_data_in,   // Parallel 16-bit data to transmit
    input  wire         i_enable,    // Enable block
    input  wire         i_fault,     // Fault indicator
    input  wire         i_clear,     // Forces FSM to clear/idle

    output reg          o_spi_cs_b,  // SPI chip select (active-low)
    output reg          o_spi_clk,   // SPI clock
    output reg          o_spi_data,  // Serialized SPI data out
    output reg [4:0]    o_bits_left, // Bits left to transmit
    output reg          o_done,      // Single-cycle pulse when done or error
    output reg [1:0]    o_fsm_state  // FSM state for external monitoring
);

    // FSM state encoding
    localparam IDLE       = 2'b00;
    localparam TRANSMIT   = 2'b01;
    localparam CLOCK_TOGG = 2'b10;
    localparam ERROR      = 2'b11;

    // Internal registers
    reg [1:0] state;
    reg [15:0] shift_reg;
    reg [4:0] bits_left;
    reg done_reg;
    reg spi_clk_reg;

    // Synchronous state machine and internal register updates
    always @(posedge i_clk or negedge i_rst_b) begin
        if (!i_rst_b) begin
            state       <= IDLE;
            shift_reg   <= 16'd0;
            bits_left   <= 5'd16;  // 16 bits remaining (0x10)
            done_reg    <= 1'b0;
            spi_clk_reg <= 1'b0;
        end 
        else begin
            // i_clear takes highest priority: force idle
            if (i_clear) begin
                state       <= IDLE;
                shift_reg   <= 16'd0;
                bits_left   <= 5'd16;
                done_reg    <= 1'b0;
                spi_clk_reg <= 1'b0;
            end 
            // Fault condition: enter error state
            else if (i_fault) begin
                state       <= ERROR;
                shift_reg   <= 16'd0;
                bits_left   <= 5'd10;  // Safe default in error state
                done_reg    <= 1'b0;
                spi_clk_reg <= 1'b0;
            end 
            // If i_enable is deasserted, go to idle
            else if (!i_enable) begin
                state       <= IDLE;
                shift_reg   <= 16'd0;
                bits_left   <= 5'd16;
                done_reg    <= 1'b0;
                spi_clk_reg <= 1'b0;
            end 
            else begin
                case (state)
                    IDLE: begin
                        // Wait for enable to start transmission
                        if (i_enable) begin
                            shift_reg   <= i_data_in;  // Load input data
                            bits_left   <= 5'd16;       // Reset bit counter
                            state       <= TRANSMIT;
                        end
                    end
                    TRANSMIT: begin
                        // In Transmit state, output the MSB of the shift register.
                        // Transition to CLOCK_TOGG to toggle the clock and shift the data.
                        state <= CLOCK_TOGG;
                    end
                    CLOCK_TOGG: begin
                        // Toggle the SPI clock signal
                        spi_clk_reg <= ~spi_clk_reg;
                        // Shift the data register right by one bit
                        shift_reg   <= shift_reg >> 1;
                        // Decrement the bit counter
                        bits_left   <= bits_left - 1;
                        // If this was the last bit, go back to idle and assert done pulse
                        if (bits_left == 1) begin
                            state  <= IDLE;
                            done_reg <= 1'b1;
                        end 
                        else begin
                            state <= TRANSMIT;
                        end
                    end
                    ERROR: begin
                        // Remain in ERROR until cleared
                        if (i_clear) begin
                            state       <= IDLE;
                            shift_reg   <= 16'd0;
                            bits_left   <= 5'd16;
                            done_reg    <= 1'b0;
                            spi_clk_reg <= 1'b0;
                        end
                    end
                    default: begin
                        state <= IDLE;
                    end
                endcase
            end
        end
    end

    // Output logic based on current state
    always @(*) begin
        case (state)
            IDLE: begin
                o_spi_cs_b = 1'b1;  // Chip select inactive (high)
                o_spi_clk  = 1'b0;
                o_spi_data = 1'b0;
            end
            TRANSMIT, CLOCK_TOGG: begin
                o_spi_cs_b = 1'b0;  // Activate chip select during transmission
                o_spi_clk  = spi_clk_reg;
                o_spi_data = shift_reg[15];  // Output MSB of data register
            end
            ERROR: begin
                o_spi_cs_b = 1'b1;  // Safe default: chip select inactive
                o_spi_clk  = 1'b0;
                o_spi_data = 1'b0;
            end
            default: begin
                o_spi_cs_b = 1'b1;
                o_spi_clk  = 1'b0;
                o_spi_data = 1'b0;
            end
        endcase
    end

    // Drive remaining outputs
    assign o_bits_left = bits_left;
    assign o_done      = done_reg;
    assign o_fsm_state = state;

endmodule

output.rtl/unique_number_identifier.v:
module unique_number_identifier #(
    parameter p_bit_width = 8, 
    parameter p_max_numbers = 16 
)(
    input wire i_clk, 
    input wire i_rst_n, 
    input wire i_ready, 
    input wire [p_bit_width-1:0] i_number, 
    output reg [p_bit_width-1:0] o_unique_number 
);

// Internal register to accumulate the XOR of all received numbers.
// The unique number is obtained by XOR-ing all numbers in the series,
// because every number (except the unique one) appears twice.
reg [p_bit_width-1:0] xor_acc;

always @(posedge i_clk or negedge i_rst_n) begin
    if (!i_rst_n) begin
        xor_acc <= 0;
        o_unique_number <= 0;
    end else begin
        if (i_ready) begin
            xor_acc <= xor_acc ^ i_number;
        end
        // Continuously update the output with the accumulated XOR.
        // When i_ready is deasserted, the previous value is retained.
        o_unique_number <= xor_acc;
    end
end

endmodule

