input.rtl/sorting_engine.sv:
module sorting_engine #(
    parameter N = 8,             // Number of elements to sort
    parameter WIDTH = 8          // Bit-width of each element
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);

    // Internal registers to hold the array
    reg [WIDTH-1:0] array [0:N-1];

    // FSM states
    localparam IDLE    = 2'd0;
    localparam SORTING = 2'd1;
    localparam DONE    = 2'd2;

    reg [1:0]  state, next_state;

    // Variables for bubble sort indexing
    reg [$clog2(N)-1:0] i;  // Outer loop index
    reg [$clog2(N)-1:0] j;  // Inner loop index

    // Wires for comparison and swap
    wire [WIDTH-1:0] val_j;
    wire [WIDTH-1:0] val_j1;

    assign val_j  = array[j];
    assign val_j1 = array[j+1];

    // FSM: Next state logic
    always @(*) begin
        next_state = state;
        case (state)
            IDLE: begin
                if (start)
                    next_state = SORTING;
            end
            SORTING: begin
                // Transition to DONE once all passes are complete
                if (i == (N-1) && j == (N-2))
                    next_state = DONE;
            end
            DONE: begin
                next_state = IDLE;
            end
            default: begin
                next_state = IDLE;
            end
        endcase
    end

    // FSM: Output and counter updates
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            i <= 0;
            j <= 0;
            done <= 0;
        end else begin
            state <= next_state;

            case (state)
                IDLE: begin
                    done <= 0;
                    if (start) begin
                        // Load the array from in_data
                        for (int k = 0; k < N; k = k + 1) begin
                            array[k] <= in_data[(k+1)*WIDTH-1 -: WIDTH];
                        end
                        i <= 0;
                        j <= 0;
                    end
                end

                SORTING: begin
                    // Perform a single comparison and swap if needed
                    if (val_j > val_j1) begin
                        array[j]   <= val_j1;
                        array[j+1] <= val_j;
                    end

                    // Update j
                    if (j == N-2) begin
                        // One pass completed, increment i
                        j <= 0;
                        i <= i + 1;
                    end else begin
                        j <= j + 1;
                    end
                end

                DONE: begin
                    // Sorting complete
                    done <= 1;
                    // Output the sorted data
                    for (int m = 0; m < N; m = m + 1) begin
                        out_data[(m+1)*WIDTH-1 -: WIDTH] <= array[m];
                    end
                end
                default: begin
                end
            endcase
        end
    end

endmodule

output.rtl/sorting_engine.sv:
module sorting_engine #(
    parameter N = 8,     
    parameter WIDTH = 8  
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);
    // FSM state encoding
    localparam IDLE = 2'd0,
               LOAD = 2'd1,
               SORT = 2'd2,
               DONE = 2'd3;

    // Internal registers and arrays
    reg [1:0]  state, next_state;
    reg [WIDTH-1:0] data_array [0:N-1];
    reg [$clog2(N+1)-1:0] pass_cnt;
    reg [$clog2(N/2+1)-1:0] pair_idx;

    // Determine number of comparisons per pass:
    // For even passes (pass_cnt[0] == 0) use N/2 comparisons;
    // For odd passes use (N/2)-1 comparisons.
    wire [$clog2(N/2+1)-1:0] pairs_in_this_pass;
    assign pairs_in_this_pass = (pass_cnt[0] == 1'b0) ? (N/2) : ((N/2) > 0 ? (N/2) - 1 : 0);

    // Next state logic
    always @(*) begin
        next_state = state;
        case (state)
            IDLE: if (start)
                    next_state = LOAD;
            LOAD:  next_state = SORT;
            SORT:  if (pass_cnt == N)
                    next_state = DONE;
                  else
                    next_state = SORT;
            DONE:  next_state = IDLE;
            default: next_state = IDLE;
        endcase
    end

    // FSM sequential process
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state      <= IDLE;
            done       <= 1'b0;
            pass_cnt   <= 0;
            pair_idx   <= 0;
        end else begin
            state <= next_state;
            case (state)
                IDLE: begin
                    // Remain idle until start is asserted.
                end
                LOAD: begin
                    // Load the input data into the internal array in one clock cycle.
                    integer i;
                    for (i = 0; i < N; i = i + 1) begin
                        data_array[i] <= in_data[i*WIDTH +: WIDTH];
                    end
                    pass_cnt   <= 0;
                    pair_idx   <= 0;
                    done       <= 1'b0;
                end
                SORT: begin
                    // Perform one compare-and-swap per clock cycle.
                    if (pair_idx < pairs_in_this_pass) begin
                        if (pass_cnt[0] == 1'b0) begin
                            // Even pass: compare and swap even-indexed pairs (0,1), (2,3), ...
                            if (data_array[2*pair_idx] > data_array[2*pair_idx+1]) begin
                                data_array[2*pair_idx] <= data_array[2*pair_idx+1];
                                data_array[2*pair_idx+1] <= data_array[2*pair_idx];
                            end
                        end else begin
                            // Odd pass: compare and swap odd-indexed pairs (1,2), (3,4), ...
                            if (data_array[2*pair_idx+1] > data_array[2*pair_idx+2]) begin
                                data_array[2*pair_idx+1] <= data_array[2*pair_idx+2];
                                data_array[2*pair_idx+2] <= data_array[2*pair_idx+1];
                            end
                        end
                        pair_idx <= pair_idx + 1;
                    end else begin
                        // End of current pass; move to the next pass.
                        pass_cnt <= pass_cnt + 1;
                        pair_idx <= 0;
                    end
                end
                DONE: begin
                    // Pack the sorted data into out_data and assert done for one clock cycle.
                    integer j;
                    for (j = 0; j < N; j = j + 1)
                        out_data[j*WIDTH +: WIDTH] <= data_array[j];
                    done <= 1'b1;
                end
                default: begin
                    // No operation.
                end
            endcase
        end
    end

endmodule

always @(*) begin
  // default assignments: next_state = current_state, etc.
  next_state = current_state;
  next_load_cnt = load_cnt;
  next_find_cnt = find_cnt;
  next_count_cnt = count_cnt;
  next_prefix_cnt = prefix_cnt;
  next_build_cnt = build_cnt;
  next_copy_cnt = copy_cnt;
  next_done = done;
  next_out_data = out_data;
  // and for arrays, next_data_array[i] = data_array[i] for all i, next_out_array[i] = out_array[i] for all i, next_count_array[j] = count_array[j] for all j.
  // Then based on state, update transitions.
end

