module sorting_engine #(
    parameter N = 8,             // Number of elements to sort
    parameter WIDTH = 8          // Bit-width of each element
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);

    // Internal array
    reg [WIDTH-1:0] array [0:N-1];

    // FSM states
    localparam IDLE    = 2'd0;
    localparam SORTING = 2'd1;
    localparam DONE    = 2'd2;

    reg [1:0] state, next_state;

    // Insertion sort variables
    integer i;
    integer j;
    reg [WIDTH-1:0] key;

    // Insertion sort phases for each i
    // 0: Initialize key and j
    // 1: Shift elements greater than key
    // 2: Insert key
    reg [1:0] insert_phase;

    // FSM: Next state logic
    always @(*) begin
        next_state = state;
        case (state)
            IDLE: begin
                if (start)
                    next_state = SORTING;
            end
            SORTING: begin
                // Once i reaches N, sorting is done
                if (i == N)
                    next_state = DONE;
            end
            DONE: begin
                next_state = IDLE;
            end
            default: next_state = IDLE;
        endcase
    end

    // FSM: main logic
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state         <= IDLE;
            done          <= 0;
            i             <= 0;
            j             <= 0;
            key           <= 0;
            insert_phase  <= 0;
        end else begin
            state <= next_state;

            case (state)
                IDLE: begin
                    done <= 0;
                    if (start) begin
                        // Load array from in_data
                        for (int k = 0; k < N; k = k + 1) begin
                            array[k] <= in_data[(k+1)*WIDTH-1 -: WIDTH];
                        end
                        i <= 1; // Start insertion sort from index 1
                        j <= 0;
                        key <= 0;
                        insert_phase <= 0;
                    end
                end

                SORTING: begin
                    // Perform insertion sort step-by-step
                    case (insert_phase)
                        0: begin
                            // Phase 0: Setup for inserting array[i]
                            if (i < N) begin
                                key <= array[i];
                                j <= i - 1;
                                insert_phase <= 1;
                            end
                            // If i == N, sorting complete, next cycle moves to DONE
                        end

                        1: begin
                            // Phase 1: Shift elements to the right until the correct spot is found
                            if (j >= 0 && array[j] > key) begin
                                array[j+1] <= array[j];
                                j <= j - 1;
                            end else begin
                                // We found the spot (or j < 0)
                                insert_phase <= 2;
                            end
                        end

                        2: begin
                            // Phase 2: Insert the key at array[j+1]
                            array[j+1] <= key;
                            i <= i + 1;
                            insert_phase <= 0; 
                        end

                        default: insert_phase <= 0;
                    endcase
                end

                DONE: begin
                    // Sorting complete, output the result
                    done <= 1;
                    for (int m = 0; m < N; m = m + 1) begin
                        out_data[(m+1)*WIDTH-1 -: WIDTH] <= array[m];
                    end
                end

                default: begin
                    // Should not get here
                end
            endcase
        end
    end

endmodule

output.rtl/soundgenerator.sv:
module soundgenerator #(
	parameter CLOCK_HZ = 10_000_000
)(
	input wire clk,                                         // Input clock signal with frequency 10MHz
	input wire nrst,                                        // Active low asynchronous reset
	input wire start,                                       // Signal to indicate the start of the operation
	input wire finish,                                      // Signal to indicate the end of the operation
	input wire [15:0] sond_dur_ms_i,                        // Duration (in milliseconds) for which the sound should be generated
	input wire [15:0] half_period_us_i,                     // Half period of the desired soundwave frequency (in microseconds)
	output wire soundwave_o,                                // Generated soundwave output signal
	output wire busy,                                       // Indicates that the system is actively generating sound
	output wire done                                        // Indicates that the sound generation operation is complete
);

	// Internal state declaration: IDLE and SOUND
	typedef enum logic { IDLE, SOUND } state_t;
	state_t state, state_next;
	logic busy_prev;

	// Counters for duration and half-period timing
	logic [15:0] duration_count;
	logic [15:0] halfperiod_timer;

	// Internal register for soundwave output
	logic soundwave_reg;

	// Drive outputs based on state
	assign busy   = (state == SOUND);
	assign soundwave_o = (state == SOUND) ? soundwave_reg : 1'b0;
	// The done signal is asserted for one cycle when busy transitions from high to low.
	assign done   = (!state && busy_prev);

	// Instantiate strob_gen modules for millisecond and microsecond strobe pulses
	wire tickmilli_strobe;
	wire tickmicro_strobe;

	strob_gen #(
		.CLOCK_HZ(10_000_000),
		.PERIOD_US(1000)  // 1 ms pulse
	) tickmilli_inst (
		.clk(clk),
		.nrst(nrst),
		.enable(busy),       // Enable strobe generation when in SOUND state
		.strobe_o(tickmilli_strobe)
	);

	strob_gen #(
		.CLOCK_HZ(10_000_000),
		.PERIOD_US(1)       // 1 us pulse
	) tickmicro_inst (
		.clk(clk),
		.nrst(nrst),
		.enable(busy),
		.strobe_o(tickmicro_strobe)
	);

	// State register update (synchronous to clk, asynchronous reset)
	always_ff @(posedge clk or negedge nrst) begin
		if (!nrst) begin
			state      <= IDLE;
			duration_count <= 16'd0;
			halfperiod_timer <= 16'd0;
			soundwave_reg <= 1'b0;
			busy_prev   <= 1'b0;
		end else begin
			busy_prev   <= busy;  // Capture previous busy for done detection
			state       <= state_next;
		end
	end

	// Next state logic and counter updates
	always_comb begin
		// Default: retain current state and no counter updates
		state_next = state;

		if (state == SOUND) begin
			// If finish is asserted or duration has elapsed, transition to IDLE
			if (finish || (duration_count == 16'd0))
				state_next = IDLE;
			else begin
				// On each 1ms strobe pulse, decrement the duration counter
				if (tickmilli_strobe)
					duration_count = duration_count - 16'd1;

				// On each 1us strobe pulse, update the half-period timer and toggle soundwave
				if (tickmicro_strobe) begin
					if (halfperiod_timer > 16'd0)
						halfperiod_timer = halfperiod_timer - 16'd1;
					else begin
						halfperiod_timer = half_period_us_i;
						soundwave_reg = ~soundwave_reg;
					end
				end
			end
		end else begin
			// In IDLE state, wait for start signal to begin sound generation
			if (start) begin
				state_next = SOUND;
				duration_count = sond_dur_ms_i;
				halfperiod_timer = half_period_us_i;
				soundwave_reg = 1'b0;
			end
		end
	end

endmodule

module strob_gen #(
	parameter CLOCK_HZ = 10_000_000,
	parameter PERIOD_US = 100
)(
	input wire clk,
	input wire nrst,
	input wire enable,
	output reg strobe_o
);

	// Calculate delay based on clock frequency and desired period (in microseconds)
	// DELAY = (CLOCK_HZ / 1,000,000) * PERIOD_US
	localparam integer DELAY = CLOCK_HZ / 1_000_000 * PERIOD_US;

	reg [31:0] counter;  // Wide enough counter to cover the delay period

	always_ff @(posedge clk or negedge nrst) begin
		if (!nrst) begin
			counter   <= DELAY;
			strobe_o  <= 1'b0;
		end else begin
			// When disabled, reset the counter and strobe output
			if (!enable) begin
				counter   <= DELAY;
				strobe_o  <= 1'b0;
			end else begin
				if (counter == 32'd0) begin
					strobe_o  <= 1'b1;
					counter   <= DELAY;
				end else begin
					strobe_o  <= 1'b0;
					counter   <= counter - 32'd1;
				end
			end
		end
	end

endmodule

output.rtl/sprite_fsm.sv:
module sprite_controller_fsm#(
   parameter MEM_ADDR_WIDTH = 16,
   parameter PIXEL_WIDTH    = 24,
   parameter SPRITE_WIDTH   = 16,
   parameter SPRITE_HEIGHT  = 16,
   parameter WAIT_WIDTH     = 4,
   parameter N_ROM          = 256
)(
   input  logic clk,
   input  logic rst_n,
   input  logic [WAIT_WIDTH-1:0] i_wait,
   output logic rw,                             
   output logic [MEM_ADDR_WIDTH-1:0] write_addr,
   output logic [PIXEL_WIDTH-1:0] write_data,   
   output logic [SPRITE_WIDTH-1:0] x_pos,       
   output logic [SPRITE_HEIGHT-1:0] y_pos,      
   input  logic [PIXEL_WIDTH-1:0] pixel_out,    
   output logic done                            
);

   // FSM state declaration
   typedef enum logic [2:0] {
       IDLE,
       INIT_WRITE,
       WRITE,
       INIT_READ,
       READ,
       WAIT,
       DONE
   } state_t;

   state_t current_state, next_state;

   // Counters
   logic [MEM_ADDR_WIDTH-1:0] addr_counter; 
   logic [PIXEL_WIDTH-1:0] data_counter;    
   logic [WAIT_WIDTH-1:0] wait_counter;     

   // Next state logic
   always_comb begin
       next_state = current_state; // default assignment
       case (current_state)
           IDLE:           next_state = INIT_WRITE;
           INIT_WRITE:     next_state = WRITE;
           WRITE: begin
               if (addr_counter == N_ROM - 1)
                   next_state = INIT_READ;
               else
                   next_state = WRITE;
           end
           INIT_READ:      next_state = READ;
           READ: begin
               if (addr_counter == N_ROM - 1)
                   next_state = WAIT;
               else
                   next_state = READ;
           end
           WAIT: begin
               if (wait_counter == i_wait)
                   next_state = DONE;
               else
                   next_state = WAIT;
           end
           DONE:           next_state = IDLE;
           default:        next_state = IDLE;
       endcase
   end

   // Sequential logic: state register and counter updates
   always_ff @(posedge clk or negedge rst_n) begin
       if (!rst_n) begin
           current_state  <= IDLE;
           addr_counter   <= '0;
           data_counter   <= '0;
           wait_counter   <= '0;
           done           <= 1'b0;
       end
       else begin
           current_state <= next_state;
           case (current_state)
               IDLE: begin
                   addr_counter  <= '0;
                   data_counter  <= '0;
                   wait_counter  <= '0;
                   done          <= 1'b0;
               end
               INIT_WRITE: begin
                   addr_counter <= '0; // ensure reset
               end
               WRITE: begin
                   addr_counter <= addr_counter + 1;
                   data_counter <= data_counter + 1;
               end
               INIT_READ: begin
                   addr_counter <= '0;
               end
               READ: begin
                   addr_counter <= addr_counter + 1;
               end
               WAIT: begin
                   wait_counter <= wait_counter + 1;
               end
               DONE: begin
                   done <= 1'b1;
               end
               default: begin
                   // No action
               end
           endcase
       end
   end

   // Output logic: drive outputs based on current state and counter values
   always_comb begin
       // Default assignments
       rw         = 1'b0;
       write_addr = addr_counter;
       write_data = data_counter;
       // Calculate sprite positions using modulus and division
       x_pos = addr_counter % SPRITE_WIDTH;
       y_pos = addr_counter / SPRITE_WIDTH;
       done  = 1'b0;

       case (current_state)
           IDLE: begin
               rw = 1'b0;
           end
           INIT_WRITE: begin
               rw         = 1'b1;
               write_data = 24'hFF0000;
           end
           WRITE: begin
               rw         = 1'b1;
               write_addr = addr_counter;
               write_data = data_counter;
           end
           INIT_READ: begin
               rw = 1'b0;
           end
           READ: begin
               rw         = 1'b0;
               write_addr = addr_counter; // Reused for addressing read operations
               // x_pos and y_pos already computed above
           end
           WAIT: begin
               rw = 1'b0;
           end
           DONE: begin
               done = 1'b1;
           end
       endcase
   end

endmodule

input.rtl/Bitstream.sv:
module Bitstream(input  logic clk,rst_n,
                 input  logic enb,
                 input  logic rempty_in,
                 input  logic rinc_in,
                 input  logic [7:0] i_byte,
                 output logic o_bit,
                 output logic rempty_out,
                 output logic rinc_out);

    parameter IDLE  = 3'b000;
    parameter WaitR = 3'b001;
    parameter Ready = 3'b010;
    logic [1:0] curr_state,next_state;

    logic [0:7] byte_buf;
    logic [3:0] bp;
    logic rde;

    //FSM block

    always_ff @(posedge clk) begin
        if(!rst_n) curr_state <= IDLE;
        else curr_state <= next_state;
    end

    always_comb begin
        case(curr_state)
            IDLE: next_state = Ready;
            IDLE:begin
                if(enb)begin
                    next_state = WaitR;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
                else begin
                    next_state = IDLE;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
            end
            WaitR:begin
                if(rempty_in)begin
                    next_state = WaitR;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
                else begin
                    next_state = Ready;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b1;
                end
            end
            Ready:begin
                if(rde)begin
                    if(rempty_in)begin
                        next_state = WaitR;
                        rempty_out = 1'b1;
                        rinc_out   = 1'b0;
                    end
                    else begin
                        next_state = Ready;
                        rempty_out = 1'b1;
                        rinc_out   = 1'b1;
                    end
                end
                else begin
                    next_state = Ready;
                    rempty_out = 1'b0;
                    rinc_out   = 1'b0;
                end
            end
            default:begin
                next_state = IDLE;
                rempty_out = 1'b1;
                rinc_out   = 1'b0;
            end
        endcase
    end

    always @(posedge clk) begin
        if(rinc_out) 
           byte_buf <= i_byte[7:1];
    end

    always @(posedge clk) begin
        if(rinc_out) 
            bp <= 4'b0;
        else 
            if(rinc_in & ~rempty_out) 
               bp <= bp + 1'b1;
    end

    //Other comb logic

    assign rde = bp[3];
    assign o_bit = byte_buf[bp];

endmodule

output.rtl/Bitstream.sv:
module Bitstream(input  logic clk, rst_n,
                 input  logic enb,
                 input  logic rempty_in,
                 input  logic rinc_in,
                 input  logic [7:0] i_byte,
                 output logic o_bit,
                 output logic rempty_out,
                 output logic rinc_out);

    // Define states using a consistent 3-bit width
    parameter IDLE  = 3'b000;
    parameter WaitR = 3'b001;
    parameter Ready = 3'b010;

    // Use a 3-bit state register to match the parameter width
    logic [2:0] curr_state, next_state;

    // Correct the byte buffer declaration to use the proper bit order and full width
    logic [7:0] byte_buf;

    // Reduce bp width to 3 bits (indices 0 to 7) and update related logic
    logic [2:0] bp;
    logic rde;

    // FSM state register with asynchronous reset
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            curr_state <= IDLE;
        else
            curr_state <= next_state;
    end

    // FSM next state logic with non-overlapping case conditions
    always_comb begin
        case (curr_state)
            IDLE: begin
                if (enb)
                    next_state = WaitR;
                else
                    next_state = IDLE;
                rempty_out = 1'b1;
                rinc_out   = 1'b0;
            end

            WaitR: begin
                if (rempty_in) begin
                    next_state = WaitR;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end else begin
                    next_state = Ready;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b1;
                end
            end

            Ready: begin
                if (rde) begin
                    if (rempty_in) begin
                        next_state = WaitR;
                        rempty_out = 1'b1;
                        rinc_out   = 1'b0;
                    end else begin
                        next_state = Ready;
                        rempty_out = 1'b1;
                        rinc_out   = 1'b1;
                    end
                end else begin
                    next_state = Ready;
                    rempty_out = 1'b0;
                    rinc_out   = 1'b0;
                end
            end

            default: begin
                next_state = IDLE;
                rempty_out = 1'b1;
                rinc_out   = 1'b0;
            end
        endcase
    end

    // Update the byte buffer with the full 8-bit value (avoiding truncation)
    always_ff @(posedge clk) begin
        if (rinc_out)
            byte_buf <= i_byte;
    end

    // Update the bit position counter. When rinc_out is high, reset bp; otherwise, increment bp if allowed.
    always_ff @(posedge clk) begin
        if (rinc_out)
            bp <= 3'b0;
        else if (rinc_in & ~rempty_out)
            bp <= bp + 1'b1;
    end

    // Generate the ready signal from the MSB of bp and extract the current bit from byte_buf
    assign rde = bp[2];
    assign o_bit = byte_buf[bp];

endmodule

input.rtl/square_root.sv:
module square_root #(parameter WIDTH = 16) (
    input  wire [WIDTH-1:0] num,       
    output reg  [WIDTH/2-1:0] root     
);
    reg [WIDTH-1:0] remainder,square;         
    reg [WIDTH/2-1:0] test_bit, temp_square;        
    integer i,j;

    always @(*) 
    begin
        remainder = num;               
        root = 0;                      
        temp_square = 0;


        for (i = WIDTH/2-1; i >= 0; i = i - 1) 
        begin
            test_bit = 1'b1 << i;      
            temp_square = (root | test_bit);        
            square = 0; 
            for (j = 0; j < WIDTH; j = j + 1) 
            begin
              if (temp_square[j]) 
              begin 
                  square = square + (temp_square << j); 
              end 
            end

            if (square <= remainder) 
            begin
                root = root | test_bit; 
            end
        end
    end
endmodule

output.rtl/square_root_seq.sv:
module square_root_seq #(parameter WIDTH = 16) (
    input  wire clk,
    input  wire rst,
    input  wire start,
    input  wire [WIDTH-1:0] num,
    output reg  [WIDTH/2-1:0] final_root,
    output reg  done
);

    // State encoding: 00 = IDLE, 01 = COMPUTE, 10 = DONE
    localparam IDLE   = 2'b00;
    localparam COMPUTE = 2'b01;
    localparam DONE   = 2'b10;

    reg [1:0] state;
    reg [WIDTH-1:0] remainder;
    reg [WIDTH-1:0] odd;
    reg [WIDTH/2-1:0] root_reg; // holds the computed square root

    // Sequential process: state machine with asynchronous reset
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state         <= IDLE;
            remainder     <= 0;
            odd           <= 0;
            root_reg      <= 0;
            done          <= 0;
            final_root    <= 0;
        end else begin
            case (state)
                IDLE: begin
                    // Wait for start signal
                    if (start) begin
                        remainder <= num;   // initialize remainder with input number
                        odd       <= 1;     // first odd number is 1
                        root_reg  <= 0;     // reset square root counter
                        state     <= COMPUTE;
                    end
                    // When not started, hold outputs
                    done          <= 0;
                    final_root    <= final_root;
                end

                COMPUTE: begin
                    // Subtraction-based iterative algorithm
                    if (remainder >= odd) begin
                        remainder <= remainder - odd;
                        root_reg  <= root_reg + 1;
                        odd       <= odd + 2;
                        state     <= COMPUTE;
                    end else begin
                        // When remainder is less than the current odd number,
                        // assign the computed square root and transition to DONE state.
                        final_root <= root_reg;
                        state      <= DONE;
                    end
                end

                DONE: begin
                    // Assert done for one clock cycle to indicate completion
                    done <= 1;
                    state <= IDLE;
                end

                default: state <= IDLE;
            endcase
        end
    end

endmodule

output.rtl/static_branch_predict.sv:
module static_branch_predict (
    input  logic [31:0] fetch_rdata_i,  // Fetched 32-bit instruction
    input  logic [31:0] fetch_pc_i,     // Current program counter
    input  logic        fetch_valid_i,  // Indicates valid instruction
    output logic        predict_branch_taken_o, // 1 if branch/jump is predicted taken
    output logic [31:0] predict_branch_pc_o    // Predicted target address
);

  // Local parameters for instruction opcodes
  localparam logic [6:0] OPCODE_BRANCH = 7'h63; // Uncompressed branch (BXXX, C.BEQZ/C.BNEZ)
  localparam logic [6:0] OPCODE_JAL    = 7'h6F; // Uncompressed jump (JAL, C.JAL)
  localparam logic [6:0] OPCODE_JALR   = 7'h67; // Uncompressed jump and link register (JALR)

  // Wires for immediate extraction and prediction logic
  logic [31:0] imm_j_type;  // Immediate for jump instructions (JAL or JALR)
  logic [31:0] imm_b_type;  // Immediate for branch instructions (BXXX or compressed branch)
  logic        taken;       // Internal signal: 1 if branch/jump is predicted taken
  logic [31:0] branch_imm;  // Final immediate/sign-extended offset used for target address calculation

  always_comb begin
    // Default assignments
    predict_branch_taken_o = 1'b0;
    predict_branch_pc_o    = 32'd0;
    taken                  = 1'b0;
    branch_imm             = 32'd0;

    if (fetch_valid_i) begin
      // Decode the opcode from bits [6:0] of the instruction
      case (fetch_rdata_i[6:0])
        // For jump instructions (JAL or C.JAL): Always predict as taken.
        OPCODE_JAL: begin
          // Immediate extraction for JAL:
          // {imm[20], imm[10:1], imm[11], imm[30:21], 1'b0} sign-extended with {{12{instr[31]}}}
          imm_j_type = {{12{fetch_rdata_i[31]}}, fetch_rdata_i[19:12], fetch_rdata_i[20], fetch_rdata_i[30:21], 1'b0};
          taken      = 1'b1;
          branch_imm = imm_j_type;
        end

        // For jump and link register (JALR): Always predict as taken.
        OPCODE_JALR: begin
          // Immediate extraction for JALR:
          // {imm[11:0]} sign-extended with {{20{instr[31]}}}
          imm_j_type = {{20{fetch_rdata_i[31]}}, fetch_rdata_i[31:20]};
          taken      = 1'b1;
          branch_imm = imm_j_type;
        end

        // For branch instructions (BXXX, C.BEQZ/C.BNEZ):
        OPCODE_BRANCH: begin
          // Immediate extraction for branch:
          // {imm[12], imm[10:5], imm[4:1], imm[11]} with sign extension:
          // imm_b_type = {{19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0}
          imm_b_type = {{19{fetch_rdata_i[31]}}, fetch_rdata_i[31], fetch_rdata_i[7],
                        fetch_rdata_i[30:25], fetch_rdata_i[11:8], 1'b0};
          // For static branch prediction, if the sign bit of the immediate is 1, predict branch as taken.
          taken      = imm_b_type[31];
          branch_imm = imm_b_type;
        end

        // For any other instruction, do not predict as taken.
        default: begin
          taken      = 1'b0;
          branch_imm = 32'd0;
        end
      endcase

      // Calculate the predicted target address by adding the sign-extended immediate to the current PC.
      predict_branch_taken_o = taken;
      predict_branch_pc_o    = fetch_pc_i + branch_imm;
    end
  end

endmodule

input.rtl/static_branch_predict.sv:
module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;


  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  assign imm_jal_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
  assign imm_jalr_type = {{20{instr[31]}}, instr[31:20]}+reg_addr;
  assign imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };

  assign imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7],
    instr[2], instr[11], instr[5:3], 1'b0 };

  assign imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10],
    instr[4:3], 1'b0};

  assign instr_b    = instr[6:0] == OPCODE_BRANCH;
  assign instr_jal  = instr[6:0] == OPCODE_JAL;
  assign instr_jalr = instr[6:0] == OPCODE_JALR;

  assign instr_cb = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b110) | (instr[15:13] == 3'b111));
  assign instr_cj = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b101) | (instr[15:13] == 3'b001));

  always_comb begin
    branch_imm = imm_b_type;

    case(1'b1)
      instr_jal  : branch_imm = imm_jal_type;
      instr_jalr : branch_imm = imm_jalr_type;
      instr_b    : branch_imm = imm_b_type;
      instr_cj   : branch_imm = imm_cj_type;
      instr_cb   : branch_imm = imm_cb_type;
      default    : ;
    endcase
  end
  assign predict_branch_pc_o    = fetch_pc_i + branch_imm; 
  assign instr_b_taken = (instr_b & imm_b_type[31]) | (instr_cb & imm_cb_type[31]);
  assign predict_branch_taken_o = fetch_valid_i & (instr_jal | instr_jalr | instr_cj | instr_b_taken);

endmodule

output.rtl/static_branch_predict.sv:
module static_branch_predict (
  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o,
  output logic [7:0]  predict_confidence_o,
  output logic        predict_exception_o,
  output logic [2:0]  predict_branch_type_o,
  output logic [31:0] predict_branch_offset_o
);

  // Internal signals for immediate extraction and instruction decoding
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  // Opcode definitions
  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  // Connect inputs to internal signals
  assign instr  = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  // Immediate extraction for jump and branch instructions
  assign imm_jal_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
  assign imm_jalr_type = {{20{instr[31]}}, instr[31:20]} + reg_addr;
  assign imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };

  assign imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7],
                          instr[2], instr[11], instr[5:3], 1'b0 };

  assign imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10],
                          instr[4:3], 1'b0};

  // Instruction type detection based on opcode and compressed format
  assign instr_b    = (instr[6:0] == OPCODE_BRANCH);
  assign instr_jal  = (instr[6:0] == OPCODE_JAL);
  assign instr_jalr = (instr[6:0] == OPCODE_JALR);

  assign instr_cb = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b110) | (instr[15:13] == 3'b111));
  assign instr_cj = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b101) | (instr[15:13] == 3'b001));

  // Combinational logic implementing Value Range Propagation for static branch prediction
  always_comb begin
    // Default assignments for outputs
    predict_branch_taken_o     = 1'b0;
    predict_confidence_o       = 8'd0;
    predict_branch_type_o      = 3'd0;
    predict_branch_offset_o    = 32'd0;
    branch_imm                 = 32'd0;

    if(fetch_valid_i) begin
      if(instr_jal) begin
         branch_imm = imm_jal_type;
         predict_confidence_o = 8'd100;  // Jump instructions always predicted taken
         predict_branch_type_o = 3'b001; // JAL type
      end else if(instr_jalr) begin
         branch_imm = imm_jalr_type;
         predict_confidence_o = 8'd100;  // JALR always predicted taken
         predict_branch_type_o = 3'b010; // JALR type
      end else if(instr_b) begin
         branch_imm = imm_b_type;
         // For branch instructions: negative offset (backward) gets 90% confidence; forward gets 50%
         if(imm_b_type[31])
            predict_confidence_o = 8'd90;
         else
            predict_confidence_o = 8'd50;
         predict_branch_type_o = 3'b011; // Branch type
      end else if(instr_cj) begin
         branch_imm = imm_cj_type;
         predict_confidence_o = 8'd100;  // Compressed jump always taken
         predict_branch_type_o = 3'b100; // Compressed Jump type
      end else if(instr_cb) begin
         branch_imm = imm_cb_type;
         // For compressed branch: negative offset gets 90% confidence; forward gets 50%
         if(imm_cb_type[31])
            predict_confidence_o = 8'd90;
         else
            predict_confidence_o = 8'd50;
         predict_branch_type_o = 3'b101; // Compressed Branch type
      end else begin
         // For unrecognized instructions, defaults remain (0% confidence, not taken)
      end

      // Prediction decision: if confidence > 50%, predict branch taken
      if(predict_confidence_o > 8'd50)
         predict_branch_taken_o = 1'b1;
      else
         predict_branch_taken_o = 1'b0;

      // Output the branch offset as the extracted immediate value
      predict_branch_offset_o = branch_imm;
    end
  end

  // Calculate the predicted target address by adding the sign-extended immediate to the fetch PC
  assign predict_branch_pc_o = fetch_pc_i + branch_imm;

  // Misalignment detection: if fetch_pc_i is not word aligned (lower 2 bits not zero), flag an exception
  assign predict_exception_o = (fetch_pc_i[1:0] != 2'b00);

endmodule

module static_branch_predict (
    // Instruction from fetch stage
    input  logic [31:0] fetch_rdata_i,
    input  logic [31:0] fetch_pc_i,
    input  logic [31:0] register_addr_i,
    input  logic        fetch_valid_i,

    // Prediction for supplied instruction
    output logic        predict_branch_taken_o,
    output logic [31:0] predict_branch_pc_o
);

  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  // Assign fetched values
  assign instr  = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  // Combinational logic for branch prediction
  always_comb begin
      // Calculate immediates based on instruction format

      // JAL immediate: bits [31:20] sign-extended, bits [19:12], bit[20], bits[30:21], and LSB = 0
      imm_jal_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0};

      // JALR immediate: 12-bit immediate sign-extended, then added to register address
      imm_jalr_type = reg_addr + {{20{instr[31]}}, instr[31:20]};

      // B-type immediate: sign-extend bit31, then bits [7], [30:25], [11:8], and LSB = 0
      imm_b_type = {{19{instr[31]}}, instr[7], instr[30:25], instr[11:8], 1'b0};

      // CJ immediate: for compressed jump, extract immediate from bits [15:2]
      imm_cj_type = {{14{instr[15]}}, instr[12:10], instr[6:2], 1'b0};

      // CB immediate: for compressed branch, extract immediate similarly
      imm_cb_type = {{14{instr[15]}}, instr[12:10], instr[6:2], 1'b0};

      // Decode instruction types based on opcode fields
      instr_jal  = (instr[6:0] == 7'h6F);  // JAL
      instr_jalr = (instr[6:0] == 7'h67);  // JALR
      instr_b    = (instr[6:0] == 7'h63);  // B-type branch

      // For compressed instructions, use bits [15:13]
      instr_cj   = (instr[15:13] == 3'b110); // CJ compressed jump
      instr_cb   = (instr[15:13] == 3'b111); // CB compressed branch

      // Select branch immediate based on the decoded instruction type
      if (instr_jal) begin
          branch_imm = imm_jal_type;
      end else if (instr_jalr) begin
          branch_imm = imm_jalr_type;
      end else if (instr_b) begin
          branch_imm = imm_b_type;
      end else if (instr_cj) begin
          branch_imm = imm_cj_type;
      end else if (instr_cb) begin
          branch_imm = imm_cb_type;
      end else begin
          // Default fallback (should not occur for branch instructions)
          branch_imm = imm_b_type;
      end

      // Branch taken decision
      // For JAL, JALR, and CJ, branch is always predicted as taken.
      if (instr_jal || instr_jalr || instr_cj) begin
          predict_branch_taken_o = 1'b1;
      end
      // For B-type and CB-type, branch is taken if the sign bit of the immediate is set.
      else if (instr_b || instr_cb) begin
          predict_branch_taken_o = (instr_b ? imm_b_type[31] : 1'b0) |
                                   (instr_cb ? imm_cb_type[31] : 1'b0);
      end
      else begin
          predict_branch_taken_o = 1'b0;
      end

      // Calculate predicted branch target address by adding the immediate to the current PC
      predict_branch_pc_o = fetch_pc_i + branch_imm;
  end

endmodule

module static_branch_predict(
  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o,

  // Additional outputs
  output logic [7:0]  predict_confidence_o,   // Confidence level in prediction
  output logic        predict_exception_o,    // Exception/misalignment detection
  output logic [2:0]  predict_branch_type_o,  // Type of branch
  output logic [31:0] predict_branch_offset_o // Calculated branch offset
);

  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;
  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  // Combinational always block for branch prediction logic
  always_comb begin
    // Default assignments when fetch is not valid
    if (!fetch_valid_i) begin
      predict_confidence_o   = 8'd0;
      predict_branch_taken_o = 1'b0;
      predict_branch_pc_o    = 32'd0;
      predict_exception_o    = 1'b0;
      predict_branch_type_o  = 3'd0;
      predict_branch_offset_o= 32'd0;
    end
    else begin
      // Assign internal registers
      instr  = fetch_rdata_i;
      reg_addr = register_addr_i;

      // Decode the instruction type based on opcode bits
      instr_jal  = (instr[6:0] == 7'h6F); // JAL
      instr_jalr = (instr[6:0] == 7'h67); // JALR
      instr_b    = (instr[6:0] == 7'h63); // B-type

      // For compressed instructions, assume that if none of the above match,
      // then the instruction is compressed. Use bit[12] to differentiate:
      //   - CJ: if instr[12] == 1
      //   - CB: if instr[12] == 0
      instr_cj = (~instr_jal & ~instr_jalr & ~instr_b) & (instr[12] == 1);
      instr_cb = (~instr_jal & ~instr_jalr & ~instr_b) & (instr[12] == 0);

      // Calculate immediate values based on instruction type
      if (instr_jal) begin
        imm_jal_type = { {12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
        imm_jalr_type = '0;
        imm_b_type = '0;
        imm_cj_type = '0;
        imm_cb_type = '0;
      end
      else if (instr_jalr) begin
        imm_jalr_type = {{20{instr[31]}}, instr[31:20]} + reg_addr;
        imm_jal_type = '0;
        imm_b_type = '0;
        imm_cj_type = '0;
        imm_cb_type = '0;
      end
      else if (instr_b) begin
        imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };
        imm_jal_type = '0;
        imm_jalr_type = '0;
        imm_cj_type = '0;
        imm_cb_type = '0;
      end
      else if (instr_cj) begin
        imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7],
                        instr[2], instr[11], instr[5:3], 1'b0 };
        imm_jal_type = '0;
        imm_jalr_type = '0;
        imm_b_type = '0;
        imm_cb_type = '0;
      end
      else if (instr_cb) begin
        imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10], instr[4:3], 1'b0 };
        imm_jal_type = '0;
        imm_jalr_type = '0;
        imm_b_type = '0;
        imm_cj_type = '0;
      end

      // Default assignments for outputs
      predict_branch_pc_o    = fetch_pc_i;
      predict_confidence_o   = 8'd0;
      predict_branch_taken_o = 1'b0;
      predict_branch_type_o  = 3'd0;
      predict_branch_offset_o= 32'd0;

      // Exception detection: check for proper PC alignment (assumed 4-byte alignment)
      predict_exception_o = (fetch_pc_i[1:0] != 2'b00);

      // Branch prediction decision and target address calculation
      if (instr_jal) begin
        // JAL: always taken with full confidence
        predict_branch_type_o  = 3'b000; // Encoding for JAL
        predict_confidence_o   = 8'd100;
        predict_branch_taken_o = 1'b1;
        predict_branch_offset_o= imm_jal_type;
        predict_branch_pc_o    = fetch_pc_i + imm_jal_type;
      end
      else if (instr_jalr) begin
        // JALR: always taken with full confidence
        predict_branch_type_o  = 3'b001; // Encoding for JALR
        predict_confidence_o   = 8'd100;
        predict_branch_taken_o = 1'b1;
        predict_branch_offset_o= imm_jalr_type;
        predict_branch_pc_o    = fetch_pc_i + imm_jalr_type;
      end
      else if (instr_b) begin
        // B-type: taken if sign bit of immediate is set, otherwise not taken
        predict_branch_type_o  = 3'b010; // Encoding for B-type
        if (imm_b_type[31]) begin
          predict_confidence_o   = 8'd90;
          predict_branch_taken_o = 1'b1;
        end
        else begin
          predict_confidence_o   = 8'd50;
          predict_branch_taken_o = 1'b0;
        end
        predict_branch_offset_o= imm_b_type;
        predict_branch_pc_o    = fetch_pc_i + imm_b_type;
      end
      else if (instr_cj) begin
        // CJ: similar logic as B-type using imm_cj_type
        predict_branch_type_o  = 3'b011; // Encoding for CJ
        if (imm_cj_type[31]) begin
          predict_confidence_o   = 8'd90;
          predict_branch_taken_o = 1'b1;
        end
        else begin
          predict_confidence_o   = 8'd50;
          predict_branch_taken_o = 1'b0;
        end
        predict_branch_offset_o= imm_cj_type;
        predict_branch_pc_o    = fetch_pc_i + imm_cj_type;
      end
      else if (instr_cb) begin
        // CB: similar logic as B-type using imm_cb_type
        predict_branch_type_o  = 3'b100; // Encoding for CB
        if (imm_cb_type[31]) begin
          predict_confidence_o   = 8'd90;
          predict_branch_taken_o = 1'b1;
        end
        else begin
          predict_confidence_o   = 8'd50;
          predict_branch_taken_o = 1'b0;
        end
        predict_branch_offset_o= imm_cb_type;
        predict_branch_pc_o    = fetch_pc_i + imm_cb_type;
      end
      else begin
        // If none of the known branch types match, assume no branch
        predict_branch_type_o  = 3'b000;
        predict_confidence_o   = 8'd0;
        predict_branch_taken_o = 1'b0;
        predict_branch_offset_o= 32'd0;
        predict_branch_pc_o    = fetch_pc_i;
      end
    end
  end

endmodule

