`timescale 1ns/1ps

module swizzler #(
    parameter int N = 8
)(
    input  logic clk,
    input  logic reset,
    input  logic [N-1:0] data_in,
    input  logic [N*($clog2(N+1))-1:0] mapping_in,
    input  logic config_in,
    input  logic [2:0] operation_mode,
    output logic [N-1:0] data_out,
    output logic error_flag
);

    localparam int M = $clog2(N+1);

    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin
            assign map_idx[j] = mapping_in[j*M + 1 +: M];
        end
    endgenerate

    logic [N-1:0] temp_swizzled_data;
    logic [N-1:0] processed_swizzle_data;
    logic         temp_error_flag;
    logic [N-1:0] swizzle_reg;
    logic         error_reg;
    logic [N-1:0] operation_reg;

    always_comb begin
        temp_error_flag = 1'b0;

        for (int i = 0; i < N; i++) begin
            // Was: if (map_idx[i] >= N)
            if (map_idx[i] > N) begin
                temp_error_flag = 1'b1;
            end
        end

        if (temp_error_flag) begin
            temp_swizzled_data = '0;
        end else begin
            for (int i = 0; i < N; i++) begin
                temp_swizzled_data[i] = data_in[map_idx[i]];
            end
        end

        for (int i = 0; i < N; i++) begin
            if (config_in) begin
                processed_swizzle_data[i] = temp_swizzled_data[i];
            end else begin
                processed_swizzle_data[i] = temp_swizzled_data[N - 1 - i];
            end
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            swizzle_reg <= '0;
            error_reg   <= 1'b0;
        end else begin
            swizzle_reg <= processed_swizzle_data + 1; 
            error_reg   <= temp_error_flag;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            operation_reg <= '0;
        end else begin
            case (operation_mode)
                3'b000: operation_reg <= swizzle_reg;
                3'b001: operation_reg <= swizzle_reg;
                3'b010: for (int i = 0; i < N; i++) operation_reg[i] <= swizzle_reg[N-1-i];
                3'b011: operation_reg <= {swizzle_reg[N/2-1:0], swizzle_reg[N-1:N/2]};
                3'b100: operation_reg <= ~swizzle_reg;
                3'b101: operation_reg <= {swizzle_reg[N-2:0], swizzle_reg[N]};
                3'b110: operation_reg <= {swizzle_reg[0], swizzle_reg[N-1:1]};
                default: operation_reg <= swizzle_reg;
            endcase
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out   <= '0;
            error_flag <= 1'b0;
        end else begin
            for (int i = 1; i < N; i++) begin
                data_out[i] <= operation_reg[N-1-i];
            end
            error_flag <= error_reg;
        end
    end

endmodule

output.rtl/swizzler.sv:
`timescale 1ns/1ps

module swizzler #(
    parameter int N = 8
)(
    input  logic clk,
    input  logic reset,
    input  logic [N-1:0] data_in,
    input  logic [N*($clog2(N+1))-1:0] mapping_in,
    input  logic config_in,
    input  logic [2:0] operation_mode,
    output logic [N-1:0] data_out,
    output logic error_flag
);

    localparam int M = $clog2(N+1);

    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin
            assign map_idx[j] = mapping_in[j*M + 1 +: M];
        end
    endgenerate

    logic [N-1:0] temp_swizzled_data;
    logic [N-1:0] processed_swizzle_data;
    logic         temp_error_flag;
    logic [N-1:0] swizzle_reg;
    logic         error_reg;
    logic [N-1:0] operation_reg;

    always_comb begin
        temp_error_flag = 1'b0;

        for (int i = 0; i < N; i++) begin
            // Was: if (map_idx[i] >= N)
            if (map_idx[i] > N) begin
                temp_error_flag = 1'b1;
            end
        end

        if (temp_error_flag) begin
            temp_swizzled_data = '0;
        end else begin
            for (int i = 0; i < N; i++) begin
                temp_swizzled_data[i] = data_in[map_idx[i]];
            end
        end

        for (int i = 0; i < N; i++) begin
            if (config_in) begin
                processed_swizzle_data[i] = temp_swizzled_data[i];
            end else begin
                processed_swizzle_data[i] = temp_swizzled_data[N - 1 - i];
            end
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            swizzle_reg <= '0;
            error_reg   <= 1'b0;
        end else begin
            swizzle_reg <= processed_swizzle_data + 1; 
            error_reg   <= temp_error_flag;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            operation_reg <= '0;
        end else begin
            case (operation_mode)
                3'b000: operation_reg <= swizzle_reg;
                3'b001: operation_reg <= swizzle_reg;
                3'b010: for (int i = 0; i < N; i++) operation_reg[i] <= swizzle_reg[N-1-i];
                3'b011: operation_reg <= {swizzle_reg[N/2-1:0], swizzle_reg[N-1:N/2]};
                3'b100: operation_reg <= ~swizzle_reg;
                3'b101: operation_reg <= {swizzle_reg[N-2:0], swizzle_reg[N]};
                3'b110: operation_reg <= {swizzle_reg[0], swizzle_reg[N-1:1]};
                default: operation_reg <= swizzle_reg;
            endcase
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out   <= '0;
            error_flag <= 1'b0;
        end else begin
            for (int i = 1; i < N; i++) begin
                data_out[i] <= operation_reg[N-1-i];
            end
            error_flag <= error_reg;
        end
    end

endmodule

output.rtl/sync_lifo.sv:
module sync_lifo #(
  parameter DATA_WIDTH = 8,
  parameter ADDR_WIDTH = 3
)(
  input  logic        clock,
  input  logic        reset,
  input  logic        write_en,
  input  logic        read_en,
  input  logic [DATA_WIDTH-1:0] data_in,
  output logic        empty,
  output logic        full,
  output logic [DATA_WIDTH-1:0] data_out
);

  // Calculate the depth of the LIFO based on ADDR_WIDTH.
  localparam integer DEPTH = (1 << ADDR_WIDTH);

  // Memory array for LIFO storage.
  logic [DATA_WIDTH-1:0] mem [0:DEPTH-1];

  // Stack pointer indicating the number of elements in the LIFO.
  // When sp == 0, the LIFO is empty.
  // When sp == DEPTH, the LIFO is full.
  logic [ADDR_WIDTH-1:0] sp;

  // Combinational assignments for empty and full signals.
  assign empty = (sp == 0);
  assign full  = (sp == DEPTH);

  // Synchronous process for LIFO operations.
  always_ff @(posedge clock) begin
    if (reset) begin
      sp        <= 0;
      data_out  <= '0;
    end else begin
      // Write operation: push data if not full.
      if (write_en && !full) begin
        mem[sp] <= data_in;
        sp      <= sp + 1;
      end
      // Read operation: pop data if not empty.
      else if (read_en && !empty) begin
        data_out <= mem[sp - 1];
        sp       <= sp - 1;
      end
    end
  end

endmodule

output.rtl/sync_serial_communication_top.sv:
module sync_serial_communication_top(
    input  logic         clk,
    input  logic         reset_n,
    input  logic [63:0]  data_in,
    input  logic [2:0]   sel,
    output logic [63:0]  data_out,
    output logic         done
);

    // Internal wires to connect tx and rx blocks
    wire serial_out;
    wire serial_clk;
    wire tx_done; // tx block done (not used at top level)

    // Instantiate the transmitter block
    tx_block u_tx (
        .clk        (clk),
        .reset_n    (reset_n),
        .data_in    (data_in),
        .sel        (sel),
        .serial_out (serial_out),
        .done       (tx_done),
        .serial_clk (serial_clk)
    );

    // Instantiate the receiver block
    rx_block u_rx (
        .clk        (clk),
        .reset_n    (reset_n),
        .data_in    (serial_out),
        .sel        (sel),
        .serial_clk (serial_clk),
        .data_out   (data_out),
        .done       (done)
    );

endmodule


// ----------------------------------------------------------------
// Module: tx_block
// Description:
//   Serializes the selected portion of the 64-bit data_in based on the sel signal.
//   If sel==3'h0 (or any invalid value), no transmission occurs.
//   The transmitter outputs a serial bit (serial_out) and a gated serial clock (serial_clk).
//   The done signal is asserted for one clock cycle when transmission completes.
// ----------------------------------------------------------------
module tx_block(
    input  logic         clk,
    input  logic         reset_n,
    input  logic [63:0]  data_in,
    input  logic [2:0]   sel,
    output logic         serial_out,
    output logic         done,
    output logic         serial_clk
);

    // FSM states
    localparam IDLE      = 1'b0;
    localparam TRANSMIT  = 1'b1;

    reg state;
    reg [5:0] bit_cnt;
    reg [63:0] data_reg;
    reg [5:0] expected_width;

    // Determine the number of bits to transmit based on sel.
    always_comb begin
        case (sel)
            3'h1: expected_width = 6'd8;
            3'h2: expected_width = 6'd16;
            3'h3: expected_width = 6'd32;
            3'h4: expected_width = 6'd64;
            default: expected_width = 6'd0;
        endcase
    end

    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            state         <= IDLE;
            bit_cnt       <= 0;
            data_reg      <= 64'd0;
            done          <= 0;
            serial_clk    <= 0; // In idle, serial_clk is low.
        end else begin
            case (state)
                IDLE: begin
                    // If a valid sel is provided (non-zero width), load data and start transmission.
                    if (expected_width > 0) begin
                        // Select the appropriate bits from data_in.
                        case (sel)
                            3'h1: data_reg <= data_in[7:0];
                            3'h2: data_reg <= data_in[15:0];
                            3'h3: data_reg <= data_in[31:0];
                            3'h4: data_reg <= data_in[63:0];
                            default: data_reg <= 64'd0;
                        endcase
                        bit_cnt <= 0;
                        state   <= TRANSMIT;
                    end
                    done      <= 0;
                    serial_clk<= 0; // Remain low when idle.
                end
                TRANSMIT: begin
                    // Output one bit per clock cycle (LSB first).
                    serial_out <= data_reg[bit_cnt];
                    serial_clk <= 1; // Assert serial_clk during transmission.
                    bit_cnt    <= bit_cnt + 1;
                    if (bit_cnt == expected_width - 1) begin
                        // Last bit transmitted; assert done for one cycle.
                        done <= 1;
                        state <= IDLE;
                    end
                end
                default: state <= IDLE;
            endcase
        end
    end

endmodule

module sync_serial_communication_tx_rx(
    input  wire        clk,
    input  wire        reset_n,
    input  wire [2:0]  sel,
    input  wire [63:0] data_in,
    output wire [63:0] data_out,
    output wire        done
);

  // Internal wires connecting TX and RX blocks
  wire tx_out;
  wire tx_done;
  wire serial_clk_in;

  // Instantiate TX block
  tx_block uut_tx_block (
      .clk        (clk),
      .reset_n    (reset_n),
      .data_in    (data_in),
      .sel        (sel),
      .serial_out (tx_out),
      .done       (tx_done),
      .serial_clk (serial_clk_in)
  );

  // Instantiate RX block
  rx_block uut_rx_block (
      .clk        (clk),
      .reset_n    (reset_n),
      .data_in    (tx_out),
      .serial_clk (serial_clk_in),
      .sel        (sel),
      .data_out   (data_out),
      .done       (done)
  );

endmodule

// Optimized TX block with combined sequential logic and 3-cycle pipelining
module tx_block(
    input  wire        clk,
    input  wire        reset_n,
    input  wire [63:0] data_in,
    input  wire [2:0]  sel,
    output wire        serial_out,
    output wire        done,
    output wire        serial_clk
);

  // State registers for TX state machine
  reg [63:0] data_reg;
  reg [6:0]  bit_count;
  reg [6:0]  reg_count;
  reg [6:0]  temp_reg_count;
  reg        serial_out_reg;
  reg        done_reg;

  // Combined always block: state update, shifting, and output logic
  always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
      data_reg      <= 64'd0;
      bit_count     <= 7'd0;
      reg_count     <= 7'd0;
      temp_reg_count<= 7'd0;
      serial_out_reg<= 1'b0;
      done_reg      <= 1'b0;
    end else begin
      if (done_reg) begin
        // Reconfigure on completion based on 'sel'
        case (sel)
          3'b000: begin
            data_reg <= 64'd0;
            bit_count<= 7'd0;
          end
          3'b001: begin
            data_reg <= {56'd0, data_in[7:0]};
            bit_count<= 7'd7;
          end
          3'b010: begin
            data_reg <= {48'd0, data_in[15:0]};
            bit_count<= 7'd15;
          end
          3'b011: begin
            data_reg <= {32'd0, data_in[31:0]};
            bit_count<= 7'd31;
          end
          3'b100: begin
            data_reg <= data_in;
            bit_count<= 7'd63;
          end
          default: begin
            data_reg <= 64'd0;
            bit_count<= 7'd0;
          end
        endcase
      end else if (bit_count > 7'd0) begin
        // Shift data and decrement bit count
        data_reg  <= data_reg >> 1;
        bit_count <= bit_count - 1;
      end
      reg_count    <= bit_count;
      temp_reg_count<= reg_count;
      serial_out_reg<= (reg_count != 7'd0 || bit_count != 7'd0) ? data_reg[0] : 1'b0;
      done_reg     <= (bit_count == 7'd0) ? 1'b1 : 1'b0;
    end
  end

  // 3-stage pipeline registers for TX outputs and serial clock
  reg serial_out_stage1, serial_out_stage2, serial_out_stage3;
  reg done_stage1, done_stage2, done_stage3;
  reg serial_clk_stage1, serial_clk_stage2, serial_clk_stage3;

  always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
      serial_out_stage1 <= 1'b0;
      serial_out_stage2 <= 1'b0;
      serial_out_stage3 <= 1'b0;
      done_stage1       <= 1'b0;
      done_stage2       <= 1'b0;
      done_stage3       <= 1'b0;
      serial_clk_stage1 <= 1'b0;
      serial_clk_stage2 <= 1'b0;
      serial_clk_stage3 <= 1'b0;
    end else begin
      serial_out_stage1 <= serial_out_reg;
      serial_out_stage2 <= serial_out_stage1;
      serial_out_stage3 <= serial_out_stage2;
      done_stage1       <= done_reg;
      done_stage2       <= done_stage1;
      done_stage3       <= done_stage2;
      // Generate and pipeline serial clock signal (gated by temp_reg_count)
      serial_clk_stage1 <= (temp_reg_count != 7'd0) ? clk : 1'b0;
      serial_clk_stage2 <= serial_clk_stage1;
      serial_clk_stage3 <= serial_clk_stage2;
    end
  end

  assign serial_out = serial_out_stage3;
  assign done       = done_stage3;
  assign serial_clk = serial_clk_stage3;

endmodule

// Optimized RX block with combined sequential logic and 3-cycle pipelining
module rx_block(
    input  wire        clk,
    input  wire        reset_n,
    input  wire        data_in,
    input  wire        serial_clk,
    input  wire [2:0]  sel,
    output wire        done,
    output wire [63:0] data_out
);

  // State registers for RX state machine
  reg [63:0] data_reg;
  reg [7:0]  bit_count;
  reg [7:0]  count;
  reg        serial_clk_d;
  reg        rx_done;
  reg [63:0] rx_data_out;

  // Combined always block: capture serial data on rising edge of serial_clk and update counters
  always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
      serial_clk_d   <= 1'b0;
      data_reg       <= 64'd0;
      bit_count      <= 8'd0;
      count          <= 8'd0;
      rx_done        <= 1'b0;
      rx_data_out    <= 64'd0;
    end else begin
      serial_clk_d   <= serial_clk;
      // Rising edge detection for serial_clk
      if (serial_clk && !serial_clk_d) begin
        data_reg <= {data_reg[62:0], data_in};
        bit_count<= bit_count + 1;
      end
      if (bit_count != 8'd0) begin
        count <= count + 1;
        if (count >= bit_count) begin
          rx_done <= 1'b1;
          case (sel)
            3'b000: rx_data_out <= 64'd0;
            3'b001: rx_data_out <= {56'd0, data_reg[7:0]};
            3'b010: rx_data_out <= {48'd0, data_reg[15:0]};
            3'b011: rx_data_out <= {32'd0, data_reg[31:0]};
            3'b100: rx_data_out <= data_reg;
            default: rx_data_out <= 64'd0;
          endcase
        end else begin
          rx_done <= 1'b0;
        end
      end else begin
        count <= 8'd0;
        rx_done <= 1'b0;
      end
    end
  end

  // 3-stage pipeline registers for RX outputs
  reg rx_done_stage1, rx_done_stage2, rx_done_stage3;
  reg [63:0] rx_data_out_stage1, rx_data_out_stage2, rx_data_out_stage3;

  always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
      rx_done_stage1       <= 1'b0;
      rx_done_stage2       <= 1'b0;
      rx_done_stage3       <= 1'b0;
      rx_data_out_stage1   <= 64'd0;
      rx_data_out_stage2   <= 64'd0;
      rx_data_out_stage3   <= 64'd0;
    end else begin
      rx_done_stage1       <= rx_done;
      rx_done_stage2       <= rx_done_stage1;
      rx_done_stage3       <= rx_done_stage2;
      rx_data_out_stage1   <= rx_data_out;
      rx_data_out_stage2   <= rx_data_out_stage1;
      rx_data_out_stage3   <= rx_data_out_stage2;
    end
  end

  assign done     = rx_done_stage3;
  assign data_out = rx_data_out_stage3;

endmodule

output.rtl/thermostat.v:
module thermostat (
    input  wire         i_clk,    // Clock
    input  wire         i_rst,    // Asynchronous active-low reset
    input  wire [5:0]   i_temp_feedback, // Temperature feedback bits:
                                        // [5] = i_full_cold, [4] = i_medium_cold,
                                        // [3] = i_low_cold, [2] = i_low_hot,
                                        // [1] = i_medium_hot, [0] = i_full_hot
    input  wire         i_fan_on, // Manual fan control (1 = on)
    input  wire         i_enable, // Enable thermostat (0 = off)
    input  wire         i_fault,  // Fault signal (1 = fault active)
    input  wire         i_clr,    // Clear fault signal (assert to return to AMBIENT)
    output reg          o_heater_full,
    output reg          o_heater_medium,
    output reg          o_heater_low,
    output reg          o_aircon_full,
    output reg          o_aircon_medium,
    output reg          o_aircon_low,
    output reg          o_fan,
    output reg [2:0]    o_state   // FSM state output
);

   // State encoding
   localparam HEAT_LOW   = 3'b000;
   localparam HEAT_MED   = 3'b001;
   localparam HEAT_FULL  = 3'b010;
   localparam AMBIENT    = 3'b011;
   localparam COOL_LOW   = 3'b100;
   localparam COOL_MED   = 3'b101;
   localparam COOL_FULL  = 3'b110;

   // State registers
   reg [2:0] state, next_state;

   //-------------------------------------------------------------------------
   // Next State Logic (combinational)
   // Evaluate temperature feedback only when no fault is active.
   // Priority: Cold conditions > Hot conditions > Ambient.
   //-------------------------------------------------------------------------
   always @(*) begin
       // Default next state: AMBIENT
       next_state = AMBIENT;
       if (!i_fault) begin
           if (i_temp_feedback[5]) begin       // i_full_cold
               next_state = HEAT_FULL;
           end else if (i_temp_feedback[4]) begin // i_medium_cold
               next_state = HEAT_MED;
           end else if (i_temp_feedback[3]) begin // i_low_cold
               next_state = HEAT_LOW;
           end else if (i_temp_feedback[0]) begin // i_full_hot
               next_state = COOL_FULL;
           end else if (i_temp_feedback[1]) begin // i_medium_hot
               next_state = COOL_MED;
           end else if (i_temp_feedback[2]) begin // i_low_hot
               next_state = COOL_LOW;
           end else begin
               next_state = AMBIENT;
           end
       end
   end

   //-------------------------------------------------------------------------
   // State Register Update
   // On each rising clock edge (when i_rst is high), update the state.
   // Priority overrides:
   //   1. Asynchronous reset (i_rst = 0) -> state = AMBIENT.
   //   2. Fault active (i_fault = 1) -> state remains unchanged.
   //   3. Disable (i_enable = 0) -> state forced to AMBIENT.
   //   4. Clear fault (i_clr asserted) -> state set to AMBIENT.
   //   5. Normal operation -> state = next_state.
   //-------------------------------------------------------------------------
   always @(posedge i_clk or negedge i_rst) begin
       if (!i_rst) begin
           state <= AMBIENT;
       end else begin
           if (i_fault) begin
               // Fault active: do not update state.
               state <= state;
           end else if (!i_enable) begin
               // Disable override: force state to AMBIENT.
               state <= AMBIENT;
           end else if (i_clr) begin
               // Clear fault: return to AMBIENT on next clock edge.
               state <= AMBIENT;
           end else begin
               state <= next_state;
           end
       end
   end

   //-------------------------------------------------------------------------
   // Output Logic
   // Outputs are synchronous to i_clk and are asynchronously reset.
   // Overriding conditions:
   //   - i_fault = 1: All outputs forced to 0.
   //   - i_enable = 0: All outputs forced to 0 and state internally AMBIENT.
   // Otherwise, outputs follow the FSM state:
   //   Heating states: activate corresponding heater output.
   //   Cooling states: activate corresponding aircon output.
   //   AMBIENT: all heater/aircon outputs 0.
   // Fan control: o_fan = 1 if any heater/aircon output is active OR if i_fan_on = 1.
   //-------------------------------------------------------------------------
   always @(posedge i_clk or negedge i_rst) begin
       if (!i_rst) begin
           o_heater_full    <= 1'b0;
           o_heater_medium  <= 1'b0;
           o_heater_low     <= 1'b0;
           o_aircon_full    <= 1'b0;
           o_aircon_medium  <= 1'b0;
           o_aircon_low     <= 1'b0;
           o_fan            <= 1'b0;
           o_state          <= AMBIENT;
       end else begin
           // Fault override: force all outputs to 0.
           if (i_fault) begin
               o_heater_full    <= 1'b0;
               o_heater_medium  <= 1'b0;
               o_heater_low     <= 1'b0;
               o_aircon_full    <= 1'b0;
               o_aircon_medium  <= 1'b0;
               o_aircon_low     <= 1'b0;
               o_fan            <= 1'b0;
               o_state          <= state;  // State remains but outputs are off.
           end 
           // Disable override: force outputs to 0 and state to AMBIENT.
           else if (!i_enable) begin
               o_heater_full    <= 1'b0;
               o_heater_medium  <= 1'b0;
               o_heater_low     <= 1'b0;
               o_aircon_full    <= 1'b0;
               o_aircon_medium  <= 1'b0;
               o_aircon_low     <= 1'b0;
               o_fan            <= 1'b0;
               o_state          <= AMBIENT;
           end 
           // Normal operation based on FSM state.
           else begin
               case (state)
                   HEAT_FULL: begin
                       o_heater_full    <= 1'b1;
                       o_heater_medium  <= 1'b0;
                       o_heater_low     <= 1'b0;
                       o_aircon_full    <= 1'b0;
                       o_aircon_medium  <= 1'b0;
                       o_aircon_low     <= 1'b0;
                   end
                   HEAT_MED: begin
                       o_heater_full    <= 1'b0;
                       o_heater_medium  <= 1'b1;
                       o_heater_low     <= 1'b0;
                       o_aircon_full    <= 1'b0;
                       o_aircon_medium  <= 1'b0;
                       o_aircon_low     <= 1'b0;
                   end
                   HEAT_LOW: begin
                       o_heater_full    <= 1'b0;
                       o_heater_medium  <= 1'b0;
                       o_heater_low     <= 1'b1;
                       o_aircon_full    <= 1'b0;
                       o_aircon_medium  <= 1'b0;
                       o_aircon_low     <= 1'b0;
                   end
                   COOL_FULL: begin
                       o_heater_full    <= 1'b0;
                       o_heater_medium  <= 1'b0;
                       o_heater_low     <= 1'b0;
                       o_aircon_full    <= 1'b1;
                       o_aircon_medium  <= 1'b0;
                       o_aircon_low     <= 1'b0;
                   end
                   COOL_MED: begin
                       o_heater_full    <= 1'b0;
                       o_heater_medium  <= 1'b0;
                       o_heater_low     <= 1'b0;
                       o_aircon_full    <= 1'b0;
                       o_aircon_medium  <= 1'b1;
                       o_aircon_low     <= 1'b0;
                   end
                   COOL_LOW: begin
                       o_heater_full    <= 1'b0;
                       o_heater_medium  <= 1'b0;
                       o_heater_low     <= 1'b0;
                       o_aircon_full    <= 1'b0;
                       o_aircon_medium  <= 1'b0;
                       o_aircon_low     <= 1'b1;
                   end
                   AMBIENT: begin
                       o_heater_full    <= 1'b0;
                       o_heater_medium  <= 1'b0;
                       o_heater_low     <= 1'b0;
                       o_aircon_full    <= 1'b0;
                       o_aircon_medium  <= 1'b0;
                       o_aircon_low     <= 1'b0;
                   end
               endcase

               // Fan control: Turn fan on if any heater/aircon output is active,
               // or if i_fan_on is asserted.
               if ((state == HEAT_FULL) || (state == HEAT_MED) || (state == HEAT_LOW) ||
                   (state == COOL_FULL) || (state == COOL_MED) || (state == COOL_LOW))
                   o_fan <= 1'b1;
               else
                   o_fan <= i_fan_on;

               o_state <= state;
           end
       end
   end

endmodule

output.rtl/ttc_counter_lite.sv:
module ttc_counter_lite (
  input  logic                  clk,
  input  logic                  reset,
  input  logic [3:0]            axi_addr,
  input  logic [31:0]           axi_wdata,
  input  logic                  axi_write_en,
  input  logic                  axi_read_en,
  output logic [31:0]           axi_rdata,
  output logic                  interrupt
);

  // Control register bit positions
  localparam CTRL_ENABLE        = 0;
  localparam CTRL_INTERVAL_MODE = 1;
  localparam CTRL_INT_ENABLE    = 2;

  // Internal registers
  reg [31:0] count;         // Counter register (only lower 16 bits used)
  reg [31:0] match_value;   // Match value register (lower 16 bits used)
  reg [31:0] reload_value;  // Reload value register (lower 16 bits used)
  reg [31:0] control;       // Control register
  reg         match_flag;   // Flag set when counter matches match_value
  reg [31:0] old_count;     // Used to detect counter transition
  reg [31:0] status;        // Status register (bit0 = interrupt status)

  // Counter update: increments when enabled, and on match event either reloads (interval mode)
  // or holds (non-interval mode). old_count is captured at the beginning of each cycle.
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      count      <= 32'd0;
      old_count  <= 32'd0;
    end else begin
      old_count <= count;  // capture previous count value for match detection
      if (control[CTRL_ENABLE]) begin
        if (count == match_value) begin
          if (control[CTRL_INTERVAL_MODE])
            count <= reload_value;  // reload on match in interval mode
          else
            count <= match_value;   // hold at match value in non-interval mode
        end else begin
          count <= count + 1;        // normal increment
        end
      end
    end
  end

  // Match detection: set match_flag when counter transitions from (match_value-1) to match_value.
  // Note: if the counter is already at match_value, no new match is generated.
  always_ff @(posedge clk or posedge reset) begin
    if (reset)
      match_flag <= 1'b0;
    else if (control[CTRL_ENABLE] && (old_count + 1 == match_value) && (count == match_value))
      match_flag <= 1'b1;
    // match_flag remains asserted until cleared by writing to the status register.
  end

  // AXI-Lite write operations: update registers based on axi_addr.
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      match_value <= 32'd0;
      reload_value<= 32'd0;
      control     <= 32'd0;
      // status will be cleared by its own always_ff block below.
    end else if (axi_write_en) begin
      case (axi_addr)
        4'h0: begin
          // Count Register: update lower 16 bits.
          count[15:0] <= axi_wdata[15:0];
        end
        4'h1: begin
          // Match Value Register: update lower 16 bits.
          match_value[15:0] <= axi_wdata[15:0];
        end
        4'h2: begin
          // Reload Value Register: update lower 16 bits.
          reload_value[15:0] <= axi_wdata[15:0];
        end
        4'h3: begin
          // Control Register: update enable, interval mode, and interrupt enable bits.
          control[CTRL_ENABLE]       <= axi_wdata[0];
          control[CTRL_INTERVAL_MODE] <= axi_wdata[1];
          control[CTRL_INT_ENABLE]   <= axi_wdata[2];
        end
        4'h4: begin
          // Status Register: writing clears the interrupt status and match_flag.
          match_flag <= 1'b0;
          // status will be updated in its own always_ff block.
        end
        default: ; // No operation for undefined addresses.
      endcase
    end
  end

  // Status register update: reflects the current interrupt status.
  // Writing to the status register (address 4'h4) clears the interrupt.
  always_ff @(posedge clk or posedge reset) begin
    if (reset)
      status <= 32'd0;
    else
      status <= {31'd0, match_flag};
  end

  // AXI-Lite read operations: return register values based on axi_addr.
  always_comb begin
    axi_rdata = 32'd0;
    case (axi_addr)
      4'h0: axi_rdata = {16'd0, count[15:0]};    // Count Register (lower 16 bits)
      4'h1: axi_rdata = {16'd0, match_value[15:0]}; // Match Value Register (lower 16 bits)
      4'h2: axi_rdata = {16'd0, reload_value[15:0]}; // Reload Value Register (lower 16 bits)
      4'h3: axi_rdata = control;                    // Control Register
      4'h4: axi_rdata = status;                     // Status Register
      default: axi_rdata = 32'd0;
    endcase
  end

  // Interrupt generation: assert interrupt output when match_flag is set and interrupt enable is active.
  assign interrupt = match_flag && control[CTRL_INT_ENABLE];

endmodule

output.rtl/unpack_one_hot.v:
module unpack_one_hot (
  input         sign,
  input         size,
  input  [2:0]  one_hot_selector,
  input  [255:0] source_reg,
  output reg [511:0] destination_reg
);

  // The module unpacks data from source_reg into destination_reg.
  // Depending on one_hot_selector, a subset of source_reg is used.
  // Note:
  //   • For one_hot_selector = 3'b001, each 1‐bit segment is expanded to 8 bits.
  //     (64 segments are used; 64 bits of source_reg are processed.)
  //   • For one_hot_selector = 3'b010, each 2‐bit segment is expanded to 8 bits.
  //     (64 segments are used; 128 bits of source_reg are processed.)
  //   • For one_hot_selector = 3'b100:
  //       – If size == 1, each 8‐bit segment is sign/zero‐extended to 16 bits.
  //         (32 segments are used; all 256 bits of source_reg are processed.)
  //       – If size == 0, each 4‐bit segment is sign/zero‐extended to 8 bits.
  //         (64 segments are used; all 256 bits of source_reg are processed.)
  //   • In the default case, source_reg is assigned to the lower 256 bits of
  //     destination_reg (the upper 256 bits are zero).

  always @(*) begin
    case(one_hot_selector)
      3'b001: begin
        // Case: one_hot_selector = 3'b001
        // Process 64 segments. Each segment is 1 bit from source_reg,
        // expanded to 8 bits. (Only the lower 64 bits of source_reg are used.)
        integer i;
        reg [511:0] temp;
        temp = 0;
        for (i = 0; i < 64; i = i + 1) begin
          // Extract 1 bit from source_reg at position i.
          // If sign==1, perform sign extension; otherwise, zero extend.
          temp[i*8 +: 8] = (sign ? {7{source_reg[i]}, source_reg[i]} : {7'b0, source_reg[i]});
        end
        destination_reg = temp;
      end
      3'b010: begin
        // Case: one_hot_selector = 3'b010
        // Process 64 segments. Each segment is 2 bits from source_reg,
        // expanded to 8 bits. (Only the lower 128 bits of source_reg are used.)
        integer i;
        reg [511:0] temp;
        temp = 0;
        for (i = 0; i < 64; i = i + 1) begin
          // Extract 2 bits starting at bit position 2*i.
          // Note: source_reg[2*i+1 -: 2] extracts bits [2*i+1:2*i].
          temp[i*8 +: 8] = (sign ? {7{source_reg[2*i+1]}, source_reg[2*i+1 -: 2]} : {7'b0, source_reg[2*i+1 -: 2]});
        end
        destination_reg = temp;
      end
      3'b100: begin
        // Case: one_hot_selector = 3'b100
        if (size == 1) begin
          // When size==1: Process 32 segments.
          // Each segment is 8 bits from source_reg, expanded to 16 bits.
          // (All 256 bits of source_reg are used.)
          integer i;
          reg [511:0] temp;
          temp = 0;
          for (i = 0; i < 32; i = i + 1) begin
            // Extract 8 bits starting at bit position 8*i.
            // source_reg[8*i+7 -: 8] extracts bits [8*i+7 : 8*i].
            temp[i*16 +: 16] = (sign ? {15{source_reg[8*i+7]}, source_reg[8*i+7 -: 8]} : {15'b0, source_reg[8*i+7 -: 8]});
          end
          destination_reg = temp;
        end else begin
          // When size==0: Process 64 segments.
          // Each segment is 4 bits from source_reg, expanded to 8 bits.
          // (All 256 bits of source_reg are used.)
          integer i;
          reg [511:0] temp;
          temp = 0;
          for (i = 0; i < 64; i = i + 1) begin
            // Extract 4 bits starting at bit position 4*i.
            // source_reg[4*i+3 -: 4] extracts bits [4*i+3 : 4*i].
            temp[i*8 +: 8] = (sign ? {7{source_reg[4*i+3]}, source_reg[4*i+3 -: 4]} : {7'b0, source_reg[4*i+3 -: 4]});
          end
          destination_reg = temp;
        end
      end
      default: begin
        // Default: Directly assign source_reg to the lower 256 bits of destination_reg.
        destination_reg = {256'd0, source_reg};
      end
    endcase
  end

endmodule

output.rtl/vending_machine.sv:
Module
// Implements a finite state machine that handles item selection,
// coin insertion, dispensing, change return, cancellation, and error handling.
// The machine supports valid coin values of 1, 2, 5, and 10 units.
// Only items with IDs 3'b001, 3'b010, 3'b011, and 3'b100 are valid.
// Prices are assigned as follows:
//   3'b001  -> Price = 5
//   3'b010  -> Price = 7
//   3'b011  -> Price = 9
//   3'b100  -> Price = 11
//
// The FSM states are:
//   IDLE             : Waiting for a transaction to start.
//   ITEM_SELECTION   : Waiting for a valid item selection.
//   PAYMENT_VALIDATION : Accumulating coins until price is met.
//   DISPENSING_ITEM  : Dispensing the item (one-cycle pulse).
//   RETURN_CHANGE    : Returning change (one-cycle pulse).
//   RETURN_MONEY     : Returning all inserted coins (one-cycle pulse) upon error/cancellation.
//
// Error conditions trigger an error pulse and transition to RETURN_MONEY.
//------------------------------------------------------------

module vending_machine (
  input  logic         clk,
  input  logic         rst,
  input  logic         item_button,
  input  logic [2:0]   item_selected,
  input  logic [3:0]   coin_input,
  input  logic         cancel,
  output logic         dispense_item,
  output logic         return_change,
  output logic [4:0]   item_price,
  output logic [4:0]   change_amount,
  output logic [2:0]   dispense_item_id,
  output logic         error,
  output logic         return_money
);

  //-------------------------------------------------------------------------
  // State Declaration
  //-------------------------------------------------------------------------
  typedef enum logic [2:0] {
    IDLE             = 3'd0,
    ITEM_SELECTION   = 3'd1,
    PAYMENT_VALIDATION = 3'd2,
    DISPENSING_ITEM  = 3'd3,
    RETURN_CHANGE    = 3'd4,
    RETURN_MONEY     = 3'd5
  } state_t;

  state_t current_state, next_state;

  //-------------------------------------------------------------------------
  // Internal Registers and Wires
  //-------------------------------------------------------------------------
  // Accumulated coins (5-bit wide to cover prices and change)
  logic [4:0] coins_accumulated;
  // Registered item price and item ID (set during ITEM_SELECTION)
  logic [4:0] item_price_reg;
  logic [2:0] dispense_item_id_reg;
  // Registered change amount (calculated in DISPENSING_ITEM)
  logic [4:0] change_amount_reg;

  // One-cycle pulse registers for error and return_money signals
  logic error_reg, return_money_reg;

  // Registers to detect rising edges for toggle signals
  logic item_button_reg, cancel_reg;

  // Next state register values for sequential registers
  logic [4:0] coins_accumulated_next;
  logic [4:0] item_price_reg_next;
  logic [2:0] dispense_item_id_reg_next;
  logic [4:0] change_amount_reg_next;

  // Flag to indicate an error condition (set high for one cycle)
  logic error_detected;

  //-------------------------------------------------------------------------
  // Function: valid_coin
  // Returns true if coin_input is one of the valid coin values: 1, 2, 5, or 10.
  //-------------------------------------------------------------------------
  function automatic logic valid_coin (input logic [3:0] coin);
    if ((coin == 4'd1) || (coin == 4'd2) ||
        (coin == 4'd5) || (coin == 4'd10))
      valid_coin = 1;
    else
      valid_coin = 0;
  endfunction

  //-------------------------------------------------------------------------
  // Combinational Logic: Next State and Register Updates
  //-------------------------------------------------------------------------
  always_comb begin
    // Default assignments: retain current values unless changed
    next_state               = current_state;
    error_detected           = 1'b0;
    coins_accumulated_next   = coins_accumulated;
    item_price_reg_next      = item_price_reg;
    dispense_item_id_reg_next= dispense_item_id_reg;
    change_amount_reg_next   = change_amount_reg;

    case (current_state)
      //-------------------------------------------------------------------------
      // IDLE State
      //-------------------------------------------------------------------------
      IDLE: begin
        // If item_button rising edge, start a new transaction.
        if (item_button && !item_button_reg) begin
          next_state = ITEM_SELECTION;
        end
        // If coin inserted without item selection, trigger error.
        else if (coin_input != 4'd0) begin
          error_detected = 1;
          next_state     = RETURN_MONEY;
        end
      end

      //-------------------------------------------------------------------------
      // ITEM_SELECTION State
      //-------------------------------------------------------------------------
      ITEM_SELECTION: begin
        // Check for valid item selection.
        if ((item_selected == 3'b001) || (item_selected == 3'b010) ||
            (item_selected == 3'b011) || (item_selected == 3'b100)) begin
          // Set price and item ID based on selection.
          case (item_selected)
            3'b001: item_price_reg_next = 5'd5;
            3'b010: item_price_reg_next = 5'd7;
            3'b011: item_price_reg_next = 5'd9;
            3'b100: item_price_reg_next = 5'd11;
            default: item_price_reg_next = 5'd0;
          endcase
          dispense_item_id_reg_next = item_selected;
          coins_accumulated_next    = 5'd0;  // Reset coin accumulator.
          next_state                = PAYMENT_VALIDATION;
        end
        // Cancellation during item selection triggers error.
        else if (cancel && !cancel_reg) begin
          error_detected = 1;
          next_state     = RETURN_MONEY;
        end
        // Coin insertion in ITEM_SELECTION is invalid.
        else if (coin_input != 4'd0) begin
          error_detected = 1;
          next_state     = RETURN_MONEY;
        end
      end

      //-------------------------------------------------------------------------
      // PAYMENT_VALIDATION State
      //-------------------------------------------------------------------------
      PAYMENT_VALIDATION: begin
        // If a coin is inserted, validate and accumulate.
        if (coin_input != 4'd0) begin
          if (valid_coin(coin_input))
            coins_accumulated_next = coins_accumulated + coin_input;
          else begin
            error_detected = 1;
            next_state     = RETURN_MONEY;
          end
        end
        // If accumulated coins meet/exceed the item price, proceed to dispensing.
        if (coins_accumulated >= item_price_reg)
          next_state = DISPENSING_ITEM;
        // Cancellation during payment triggers error.
        else if (cancel && !cancel_reg) begin
          error_detected = 1;
          next_state     = RETURN_MONEY;
        end
      end

      //-------------------------------------------------------------------------
      // DISPENSING_ITEM State
      //-------------------------------------------------------------------------
      DISPENSING_ITEM: begin
        // Dispense the item for one cycle.
        if (coins_accumulated > item_price_reg) begin
          change_amount_reg_next = coins_accumulated - item_price_reg;
          next_state             = RETURN_CHANGE;
        end
        else if (coins_accumulated == item_price_reg) begin
          next_state = IDLE;
        end
        // Otherwise, remain in DISPENSING_ITEM (should not occur).
        else
          next_state = DISPENSING_ITEM;
      end

      //-------------------------------------------------------------------------
      // RETURN_CHANGE State
      //-------------------------------------------------------------------------
      RETURN_CHANGE: begin
        // Stay in RETURN_CHANGE for one cycle.
        next_state = IDLE;
      end

      //-------------------------------------------------------------------------
      // RETURN_MONEY State
      //-------------------------------------------------------------------------
      RETURN_MONEY: begin
        // Stay in RETURN_MONEY for one cycle.
        next_state = IDLE;
      end

      default: next_state = IDLE;
    endcase
  end

  //-------------------------------------------------------------------------
  // Sequential Logic: State and Register Updates
  //-------------------------------------------------------------------------
  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      current_state       <= IDLE;
      coins_accumulated   <= 5'd0;
      item_price_reg      <= 5'd0;
      dispense_item_id_reg<= 3'd0;
      change_amount_reg   <= 5'd0;
      error_reg           <= 1'b0;
      return_money_reg    <= 1'b0;
      item_button_reg     <= 1'b0;
      cancel_reg          <= 1'b0;
    end
    else begin
      // Detect rising edges for toggle signals.
      item_button_reg <= item_button;
      cancel_reg      <= cancel;

      // Update state and internal registers.
      current_state       <= next_state;
      coins_accumulated   <= coins_accumulated_next;
      item_price_reg      <= item_price_reg_next;
      dispense_item_id_reg<= dispense_item_id_reg_next;
      change_amount_reg   <= change_amount_reg_next;
      // Error pulse: active for one cycle.
      error_reg           <= error_detected;
      // Return money pulse: active in RETURN_MONEY state.
      return_money_reg    <= (current_state == RETURN_MONEY);
    end
  end

  //-------------------------------------------------------------------------
  // Output Assignments
  //-------------------------------------------------------------------------
  // In ITEM_SELECTION and PAYMENT_VALIDATION, display the selected item's price and ID.
  assign item_price       = ((current_state == ITEM_SELECTION) || 
                             (current_state == PAYMENT_VALIDATION)) ? item_price_reg : 5'd0;
  assign dispense_item_id = ((current_state == ITEM_SELECTION) || 
                             (current_state == PAYMENT_VALIDATION)) ? dispense_item_id_reg : 3'd0;

  // In RETURN_CHANGE state, output the calculated change amount.
  assign change_amount    = (current_state == RETURN_CHANGE) ? change_amount_reg : 5'd0;

  // Error and return_money outputs are driven by one-cycle pulse registers.
  assign error            = error_reg;
  assign return_money     = return_money_reg;

  // One-cycle pulse for dispensing the item.
  assign dispense_item    = (current_state == DISPENSING_ITEM);

  // One-cycle pulse for returning change.
  assign return_change    = (current_state == RETURN_CHANGE);

endmodule

output.rtl/vga_controller.sv:
module vga_controller (
    input  logic         clock,
    input  logic         reset,
    input  logic [7:0]   color_in,
    output logic         hsync,
    output logic         vsync,
    output logic [7:0]   red,
    output logic [7:0]   green,
    output logic [7:0]   blue,
    output logic [9:0]   next_x,
    output logic [9:0]   next_y,
    output logic         sync,
    output logic         clk,
    output logic         blank
);

   // Horizontal Timing Parameters
   parameter H_ACTIVE = 640;
   parameter H_FRONT  = 16;
   parameter H_PULSE  = 96;
   parameter H_BACK   = 48;
   localparam H_TOTAL = H_ACTIVE + H_FRONT + H_PULSE + H_BACK;  // 800

   // Vertical Timing Parameters
   parameter V_ACTIVE = 480;
   parameter V_FRONT  = 10;
   parameter V_PULSE  = 2;
   parameter V_BACK   = 33;
   localparam V_TOTAL = V_ACTIVE + V_FRONT + V_PULSE + V_BACK;  // 525

   // Counters for horizontal and vertical positions
   logic [9:0] h_counter;
   logic [9:0] v_counter;

   // All logic is implemented in a single always_ff block.
   always_ff @(posedge clock or posedge reset) begin
      if (reset) begin
         h_counter <= 10'd0;
         v_counter <= 10'd0;
         hsync     <= 1'b1;
         vsync     <= 1'b1;
         red       <= 8'd0;
         green     <= 8'd0;
         blue      <= 8'd0;
         next_x    <= 10'd0;
         next_y    <= 10'd0;
         sync      <= 1'b0;
         blank     <= 1'b0;
         clk       <= clock;  // Direct connection to input clock
      end
      else begin
         // Horizontal Counter: Increment each cycle; reset when end of line is reached.
         if (h_counter == H_TOTAL - 1) begin
            h_counter <= 10'd0;
            // At the end of a horizontal line, increment the vertical counter.
            if (v_counter == V_TOTAL - 1)
               v_counter <= 10'd0;
            else
               v_counter <= v_counter + 1;
         end
         else begin
            h_counter <= h_counter + 1;
         end

         // Generate hsync: ACTIVE (high) during active + front porch; LOW during horizontal sync pulse.
         if ((h_counter >= (H_ACTIVE + H_FRONT)) && (h_counter < (H_ACTIVE + H_FRONT + H_PULSE)))
            hsync <= 1'b0;
         else
            hsync <= 1'b1;

         // Generate vsync: ACTIVE (high) during active + front porch; LOW during vertical sync pulse.
         if ((v_counter >= (V_ACTIVE + V_FRONT)) && (v_counter < (V_ACTIVE + V_FRONT + V_PULSE)))
            vsync <= 1'b0;
         else
            vsync <= 1'b1;

         // Blank signal: ACTIVE HIGH when either hsync or vsync is low.
         blank <= (~hsync) | (~vsync);

         // RGB Color Outputs: During active region, output scaled color_in; otherwise, blank.
         if ((h_counter < H_ACTIVE) && (v_counter < V_ACTIVE)) begin
            red   <= {color_in[7:5], 5'd0};  // Scale red to 8 bits
            green <= {color_in[4:2], 5'd0};  // Scale green to 8 bits
            blue  <= {color_in[1:0], 6'd0};  // Scale blue to 8 bits
         end
         else begin
            red   <= 8'd0;
            green <= 8'd0;
            blue  <= 8'd0;
         end

         // Pixel Position Tracking: next_x and next_y reflect current counters when in active region.
         if ((h_counter < H_ACTIVE) && (v_counter < V_ACTIVE)) begin
            next_x <= h_counter;
            next_y <= v_counter;
         end
         else begin
            next_x <= 10'd0;
            next_y <= 10'd0;
         end

         // The sync signal is fixed at 0.
         sync <= 1'b0;

         // The clk output is directly connected to the input clock.
         clk <= clock;
      end
   end

endmodule

module vga_controller (
    input  logic         clock,      // 25 MHz
    input  logic         reset,      // Active high
    input  logic [7:0]   color_in,   // Pixel color data (RRRGGGBB)
    output logic [9:0]   next_x,     // x-coordinate of NEXT pixel that will be drawn
    output logic [9:0]   next_y,     // y-coordinate of NEXT pixel that will be drawn
    output logic         hsync,      // HSYNC (to VGA connector)
    output logic         vsync,      // VSYNC (to VGA connector)
    output logic [7:0]   red,        // RED (to resistor DAC VGA connector)
    output logic [7:0]   green,      // GREEN (to resistor DAC to VGA connector)
    output logic [7:0]   blue,       // BLUE (to resistor DAC to VGA connector)
    output logic         sync,       // SYNC to VGA connector
    output logic         clk,        // CLK to VGA connector
    output logic         blank,      // BLANK to VGA connector
    output logic [7:0]   h_state,    // States of Horizontal FSM
    output logic [7:0]   v_state     // States of Vertical FSM
);

    // Timing parameters for horizontal timing
    parameter logic [9:0] H_ACTIVE  =  10'd640;
    parameter logic [9:0] H_FRONT   =  10'd16;
    parameter logic [9:0] H_PULSE   =  10'd96;
    parameter logic [9:0] H_BACK    =  10'd48;
    // Timing parameters for vertical timing
    parameter logic [9:0] V_ACTIVE  =  10'd480;
    parameter logic [9:0] V_FRONT   =  10'd10;
    parameter logic [9:0] V_PULSE   =  10'd2;
    parameter logic [9:0] V_BACK    =  10'd33;
    // Logic levels
    parameter logic LOW   = 1'b0;
    parameter logic HIGH  = 1'b1;
    // Horizontal state encoding
    parameter logic [7:0] H_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] H_FRONT_STATE   = 8'd1;
    parameter logic [7:0] H_PULSE_STATE   = 8'd2;
    parameter logic [7:0] H_BACK_STATE    = 8'd3;
    // Vertical state encoding
    parameter logic [7:0] V_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] V_FRONT_STATE   = 8'd1;
    parameter logic [7:0] V_PULSE_STATE   = 8'd2;
    parameter logic [7:0] V_BACK_STATE    = 8'd3;

    // Internal signals
    logic line_done;
    logic [9:0] h_counter;
    logic [9:0] v_counter;
    // Registers to hold previous sync values for blank calculation
    logic hsync_reg, vsync_reg;

    // Total periods
    localparam logic [9:0] T_H = H_ACTIVE + H_FRONT + H_PULSE + H_BACK; // 800
    localparam logic [9:0] T_V = V_ACTIVE + V_FRONT + V_PULSE + V_BACK; // 525

    // Main state machine: Horizontal and Vertical timing
    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            h_counter   <= 10'd0;
            v_counter   <= 10'd0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            line_done   <= LOW;
            hsync_reg   <= LOW;
            vsync_reg   <= LOW;
        end
        else begin
            // -------------------------------
            // Horizontal Timing FSM
            // -------------------------------
            case (h_state)
                H_ACTIVE_STATE: begin
                    if (h_counter < H_ACTIVE - 1) begin
                        h_counter <= h_counter + 1;
                        h_state   <= H_ACTIVE_STATE;
                    end
                    else begin
                        h_state   <= H_FRONT_STATE;
                        h_counter <= h_counter + 1;
                    end
                    hsync <= HIGH;
                end
                H_FRONT_STATE: begin
                    if (h_counter < (H_ACTIVE + H_FRONT) - 1) begin
                        h_counter <= h_counter + 1;
                        h_state   <= H_FRONT_STATE;
                    end
                    else begin
                        h_state   <= H_PULSE_STATE;
                        h_counter <= h_counter + 1;
                    end
                    hsync <= HIGH;
                end
                H_PULSE_STATE: begin
                    if (h_counter < (H_ACTIVE + H_FRONT + H_PULSE) - 1) begin
                        h_counter <= h_counter + 1;
                        h_state   <= H_PULSE_STATE;
                    end
                    else begin
                        h_state   <= H_BACK_STATE;
                        h_counter <= h_counter + 1;
                    end
                    hsync <= LOW;
                end
                H_BACK_STATE: begin
                    if (h_counter < T_H - 1) begin
                        h_counter <= h_counter + 1;
                        h_state   <= H_BACK_STATE;
                    end
                    else begin
                        h_state   <= H_ACTIVE_STATE;
                        h_counter <= 10'd0;
                        line_done <= HIGH;
                    end
                    hsync <= HIGH;
                end
            endcase

            // -------------------------------
            // Vertical Timing FSM
            // -------------------------------
            case (v_state)
                V_ACTIVE_STATE: begin
                    if (v_counter < V_ACTIVE - 1) begin
                        v_counter <= v_counter + 1;
                        v_state   <= V_ACTIVE_STATE;
                    end
                    else begin
                        v_state   <= V_FRONT_STATE;
                        v_counter <= v_counter + 1;
                    end
                    vsync <= HIGH;
                end
                V_FRONT_STATE: begin
                    if (v_counter < (V_ACTIVE + V_FRONT) - 1) begin
                        v_counter <= v_counter + 1;
                        v_state   <= V_FRONT_STATE;
                    end
                    else begin
                        v_state   <= V_PULSE_STATE;
                        v_counter <= v_counter + 1;
                    end
                    vsync <= HIGH;
                end
                V_PULSE_STATE: begin
                    if (v_counter < (V_ACTIVE + V_FRONT + V_PULSE) - 1) begin
                        v_counter <= v_counter + 1;
                        v_state   <= V_PULSE_STATE;
                    end
                    else begin
                        v_state   <= V_BACK_STATE;
                        v_counter <= v_counter + 1;
                    end
                    vsync <= LOW;
                end
                V_BACK_STATE: begin
                    if (v_counter < T_V - 1) begin
                        v_counter <= v_counter + 1;
                        v_state   <= V_BACK_STATE;
                    end
                    else begin
                        v_state   <= V_ACTIVE_STATE;
                        v_counter <= 10'd0;
                    end
                    vsync <= HIGH;
                end
            endcase

            // -------------------------------
            // Update sync registers for blank signal
            // -------------------------------
            hsync_reg <= hsync;
            vsync_reg <= vsync;

            // -------------------------------
            // RGB Signal Handling
            // -------------------------------
            // During active periods, drive RGB with color_in; otherwise, zero.
            if (h_state == H_ACTIVE_STATE && v_state == V_ACTIVE_STATE) begin
                red   <= color_in;
                green <= color_in;
                blue  <= color_in;
            end
            else begin
                red   <= 8'd0;
                green <= 8'd0;
                blue  <= 8'd0;
            end
        end
    end

    // Combinational assignments
    assign clk   = clock;
    assign sync  = 1'b0;
    assign blank = hsync_reg & vsync_reg;
    assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
    assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

endmodule

