output.rtl/virtual2physical_tlb.sv:
Module with TLB, Page Table Handler, and Control Unit

module virtual2physical_tlb #(parameter ADDR_WIDTH = 8, PAGE_WIDTH = 8, TLB_SIZE = 4, PAGE_TABLE_SIZE = 16) (
    input         clk,
    input         reset,
    input  [ADDR_WIDTH-1:0] virtual_address,
    output [PAGE_WIDTH-1:0] physical_address,
    output        hit,
    output        miss
);
    wire tlb_write_enable, flush, ready;
    wire [PAGE_WIDTH-1:0] page_table_entry;

    // Instantiate the TLB module
    TLB #(.TLB_SIZE(TLB_SIZE), .ADDR_WIDTH(ADDR_WIDTH), .PAGE_WIDTH(PAGE_WIDTH)) tlb (
        .clk(clk),
        .reset(reset),
        .virtual_address(virtual_address),
        .tlb_write_enable(tlb_write_enable),
        .flush(flush),
        .page_table_entry(page_table_entry),
        .physical_address(physical_address),
        .hit(hit),
        .miss(miss)
    );

    // Instantiate the Page Table Handler module
    PageTableHandler #(.ADDR_WIDTH(ADDR_WIDTH), .PAGE_WIDTH(PAGE_WIDTH), .PAGE_TABLE_SIZE(PAGE_TABLE_SIZE)) page_table_handler(
        .clk(clk),
        .reset(reset),
        .miss(miss),
        .virtual_page(virtual_address),
        .page_table_entry(page_table_entry),
        .ready(ready)
    );

    // Instantiate the Control Unit module
    ControlUnit control_unit (
        .clk(clk),
        .reset(reset),
        .hit(hit),
        .miss(miss),
        .ready(ready),
        .tlb_write_enable(tlb_write_enable),
        .flush(flush)
    );
endmodule

module TLB #(parameter TLB_SIZE = 4, ADDR_WIDTH = 8, PAGE_WIDTH = 8) (
    input         clk,
    input         reset,
    input  [ADDR_WIDTH-1:0] virtual_address,
    input         tlb_write_enable,
    input         flush,
    input  [PAGE_WIDTH-1:0] page_table_entry,
    output reg [PAGE_WIDTH-1:0] physical_address,
    output reg      hit,
    output reg      miss
);
    // TLB Storage
    reg [ADDR_WIDTH-1:0] virtual_tags [0:TLB_SIZE-1];
    reg [PAGE_WIDTH-1:0] physical_pages [0:TLB_SIZE-1];
    reg valid_bits [0:TLB_SIZE-1];
    reg [$clog2(TLB_SIZE)-1:0] replacement_index; // Index for the next replacement
    integer i;

    // Combinational logic for TLB lookup
    always_comb begin
        hit      = 1'b0;
        miss     = 1'b1;
        physical_address = {PAGE_WIDTH{1'b0}};
        if (flush) begin
            // When flushing, treat the TLB as empty
            hit      = 1'b0;
            miss     = 1'b0;
            physical_address = {PAGE_WIDTH{1'b0}};
        end else begin
            for (i = 0; i < TLB_SIZE; i = i + 1) begin
                if (valid_bits[i] && (virtual_tags[i] == virtual_address)) begin
                    hit      = 1'b1;
                    miss     = 1'b0;
                    physical_address = physical_pages[i];
                end
            end
        end
    end

    // Sequential logic for updating the TLB
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            for (i = 0; i < TLB_SIZE; i = i + 1) begin
                valid_bits[i] <= 1'b0;
            end
            replacement_index <= 0;
        end else begin
            if (flush) begin
                // Invalidate all TLB entries on flush
                for (i = 0; i < TLB_SIZE; i = i + 1) begin
                    valid_bits[i] <= 1'b0;
                end
            end else if (tlb_write_enable) begin
                // Update the TLB with the new page table entry using a simple replacement policy
                if (|valid_bits) begin
                    // All entries are valid; use the replacement index to update
                    virtual_tags[replacement_index] <= virtual_address;
                    physical_pages[replacement_index] <= page_table_entry;
                    valid_bits[replacement_index] <= 1'b1;
                    replacement_index <= (replacement_index + 1) % TLB_SIZE;
                end else begin
                    // Find a free slot
                    integer j;
                    for (j = 0; j < TLB_SIZE; j = j + 1) begin
                        if (!valid_bits[j]) begin
                            virtual_tags[j] <= virtual_address;
                            physical_pages[j] <= page_table_entry;
                            valid_bits[j] <= 1'b1;
                            replacement_index <= (j + 1) % TLB_SIZE;
                            break;
                        end
                    end
                end
            end
        end
    end
endmodule

module PageTableHandler #(parameter ADDR_WIDTH = 8, PAGE_WIDTH = 8, PAGE_TABLE_SIZE = 16) (
    input         clk,
    input         reset,
    input         miss,
    input  [ADDR_WIDTH-1:0] virtual_page,
    output reg [PAGE_WIDTH-1:0] page_table_entry,
    output reg      ready
);
    // Parameterized Page Table Memory
    reg [PAGE_WIDTH-1:0] page_table_memory [0:PAGE_TABLE_SIZE-1];

    // Combinational read of the page table entry
    assign page_table_entry = page_table_memory[virtual_page];

    // Sequential logic for initializing and updating the page table handler
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            // Initialize Page Table Memory during reset
            page_table_memory[0] <= 8'h0;
            page_table_memory[1] <= 8'h1;
            page_table_memory[2] <= 8'h2;
            page_table_memory[3] <= 8'h3;  
            page_table_memory[4] <= 8'h4;
            page_table_memory[5] <= 8'h5;
            page_table_memory[6] <= 8'h6;
            page_table_memory[7] <= 8'h7;
            page_table_memory[8] <= 8'h8;  
            page_table_memory[9] <= 8'h9;
            page_table_memory[10] <= 8'hA;
            page_table_memory[11] <= 8'hB;  
            page_table_memory[12] <= 8'hC;
            page_table_memory[13] <= 8'hD;
            page_table_memory[14] <= 8'hE;
            page_table_memory[15] <= 8'hF;          
            ready <= 1'b0;
        end else if (miss) begin
            // Simulate memory access delay and indicate readiness
            ready <= 1'b1;
        end else begin
            ready <= 1'b0;
        end
    end
endmodule

module ControlUnit (
    input         clk,
    input         reset,
    input         hit,
    input         miss,
    input         ready,
    output reg    tlb_write_enable,
    output reg    flush
);
    reg [1:0] state;

    localparam IDLE   = 2'b00,
               FETCH  = 2'b01,
               UPDATE = 2'b10;

    // State machine to manage control flow for TLB updates and flushing
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            state         <= IDLE;
            tlb_write_enable <= 1'b0;
            flush         <= 1'b0;
        end else begin
            case (state)
                IDLE: begin
                    // Wait for a TLB miss to trigger a fetch of the page table entry
                    if (miss) begin
                        state <= FETCH;
                    end
                    tlb_write_enable <= 1'b0;
                    flush <= 1'b0;
                end
                FETCH: begin
                    // Wait until the Page Table Handler indicates that the entry is ready
                    if (ready) begin
                        state <= UPDATE;
                        tlb_write_enable <= 1'b1; // Enable TLB write for updating the entry
                    end else begin
                        tlb_write_enable <= 1'b0;
                    end
                    flush <= 1'b0;
                end
                UPDATE: begin
                    // After updating the TLB, return to the idle state
                    state <= IDLE;
                    tlb_write_enable <= 1'b0;
                    flush <= 1'b0;
                end
                default: begin
                    state <= IDLE;
                    tlb_write_enable <= 1'b0;
                    flush <= 1'b0;
                end
            endcase
        end
    end
endmodule

output.rtl/wishbone_to_ahb_bridge.sv:
module wishbone_to_ahb_bridge (
  input  wire         clk_i,       // Wishbone clock
  input  wire         rst_i,       // Active-low Wishbone reset
  input  wire         cyc_i,       // Wishbone cycle valid
  input  wire         stb_i,       // Wishbone strobe valid
  input  wire [3:0]   sel_i,       // Wishbone byte enables
  input  wire         we_i,        // Wishbone write enable
  input  wire [31:0]  addr_i,      // Wishbone address
  input  wire [31:0]  data_i,      // Wishbone write data
  input  wire         hclk,        // AHB clock (assumed same as clk_i for simplicity)
  input  wire         hreset_n,    // Active-low AHB reset
  input  wire [31:0]  hrdata,      // AHB read data
  input  wire [1:0]   hresp,       // AHB response
  input  wire         hready,      // AHB slave ready signal
  output reg  [31:0]  data_o,      // Wishbone read data
  output reg          ack_o,       // Wishbone acknowledge
  output reg [1:0]    htrans,      // AHB transaction type
  output reg [2:0]    hsize,       // AHB transfer size
  output reg [2:0]    hburst,      // AHB burst type (SINGLE only)
  output reg          hwrite,      // AHB write enable
  output reg [31:0]   haddr,       // AHB address
  output reg [31:0]   hwdata       // AHB write data
);

  //-------------------------------------------------------------------------
  // State Encoding for the Wishbone-to-AHB bridge FSM
  //-------------------------------------------------------------------------
  typedef enum logic [1:0] {
    IDLE = 2'b00,
    WAIT = 2'b01
  } state_t;

  state_t state, next_state;

  // Internal registers to latch Wishbone transaction parameters
  reg [31:0] latched_addr;
  reg [31:0] latched_data;
  reg [3:0]  latched_sel;
  reg        latched_we;
  reg [2:0]  latched_hsize;  // Computed based on sel_i

  //-------------------------------------------------------------------------
  // FSM: Manages the protocol translation and pipelining of AHB transactions.
  // In IDLE state, the bridge waits for a valid Wishbone transaction (cyc_i & stb_i).
  // Upon detection, it latches the transaction parameters, computes the aligned
  // AHB address and transfer size, performs endian conversion on the write data,
  // and drives the AHB interface signals.
  // In the WAIT state, the bridge holds the AHB signals until the AHB slave asserts
  // hready. Once hready is seen, for read transactions the hrdata is converted back,
  // and ack_o is asserted to complete the Wishbone transaction.
  //-------------------------------------------------------------------------
  always @(posedge clk_i or negedge rst_i) begin
    if (!rst_i) begin
      state         <= IDLE;
      ack_o         <= 1'b0;
      htrans        <= 2'b00;
      hburst        <= 3'b000;
      haddr         <= 32'd0;
      hwdata        <= 32'd0;
      hwrite        <= 1'b0;
      hsize         <= 3'b000;
      data_o        <= 32'd0;
    end
    else begin
      case (state)
        IDLE: begin
          ack_o         <= 1'b0;
          // Clear AHB signals when idle
          htrans        <= 2'b00;
          hburst        <= 3'b000;
          haddr         <= 32'd0;
          hwdata        <= 32'd0;
          hwrite        <= 1'b0;
          hsize         <= 3'b000;
          data_o        <= 32'd0;

          // Detect a valid Wishbone transaction
          if (cyc_i && stb_i) begin
            // Latch Wishbone transaction parameters
            latched_addr  <= addr_i;
            latched_data  <= data_i;
            latched_sel   <= sel_i;
            latched_we    <= we_i;

            // Determine AHB transfer size based on sel_i:
            //  - 4'b1111: Full word transfer (size = 3'b011)
            //  - 4'b0011: Halfword transfer (size = 3'b010)
            //  - 4'b0001: Byte transfer (size = 3'b001)
            // For any other sel_i value, default to word transfer.
            case (latched_sel)
              4'b1111: latched_hsize <= 3'b011;
              4'b0011: latched_hsize <= 3'b010;
              4'b0001: latched_hsize <= 3'b001;
              default: latched_hsize <= 3'b011;
            endcase

            // Drive AHB transaction signals:
            // Set htrans to NON_SEQ (2'b10) to indicate address phase.
            htrans        <= 2'b10;
            // hburst is always SINGLE (3'b000).
            hburst        <= 3'b000;
            // Align the AHB address based on the transfer size.
            case (latched_sel)
              4'b1111: haddr <= latched_addr;
              4'b0011: haddr <= latched_addr & 32'hFFFFFFFC;
              4'b0001: haddr <= latched_addr & 32'hFFFFFFF8;
              default: haddr <= latched_addr;
            endcase
            // Drive the write enable.
            hwrite        <= latched_we;
            // Perform endian conversion: convert Wishbone little-endian data
            // to AHB big-endian format.
            hwdata        <= { latched_data[7:0],
                                latched_data[15:8],
                                latched_data[23:16],
                                latched_data[31:24] };
            // Transition to WAIT state to await AHB slave readiness.
            state         <= WAIT;
          end
        end

        WAIT: begin
          // Hold AHB signals until hready is asserted.
          if (hready) begin
            // For read transactions, perform endian conversion on hrdata.
            if (!latched_we) begin
              data_o <= { hrdata[7:0],
                          hrdata[15:8],
                          hrdata[23:16],
                          hrdata[31:24] };
            end
            // Assert ack_o to signal completion of the Wishbone transaction.
            ack_o <= 1'b1;
            // Clear AHB signals after transaction completion.
            htrans        <= 2'b00;
            hburst        <= 3'b000;
            haddr         <= 32'd0;
            hwdata        <= 32'd0;
            hwrite        <= 1'b0;
            // Pass the computed transfer size to hsize.
            hsize         <= latched_hsize;
            // Return to IDLE state.
            state         <= IDLE;
          end
          else begin
            // Maintain AHB signals while waiting.
            htrans        <= 2'b10;
            hburst        <= 3'b000;
            // haddr, hwdata, and hwrite remain as latched.
          end
        end

        default: state <= IDLE;
      endcase
    end
  end

endmodule

output.rtl/Word_Change_Pulse.sv:
module Word_Change_Pulse#(
    parameter DATA_WIDTH = 8 // Default word width
) (
    input  wire                  clk,               // Clock signal for synchronizing operations
    input  wire                  reset,             // Reset signal to initialize the module
    input  wire [DATA_WIDTH-1:0] data_in,           // Input data, width defined by parameter DATA_WIDTH
    input  wire [DATA_WIDTH-1:0] mask,              // Mask signal to enable/disable change detection for each bit
    input  wire [DATA_WIDTH-1:0] match_pattern,     // Pattern to match for generating the pulse
    input  wire                  enable,            // Enable signal to allow module operation
    input  wire                  latch_pattern,     // Signal to latch the match pattern
    output reg                   word_change_pulse, // Output signal indicating a change in any bit of data_in
    output reg                   pattern_match_pulse, // Output signal indicating a match with the pattern
    output reg [DATA_WIDTH-1:0]  latched_pattern    // Latched pattern for comparison
);

    wire [DATA_WIDTH-1:0] change_pulses;

    reg [DATA_WIDTH-1:0] masked_data_in;
    reg [DATA_WIDTH-1:0] masked_change_pulses;

    // Registers used to generate one-cycle pulses
    reg word_prev;
    reg pattern_prev;

    // Instantiate Bit_Change_Detector modules for each bit
    genvar i;
    generate
       for(i = 0; i < DATA_WIDTH; i = i + 1) begin : bit_detectors
          Bit_Change_Detector bit_detector_inst (
             .clk(clk),
             .reset(reset),
             .bit_in(data_in[i]),
             .change_pulse(change_pulses[i])
          );
       end
    endgenerate

    // Main synchronous process
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            masked_data_in          <= {DATA_WIDTH{1'b0}};
            masked_change_pulses    <= {DATA_WIDTH{1'b0}};
            word_change_pulse       <= 1'b0;
            pattern_match_pulse     <= 1'b0;
            latched_pattern         <= {DATA_WIDTH{1'b0}};
            word_prev               <= 1'b0;
            pattern_prev            <= 1'b0;
        end else if (enable) begin
            // Latch the current match pattern if latch_pattern is asserted
            if (latch_pattern)
                latched_pattern <= match_pattern;

            // Apply the mask to data_in and the change pulses
            masked_data_in          <= data_in & mask;
            masked_change_pulses    <= change_pulses & mask;

            // Generate a one-cycle pulse for word_change_pulse when any masked bit changes.
            // The pulse is generated on the rising edge of the condition.
            if ((|masked_change_pulses) && (!word_prev))
                word_change_pulse <= 1'b1;
            else
                word_change_pulse <= 1'b0;
            word_prev <= (|masked_change_pulses);

            // Generate a one-cycle pulse for pattern_match_pulse when the masked data matches
            // the latched pattern (only on the rising edge of the match condition).
            if ((masked_data_in == (latched_pattern & mask)) && (!pattern_prev))
                pattern_match_pulse <= 1'b1;
            else
                pattern_match_pulse <= 1'b0;
            pattern_prev <= (masked_data_in == (latched_pattern & mask));
        end else begin
            // When enable is low, clear the pulses and internal flags.
            word_change_pulse <= 1'b0;
            pattern_match_pulse <= 1'b0;
            word_prev <= 1'b0;
            pattern_prev <= 1'b0;
        end
    end

endmodule


// Bit_Change_Detector Module
module Bit_Change_Detector (
   input  wire clk,          // Clock signal
   input  wire reset,        // Reset signal to initialize the module
   input  wire bit_in,       // Single bit input to detect changes
   output reg  change_pulse  // Pulse signal indicating a change in the input bit
);

    reg bit_in_d;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            bit_in_d      <= 1'b0;
            change_pulse  <= 1'b0;
        end else begin
            // If the current bit differs from the previous value, assert the pulse.
            if (bit_in !== bit_in_d)
                change_pulse <= 1'b1;
            else
                change_pulse <= 1'b0;
            // Update the stored previous bit value.
            bit_in_d <= bit_in;
        end
    end

endmodule

